-- Poems batch 399
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-572','木兰花慢','刘克庄','宋','宋词','song-ci','木兰花慢','[]','新来衰态见，书懒读，镜休看。',122,'宋词/ci.song.14000.json','["新来衰态见，书懒读，镜休看。", "笑量窄才悭，卷无警策，杯有留残。", "思量减些年甲，怎奈何、须与鬓难瞒。", "假使诏催上道，不如敕放还山。", "数年前乞挂衣冠。", "耄矣尚盘桓。", "且行歌拾穗，未应天上，解胜人间。", "仙家更无理会，至今传、都厕处刘安。", "莫怪是翁矍铄，止缘老子痴顽。"]'),
('song-ci-573','木兰花慢','刘克庄','宋','宋词','song-ci','木兰花慢','[]','维摩居士室，晨有鹊、噪檐声。',122,'宋词/ci.song.14000.json','["维摩居士室，晨有鹊、噪檐声。", "排闼者谁欤，冶容袨服，宝髻珠璎。", "疑是毗耶城里，那天魔、变作散花人。", "姑射神仙雪艳，开元妃子春酲。", "鄜延第一次西京。", "姚魏是知名。", "向欧九记中，思公屏上，描画难成。", "一自朝陵使去，赚洛阳、花鸟望升平。", "感慨桑榆暮景，抉挑草木微情。"]'),
('song-ci-574','摸鱼儿','刘克庄','宋','宋词','song-ci','摸鱼儿','[]','怪新年、倚楼看镜，清狂浑不如旧。',140,'宋词/ci.song.14000.json','["怪新年、倚楼看镜，清狂浑不如旧。", "暮云千里伤心处，那更乱蝉疏柳。", "凝望久。", "怆故国，百年陵阙谁回首。", "功名大谬。", "叹采药名山，读书精舍，此计几时就。", "封侯事，久矣输人妙手。", "沧洲聊作渔叟。", "高冠长剑浑闲物，世上切身惟酒。", "千载后。", "君试看，拔山扛鼎俱乌有。", "英雄骨朽。", "问顾曲周郎，而今还解，来听小词否。"]'),
('song-ci-575','摸鱼儿','刘克庄','宋','宋词','song-ci','摸鱼儿','[]','甚春来、冷烟凄雨，朝朝迟了芳信。',140,'宋词/ci.song.14000.json','["甚春来、冷烟凄雨，朝朝迟了芳信。", "蓦然作暖晴三日，又觉万姝娇困。", "霜点鬓。", "潘令老，年年不带看花分。", "才情减尽。", "怅玉局飞仙，石湖绝笔，孤负这风韵。", "倾城色，懊恼佳人薄命。", "墙头岑寂谁问。", "东风日暮无聊赖，吹得胭脂成粉。", "君细认。", "花共酒，古来二事天尤吝。", "年光去迅。", "漫绿叶成阴，青苔满地，做得异时恨。"]'),
('song-ci-576','摸鱼儿','刘克庄','宋','宋词','song-ci','摸鱼儿','[]','便披蓑、荷锄归去，何须身著宫锦。',140,'宋词/ci.song.14000.json','["便披蓑、荷锄归去，何须身著宫锦。", "与谁共话桑麻事，朱老阮生尤稔。", "筛样饼。", "瓮样茧，长须赤脚供樵饪。", "清流浊品。", "尽扫去胸中，置诸膜外，对酒莫辞饮。", "华胥梦，怕杀人惊晓枕。", "疏窗惟月来闯。", "一生常被弓旌误，且告朝家追寝。", "愁个甚。", "君管取，有薇堪采松堪荫。", "茅山再任。", "幸不是谋臣，又非世将，免犯道家禁。"]'),
('song-ci-577','转调二郎神・二郎神','刘克庄','宋','宋词','song-ci','转调二郎神・二郎神','[]','抽还手版，受用处、十分轻省。',129,'宋词/ci.song.14000.json','["抽还手版，受用处、十分轻省。", "便衣翦家机，饭炊躬稼，且免支移系省。", "帝悯龙锺蠲朝谒，予长假、毋烦申省。", "笑木石虚斋，暮年忺做，端明提省。", "闲冷。", "橐金散尽，书筒来省。", "有小小楼儿，看山待月，绝胜崔公望省。", "两鹤随轩，一奴负锸，此外诸馀从省。", "把一身本末，绿章奏过，泰玄都省。"]'),
('song-ci-578','转调二郎神・二郎神','刘克庄','宋','宋词','song-ci','转调二郎神・二郎神','[]','黄粱梦觉，忽跳出、北扉西省。',127,'宋词/ci.song.14000.json','["黄粱梦觉，忽跳出、北扉西省。", "今似得何人，老僧退院，秀才下省。", "罢草河西淮南诏，没一字、谘尚书省。", "已交侣樵渔，免教人道，弥封官省。", "多幸。", "条冰解去，新衔全省。", "笑杀太师光，赐灵寿杖，有诏扶他入省。", "死谥醉侯，生封诗伯，此事不关朝省。", "便茅屋、送老云边，也胜倚金华省。"]'),
('song-ci-579','转调二郎神・二郎神','刘克庄','宋','宋词','song-ci','转调二郎神・二郎神','[]','一筇两屦，导从比、在京差省。',127,'宋词/ci.song.14000.json','["一筇两屦，导从比、在京差省。", "更不草白麻，不批黄敕，稍觉心清力省。", "幸有善和书堪读，何必然藜芸省。", "且阁起庄骚，专看老易，课程尤省。", "梦境。", "槐阴禁苑，药翻纶省。", "纸裹里，有青铜钱三百，送与酒家展省。", "吊李白坟，挂徐君剑，零落端平同省。", "仅留得、老子婆娑，怎不拂衣华省。"]'),
('song-ci-580','转调二郎神・二郎神','刘克庄','宋','宋词','song-ci','转调二郎神・二郎神','[]','近来塞上，喜蜡弹、羽书清省。',127,'宋词/ci.song.14000.json','["近来塞上，喜蜡弹、羽书清省。", "更万灶分屯，百年和籴，惭傀而今半省。", "蒙鞑残兵骑猪遁，永绝生猺侵省。", "做个太平民，戴花身健，催租符省。", "何幸。", "行人来密，佥军抽省。", "但进有都俞，退无科琐，不用依时出省。", "子厚南宫，仲舒西掖，又报岑参东省。", "趁此际、纳禄悬车，亦为大司农省。"]'),
('song-ci-581','转调二郎神・二郎神','刘克庄','宋','宋词','song-ci','转调二郎神・二郎神','[]','人言官冗，老病底、法当先省。',129,'宋词/ci.song.14000.json','["人言官冗，老病底、法当先省。", "况行则蹒跚，立时跛倚，幸免做他两省。", "客怕逢迎书慵答，得省处、而今姑省。", "笑落尽桃花，仆家梦得，重来郎省。", "凉冷。", "綀衣差薄，蒲葵堪省。", "叹三纪单栖，二毛纯白，情味似潘骑省。", "鬻马遣姬，惟书与画，点检依然难省。", "也不用、畜犬防偷，老去睡眠常省。"]'),
('song-ci-582','长相思','刘克庄','宋','宋词','song-ci','长相思','[]','寒相催。',44,'宋词/ci.song.14000.json','["寒相催。", "暖相催。", "催了开时催谢时。", "丁宁花放迟。", "角声吹。", "笛声吹。", "吹了南枝吹北枝。", "明朝成雪飞。"]'),
('song-ci-583','长相思','刘克庄','宋','宋词','song-ci','长相思','[]','朝有时。',44,'宋词/ci.song.14000.json','["朝有时。", "暮有时。", "潮水犹知日两回。", "人生长别离。", "来有时。", "去有时。", "燕子犹知社后归。", "君行无定期。"]'),
('song-ci-584','长相思','刘克庄','宋','宋词','song-ci','长相思','[]','风萧萧。',44,'宋词/ci.song.14000.json','["风萧萧。", "雨萧萧。", "相送津亭折柳条。", "春愁不自聊。", "烟迢迢。", "水迢迢。", "准拟江边驻画桡。", "舟人频报潮。"]'),
('song-ci-585','长相思','刘克庄','宋','宋词','song-ci','长相思','[]','烟凄凄。',44,'宋词/ci.song.14000.json','["烟凄凄。", "草凄凄。", "野火原头烧断碑。", "不知名姓谁。", "印累累。", "冢累累。", "千万人中几个归。", "荣华朝露晞。"]'),
('song-ci-586','长相思','刘克庄','宋','宋词','song-ci','长相思','[]','劝一杯。',44,'宋词/ci.song.14000.json','["劝一杯。", "复一杯。", "短锸相随死便埋。", "英雄安在哉。", "眉不开。", "怀不开。", "幸有江边旧钓台。", "拂衣归去来。"]'),
('song-ci-587','昭君怨','刘克庄','宋','宋词','song-ci','昭君怨','[]','曾看洛阳旧谱。',48,'宋词/ci.song.14000.json','["曾看洛阳旧谱。", "只许姚黄独步。", "若比广陵花。", "太亏他。", "旧日王侯园圃。", "今日荆榛孤兔。", "君莫说中州。", "怕花愁。"]'),
('song-ci-588','昭君怨','刘克庄','宋','宋词','song-ci','昭君怨','[]','后土宫中标韵。',48,'宋词/ci.song.14000.json','["后土宫中标韵。", "天上人间一本。", "道号玉真妃。", "字琼姬。", "我与花曾半面。", "流落天涯重见。", "莫把玉箫吹。", "怕惊飞。"]'),
('song-ci-589','昭君怨','刘克庄','宋','宋词','song-ci','昭君怨','[]','一个恰雷州住。',48,'宋词/ci.song.14000.json','["一个恰雷州住。", "一个又廉州去。", "名姓在金瓯。", "不如休。", "昨日沙堤行马。", "今日都门飘瓦。", "君莫上长竿。", "下来难。"]'),
('song-ci-590','生查子','刘克庄','宋','宋词','song-ci','生查子','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','繁灯夺霁华。',48,'宋词/ci.song.14000.json','["繁灯夺霁华。", "戏鼓侵明发。", "物色旧时同，情味中年别。", "浅画镜中眉，深拜楼西月。", "人散市声收，渐入愁时节。"]'),
('song-ci-591','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','金甲雕戈，记当日、辕门初立。',114,'宋词/ci.song.14000.json','["金甲雕戈，记当日、辕门初立。", "磨盾鼻、一挥千纸，龙蛇犹湿。", "铁马晓嘶营壁冷，楼船夜渡风涛急。", "有谁怜、猿臂故将军，无功级。", "平戎策，从军什。", "零落尽，慵收拾。", "把茶经香传，时时温习。", "生怕客谈榆塞事，且教儿咏花间集。", "叹臣之壮也不如人，今何及。"]'),
('song-ci-592','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','老子年来，颇自许、心肠铁石。',113,'宋词/ci.song.14000.json','["老子年来，颇自许、心肠铁石。", "尚一点、消磨未尽，爱花成癖。", "懊恼每嫌寒勒住，丁宁莫被晴烘坼。", "柰暄风烈日太无情，如何得。", "张画烛，频频惜。", "凭素手，轻轻摘。", "更几番雨过，彩云无迹。", "今夕不来花下饮，明朝空向枝头觅。", "对残红满院杜鹃啼，添愁寂。"]'),
('song-ci-593','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','赤日黄埃，梦不到、清溪翠麓。',115,'宋词/ci.song.14000.json','["赤日黄埃，梦不到、清溪翠麓。", "空健羡、君家别墅，几株幽独。", "骨冷肌清偏要月，天寒日暮尤宜竹。", "想主人、杖履绕千回，山南北。", "宁委涧，嫌金屋。", "宁映水，羞银烛。", "叹出群风韵，背时装束，竞爱东邻姬傅粉，谁怜空谷人如玉。", "笑林逋、何逊漫为诗，无人读。"]'),
('song-ci-594','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','满腹诗书，馀事到、穰苴兵法。',115,'宋词/ci.song.14000.json','["满腹诗书，馀事到、穰苴兵法。", "新受了、乌公书币，著鞭垂发。", "黄纸红旗喧道路，黑风青草空巢穴。", "向幼安、宣子顶头行，方奇特。", "溪峒事，听侬说。", "龚遂外，无长策。", "便献俘非勇，纳降非怯。", "帐下健儿休尽锐，草间赤子俱求活。", "到崆峒、快寄凯歌来，宽离别。"]'),
('song-ci-595','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','落日登楼，谁管领、倦游狂客。',115,'宋词/ci.song.14000.json','["落日登楼，谁管领、倦游狂客。", "待唤起、沧浪渔父，隔江吹笛。", "看水看山身尚健，忧晴忧雨头先白。", "对暮云、不见美人来，遥天碧。", "山中鹤，应相忆。", "沙上鹭，浑相识。", "想石田茅屋，草深三尺。", "空有鬓如潘骑省，断无面见陶彭泽。", "便倒倾、海水浣衣尘，难湔涤。"]'),
('song-ci-596','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','天壤王郎，数人物、方今第一。',115,'宋词/ci.song.14000.json','["天壤王郎，数人物、方今第一。", "谈笑里、风霆惊座，云烟生笔。", "落落元龙湖海气，琅琅董相天人策。", "问如何、十载尚青衫，诸侯客。", "易爱底，些官职。", "难保底，些名节。", "拟闭门投辖，剧谈三日。", "畴昔评君天下宝，当为天下苍生惜。", "向临分、慷慨出商声，摧金石。"]'),
('song-ci-597','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','鹤驭来时，长占定、一年清绝。',115,'宋词/ci.song.14000.json','["鹤驭来时，长占定、一年清绝。", "九万里、纤云收尽，帝青空阔。", "月露偏为丹桂地，风霜欲放黄花节。", "听玉笙、缥缈度缑山，吹初彻。", "曾直把，龙鳞批。", "曾戏取，鲸牙拔。", "向绛河濯足，咸池晞发。", "俗子底量吾辈事，天仙不在臞儒列。", "世岂无、瑶草与蟠桃，堪攀掇。"]'),
('song-ci-598','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','怪雨盲风，留不住、江边行色。',115,'宋词/ci.song.14000.json','["怪雨盲风，留不住、江边行色。", "烦问讯、冥鸿高士，钓鳌词客。", "千百年传吾辈话，二三子系斯文脉。", "听王郎、一曲玉箫声，凄金石。", "晞发处，怡山碧。", "垂钓处，沧溟白。", "笑而今拙宦，他年遗直。", "只愿常留相见面，未宜轻屈平生膝。", "有狂谈、欲吐且休休，惊邻壁。"]'),
('song-ci-599','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','往日封章，曾耸动、君王颜色。',114,'宋词/ci.song.14000.json','["往日封章，曾耸动、君王颜色。", "今似得、三闾公子，四明狂客。", "古不能箝言者口，天方欲寿中朝脉。", "算人间、岂有病无医，须针石。", "年冉冉，袍犹碧。", "心耿耿，头先白。", "笑臣舒迂缓，臣山愚直。", "拂袖归来羞炙手，望尘拜了难伸膝。", "把富春濑与首阳山，图斋壁。"]'),
('song-ci-600','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','三黜归来，饭疏食、浑无愠色。',115,'宋词/ci.song.14000.json','["三黜归来，饭疏食、浑无愠色。", "中年后、家如旅舍，身如行客。", "轩冕岂非疣赘具，烟霞已是膏盲脉。", "有些儿、隙地更疏泉，堆卷石。", "邻媪饷，新篘碧。", "溪友卖，鲜鳞白。", "向陈编冷笑，孔明元直。", "俗事不教污两耳，宴居聊可盘双膝。", "取当年、行脚一枝筇，悬高壁。"]'),
('song-ci-601','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','畴昔胪传，仗下奏、祥云五色。',115,'宋词/ci.song.14000.json','["畴昔胪传，仗下奏、祥云五色。", "何况是、西山弟子，鹤山宾客。", "上帝照临忠义胆，老师付授文章脉。", "问此君、彷佛似何人，徂徕石。", "园官菜，登盘碧。", "田舍米，翻匙白。", "懒投诗见素，寄书杓直。", "德耀不嫌为隐髻，龟儿已解摇吟膝。", "有谁怜、给札老相如，家徒壁。"]'),
('song-ci-602','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','下见西山，料他日、面无惭色。',115,'宋词/ci.song.14000.json','["下见西山，料他日、面无惭色。", "君记取、不为吕党，亦非秦客。", "有意挽回当世事，无方延得诸贤脉。", "笑海波、渺渺几时平，空衔石。", "园五亩，纷红碧。", "家四世，传清白。", "任天孙笑拙，女嬃嫌直。", "老去何烦援以手，向来不要加诸膝。", "待深山、深处著茅斋，看青壁。"]'),
('song-ci-603','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','八十加三，人尽讶、还童返少。',115,'宋词/ci.song.14000.json','["八十加三，人尽讶、还童返少。", "争信道、夜舂晓织，总曾经了。", "凛凛共姜当日誓，谆谆孟母平生教。", "到如今、象服拥鱼轩，天之报。", "如船藕，如瓜枣。", "斑衣舞，金锺釂。", "望秋宵一点，老人星照。", "尘世少如娘福寿，上苍知得儿忠孝。", "待看他、孙子又生孙，添怀抱。"]'),
('song-ci-604','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','著破青鞋，浑不忆、踏他龙尾。',115,'宋词/ci.song.14000.json','["著破青鞋，浑不忆、踏他龙尾。", "更冷笑、痴人擘划，二三百岁。", "殇子彭篯谁寿夭，灵均渔父争醒醉。", "向江天、极目羡禽鱼，悠然矣。", "杯中物，姑停止。", "床头易，聊抛废。", "慨事常八九，不如人意。", "白雪调高尤协律，落霞语好终伤绮。", "待烦公、老手一摩挲，文公记。"]'),
('song-ci-605','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','昨日梢头，点点似、玉尘珠砾。',115,'宋词/ci.song.14000.json','["昨日梢头，点点似、玉尘珠砾。", "一夜里、天公染就，金丹颜色。", "体质翻嫌西子白，浓妆却笑东邻赤。", "尽重重、帘幕不能遮，香消息。", "寒日短，霜飞急。", "未摇落，须怜惜。", "且乱簪破帽，旋呼鸣瑟。", "便好移来云月地，莫教归去栴檀国。", "怕彩鸾、隐见霎时间，寻无迹。"]'),
('song-ci-606','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','祷祝封姨，休把做、扬沙吹砾。',115,'宋词/ci.song.14000.json','["祷祝封姨，休把做、扬沙吹砾。", "费西帝、许多薰染，浓香深色。", "满插铜匜芳气烈，高张画烛祥光赤。", "向先生、鼻观细参来，三千息。", "人老大，年华急。", "花妖艳，天公惜。", "到一枝摇落，千林萧瑟。", "摘蕊莫教轻糁地，返魂依旧能倾国。", "待彩云、月下再来时，寻陈迹。"]'),
('song-ci-607','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','月露晶英，融结做、秦宫块砾。',115,'宋词/ci.song.14000.json','["月露晶英，融结做、秦宫块砾。", "长殿后、一年芳事，十分秋色。", "织女机边云锦烂，天台赋里晴霞赤。", "恍女仙、空际驾翔鸾，来游息。", "装束晚，飘零急。", "今不乐，空追惜。", "欠红牙按舞，朱弦调瑟。", "岂是时无花鸟使，是他自择风霜国。", "任落英、狼藉委苍苔，稀行迹。"]'),
('song-ci-608','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','谁把灵丹，点化了、荒园瓦砾。',115,'宋词/ci.song.14000.json','["谁把灵丹，点化了、荒园瓦砾。", "奇特处、恰当秋杪，不争春色。", "因甚素娥脂粉艳，怪他白帝车旗赤。", "叹暮年、无句比红儿，芳心息。", "狂飙起，行云急。", "开与谢，俱堪惜。", "唤妓行按酒，客来操瑟。", "扑鼻微香薰世界，解颜一笑迷人国。", "怕匆匆、归去广寒宫，难踪迹。"]'),
('song-ci-609','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','楮叶工夫，辛苦似、镂冰炊砾。',115,'宋词/ci.song.14000.json','["楮叶工夫，辛苦似、镂冰炊砾。", "君看取、天公巧处，自然形色。", "发彩已非前度绿，眼花休问何时赤。", "又谁能、月下待红娘，传音息。", "投辖饮，追欢急。", "持帚扫，痴心惜。", "有埙篪谐律，不宵竽瑟。", "点点散来居士室，丛丛生占骚人国，便高烧、绛蜡写乌丝，留真迹。"]'),
('song-ci-610','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','糁径红裀，莫要放、儿童抛砾。',115,'宋词/ci.song.14000.json','["糁径红裀，莫要放、儿童抛砾。", "知渠是、仙家变幻，佛家空色。", "青女无端工翦彩，紫姑有崇曾迷赤。", "但双双、戏蝶绕空枝，飞还息。", "鲸量减，驹阴急。", "芳事过，馀情惜。", "漫新腔窈渺，奏云和瑟。", "飘荡随他红叶水，萧条化作青芜国。", "忆桥边、池上共攀翻，空留迹。"]'),
('song-ci-611','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','梅雨初收，浑不辨、东坡南荡。',113,'宋词/ci.song.14000.json','["梅雨初收，浑不辨、东坡南荡。", "清旦里、鼓铙动地，车轮空巷。", "画舫稍渐京辇俗，红旗会踏吴儿浪。", "共葬鱼娘子斩蛟翁，穷欢赏。", "麻与麦，俱成长。", "蕉与荔，应来享。", "有累臣泽畔，感时惆怅。", "纵使菖蒲生九节，争如白发长千丈。", "但浩然一笑独醒人，空悲壮。"]'),
('song-ci-612','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','说与行云，且撋就、嫦娥今夕。',115,'宋词/ci.song.14000.json','["说与行云，且撋就、嫦娥今夕。", "俄变见、金蛇能紫，玉蟾能白。", "九万里风清黑眚，三千世界纯银色。", "想天寒、桂老已吹香，堪攀摘。", "湘妃远，谁鸣瑟。", "桓伊去，谁横笛。", "叹素光如旧，朱颜非昔。", "老去欢悰无奈减，向来酒量常嫌窄。", "倩何人、天外挽冰轮，应留得。"]'),
('song-ci-613','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','天上人间，好时节、无过初夏。',113,'宋词/ci.song.14000.json','["天上人间，好时节、无过初夏。", "君记取、瞿昙生后，纯阳来也。", "风骨清臞如野鹤，门庭低小才旋马。", "更旁无红粉有青奴，堪娱夜。", "鲸口吸，银瓶泻。", "蝇头字，篝灯写。", "数而今铁笔，谁如公者。", "便合去开丞相阁，未应牵入耆英社。", "待调羹事了却归来，寻前话。"]'),
('song-ci-614','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','屈指耆英，谁似得、三朝元老。',115,'宋词/ci.song.14000.json','["屈指耆英，谁似得、三朝元老。", "尚留个、管夷吾在，何忧江表。", "世道方占公出处，裔夷争问今年貌。", "怎不移、此手整乾坤，长闲了。", "灵寿却，斑衣绕。", "如瓶李，如瓜枣。", "把禅龛闭定，怕蒲轮到。", "师尚父年浑未艾，中书令考犹为少。", "看画盆、岁岁浴曾玄，添怀抱。"]'),
('song-ci-615','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','笳鼓春城，处处有、丰年语笑。',115,'宋词/ci.song.14000.json','["笳鼓春城，处处有、丰年语笑。", "浑忘却、金莲前导，青藜下照。", "白雪唱来遍寡和，朱颜老去难重少。", "羡遨头、四十已专城，真英妙。", "奎文宠，崇儒教。", "田毛喜，宽租诏。", "有舂陵之什，无潮州表。", "怪雨盲风稀发作，华星秋月争光耀。", "看来年、此夜侍端门，开佳兆。"]'),
('song-ci-616','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','奎墨西来，落笔处、亲蒙天笑。',114,'宋词/ci.song.14000.json','["奎墨西来，落笔处、亲蒙天笑。", "谁信道、郡人生怕，福星移照。", "宾客唱予还和汝，使君安老兼怀少。", "况醉能同乐醒能文，新腔妙。", "无诸国，渐声教。", "元结辈，宣明诏。", "恍梦中辽鹤，重来华表。", "一盏勘书殊简径，万灯侍辇曾荣耀。", "怪晴檐、乾鹊语查查，公归兆。"]'),
('song-ci-617','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','江左惟公，争些子、吾其衽发。',114,'宋词/ci.song.14000.json','["江左惟公，争些子、吾其衽发。", "谈笑里、旄头泛扫，斗杓旋斡。", "投一粒丹元气转，下三数著输棋活。", "把晋朝王谢传同看，谁优劣。", "飞凯奏，清夔峡。", "蠲和籴，宽畿浙。", "有三千功行，待从头说。", "玉斝满斟长寿酒，冰轮探借中秋月。", "更慈帏、喜见凤将雏，添丹穴。"]'),
('song-ci-618','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','见宰官身，出只手、擎他宇宙。',115,'宋词/ci.song.14000.json','["见宰官身，出只手、擎他宇宙。", "筹边外、招徕名胜，登崇勋旧。", "不下莱公扶景德，又如涑水开元祐。", "尽从渠、干贽及吾门，归斯受。", "上林苑，多花柳。", "祁连塞，稀刁斗。", "更红旗破贼，黄云栖亩。", "阿母瑶池枝上实，仙人太华峰头藕。", "泻铜盘、沆瀣入金卮，为公寿。"]'),
('song-ci-619','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','礼乐衣冠，浑靠定、堂堂国老。',114,'宋词/ci.song.14000.json','["礼乐衣冠，浑靠定、堂堂国老。", "出双手、把天裂处，等闲补了。", "谢傅东山心未遂，周郎赤壁功犹小。", "事难於张赵两元台，扶炎绍。", "恢鹤禁，迎商皓。", "开兔苑，延枚叟。", "喜奎星来聚，旄头都扫。", "重译争询裴令貌，御诗也祝汾阳考。", "更何须、远向海山求，安期枣。"]'),
('song-ci-620','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','压倒群芳，天赋与、十分秾艳。',115,'宋词/ci.song.14000.json','["压倒群芳，天赋与、十分秾艳。", "娇嫩处、有情皆惜，无香何慊。", "恰则才如针粟大，忽然谁把胭脂染。", "放迟开、不肯婿梅花，羞寒俭。", "时易过，春难占。", "欢事薄，才情欠。", "觉芳心欲诉，冶容微敛。", "四畔人来攀折去，一番雨有离披渐。", "更那堪、几阵夜来风，吹千点。"]'),
('song-ci-621','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','嫌杀双轮，驾行客、之燕适粤。',115,'宋词/ci.song.14000.json','["嫌杀双轮，驾行客、之燕适粤。", "也不喜、船儿无赖，载他江浙。", "荡子不归鸳被冷，昭君远嫁毡车发。", "叹子规、闲管昔人愁，啼成血。", "渭城柳，争攀折。", "关山月，空圆缺。", "有琵琶改语，锦书难说。", "若要人生长美满，除非世上无离别。", "算古今、此恨似连环，何时绝。"]'),
('song-ci-622','水龙吟','刘克庄','宋','宋词','song-ci','水龙吟','[]','年年岁岁今朝，左弧悬罢浑无事。',125,'宋词/ci.song.14000.json','["年年岁岁今朝，左弧悬罢浑无事。", "吾衰久矣，我辰安在，老之将至。", "懒写京书，怕看除目，败人佳思。", "把东篱掩定，北窗开了，悠然酌、颓然睡。", "客有过门投贽。", "道先生访华胥氏。", "谁能辛苦，陪他绮语，记他奇字。", "屈指先贤，戴花老监，岂其苗裔。", "待异时约取，宽夫彦国，入耆英会。"]'),
('song-ci-623','水龙吟','刘克庄','宋','宋词','song-ci','水龙吟','[]','先生放逐方归，不如前辈抽身早。',125,'宋词/ci.song.14000.json','["先生放逐方归，不如前辈抽身早。", "台郎旧秩，看来俗似，散人新号。", "起舞非狂，行吟非怨，高眠非傲。", "叹终南捷径，太行盘谷，用卿法、从吾好。", "闭了草庐长啸。", "后将军来时休报。", "床头书在，古人出处，今人非笑。", "制个淡词，呷些薄酒，野花簪帽。", "愿云台任满，又还因任，赛汾阳考。"]'),
('song-ci-624','水龙吟','刘克庄','宋','宋词','song-ci','水龙吟','[]','病翁一榻萧然，不知世有欢娱事。',126,'宋词/ci.song.14000.json','["病翁一榻萧然，不知世有欢娱事。", "雀罗庭院，载醪客去，催租人至。", "报答秋光，要些酒量，要些诗思。", "奈长鲸罢吸，寒蛩息响，查瓯外、惟贪睡。", "穷巷幸无干贽。", "或相过、莫知谁氏。", "柴门草户，阙人守舍，任伊题字。", "自和山歌，国风之变，离骚之裔。", "待从今向去，年年强健，插花高会。"]'),
('song-ci-625','水龙吟','刘克庄','宋','宋词','song-ci','水龙吟','[]','平生酷爱渊明，偶然一出归来早。',126,'宋词/ci.song.14000.json','["平生酷爱渊明，偶然一出归来早。", "题诗信意，也书甲子，也书年号。", "陶侃孙儿，孟嘉甥子，疑狂疑傲。", "与柴桑樵牧，斜川鱼鸟，同盟后、归於好。", "除了登临吟啸。", "事如天、莫相谘报。", "田园闲静，市朝翻覆，回头堪笑。", "节序催人，东篱把菊，西风吹帽。", "做先生处士，一生一世，不论资考。"]'),
('song-ci-626','水龙吟','刘克庄','宋','宋词','song-ci','水龙吟','[]','祁公一度貂蝉，先生三度貂蝉了。',126,'宋词/ci.song.14000.json','["祁公一度貂蝉，先生三度貂蝉了。", "燔柴升辂，银蟾烛夜，金乌腾晓。", "喜动龙颜，瑞班虹玉，归功元老。", "纵擎天力倦，明农心切，先还取、中书考。", "末著留侯难办，算除非、烦他商皓。", "紫芝产遍，赤松待久，何时高蹈。", "人世无过，鱼羹饭美，布衾铭好。", "待角巾东路，蹇驴北阜，伴公游钓。"]'),
('song-ci-627','水龙吟','刘克庄','宋','宋词','song-ci','水龙吟','[]','依然这后村翁，阿谁改换新曹号。',126,'宋词/ci.song.14000.json','["依然这后村翁，阿谁改换新曹号。", "虚名砂砾，旁观冷笑，何曾明道。", "吟歇后诗，说无生话，热瞒村獠。", "被儿童盘问，先生因甚，身顽健、年多少。", "不茹园公芝草。", "不曾餐、安期瓜枣。", "要知甲子，陈抟差大，邵雍差小。", "肯学痴人，据鞍求用，染髭藏老。", "待眉毛覆面，看千桃谢，阅三松倒。"]'),
('song-ci-628','水龙吟','刘克庄','宋','宋词','song-ci','水龙吟','[]','儿童不识樗翁。',126,'宋词/ci.song.14000.json','["儿童不识樗翁。", "挽衣借问年今几。", "少如彦国，大如君实，披襟高比。", "德业天渊，有些似处，须眉而已。", "愿老身无事，小车乘兴，名园内、行窝里。", "做取出关周史。", "莫做他、下山园绮。", "从人谤道，是浮丘伯，是庚桑子。", "背伛肩高，幅巾藜杖，敞袍穿履。", "向画图上面，十分似个，见端门底。"]'),
('song-ci-629','水龙吟','刘克庄','宋','宋词','song-ci','水龙吟','[]','即令七十平头，岂能久作人间客。',126,'宋词/ci.song.14000.json','["即令七十平头，岂能久作人间客。", "左车牙落，半分臂小，几茎须白。", "挟种树书，举障尘扇，著游山屐。", "任蛙蟆胜负，鱼龙变化，侬方在、华胥国。", "岛大功名官职。", "眼中花、须臾无迹。", "小儿破贼，二郎作相，有何奇特。", "同辈萧疏，且留铁汉，要摩铜狄。", "向宝钗楼里，天津桥上，月明横笛。"]'),
('song-ci-630','玉漏迟','蒋捷','宋','宋词','song-ci','玉漏迟','["\u897f\u6e56"]','翠鸳双穗冷。',115,'宋词/ci.song.14000.json','["翠鸳双穗冷。", "莺声唤转，春风芳景。", "花涌□香，此度徐妆偏称。", "水月仙人院宇，到处有、西湖如镜。", "烟岫暝。", "纤葱误指，莲峰篁岭。", "料想小阁初逢，正浪拍红猊，袖飞金饼。", "楼倚斜晖，暗把佳期重省。", "万种惺忪笑语，□一点、温柔情性。", "钗倦整。", "盈盈背灯娇影。"]'),
('song-ci-631','高阳台','蒋捷','宋','宋词','song-ci','高阳台','[]','宛转怜香，徘徊顾影，临芳更倚苔身。',122,'宋词/ci.song.14000.json','["宛转怜香，徘徊顾影，临芳更倚苔身。", "多谢残英，飞来远远随人。", "回头却望晴檐下，等几番、小摘微薰。", "到而今、独袅鞭梢，笑不成春。", "愁吟未了烟林晓，有垂杨夹路，也为轻嚬。", "今夜山窗，还□□绕梨云。", "行囊不是吴笺少，问倩谁、去写花真。", "待归时，叶底红肥，细雨如尘。"]'),
('song-ci-632','探春令','蒋捷','宋','宋词','song-ci','探春令','[]','玉窗蝇字记春寒，满茸丝红处。',64,'宋词/ci.song.14000.json','["玉窗蝇字记春寒，满茸丝红处。", "画翠鸳、双展金蜩翅。", "未抵我、愁红腻。", "芳心一点天涯去。", "絮濛濛遮住。", "旧对花、弹阮纤琼指。", "为粉靥、空弹泪。"]'),
('song-ci-633','秋夜雨','蒋捷','宋','宋词','song-ci','秋夜雨','[]','黄云水驿秋笳噎。',62,'宋词/ci.song.14000.json','["黄云水驿秋笳噎。", "吹人双鬓如雪。", "愁多无奈处，谩碎把、寒花轻绝。", "红云转入香心里，夜渐深、人语初歇。", "此际愁更别。", "雁落影、西窗斜月。"]'),
('song-ci-634','秋夜雨','蒋捷','宋','宋词','song-ci','秋夜雨','[]','金衣露湿莺喉噎。',62,'宋词/ci.song.14000.json','["金衣露湿莺喉噎。", "春情不解分雪。", "宝筝弦断尽，但万缕、闲愁难绝。", "长红小白谁亭馆，过禁烟、弹指芳歇。", "今夜休要别。", "且醉宿、缃桃花月。"]'),
('song-ci-635','秋夜雨','蒋捷','宋','宋词','song-ci','秋夜雨','[]','髹车转急风如噎。',62,'宋词/ci.song.14000.json','["髹车转急风如噎。", "冰丝松藕新雪。", "有人凉满袖，怕汗湿、红梢犹绝。", "三更梦断敲荷雨，细听来、疏点还歇。", "茉莉标致别。", "占断了、纱厨香月。"]'),
('song-ci-636','秋夜雨','蒋捷','宋','宋词','song-ci','秋夜雨','[]','红麟不暖瓶笙噎。',62,'宋词/ci.song.14000.json','["红麟不暖瓶笙噎。", "炉灰一片晴雪。", "醉无香嗅醒，但手把、新橙闲绝。", "更深冻损梅花也，听画堂、箫鼓方歇。", "想是天气别。", "豫借与、春风三月。"]'),
('song-ci-637','少年游','蒋捷','宋','宋词','song-ci','少年游','[]','梨边风紧雪难晴。',60,'宋词/ci.song.14000.json','["梨边风紧雪难晴。", "千点照溪明。", "吹絮窗低，唾茸窗小，人隔翠阴行。", "而今白鸟横飞处，烟树渺乡城。", "两袖春寒，一襟春恨，斜日淡无情。"]'),
('song-ci-638','少年游','蒋捷','宋','宋词','song-ci','少年游','[]','枫林红透晚烟青。',60,'宋词/ci.song.14000.json','["枫林红透晚烟青。", "客思满鸥汀。", "二十年来，无家种竹，犹借竹为名。", "春风未了秋风到，老去万缘轻。", "只把平生，闲吟闲咏，谱作棹歌声。"]'),
('song-ci-639','柳梢青','蒋捷','宋','宋词','song-ci','柳梢青','[]','学唱新腔。',61,'宋词/ci.song.14000.json','["学唱新腔。", "秋千架上，钗股敲双。", "柳雨花风，翠松裙褶，红腻鞋帮。", "归来门掩银釭。", "淡月里、疏钟渐撞。", "娇欲人扶，醉嫌人问，斜倚楼窗。"]'),
('song-ci-640','霜天晓角','蒋捷','宋','宋词','song-ci','霜天晓角','[]','人影窗纱。',54,'宋词/ci.song.14000.json','["人影窗纱。", "是谁来折花。", "折则从他折去，知折去、向谁家。", "檐牙。", "枝最佳。", "折时高折些。", "说与折花人道，须插向、鬓边斜。"]'),
('song-ci-641','水龙吟','陈德武','宋','宋词','song-ci','水龙吟','["\u897f\u6e56"]','东南第一名州，西湖自古多佳丽。',126,'宋词/ci.song.14000.json','["东南第一名州，西湖自古多佳丽。", "临堤台榭，画船楼阁，游人歌吹。", "十里荷花，三秋桂子，四山晴翠。", "使百年南渡，一时豪杰，都忘却、平生志。", "可惜天旋时异。", "藉何人、雪当年耻。", "登临形胜，感伤今古，发挥英气。", "力士推山，天吴移水，作农桑地。", "借钱塘潮汐，为君洗尽，岳将军泪。"]'),
('song-ci-642','西江月','陈德武','宋','宋词','song-ci','西江月','[]','山拱罗城四面，柳营横接江东。',58,'宋词/ci.song.14000.json','["山拱罗城四面，柳营横接江东。", "十年前事影随风。", "今日宛如春梦。", "天下几多邮驿，人生到处飘蓬。", "丹霞楼上再相逢。", "横笛为君三弄。"]'),
('song-ci-643','望海潮','陈德武','宋','宋词','song-ci','望海潮','["\u897f\u6e56"]','珑山西峙，浙江东逝，谁馀一箭临冲。',129,'宋词/ci.song.14000.json','["珑山西峙，浙江东逝，谁馀一箭临冲。", "凤舞龙飞，地灵人杰，当年树此勋庸。", "强弩万夫雄。", "令冯夷退舍，海若潜锋。", "拥石成堤，百川约束障西东。", "至今人物蕃丰。", "仰功扬山立，德润川容。", "乐极西湖，愁多南渡，他都是梦魂空。", "感古恨无穷。", "叹表忠无观，古墓谁封。", "棹舣钱塘，浊醪和泪洒秋风。"]'),
('song-ci-644','水龙吟','陈德武','宋','宋词','song-ci','水龙吟','[]','驿楼岁暮萧条，小桃何事迎人笑。',126,'宋词/ci.song.14000.json','["驿楼岁暮萧条，小桃何事迎人笑。", "无言如诉，命暌王母，信沈青鸟。", "靥瘦繁霜，脂销零雨，梦寒清晓。", "自刘郎去后，天台路隔，知孤负、春多少。", "今日玉骢来到。", "喜相逢、菱花孤照。", "清幽谁伴，黄花告谢，芙蓉云老。", "早趁东风，移根换叶，脱身池沼。", "卜佳期，前度琴心一曲，作相思调。"]'),
('song-ci-645','沁园春','陈德武','宋','宋词','song-ci','沁园春','[]','冬夜如年，客枕无眠，怎到天明。',139,'宋词/ci.song.14000.json','["冬夜如年，客枕无眠，怎到天明。", "待数残二十五、寒更点，听馀一百八、晓钟声。", "雨却敲篷，滩头激缆，总与离人诉不平。", "遍闻得，我浚深恨海，砌起愁城。", "问君何事牵萦。", "想最苦人间是别情。", "念千山万水，沈鱼阻雁，一身两地，煼燕煎莺。", "绣枕痕多，锦衾香冷，意有巫山梦不成。", "怎撇下，这两字相思，万里虚名。"]'),
('song-ci-646','西江月','陈德武','宋','宋词','song-ci','西江月','[]','时序去如流矢，人生宛如飞蓬。',58,'宋词/ci.song.14000.json','["时序去如流矢，人生宛如飞蓬。", "石湾江上又逢冬。", "且喜一场初动。", "但见堪舆杳杳，更连山水重重。", "凄凉云物雨濛濛。", "惟足睡中归梦。"]'),
('song-ci-647','望海潮','陈德武','宋','宋词','song-ci','望海潮','[]','山涯海角，天高地厚，长安举首何妨。',129,'宋词/ci.song.14000.json','["山涯海角，天高地厚，长安举首何妨。", "万水朝宗，众星环极，平生此志无忘。", "亭上一翱翔。", "见烟收雾敛，凤翥龙骧。", "海色沧凉，金乌拍翅上扶桑。", "遥瞻咫尺清光。", "物无遐不烛，有隐皆彰。", "发蔀心劳，之官路远，篙师又促归航。", "不敢久徜徉。", "抱梧桐绮实，葵藿心肠。", "假我双翰，一朝飞上五云乡。"]'),
('song-ci-648','木兰花慢','陈德武','宋','宋词','song-ci','木兰花慢','[]','自淮阳别后，一回首、又穷年。',122,'宋词/ci.song.14000.json','["自淮阳别后，一回首、又穷年。", "叹蓬逐旋飚，叶随流水，星散维垣。", "南来忽闻归兴，岂苍天、故意要储贤。", "云慢凌司马赋，风偏动季鹰船。", "梅窗夜月见修妍。", "骏辔忆连钱。", "命画桨溪流，篮舆山郭，囊锦诗篇。", "休辞岁寒远道，对松篁、莫慰寂寥边。", "尘榻谁为我下，酒杯惟待君传。"]'),
('song-ci-649','木兰花慢','陈德武','宋','宋词','song-ci','木兰花慢','[]','对江云日暮，又那更、夜如年。',122,'宋词/ci.song.14000.json','["对江云日暮，又那更、夜如年。", "见霜满晴空，山衔星斗，月挂城垣。", "知心故人间阻，几何时、尊酒会多贤。", "冷落巴山夜雨，凄凉剡水寒船。", "孱容羞睹镜中研。", "远水与天连。", "怪梦有馀甜，酒无好味，诗不成篇。", "刀圭解生毛羽，向晨风、飞傍彩云边。", "报道东君到也，一枝春信先传。"]'),
('song-ci-650','木兰花慢','陈德武','宋','宋词','song-ci','木兰花慢','[]','一春看又尽，问何日、是归年。',122,'宋词/ci.song.14000.json','["一春看又尽，问何日、是归年。", "望五岭重关，九嶷叠翠，满目藩垣。", "苍梧几时舣棹，许论文、高议仰英贤。", "夜立残花影月，朝盼尽柳阴船。", "天台山水世间研。", "天老赤城连。", "好收拾兰庄，白云深处，咏卜居篇。", "重寻旧游莺燕，恐无心、待雁夕阳边。", "声迹今犹密迩，鸾笺莫厌频传。"]'),
('song-ci-651','望海潮','陈德武','宋','宋词','song-ci','望海潮','[]','三分春色，十分官事，令人孤负芳菲。',129,'宋词/ci.song.14000.json','["三分春色，十分官事，令人孤负芳菲。", "歌燕簧莺，语花舞柳，园林好处谁知。", "还忆旧游时。", "对海棠驻马，红药题诗。", "一别东君，回顾又是隔年期。", "相思远在天涯。", "镇海填恨臆，山锁愁眉。", "杜宇能言，鹧鸪有泪，慢劳蝴蝶于飞。", "景与少年宜。", "把榆分新火，香透罗衣。", "风月常存，双鱼报道早来归。"]'),
('song-ci-652','百字谣・念奴娇','陈德武','宋','宋词','song-ci','百字谣・念奴娇','[]','惜花心事，不由人、蝴蝶梦魂先觉。',120,'宋词/ci.song.14000.json','["惜花心事，不由人、蝴蝶梦魂先觉。", "刚纳绣鞋行掠鬓，仰见斗横林杪。", "昨日深红，今朝轻白，颜色殊昏晓。", "此中滋味，料他尘世知少。", "问二十四番风，寒梅并绛楝，始终俱好。", "须看未开开又谢，多少落英颠倒。", "彩缀隋园，鹿游唐苑，哀乐无凭祷。", "此音谁寄，凭阑犹把琴抱。"]'),
('song-ci-653','百字谣・念奴娇','陈德武','宋','宋词','song-ci','百字谣・念奴娇','[]','古今明月，魄生明后，积渐圆还缺。',120,'宋词/ci.song.14000.json','["古今明月，魄生明后，积渐圆还缺。", "秋解伤神春最好，衾枕几番铺设。", "十二瑶台，千金一刻，横竹休吹彻。", "绣帘高揭，戒他莫把灯爇。", "夜久谁共婵娟，掩孤帏睡去，此情尤切。", "梦驾彩鸾何处觅，飞上玉楼琼阙。", "舞按霓裳，歌扬红豆，高处风光别。", "鸟声惊觉，冲冠怒竖吾发。"]'),
('song-ci-654','百字谣・念奴娇','陈德武','宋','宋词','song-ci','百字谣・念奴娇','[]','晚临湘浦，忆鲛人、曾许泪珠绡帕。',77,'宋词/ci.song.14000.json','["晚临湘浦，忆鲛人、曾许泪珠绡帕。", "盥掬空明和月待，宫锁水晶深夜。", "跃壁初圆，浮金不定，敌眼寒光射。", "水心龙镜，喜来翻不成把。", "最恨对面姮娥，舞霓裳掌上，（缺词文）"]'),
('song-ci-655','百字谣・念奴娇','陈德武','宋','宋词','song-ci','百字谣・念奴娇','[]','（缺词文）',5,'宋词/ci.song.14000.json','["（缺词文）"]'),
('song-ci-656','望海潮','陈德武','宋','宋词','song-ci','望海潮','[]','南冠一载，西流万里，离怀孰不伤情。',129,'宋词/ci.song.14000.json','["南冠一载，西流万里，离怀孰不伤情。", "富贵邯郸，雨云巫峡，回头一梦空惊。", "谁辱又谁荣。", "问当时道德，今日功名。", "楚水吴山，向来多少送和迎。", "长安古道长亭。", "叹马啼不驻，车辙难停。", "薇老首阳，芝深商谷，时遥雾拥云平。", "此意已羞评。", "但金缄白雪，锦佩青萍。", "采竹昆仑，有时吹作凤凰鸣。"]'),
('song-ci-657','望海潮','陈德武','宋','宋词','song-ci','望海潮','[]','祖觞东馆，移舟南渡，江天云树离离。',129,'宋词/ci.song.14000.json','["祖觞东馆，移舟南渡，江天云树离离。", "盘谷渔樵，舞雩风咏，渴心常望云霓。", "知与故人齐。", "念翼残犹铩，足蹶还羁。", "百折江流，峡猿水鸟助孤凄。", "几回梦绕山西。", "耐疏篷夜雨，惊枕晨鸡。", "对无声诗，哦有声画，仪形已见端倪。", "回首暮云迷。", "又桐飞金井，燕落乌衣。", "有意相思，双鳞乘羽莫教迟。"]'),
('song-ci-658','西江月','陈德武','宋','宋词','song-ci','西江月','[]','凤舞汉阳月丽，龙吟汉水波飞。',58,'宋词/ci.song.14000.json','["凤舞汉阳月丽，龙吟汉水波飞。", "行云何事驻天涯。", "横玉危阑四倚。", "问岳阳三度后，看尘世几番棋。", "鹤群何处未归来。", "冷落吴头楚尾。"]'),
('song-ci-659','西江月','陈德武','宋','宋词','song-ci','西江月','[]','为问云间滕六，天工何事依违。',58,'宋词/ci.song.14000.json','["为问云间滕六，天工何事依违。", "冬时三白不时为。", "今日驾言春瑞。", "瘦损穷彭泽柳，禁持杀傅岩梅。", "仁风反掌霁天威。", "都做一江流水。"]'),
('song-ci-660','西江月','陈德武','宋','宋词','song-ci','西江月','[]','疏散履穿东郭，流离马没蓝关。',58,'宋词/ci.song.14000.json','["疏散履穿东郭，流离马没蓝关。", "瓜洲谁问卧袁安。", "孤负新年月半。", "铁瓮成银瓮出，金山做玉山看。", "无知儿女不知寒。", "冰箸掌中争看。"]'),
('song-ci-661','西江月','陈德武','宋','宋词','song-ci','西江月','[]','压雪江山亦老，迎春草木俱新。',58,'宋词/ci.song.14000.json','["压雪江山亦老，迎春草木俱新。", "雪销春去逐飞轮。", "谁识静中机运。", "浊浊坝头泥土，攘攘市上风尘。", "为何不住往来人。", "都被利名淘尽。"]'),
('song-ci-662','西江月','陈德武','宋','宋词','song-ci','西江月','[]','有信江头春色，无凭天上浮云。',58,'宋词/ci.song.14000.json','["有信江头春色，无凭天上浮云。", "白衣苍狗又何频。", "岂是随风情性。", "法受三千谪路，翻成万里思亲。", "瓜洲中道不逢人。", "谁寄江南春信。"]'),
('song-ci-663','归朝欢','陈德武','宋','宋词','song-ci','归朝欢','[]','昨夜城头望牛斗。',122,'宋词/ci.song.14000.json','["昨夜城头望牛斗。", "金气横空作龙吼。", "朝天尺一鹤飞书，尊前夺我龙头友。", "风流江左后。", "青毡旧物曾坚守。", "念侨居、淮阳九载，闲却丝纶手。", "花骢欲系无长柳。", "玉箸频挥翻短袖。", "凤凰台近月重圆，紫薇花暖香依旧。", "功名随分有。", "论交要在知心友。", "唱阳关、一杯别酒，先祝斯文寿。"]'),
('song-ci-664','望海潮','陈德武','宋','宋词','song-ci','望海潮','[]','陵山载酒，泗河扬柁，尊前折尽将离。',129,'宋词/ci.song.14000.json','["陵山载酒，泗河扬柁，尊前折尽将离。", "才试牛刀，俄惊凫舄，令人去后多思。", "休唱别离词。", "看玉函星铁，骑佩铜丝。", "丹凤鸣阳，碧梧栖尔最高枝。", "等闲展对声词。", "对一庭明月，千里邦畿。", "西涧家声，玉堂人物，夜窗梦果心期。", "才思浩无涯。", "若深航濂洛，峻驾峨眉。", "胸抱相思，银筝锦字莫教迟。"]'),
('song-ci-665','沁园春','陈德武','宋','宋词','song-ci','沁园春','[]','飞雨一番，杜宇数声，东君又回。',139,'宋词/ci.song.14000.json','["飞雨一番，杜宇数声，东君又回。", "对花垂粉泪，舟移洛甫，柳眉颦黛，马走章台。", "南架海棠，北窗红药，都是当年手自裁。", "伤离别，想今朝去也，明日重来。", "轩车且莫相催。", "待细把衷肠诉此怀。", "这画阑六曲，懒和月倚，朱帘十二，不与风开。", "青杏园林，朱樱酪酒，争似和羹雪后梅。", "那时节，好都将心事，分付多才。"]'),
('song-ci-666','庆春宫・高阳台','陈德武','宋','宋词','song-ci','庆春宫・高阳台','[]','风送深冬，雪消残腊，天时人事相催。',126,'宋词/ci.song.14000.json','["风送深冬，雪消残腊，天时人事相催。", "堂北迎萱，水东问柳，阿谁报道春回。", "土牛装罢，候葭琯、先飞律灰。", "宜春宝字，是处人家，罗绮筵开。", "三年客里情怀。", "千里亲闱，一寸灵台。", "彩燕金钗，青丝生菜，还思纤手安排。", "韶光是也，可人的、如今再来。", "介他眉寿，但愿年年，春酒盈杯。"]'),
('song-ci-667','水调歌头','陈德武','宋','宋词','song-ci','水调歌头','[]','日色隐花萼，清夜宴华晴。',114,'宋词/ci.song.14000.json','["日色隐花萼，清夜宴华晴。", "梁州新曲初就，锦瑟按银筝。", "中坐太真妃子，列坐亲封秦虢，歌笑尽倾城。", "百斛金尊倒，一醉玉山倾。", "扶上马，东小玉，右双成。", "绛纱笼烛高照，宫漏已三更。", "抱得禄儿归去，酒醒三郎何处，忽听鼓鼙惊。", "可惜马嵬恨，不得寄丹青。"]'),
('song-ci-668','水龙吟','陈德武','宋','宋词','song-ci','水龙吟','[]','花骢柳外频嘶，使君底事拼人去。',126,'宋词/ci.song.14000.json','["花骢柳外频嘶，使君底事拼人去。", "圮桥风月，睢陵桃李，几回良遇。", "我待君来，他催君去，谁留君住。", "想尊空北海，诗成东阁，这都是、欢娱处。", "宝月才圆又缺，况人生、会难离易。", "驭风无计，缩地无术，问天无语。", "枯海为炉，赭山为炭，尽烧愁绪。", "把一心天地，一家南北，此身堪寄。"]'),
('song-ci-669','醉春风','陈德武','宋','宋词','song-ci','醉春风','[]','推枕床羞下。',78,'宋词/ci.song.14000.json','["推枕床羞下。", "临鸾眉不画。", "妒深谁复白圭瑕。", "怕怕怕。", "飞燕班姬，昭君延寿，孰知淫雅。", "背倚荼縻架。", "泪满鲛绡帕。", "白头吟断怨琵琶。", "罢罢罢。", "采柏卖珠，牵萝补屋，顺天生化。"]'),
('song-ci-670','水调歌头','陈德武','宋','宋词','song-ci','水调歌头','[]','好是三春景，都在百花轩。',114,'宋词/ci.song.14000.json','["好是三春景，都在百花轩。", "美人眠不成梦，早已绣帘掀。", "分付海棠睡足，检点牡丹开未，桃李寂无言。", "叶露联珠络，枝月坠金盆。", "树铃索，高障槛，补篱藩。", "丁宁莺燕蜂蝶，上下莫争翻。", "遥想韶光九十，只恐花飞一片，瘦减玉颜温。", "不惮银瓶冷，汲井沃芳根。"]'),
('song-ci-671','水调歌头','陈德武','宋','宋词','song-ci','水调歌头','[]','三五嫦娥月，夜色正婵娟。',114,'宋词/ci.song.14000.json','["三五嫦娥月，夜色正婵娟。", "自从窃药归去，天上几千年。", "试问广寒高处，为甚缺多圆少，此理孰为权。", "弦望知天定，离合可人怜。", "典宫锦，歌水调，载楼船。", "谪仙居士何在，月色尚依然。", "遥想人生百岁，三万六千良夜，能得几时圆。", "莫遣金盆落，达曙照无眠。"]'),
('song-ci-672','水调歌头','陈德武','宋','宋词','song-ci','水调歌头','[]','莲衬凌波步，笋浴影娥东。',114,'宋词/ci.song.14000.json','["莲衬凌波步，笋浴影娥东。", "晚妆脂粉犹腻，雪洁弄春溶。", "却似玉盘拈指，莫是金环脱腕，宝镜逐华容。", "好个明珠颗，落在掌窝中。", "可人意，拿不住，握还空。", "骑鲸便欲深取，恐触卧骊龙。", "奈玉春纤冻也，那壁团圆何处，有影却无踪。", "不上广寒殿，便入水晶宫。"]'),
('song-ci-673','水调歌头','陈德武','宋','宋词','song-ci','水调歌头','[]','梦足芙蓉曙，步入牡丹丛。',114,'宋词/ci.song.14000.json','["梦足芙蓉曙，步入牡丹丛。", "试将枝叶枚数，宠紫与娇红。", "如诉如歌体态，轻暖轻寒天气，春色把人烘。", "百斛沈檀味，两腋麝兰风。", "春衫透，罗袜沁，暗回中。", "芳心能有多少，一点束千里。", "只恐避丝行露，漫惹狂蜂轻蝶，珍重惜仪容。", "兰蕙修芳佩，苹藻荐公宫。"]'),
('song-ci-674','惜馀春慢・选冠子','陈德武','宋','宋词','song-ci','惜馀春慢・选冠子','[]','不语佳人，多才名友，天遣伴吾幽独。',138,'宋词/ci.song.14000.json','["不语佳人，多才名友，天遣伴吾幽独。", "令姿潘岳，太素何郎，争似一丛红玉。", "谁为织云锦裳，天孙巧处，暗空机轴。", "别离间、陡觉春风一度，电光惊目。", "因念著、旧日欢娱，清平歌曲。", "板按玉人横竹。", "金盆月落，银烛纱笼，一刻千金难赎。", "微醉欲醒未醒，声声唤起，睡何时足。", "待移根、与赋归来，敢比渊明松菊。"]'),
('song-ci-675','浣溪沙','陈德武','宋','宋词','song-ci','浣溪沙','[]','庭院深沈绝俗埃。',48,'宋词/ci.song.14000.json','["庭院深沈绝俗埃。", "绿苔因雨上层阶。", "画帘低卷燕归来。", "月似有情中夜入，花何无语向人开。", "谩劳飞梦到天台。"]'),
('song-ci-676','西江月','陈德武','宋','宋词','song-ci','西江月','[]','时序去如流水，功名冷似寒灰。',58,'宋词/ci.song.14000.json','["时序去如流水，功名冷似寒灰。", "尽教江庾赋多才。", "一刻千金难买。", "客里月圆月缺，尊前花落花开。", "春来何处带愁来。", "春去此愁还在。"]'),
('song-ci-677','蝶恋花','陈德武','宋','宋词','song-ci','蝶恋花','[]','昨夜狂风今日雨。',70,'宋词/ci.song.14000.json','["昨夜狂风今日雨。", "风雨相催，断送春归去。", "万计千方留不住。", "春归毕竟归何处。", "好鸟如歌花解舞。", "花鸟无情，也诉离愁苦。", "流水落花芳草渡。", "明年好记归时落。"]'),
('song-ci-678','浣溪沙','陈德武','宋','宋词','song-ci','浣溪沙','[]','月落桐梢杜宇啼。',48,'宋词/ci.song.14000.json','["月落桐梢杜宇啼。", "云埋芳树鹧鸪飞。", "夜阑分作送春诗。", "山上安山经几载，口中添口又何时。", "相思一曲诉伊谁。"]'),
('song-ci-679','木兰花慢','陈德武','宋','宋词','song-ci','木兰花慢','[]','自东君别后，对花柳、愈无聊。',122,'宋词/ci.song.14000.json','["自东君别后，对花柳、愈无聊。", "但旅寓年年，梦添夜夜，饭减朝朝。", "应怜此情何似，却梅天、风雨正潇潇。", "奁玉有谁暖眼，带围漫自松腰。", "深沈庭院好香烧。", "水远玉人遥。", "念信阻鸾笺，调空绿绮，字满鲛绡。", "东君也知人意，几黄昏、天际送兰桡。", "锦荔堂前载酒，梧桐月下吹箫。"]'),
('song-ci-680','清平乐','陈德武','宋','宋词','song-ci','清平乐','[]','娥眉淡伫。',54,'宋词/ci.song.14000.json','["娥眉淡伫。", "未约心先许。", "坐待不来来又去。", "直到碧窗深处。", "雨云偏妒妖娇。", "几孤三五良宵。", "要见残妆新画，多应暮暮朝朝。"]'),
('song-ci-681','清平乐','陈德武','宋','宋词','song-ci','清平乐','[]','天孙自织。',54,'宋词/ci.song.14000.json','["天孙自织。", "经纬天南北。", "明月楼台高百尺。", "玉手昔曾亲摘。", "种榆人去何年。", "乘槎偶认张骞。", "报道秋期近也，好将巧思相传。"]'),
('song-ci-682','清平乐','陈德武','宋','宋词','song-ci','清平乐','[]','呼来吸去。',54,'宋词/ci.song.14000.json','["呼来吸去。", "毕竟为谁主。", "软力慢扶花柳舞。", "禁不住颠狂处。", "等闲天易凉炎。", "每教人爱人嫌。", "最是相思病起，呼儿紧下珠帘。"]'),
('song-ci-683','清平乐','陈德武','宋','宋词','song-ci','清平乐','[]','丝丝线线。',54,'宋词/ci.song.14000.json','["丝丝线线。", "惹起云根燕。", "万里江山春欲遍。", "多在梨花庭院。", "经旬一见通宵。", "恍如身在蓝桥。", "记与巫山神女，不禁暮暮朝朝。"]'),
('song-ci-684','清平乐','陈德武','宋','宋词','song-ci','清平乐','[]','随风情性。',54,'宋词/ci.song.14000.json','["随风情性。", "聚散元无定。", "雨过黄昏收拾尽。", "送出月明花影。", "谁言出岫无心。", "腾腾飞上巫岑。", "梦断不知何处，玉人鬓上斜簪。"]'),
('song-ci-685','清平乐','陈德武','宋','宋词','song-ci','清平乐','[]','娇声娇语。',54,'宋词/ci.song.14000.json','["娇声娇语。", "却似深闺女。", "三叠琴心音一缕。", "躲在绿阴深处。", "此音宁与人知。", "此身不与人欺。", "薄暮背将斜月，噤声飞上高枝。"]'),
('song-ci-686','清平乐','陈德武','宋','宋词','song-ci','清平乐','[]','三三两两。',54,'宋词/ci.song.14000.json','["三三两两。", "夜夜教人想。", "偷入霜绡斜隙帐。", "直到珊瑚枕上。", "玉人梦绕江南。", "输他一饷肥甘。", "莫恨我心儿毒，只因你口儿馋。"]'),
('song-ci-687','清平乐','陈德武','宋','宋词','song-ci','清平乐','[]','轻姿傅粉。',54,'宋词/ci.song.14000.json','["轻姿傅粉。", "学得偷香俊。", "百紫千红人未问。", "先与芳心折损。", "一生天赋风流。", "不知节去蜂愁。", "堪笑庄周老子，将身梦里追游。"]'),
('song-ci-688','清平乐','陈德武','宋','宋词','song-ci','清平乐','[]','黄梅雨住。',54,'宋词/ci.song.14000.json','["黄梅雨住。", "青草池塘暮。", "轻许天然乐两部。", "遥想周郎不顾。", "生憎利口喃喃。", "凭谁井塞泥缄。", "最是玉人枕上，几回梦断江南。"]'),
('song-ci-689','清平乐','陈德武','宋','宋词','song-ci','清平乐','[]','星星散散。',54,'宋词/ci.song.14000.json','["星星散散。", "绕地无人管。", "一点寒光虽有烂。", "飞不到河西畔。", "画堂花暗银釭。", "井阑添个双双。", "欲照相思两字，藉风扶过虚窗。"]'),
('song-ci-690','清平乐','陈德武','宋','宋词','song-ci','清平乐','[]','啾啾唧唧。',54,'宋词/ci.song.14000.json','["啾啾唧唧。", "夜夜鸣东壁。", "如诉如歌如涕泣。", "乱我离怀似织。", "画堂帘幕沈深。", "美人睡稳香衾。", "懒妇知眠到晓，尔虫枉自劳心。"]'),
('song-ci-691','醉春风','陈德武','宋','宋词','song-ci','醉春风','[]','陌上轮蹄满。',78,'宋词/ci.song.14000.json','["陌上轮蹄满。", "花间蜂蝶乱，画帘低卷对南山。", "□□□。", "轻暖轻寒，乍晴乍雨，风流云散。", "罗袖伤春晚。", "纨扇惊秋换。", "谁将白雪污青鬟。", "懒懒懒。", "金星笙歌，茅檐风月，悲欢相伴。"]'),
('song-ci-692','玉蝴蝶','陈德武','宋','宋词','song-ci','玉蝴蝶','[]','好是春光秋色，天工巧处，都上花枝。',124,'宋词/ci.song.14000.json','["好是春光秋色，天工巧处，都上花枝。", "更值云情雨态，净沐芳姿。", "醉相扶、霓裳舞困，眠未得、宫锦淋漓。", "有谁知。", "眼空相对，心系相思。", "相思。", "鲛绡帕上，珠悬红泪，水洗胭脂。", "寂寞阑干，无言暗忆旧游时。", "五花骢、载将郎去，双喜鹊、报道郎归。", "卜佳期。", "梦回巫峡，春在瑶池。"]'),
('song-ci-693','千秋岁引','陈德武','宋','宋词','song-ci','千秋岁引','[]','濯锦丰姿，新凉台阁。',98,'宋词/ci.song.14000.json','["濯锦丰姿，新凉台阁。", "懊悔巫云太轻薄。", "琵琶未诉衣衫湿，菱花不照胭脂落。", "凤凰池，鸳鸯殿，重金钥。", "春色画船何处泊。", "秋色丹青人难摸。", "可惜风流总闲却。", "此情不与人知道，知时只恐人挠著。", "碧窗前，银灯下，陪孤酌。"]'),
('song-ci-694','玉蝴蝶','陈德武','宋','宋词','song-ci','玉蝴蝶','[]','金井梧桐飞报，秋期近也，乌鹊成桥。',125,'宋词/ci.song.14000.json','["金井梧桐飞报，秋期近也，乌鹊成桥。", "为问双星何事，长待今宵。", "别今年、新歌暂展，更五鼓、旧恨重摇。", "黯魂销。", "两情脉脉，一水迢迢。", "寂寥。", "寄言儿女，纵能多巧笑，奚暇相调。", "暗想离愁，人间天上古来饶。", "但心坚、天长地久，何意在、雨暮云朝。", "宝香烧。", "无缘驾海，有分吹箫。"]'),
('song-ci-695','木兰花慢','陈德武','宋','宋词','song-ci','木兰花慢','[]','值升平海宇，又春色、与俱还。',118,'宋词/ci.song.14000.json','["值升平海宇，又春色、与俱还。", "向杨柳楼台，海棠庭院，红药阑干。", "可人好风良月，都收拾入锦囊间。", "心事已超尘外，天公分付人间。", "世途陆海拥波澜。", "回首梦中看。", "想酒醒罗浮，云空巫峡，饭熟邯郸。", "从兹破琴煮鹤，猗阑不用对人弹。", "粗足少游衣食，何妨司马江山。"]'),
('song-ci-696','水龙吟','陈德武','宋','宋词','song-ci','水龙吟','[]','问津扬子江头，滔滔潮汐东流去。',126,'宋词/ci.song.14000.json','["问津扬子江头，滔滔潮汐东流去。", "六朝文物，千年陈迹，几更乌兔。", "天限东南，水流今古，地分吴楚。", "喜壮游千里，桑弧蓬矢，功名事、儒生语。", "翘首石头城北，簇楼台、远连芳树。", "雪销天气，澄江如练，碧峰无数。", "银瓮春回，金山钟晓，梦闲鸥鹭。", "早归来，尽日风平人静，孤舟横渡。"]'),
('song-ci-697','望远行','陈德武','宋','宋词','song-ci','望远行','[]','城头初鼓，天街上、渐渐行人声悄。',127,'宋词/ci.song.14000.json','["城头初鼓，天街上、渐渐行人声悄。", "半窗风月，一枕新凉，睡熟不知天晓。", "最是家山千里，远劳归梦，待说离情难觉。", "觉来时，帘外数声啼鸟。", "谁道。", "为甚新来消瘦，底事恹恹烦恼。", "不是悲花，非干病酒，有个离肠难扫。", "怅望江南，天际白云飞处，念我高堂人老。", "寸草心，朝夕怎宽怀抱。"]'),
('song-ci-698','满江红','陈德武','宋','宋词','song-ci','满江红','[]','记当年时，离筵上、把梅花折。',115,'宋词/ci.song.14000.json','["记当年时，离筵上、把梅花折。", "还经尽、江南烟雨，淮阳风雪。", "寒食清明都过了，看看又到端阳节。", "倚阑干、屈指数流光，经年别。", "心一寸、愁肠结。", "千里梦、三更月。", "□晓来寒透，不堪愁绝。", "羞见慈乌啼反哺，厌闲乳燕调新舌。", "睹禽物、愈觉倍伤情，归心切。"]'),
('song-ci-699','惜馀春慢・选冠子','陈德武','宋','宋词','song-ci','惜馀春慢・选冠子','[]','阑葺疏芦，帘编小苇，好个清幽公馆。',138,'宋词/ci.song.14000.json','["阑葺疏芦，帘编小苇，好个清幽公馆。", "栽槐夹道，种菊盈轩，景物便堪咏玩。", "门外一番雨馀，嫩绿缘枝，浅清清眼。", "悄无人，一枕新凉睡觉，燕泥香暖。", "蓦地里、对景伤怀，思量无限。", "回首故园春远。", "松期竹待，壑诮林嘲，苦被浮名牵绊。", "一种思情最长，万叠江山，怎生遮断。", "向北堂见了，忘忧萱草，此心方满。"]'),
('song-ci-700','忆秦娥','陈德武','宋','宋词','song-ci','忆秦娥','[]','疏帘揭。',56,'宋词/ci.song.14000.json','["疏帘揭。", "云端仰见娟娟月。", "娟娟月。", "不应何恨，照人离别。", "闭门独睡空愁绝。", "姮娥梦里低低说。", "低低说。", "悲欢离合，阴晴圆缺。"]'),
('song-ci-701','踏莎行','陈德武','宋','宋词','song-ci','踏莎行','[]','雾失南楼，云低东阁。',68,'宋词/ci.song.14000.json','["雾失南楼，云低东阁。", "枝头不见南飞鹊。", "姮娥何事太多情，今宵故误年时约。", "天易阴晴，人多哀乐。", "从来此事难凭度。", "匆匆又是隔年期，且烧银烛酬高酌。"]'),
('song-ci-702','一翦梅','陈德武','宋','宋词','song-ci','一翦梅','[]','新酒初香菊半含。',72,'宋词/ci.song.14000.json','["新酒初香菊半含。", "月也三三。", "日也三三。", "登高已约上崭岩。", "世事相担。", "风雨相担。", "头上茱萸颠倒簪。", "身在河南。", "心在江南。", "渊明何日解征骖。", "俯也何惭。", "仰也何惭。"]'),
('song-ci-703','鹧鸪天','陈德武','宋','宋词','song-ci','鹧鸪天','[]','三径芳根自不群。',64,'宋词/ci.song.14000.json','["三径芳根自不群。", "每於霜后播清芳。", "枝头蛱蝶如羞见，篱外征鸿不可闻。", "情脉脉，思纷纷。", "绕窗吟咏理馀薰。", "卷帘人在西风里，知是新来瘦几分。"]'),
('song-ci-704','踏莎行','陈德武','宋','宋词','song-ci','踏莎行','[]','声迹随风，浪痕如霰。',68,'宋词/ci.song.14000.json','["声迹随风，浪痕如霰。", "蓝桥路远无由见。", "黄昏肠断倚阑时，看看数尽南飞雁。", "日理丝机，宵拈针线。", "春秋不管莺和燕。", "欲将心事诉佳期，回文直上金銮殿。"]'),
('song-ci-705','踏莎行','陈德武','宋','宋词','song-ci','踏莎行','[]','梅压宫妆，柳横眉黛。',68,'宋词/ci.song.14000.json','["梅压宫妆，柳横眉黛。", "都将留得春光在。", "弄琴台上忽相逢，吹箫月下曾相待。", "海燕春归，江鸿秋迈。", "到头总是恩和爱。", "佳期约在白云间，一团和气春如海。"]'),
('song-ci-706','南浦','张炎','宋','宋词','song-ci','南浦','[]','波暖绿粼粼，燕飞来、好是苏堤才晓。',125,'宋词/ci.song.14000.json','["波暖绿粼粼，燕飞来、好是苏堤才晓。", "鱼没浪痕圆，流红去、翻笑东风难扫。", "荒桥断浦，柳阴撑出扁舟小。", "回首池塘青欲遍，绝似梦中芳草。", "和云流出空山，甚年年净洗，花香不了。", "新渌乍生时，孤村路、犹忆那回曾到。", "馀情渺渺。", "茂林觞咏如今悄。", "前度刘郎归去后，溪上碧桃多少。"]'),
('song-ci-707','高阳台','张炎','宋','宋词','song-ci','高阳台','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','接叶巢莺，平波卷絮，断桥斜日归船。',122,'宋词/ci.song.14000.json','["接叶巢莺，平波卷絮，断桥斜日归船。", "能几番游，看花又是明年。", "东风且伴蔷薇住，到蔷薇、春已堪怜。", "更凄然。", "万绿西泠，一抹荒烟。", "当年燕子知何处，但苔深韦曲，草暗斜川。", "见说新愁，如今也到鸥边。", "无心再续笙歌梦，掩重门、浅醉闲眠。", "莫开帘。", "怕见飞花，怕听啼鹃。"]'),
('song-ci-708','忆旧游','张炎','宋','宋词','song-ci','忆旧游','[]','看方壶拥翠，太极垂光，积雪初晴。',124,'宋词/ci.song.14000.json','["看方壶拥翠，太极垂光，积雪初晴。", "阊阖开黄道，正绿章封事，飞上层青。", "古台半压琪树，引袖拂寒星。", "见玉冷闲坡，金明邃宇，人住深清。", "幽寻。", "自来去，对华表千年，天籁无声。", "别有长生路，看花开花落，何处无春。", "露台深锁丹气，隔水唤青禽。", "尚记得归时，鹤衣散影都是云。"]'),
('song-ci-709','凄凉犯','张炎','宋','宋词','song-ci','凄凉犯','[]','萧疏野柳嘶寒马，芦花深、还见游猎。',116,'宋词/ci.song.14000.json','["萧疏野柳嘶寒马，芦花深、还见游猎。", "山势北来，甚时曾到，醉魂飞越。", "酸风自咽。", "拥吟鼻、征衣暗裂。", "正凄迷，天涯羁旅，不似灞桥雪。", "谁念而今老，懒赋长杨，倦怀休说。", "空怜断梗梦依依，岁华轻别。", "待击歌壶，怕如意、和冰冻折。", "且行行，平沙万里尽是月。"]'),
('song-ci-710','壶中天・念奴娇','张炎','宋','宋词','song-ci','壶中天・念奴娇','[]','杨舲万里，笑当年底事，中分南北。',120,'宋词/ci.song.14000.json','["杨舲万里，笑当年底事，中分南北。", "须信平生无梦到，却向而今游历。", "老柳官河，斜阳古道，风定波犹直。", "野人惊问，泛槎何处狂客。", "迎面落叶萧萧，水流沙共远，都无行迹。", "衰草凄迷秋更绿，惟有闲鸥独立。", "浪挟天浮，山邀云去，银浦横空碧。", "扣舷歌断，海蟾飞上孤白。"]'),
('song-ci-711','声声慢','张炎','宋','宋词','song-ci','声声慢','[]','平沙催晓，野水惊寒，遥岑寸碧烟空。',119,'宋词/ci.song.14000.json','["平沙催晓，野水惊寒，遥岑寸碧烟空。", "万里冰霜，一夜换却西风。", "晴梢渐无坠叶，撼秋声、都是梧桐。", "情正远，奈吟湘赋楚，近日偏慵。", "客里依然清事，爱窗深帐暖，戏拣香筒。", "片霎归程，无奈梦与心同。", "空教故林怨鹤，掩闲门、明月山中。", "春又小，甚梅花、犹自未逢。"]'),
('song-ci-712','绮罗香','张炎','宋','宋词','song-ci','绮罗香','[]','候馆深灯，辽天断羽，近日音书疑绝。',127,'宋词/ci.song.14000.json','["候馆深灯，辽天断羽，近日音书疑绝。", "转眼伤心，慵看剩歌残阕。", "才忘了、还著思量，待去也、怎禁离别。", "恨只恨、桃叶空江，殷勤不似谢红叶。", "良宵谁念哽咽。", "对熏炉象尺、闲伴凄切。", "独立西风，犹忆旧家时节。", "随款步、花密藏春，听私语、柳疏嫌月。", "今休问，燕约莺期，梦游空趁蝶。"]'),
('song-ci-713','庆春宫・高阳台','张炎','宋','宋词','song-ci','庆春宫・高阳台','[]','波荡兰觞，邻分杏酪，昼辉冉冉烘晴。',126,'宋词/ci.song.14000.json','["波荡兰觞，邻分杏酪，昼辉冉冉烘晴。", "罥索飞仙，戏船移景，薄游也自忺人。", "短桥虚市，听隔柳、谁家卖饧。", "月题争系，油壁相连，笑语逢迎。", "池亭小队秦筝。", "就地围香，临水湔裙。", "冶态飘云，醉妆扶玉，未应闲了芳情。", "旅怀无限，忍不住、低低问春。", "梨花落尽，一点新愁，曾到西泠。"]'),
('song-ci-714','国香','张炎','宋','宋词','song-ci','国香','[]','莺柳烟堤。',121,'宋词/ci.song.14000.json','["莺柳烟堤。", "记未吟青子，曾比红儿。", "娴娇弄春微透，鬟翠双垂。", "不道留仙不住，便无梦、吹到南枝。", "相看两流落，掩面凝羞，怕说当时。", "凄凉歌楚调，袅馀音不放，一朵云飞。", "丁香枝上，几度款语深期。", "拜了花梢淡月，最难忘、弄影牵衣。", "无端动人处，过了黄昏，犹道休归。"]'),
('song-ci-715','水龙吟','刘克庄','宋','宋词','song-ci','水龙吟','[]','不须更问旁人，劝君自拂青铜照。',126,'宋词/ci.song.14000.json','["不须更问旁人，劝君自拂青铜照。", "幅巾短褐，有些野逸，有些村拗。", "两度呼来，也曾批敕，也曾还诏。", "笑先生此手，今堪何用，苔矶上、堪垂钓。", "白雪新腔高妙。", "把侬家、调疏称道。", "六韬未试，抑诗未作，如何归老。", "玉带金貂，星儿快活，天来烦恼。", "待自笺年甲，缴还官职，换山翁号。"]'),
('song-ci-716','水龙吟','刘克庄','宋','宋词','song-ci','水龙吟','[]','行藏自决於心，不消谋及门前客。',126,'宋词/ci.song.14000.json','["行藏自决於心，不消谋及门前客。", "平生慕用，著书玄晏，挂冠贞白。", "帝奖孤高，别加九锡，一筇双屐。", "更赐之车服，胙之茅土，依稀在、槐安国。", "频领竹宫清职。", "仰飞仙、犹龙无迹。", "与谁同去，挑包徐甲，负辕班特。", "蹉过明师，且寻狎友，杜康仪狄。", "笑谢公旷达，暮年垂泪，听桓郎笛。"]'),
('song-ci-717','水龙吟','刘克庄','宋','宋词','song-ci','水龙吟','[]','先生避谤山栖，戒门不纳高轩客。',126,'宋词/ci.song.14000.json','["先生避谤山栖，戒门不纳高轩客。", "谁欤来者，吟诗张碧，诙谐侯白。", "礼数由他，谢郎著帽，王郎穿屐。", "且问花随柳，举杯邀月，那须预、人家国。", "香案旁边供职。", "鸟飞空、何曾留迹。", "臞翁铁汉，两贤安在，百夫之特。", "但愿王师，早俘颉利，早禽长狄。", "便太平无事，卖薪沽酒，骑牛腰笛。"]'),
('song-ci-718','水龙吟','刘克庄','宋','宋词','song-ci','水龙吟','[]','当年玉立清扬，屋梁落月偏相照。',125,'宋词/ci.song.14000.json','["当年玉立清扬，屋梁落月偏相照。", "而今衰飒，形骸百丑，情怀十拗。", "久已饰巾、尚堪扶杖，听山东诏。", "尽后车载汝，营丘封汝，何必在、磻溪钓。", "晚悟儋书玄妙。", "懒从他、锺离传道。", "不论资望推排，也做五更三老。", "宋玉多悲，唐衢喜哭，好闲烦恼。", "问天公，扑断散人二字，赐龟蒙号。"]'),
('song-ci-719','水龙吟','刘克庄','宋','宋词','song-ci','水龙吟','[]','此翁饱阅人间，三生似是刘宾客。',126,'宋词/ci.song.14000.json','["此翁饱阅人间，三生似是刘宾客。", "若论辈行，早陪韩柳，晚交元白。", "老矣安能，为人取履，与人争屐。", "叹酒泉郡远，醉乡路绝，今何处、堪开国。", "解去冰衔华职。", "遍空山、难寻行迹。", "道旁喘月，田间卧草，也胜郊特。", "宰相□□，周公留召，娄公容狄。", "喜时平身健，三行社饮，一声樵笛。"]'),
('song-ci-720','水龙吟','刘克庄','宋','宋词','song-ci','水龙吟','[]','病夫鬓秃颜苍，不堪持向清溪照。',126,'宋词/ci.song.14000.json','["病夫鬓秃颜苍，不堪持向清溪照。", "一生枘凿，壮夫瞋懦，通人嫌拗。", "让当行家，勒浯西颂，草淮南诏。", "幸脱离沮洳，浮游江海，悠然逝、毋吞钓。", "宴坐蒲团观妙。", "怪痴儿、舂粮求道。", "古人尚齿，迎他商皓，拜他庞老。", "鸠杖蒲轮，把身束缚，替人愁恼。", "煞为僧不了，下梢犹要，紫衣师号。"]'),
('song-ci-721','水龙吟','刘克庄','宋','宋词','song-ci','水龙吟','[]','鬳斋不是凡人，海山仙圣知来处。',126,'宋词/ci.song.14000.json','["鬳斋不是凡人，海山仙圣知来处。", "清英融结，佩瑶台月，饮金茎露。", "翰墨流行，禁中有本，御前停箸。", "向弘文馆里，薰风殿上，亲属和、微凉句。", "已被昭阳人妒。", "更那堪、鼎成龙去。", "曾传宝苑，曾将玉杵，付长生兔。", "地覆天翻，河清海浅，朱颜常驻。", "算给扶朝者，临雍拜者，下梢须做。"]'),
('song-ci-722','水龙吟','刘克庄','宋','宋词','song-ci','水龙吟','[]','此翁幸自偏盲，那堪右目生微翳。',126,'宋词/ci.song.14000.json','["此翁幸自偏盲，那堪右目生微翳。", "羽流禳谢，缁郎忏悔，天乎无罪。", "客曰不然，也因口腹，也因瞻视。", "汝夜披黄卷，日餐丹荔，贻伊戚、将谁怼。", "长智都缘更事。", "尽今生、十分珍卫。", "暮年怕杀，汗青蠹简，擘红高会。", "也莫贪他，君谟旧谱，子云奇字。", "特邀张司业，看花题竹，韩家园内。"]'),
('song-ci-723','风流子','刘克庄','宋','宋词','song-ci','风流子','[]','松桂各参天。',136,'宋词/ci.song.14000.json','["松桂各参天。", "石桥下，新种一池莲。", "似仙子御风，来从姑射，地灵献宝，产向蓝田。", "曾入先生虚白屋，不喜傅朱铅。", "记茂叔溪头，深衣听讲，远公社里，素衲安禅。", "山间。", "多红鹤，端相久，蓦地飞去蹁跹。", "但蝶戏鹭翘，有时偷近旁边。", "对月中乍可，伴娥孤另，墙头谁肯，窥玉三年。", "俗客浓妆，安知国艳天然。"]'),
('song-ci-724','满庭芳','刘克庄','宋','宋词','song-ci','满庭芳','[]','凉月如冰，素涛翻雪，人世依约三更。',118,'宋词/ci.song.14000.json','["凉月如冰，素涛翻雪，人世依约三更。", "扁舟乘兴，莫计水云程。", "忽到一洲奇绝，花无数、多不知名。", "浑疑是，芙蓉城里，又似牡丹坪。", "蓬莱，应不远，天风海浪，满目凄清。", "更一声铁笛，石裂龙惊。", "回顾尘寰局促，挥袂去、散发骑鲸。", "蘧蘧觉，元来是梦，钟动野鸡鸣。"]'),
('song-ci-725','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','吾少多奇节。',142,'宋词/ci.song.14000.json','["吾少多奇节。", "颇揶揄、玉关定远，壶头新息。", "一剑防身行万里，选甚南溟北极。", "看塞雁、衔来秋色。", "不但槊棋夸妙手，管城君、亦自无勍敌。", "终贾辈，恐难匹。", "酒肠诗胆新来窄。", "向西风、登高望远，乱山斜日。", "安得良弓并快马，聊与诸公角力。", "漫醉把、栏干频拍。", "莫恨寒蟾离海晚，待与君、秉烛游今夕。", "欢易买，健难得。"]'),
('song-ci-726','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','北望神州路。',142,'宋词/ci.song.14000.json','["北望神州路。", "试平章、这场公事，怎生分付。", "记得太行山百万，曾入宗爷驾驭。", "今把作、握蛇骑虎。", "君去京东豪杰喜，想投戈、下拜真吾父。", "谈笑里，定齐鲁。", "两河萧瑟惟狐兔。", "问当年、祖生去后，有人来否。", "多少新亭挥泪客，谁梦中原块土。", "算事业、须由人做。", "应笑书生心胆怯，向车中、闭置如新妇。", "空目送，塞鸿去。"]'),
('song-ci-727','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','["\u957f\u6c5f"]','尽说番和汉。',142,'宋词/ci.song.14000.json','["尽说番和汉。", "这琵琶、依稀似曲，蓦然弦断。", "作麽一年来一度，欺得南人技短。", "叹几处、城危如卵。", "元凯后身居玉帐，报胡儿、休作寻常看。", "布严令，运奇算。", "开门决斗雌雄判。", "笑中宵、奚车毡屋，兽惊禽散。", "个个巍冠横尘柄，谁了君王此段。", "也莫靠、长江能限。", "不论周郎并幼度，便仲尼、复起嗟微管。", "驰露布，筑京观。"]'),
('song-ci-728','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','宣引东华去。',142,'宋词/ci.song.14000.json','["宣引东华去。", "似当年、文皇亲擢，马周徒步。", "殿上风霜生白简，下殿扁舟已具。", "怎不与、官家留住。", "古有一言腰相印，谁教他、满箧婴鳞疏。", "还笏退，不回顾。", "新来边报犹飞羽。", "问诸公、可无长策，少宽明主。", "攀槛朱云头雪白，流落如今底处。", "但一片、丹心如故。", "赖有越台堪眺望，那中原、莫已平安否。", "风色恶，海天暮。"]'),
('song-ci-729','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','驿骑联翩至。',142,'宋词/ci.song.14000.json','["驿骑联翩至。", "道台家、筹边方急，酒行姑止。", "作麽携将琴鹤去，不管州人堕泪。", "富与贵、平生无味。", "可但红尘难著脚，便山林、未有安身地。", "搔白发，兀相对。", "前身小范疑公是。", "忆当年、天章阁上，建明尤伟。", "庆历诸贤方得路，便不容他老子。", "须著放、延州城里。", "一句殷勤牢记取，在朝廷、最好图西事。", "何必向，玉关外。"]'),
('song-ci-730','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','飞诏从天下。',142,'宋词/ci.song.14000.json','["飞诏从天下。", "道中朝、名流欲尽，君王思贾。", "时事祗今堪痛哭，未可徐徐俟驾。", "好著手、扶将宗社。", "多少法筵龙象众，听灵山、属付些儿话。", "千百世，要传写。", "子方行矣乘骢马。", "又送他、江南太史，去游毡厦。", "老我伴身惟有影，倚遍风轩月榭。", "怅玉手、何时重把。", "君向柳边花底问，看贞元、朝士谁存者。", "桃满观，几开谢。"]'),
('song-ci-731','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','南国秋容晚。',142,'宋词/ci.song.14000.json','["南国秋容晚。", "晓寒轻、菊花台榭，拒霜池馆。", "试向壶山堂上望，万顷黄云刈遍。", "总吃著、君侯方寸。", "不要汉廷夸击断，要史家、编入循良传。", "春脚到，福星见。", "家家香火人人愿。", "要还他、庆元狨座，建炎蝉冕。", "稳奉安舆迎两国，谁谓山遥水远。", "福寿比、河沙难算。", "来岁而今黄花节，早骖鸾、入侍瑶池宴。", "风浩荡，海清浅。"]'),
('song-ci-732','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','深院榴花吐。',142,'宋词/ci.song.14000.json','["深院榴花吐。", "画帘开、綀衣纨扇，午风清暑。", "儿女纷纷夸结束，新样钗符艾虎。", "早已有、游人观渡。", "老大逢场慵作戏，任陌头、年少争旗鼓。", "溪雨急，浪花舞。", "灵均标致高如许。", "忆生平、既纫兰佩，更怀椒糈。", "谁信骚魂千载后，波底垂涎角黍。", "又说是、蛟馋龙怒。", "把似而今醒到了，料当年、醉死差无苦。", "聊一笑，吊千古。"]'),
('song-ci-733','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','湛湛长空黑。',142,'宋词/ci.song.14000.json','["湛湛长空黑。", "更那堪、斜风细雨，乱愁如织。", "老眼平生空四海，赖有高楼百尺。", "看浩荡、千崖秋色。", "白发书生神州泪，尽凄凉、不向牛山滴。", "追往事，去无迹。", "少年自负凌云笔。", "到而今、春华落尽，满怀萧瑟。", "常恨世人新意少，爱说南朝狂客。", "把破帽、年年拈出。", "若对黄花孤负酒，怕黄花、也笑人岑寂。", "鸿北去，日西匿。"]'),
('song-ci-734','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','绝顶规危榭。',142,'宋词/ci.song.14000.json','["绝顶规危榭。", "跨高寒、鸟飞不过，云生其下。", "斤斸无声人按堵，翕曶青红变化。", "览城郭、山川如画。", "阁老凤楼修造手，笑谈间、突出凌云厦。", "台上景，买无价。", "唾壶麈尾登临暇。", "似当年、滁阳太守，欧阳公也。", "倾倒赣江供砚滴，判断雪天月夜。", "更唤取、邹枚司马。", "铜雀凌歊歌舞散，访残砖、断甓无存者。", "馀翰墨，被风雅。"]'),
('song-ci-735','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','动地东风起。',142,'宋词/ci.song.14000.json','["动地东风起。", "画桥西、绕溪桑柘，漫山桃李。", "寂寂墙阴苍苔径，犹印前回屐齿。", "惊岁月、飙驰云驶。", "太息攀翻长亭树，是先生、手种今如此。", "君不乐，欲何俟。", "傍人错会渊明意。", "笑斯翁、皇皇汲汲，登山临水。", "佳处径呼篮舆去，彷佛柴桑栗里。", "从我者、门生儿子。", "尝试平章先贤传，屈原醒、不似刘伶醉。", "拼酩酊，卧花底。"]'),
('song-ci-736','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','鹊报千林喜。',142,'宋词/ci.song.14000.json','["鹊报千林喜。", "还猛省、谢家池馆，早寒天气。", "要与瑶姬叙离索，草草杯盘藉地。", "怅减尽、何郎才思。", "不愿玉堂并金屋，愿年年、岁岁花间醉。", "餐秀色，挹高致。", "西园飞盖东山妓。", "问何如、半山雪里，孤山烟外。", "管甚夜深风露冷，人与长瓶共睡。", "任翠羽、枝头多事。", "老子平生无他过，为梅花、受取风流罪。", "簪白发，莫教坠。"]'),
('song-ci-737','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','溪上收残雨。',142,'宋词/ci.song.14000.json','["溪上收残雨。", "倚画栏、薄绵乍脱，日阴亭午。", "闹市不知春色处，散在荒园废墅。", "渐小白、长红无数。", "客子虽非河阳令，也随缘、暂作莺花主。", "那可负，瓮中醑。", "碧云四合千岩暮。", "恨匆匆、余方有事，子姑归去。", "趁取群芳未摇落，暇日提鱼就煮。", "叹激电、光阴如许。", "回首明年何处在，问桃花、尚记刘郎否。", "公莫笑，醉中语。"]'),
('song-ci-738','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','曾与瑶姬约。',142,'宋词/ci.song.14000.json','["曾与瑶姬约。", "恍相逢、翠裳摇曳，珠韝联络。", "风露青冥非人世，揽结玉龙骖鹤。", "爱万朵、千条纤弱。", "祷祝花神怜惜取，问开时、晴雨须斟酌。", "枝上雪，莫消却。", "恼人匹似中狂药。", "凭危栏、烛光交映，乐声遥作。", "身上春衫香薰透，看到参横月落。", "算茉莉、犹低一著。", "坐有缑山王郎子，倚玉箫、度曲难为酢。", "君不饮，铸成错。"]'),
('song-ci-739','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','想赴瑶池约。',142,'宋词/ci.song.14000.json','["想赴瑶池约。", "向东风、名姬骏马，翠鞯金络。", "太液池边鹄群下，又似南楼呼鹤。", "画不就、秾纤娇弱。", "罗帕封香来天上，泻铜盘、沆瀣供清酌。", "春去也，被留却。", "芳魂再返应无药。", "似诗咏、绿衣黄里，感伤而作。", "爱惜尚嫌蜂采去，何况流莺蹴落。", "且放下、珠帘遮著。", "除却江南黄九外，有何人、敢与花酬酢。", "君认取，莫教错。"]'),
('song-ci-740','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','浅把宫黄约。',142,'宋词/ci.song.14000.json','["浅把宫黄约。", "细端相、普陀烟里，金身珠络。", "萼绿华轻罗袜小，飞下祥云仙鹤。", "朵朵赛、蜂腰纤弱。", "已被色香撩病思，尽鹅儿、酒美无多酌。", "看不足，怕残却。", "人间难得伤春药。", "更枝头、流莺呼起，少年狂作。", "留取姚家花相伴，羞与万红同落。", "未肯让、蜡梅先著。", "乐府今无黄绢手，问斯人、清唱何人酢。", "休草草，认题错。"]'),
('song-ci-741','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','一梦扬州事。',142,'宋词/ci.song.14000.json','["一梦扬州事。", "画堂深、金瓶万朵，元戎高会。", "座上祥云层层起，不减洛中姚魏。", "叹别后、关山迢递。", "国色天香何处在，想东风、犹忆狂书记。", "惊岁月，一弹指。", "数枝清晓烦驰骑。", "向小窗、依稀重见，芜城妖丽。", "料得花怜侬消瘦，侬亦怜花憔悴。", "漫怅望、竹西歌吹。", "老矣应无骑鹤日，但春衫、点点当时泪。", "那更有，旧情味。"]'),
('song-ci-742','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','草草池亭宴。',142,'宋词/ci.song.14000.json','["草草池亭宴。", "又何须、珠韝络臂，琵琶遮面。", "宾主一时词翰手，倏忽龙蛇满案。", "传写处、尘飞莺啭。", "但得时平鱼稻熟，这腐儒、不用青精饭。", "阴雾扫，霁华见。", "使君偿了丰年愿。", "便从今、也无敲扑，也无厨传。", "试拂笼纱看壁记，几个标名渠观。", "想九牧、闻风争羡。", "此老饱知民疾苦，早归来、载笔薰风殿。", "诗有讽，赋无劝。"]'),
('song-ci-743','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','["\u5e90\u5c71"]','梦断钧天宴。',141,'宋词/ci.song.14000.json','["梦断钧天宴。", "怪人间、曲吹别调，局翻新面。", "不是先生喑哑了，怕杀乌台旧案。", "但掩耳、蝉嘶禽啭。", "老去把茅依地主，有瓦盆盛酒荷包饭。", "停造请、免朝见。", "少狂误发功名愿。", "苦贪他、生前死后，美官佳传。", "白发归来还自笑，管辖希夷古观。", "看一道、冰衔堪羡。", "妃子将军瞋未已，问匡山、何似金銮殿。", "休更待，杜鹃劝。"]'),
('song-ci-744','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','风露驱炎毒。',142,'宋词/ci.song.14000.json','["风露驱炎毒。", "记仙翁、飘然谪堕，吹笙骑鹄。", "历历汉初秦季事，山下瓜犹未熟。", "过眼见、群雄分鹿。", "想得拂衣游汗漫，试回头、刘项俱蛮触。", "斫鲸脍，脯麟肉。", "越人好事因成俗。", "拥遨头、如云士女，山南山北。", "问讯先生无恙否，齐鲁干戈满目。", "且游戏、扶胥黄木。", "不是世无瓜样枣，便有来、肯饱痴儿腹。", "聊举酒，笑相属。"]'),
('song-ci-745','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','此腹元空洞。',142,'宋词/ci.song.14000.json','["此腹元空洞。", "少年时、诸公过矣，上天吹送。", "老大被他禁害杀，身与浮名孰重。", "这鼓笛、休休拈弄。", "彩笔掷还残锦去，愿今生、来世无妖梦。", "且饭犊，莫吞凤。", "新来喑哑如翁仲。", "羡王郎、骖鸾缥缈，玉箫吹动。", "应笑夔州村里女，灸面生愁进奉。", "要绝代、倾城安用。", "今古何人知此理，有吾家、酒德先生颂。", "三万卷，漫充栋。"]'),
('song-ci-746','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','主判茅君洞。',142,'宋词/ci.song.14000.json','["主判茅君洞。", "有檐间、查查喜鹊，晓来传送。", "几度黄符披戴了，此度君恩越重。", "被贺监、天随调弄。", "做取散人千百岁，笑渠侬、一霎邯郸梦。", "歌而过，凤兮凤。", "灌园织屦希陈仲。", "问先生、加齐卿相，可无心动。", "除却醴泉中太乙，拣个名山自奉。", "那捷径、输他藏用。", "有耳不曾闻黜陟，免教人、贬驳徂徕颂。", "服兰佩，结茅栋。"]'),
('song-ci-747','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','谪下神清洞。',142,'宋词/ci.song.14000.json','["谪下神清洞。", "更遭他、揶揄黠鬼，路旁遮送。", "薄命书生鸡肋尔，却笑尊拳忒重。", "破故纸、谁教翻弄。", "一枕茅檐春睡美，便周公、大圣何须梦。", "门前客，任题凤。", "卜邻羊仲并求仲。", "愿春来、西畴雨足，土膏犁动。", "白发巡官占岁稔，不问京房翼奉。", "槔与瓮、从今无用。", "醉与老农同击壤，莫随人、投献嘉禾颂。", "在陋巷，胜华栋。"]'),
('song-ci-748','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','妾出於微贱。',141,'宋词/ci.song.14000.json','["妾出於微贱。", "小年时、朱弦弹绝，玉笙吹遍。", "粗识国风关雎乱，羞学流莺百啭。", "总不涉、闺情春怨。", "谁向西邻公子说，要珠鞍、迎入梨花院。", "身未动，意先懒。", "主家十二楼连苑。", "那人人、靓妆按曲，绣帘初卷。", "道是华堂箫管唱，笑杀鸡坊拍衮。", "回首望、侯门天远。", "我有平生离鸾操，颇哀而不愠微而婉。", "聊一奏，更三叹。"]'),
('song-ci-749','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','鬓雪今千缕。',142,'宋词/ci.song.14000.json','["鬓雪今千缕。", "更休休、痴心呆望，故人明主。", "晚学瞿聃无所得，不解飞升灭度。", "似晓鼓、冬冬挝五。", "散尽朝来汤饼客，且烹鸡、要饭茅容母。", "怕回首，太行路。", "麟台学士微云句。", "便樽前、周郎复出，审音无误。", "安得春莺雪儿辈，轻拍红牙按舞。", "也莫笑、侬家蛮语。", "老去山歌尤协律，又何须、手笔如燕许。", "援琴操，促筝柱。"]'),
('song-ci-750','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','放逐身蓝缕。',142,'宋词/ci.song.14000.json','["放逐身蓝缕。", "被门前、群鸥戏狎，见推盟主。", "若把士师三黜比，老子多他两度。", "袖手看、名场呼五。", "不会车边望尘拜，免他年、青史羞潘母。", "句曲洞，是归路。", "平生怕道萧萧句。", "况新来、冠敧弁侧，醉人多误。", "管甚是非并礼法，顿足低昂起舞。", "任百鸟、喧啾春语。", "欲托朱弦写悲壮，这琴心、脉脉谁堪许。", "君按拍，我调柱。"]'),
('song-ci-751','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','国脉微如缕。',142,'宋词/ci.song.14000.json','["国脉微如缕。", "问长缨、何时入手，缚将戎主。", "未必人间无好汉，谁与宽些尺度。", "试看取、当年韩五。", "岂有谷城公付授，也不干、曾遇骊山母。", "谈笑起，两河路。", "少时棋柝曾联句。", "叹而今、登楼揽镜，事机频误。", "闻说北风吹面急，边上冲梯屡舞。", "君莫道、投鞭虚语。", "自古一贤能制难，有金汤、便可无张许。", "快投笔，莫题柱。"]'),
('song-ci-752','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','万字如针缕。',142,'宋词/ci.song.14000.json','["万字如针缕。", "忆王郎、丹墀大对，气为文主。", "贵近旁观俱失色，仰止如天圣度。", "笑杜牧、成名居五。", "晚面清光犹苦谏，似封人、恳切言君母。", "谪尘世，错行路。", "当时宜和薰风句。", "又那知、青云一跌，被才名误。", "输与灵和殿前柳，柔软随风学舞。", "怪两鸟、新来停语。", "不是先生高索价，问何时、宰相先生许。", "举杯祝，莫倾柱。"]'),
('song-ci-753','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','身畔无丝缕。',142,'宋词/ci.song.14000.json','["身畔无丝缕。", "但从前、綀裳练帨，做他家主。", "甲子一周加二纪，兔走乌飞几度。", "赛孔子、如来三五。", "鹤发萧萧无可截，要一杯、留客惭陶母。", "门外草，欲迷路。", "朗吟白雪阳春句。", "待夫君、骊驹不至，鹊声还误。", "老去聊攀莱子例，倒著斑衣戏舞。", "记田舍、火炉头语。", "肘后黄金腰下印，有高堂、未敢将身许。", "且扇枕，莫倚柱。"]'),
('song-ci-754','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','辇路东风里。',142,'宋词/ci.song.14000.json','["辇路东风里。", "试回头、金闺昨梦，侵寻三纪。", "岁晚岿然灵光殿，仆与君侯而已。", "漫过眼、几番桃李。", "珠履金钗常满座，问谁人、得似张公子。", "驰骥騄，佩龟紫。", "宿云收尽檐声止。", "玳筵开、高台风月，后堂罗绮。", "恰近洛人修禊节，莫惜飞觞临水。", "怕则怕、追锋徵起。", "此老一生江海客，愿风云、际会从今始。", "宁郁郁，久居此。"]'),
('song-ci-755','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','老去光阴驶。',142,'宋词/ci.song.14000.json','["老去光阴驶。", "向西风、疏林变缬，残霞成绮。", "尚喜暮年腰脚健，不碍登山临水。", "算自古、英游能几。", "客与桓公俱臭腐，独流传、吹帽狂生尔。", "后来者，亦犹此。", "篮舆伊轧柴桑里。", "问黄花、没些消息，空篱而已。", "赖有一般芙蓉月，偏照先生怀里。", "且觅个、栏干同倚。", "检点樽前谁见在，忆平生、共插茱萸底。", "欢未足，饮姑止。"]'),
('song-ci-756','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','忆昔俱年少。',142,'宋词/ci.song.14000.json','["忆昔俱年少。", "向斯晨、登高怀古，赋诗舒啸。", "追数樽前插花客，人物并皆佳妙。", "禁几度、西风残照。", "元子寄奴曾富贵，到而今、一一消磨了。", "君不乐，后人笑。", "山南山北添华表。", "叹归来、谢池草合，黄台瓜少。", "老去爱持齐物论，谁管彭殇寿夭。", "待细说、教天知道。", "不羡两苏并二宋，愿弟兄、岁岁同吹帽。", "杯到手，莫辞釂。"]'),
('song-ci-757','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','何必游嵩少。',142,'宋词/ci.song.14000.json','["何必游嵩少。", "屋边山、松风浩荡，虎龙吟啸。", "旧效楚人悲秋作，晚爱陶诗高妙。", "发如此、临流羞照。", "屈指向来夸毗子，被西风、一笔都勾了。", "曾不满，达人笑。", "当年玉振於江表。", "怅而今、老身空在，欢娱全少。", "假使真如彭祖寿，蒙叟犹嗤渠夭。", "偶落笔、不经人道。", "岁晚连床谈至晓，胜冈头、出没看乌帽。", "君举白，我频釂。"]'),
('song-ci-758','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','人老难重少。',142,'宋词/ci.song.14000.json','["人老难重少。", "强追陪、李侯痛饮，刘郎清啸。", "报答秋光无一字，虚说君房语妙。", "且匣起、青铜休照。", "赖有多情篱下菊，待西风、不肯先开了。", "留晚节，发孤笑。", "孔璋客绍衡依表。", "有谁怜、戴花翁病，插萸人少。", "生不逢场闲则剧，年似龚生犹夭。", "吃紧处、无人曾道。", "到得扶他迂叟出，算貂蝉、未抵深衣帽。", "街酒贱，更沽釂。"]'),
('song-ci-759','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','犹记臣之少。',141,'宋词/ci.song.14000.json','["犹记臣之少。", "兴狂时、过陈遵饮，对孙登啸。", "岁晚登临多感慨，但觉齐山诗妙。", "任蓉月、柳风吹照。", "金印不来丹飞去，拟神仙、富贵都差了。", "空铸错，与人笑。", "九年前拜悬车表。", "试回看、柴桑菊老，玄都花少。", "周也曾言殇子寿，佛以白头为夭。", "末后句、岩头曾道。", "头似秃鶖巾裹懒，最不宜蝉冕宜僧帽。", "杯中物，直须釂。"]'),
('song-ci-760','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','行乐尤宜少。',142,'宋词/ci.song.14000.json','["行乐尤宜少。", "忆坡公、洞箫听罢，划然长啸。", "四海共知霜鬓满，莫问近来何妙。", "也不记、金莲曾照。", "老没太官糕酒分，把茱萸、便准登高了。", "齐得丧，等嘻笑。", "集无韩子潮州表。", "数当时、南迁者众，北归人少。", "赤壁玉堂均一梦，此岂蛮烟能夭。", "与同叔、俱尝知道。", "谁向进贤冠底说，画出来、不似眉山帽。", "秋菊盏，献公釂。"]'),
('song-ci-761','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','鹏赋年犹少。',142,'宋词/ci.song.14000.json','["鹏赋年犹少。", "晚飘蓬、夜郎秋浦，渔歌猿啸。", "骏马名姬俱散去，参透南华微妙。", "敛万丈、光芒回照。", "妃子将军瞋个甚，老先生、拂袖金闺了。", "供玉齿，粲然笑。", "解骖赖有汾阳老。", "叹今人、布衣交薄，绨袍情少。", "黄祖斗筲何足算，鹦鹉才高命夭。", "与贺监、其归同道。", "脱下锦袍与呆底，谪仙人、白伫乌纱帽。", "邀素月，入杯釂。"]'),
('song-ci-762','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','低局从头错。',142,'宋词/ci.song.14000.json','["低局从头错。", "解危机、除非唤取，国棋来著。", "不信胡儿能胆大，南岸安他阵脚。", "谈笑里、乌巢空幕。", "西起岷峨东海岱，有捷旗、露布无宵柝。", "莘渭后，到秋壑。", "淮田犁遍吴田荻。", "问台家、山河宇宙，是谁擎托。", "自觉怀中残锦尽，采色彰施技薄。", "视柳雅、韩碑瞠若。", "稽首鲁公黄发颂，世何人、堪继奚斯作。", "楚狂语，莫删却。"]'),
('song-ci-763','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','宿雨轻飘洒。',142,'宋词/ci.song.14000.json','["宿雨轻飘洒。", "少年时、追欢记节，同人于野。", "老去登临无脚力，徙倚屋东篱榭。", "但极目、海山如画。", "千古惟传吹帽汉，大将军、野马尘埃也。", "须彩笔，为陶写。", "鹤归旧里空悲咤。", "叹原头、累累高冢，洛英凋谢。", "留得香山病居士，却入渔翁保社。", "怅谁伴、先生情话。", "樽有葡萄簪有菊，西凉州、不似东篱下。", "休唤醒，利名者。"]'),
('song-ci-764','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','拂袖归来也。',142,'宋词/ci.song.14000.json','["拂袖归来也。", "懒追陪、竹林嵇阮，兰亭王谢。", "谁与此翁相暖热，赖有平生伯雅。", "且放意、高吟闲话。", "山鸟山花皆上客，又何须、胜似公荣者。", "胸磊块，总浇下。", "盘龙痴绝求鹅炙。", "这先生、黄齑瓮熟，味珍无价。", "酒颂一篇差要妙，庄列诸书土苴。", "任礼法、中人嘲骂。", "君特未知其趣耳，若还知、火急来投社。", "共秉烛，惜今夜。"]'),
('song-ci-765','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','过眼光阴驶。',142,'宋词/ci.song.14000.json','["过眼光阴驶。", "忆垂髫、留连节物，逢场游戏。", "初试綀衣弄纨扇，斗采菖蒲涧里。", "今发白、颜苍如此。", "艾子萧郎方用事，怪先生、苦死纫兰芷。", "君不乐，欲何俟。", "头标夺得群儿喜。", "向溪边、旁观助噪，叹吾衰矣。", "欲建鼓旗无气力，唤起龙泉改委。", "但酒户、加封而已。", "晚觉醉乡差快活，那独醒、公子真呆底。", "聊洗净，笛筝耳。"]'),
('song-ci-766','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','家有仙禽二。',141,'宋词/ci.song.14000.json','["家有仙禽二。", "早追随、先生杖屦，互乡童子。", "旦旦池边三薰沐，夜夜山中警睡。", "且伴我、人间游戏。", "此老生平哀大陆，到末梢、始忆华亭唳。", "评往事，败佳思。", "古云鹤算谁能纪。", "叹归来、山川如故，人民非是。", "但愿主君高飞去，莫爱乘轩禄位。", "更赛过、令威千岁。", "假使焦山真羽化，待华阳贞逸铭方瘗。", "我拍手，渠展翅。"]'),
('song-ci-767','洞仙歌','刘克庄','宋','宋词','song-ci','洞仙歌','[]','上林全树，曾借君栖宿。',102,'宋词/ci.song.14000.json','["上林全树，曾借君栖宿。", "朝过瑶台暮群玉。", "忽翩然、脱下宫锦袍来，□□□，却向齐州受箓。", "等闲挥醉笔，咳唾千篇，长与诗家窃膏馥。", "身是酒星文星，刚被诗人，□唤做、禁中颇牧。", "便散发、骑鲸去何妨，从我者谁欤，安期徐福。"]'),
('song-ci-768','洞仙歌','刘克庄','宋','宋词','song-ci','洞仙歌','[]','眇难揽镜，跛尤难穿履。',102,'宋词/ci.song.14000.json','["眇难揽镜，跛尤难穿履。", "赖有胡公菊潭水。", "信医言、断了重碧轻红，禁害杀，不遣高吟大醉。", "古来稀七十，添许多年，赢得笺天致君事。", "莫问客去门前，金尽床头，留宝扇、御诗珍秘。", "畴昔慕、乖崖老尚书，到晚节依稀，有些儿似。"]'),
('song-ci-769','八声甘州','刘克庄','宋','宋词','song-ci','八声甘州','[]','物微生处远，往还来、非但稻粱求。',116,'宋词/ci.song.14000.json','["物微生处远，往还来、非但稻粱求。", "似爱长安日，怕阴山雪，善自为谋。", "个里幸无鸣镝，随意占沙洲。", "归兴何妨待，风景和柔。", "昔到衡阳回去，今随阳避地，遍海南头。", "与西川流寓，彼此各淹留。", "未得云中消息，登望乡台了又登楼。", "江天阔，几行草字，字字含愁。"]'),
('song-ci-770','烛影摇红','刘克庄','宋','宋词','song-ci','烛影摇红','[]','拙者平生，不曾乞得天孙巧。',116,'宋词/ci.song.14000.json','["拙者平生，不曾乞得天孙巧。", "那回忝扈属车来，岂是齐卿小。", "此膝不曾屈了。", "更休文、腰难运掉。", "前贤样子，表圣宜休，申公告老。", "凉簟安眠，绝胜儤直铃声搅。", "集中大半是诗词，幸没潮州表。", "月夕花朝咏啸。", "叹人间、愁多乐少。", "蓬莱有路，办个船儿，逆风也到。"]'),
('song-ci-771','祝英台近','刘克庄','宋','宋词','song-ci','祝英台近','[]','雨凄迷，风料峭。',95,'宋词/ci.song.14000.json','["雨凄迷，风料峭。", "情绪被花恼。", "白白红红，满地无人扫。", "可堪解佩盟寒，坠楼命薄，更杜宇、枝头闲煼。", "绿阴绕。", "青帝结束匆匆，转眼朱明了。", "怕与春辞，茗艼玉山倒。", "后期觉做明年，春年年好，却不道、明年人老。"]'),
('song-ci-772','最高楼','刘克庄','宋','宋词','song-ci','最高楼','["\u8861\u5c71"]','南岳后，累任作祠官。',100,'宋词/ci.song.14000.json','["南岳后，累任作祠官。", "试说与君看。", "仙都玉局才交卸，新衔又管华州山。", "怪先生，吟胆壮，饮肠宽。", "去岁拥、旌旗称太守。", "今岁带、笭箵称漫叟。", "慵入闹，惯投闲。", "有时拂袖寻种放，有时携枕就陈抟。", "任旁人，嘲潦倒，笑痴顽。"]'),
('song-ci-773','最高楼','刘克庄','宋','宋词','song-ci','最高楼','[]','周郎后，直数到清真。',100,'宋词/ci.song.14000.json','["周郎后，直数到清真。", "君莫是前身。", "八音相应谐韶乐，一声未了落梁尘。", "笑而今，轻郢客，重巴人。", "只少个、绿珠横玉笛。", "更少个、雪儿弹锦瑟。", "欺贺晏，压黄秦。", "可怜樵唱并菱曲，不逢御手与龙巾。", "且醉眠，篷底月，瓮间春。"]'),
('song-ci-774','最高楼','刘克庄','宋','宋词','song-ci','最高楼','[]','吾衰矣，百事且随缘。',100,'宋词/ci.song.14000.json','["吾衰矣，百事且随缘。", "只字不笺天。", "几曾三宿为归计，更巴一岁是希年。", "记儿时，闻祖父，说隆乾。", "我不与、少年争遇合。", "你莫共、老僧争戒腊。", "靴皱面，帨垂肩。", "锦袍夺去饶之问，虎皮撤起付伊川。", "剩空身，无长物，可飞仙。"]'),
('song-ci-775','最高楼','刘克庄','宋','宋词','song-ci','最高楼','[]','吾衰矣，不慕勒燕然。',100,'宋词/ci.song.14000.json','["吾衰矣，不慕勒燕然。", "不爱画凌烟。", "此生惭愧支离叟，何功消受水衡钱。", "错教人，占卦气，算流年。", "漫摘取、野花簪一朵。", "更拣取、小词填一个。", "晞素发、暖丹田。", "罗浮杖胜如旌节，华阳巾不减貂蝉。", "这先生，非散圣，即臞仙。"]'),
('song-ci-776','最高楼','刘克庄','宋','宋词','song-ci','最高楼','[]','辛亥后，六请挂衣冠。',100,'宋词/ci.song.14000.json','["辛亥后，六请挂衣冠。", "甲子始休官。", "白驹恰则来空谷，青牛早已出函关。", "笑狂生，还笏易，上竿难。", "也莫爱、宫中请内相。", "也莫爱、堂中呼六丈。", "但祷祝，要痴顽。", "懒挥玉斧重修月，不扶铁拐会登山。", "免飞升，长快活，戏人间。"]'),
('song-ci-777','最高楼','刘克庄','宋','宋词','song-ci','最高楼','[]','臣少也，豪举泛星槎。',100,'宋词/ci.song.14000.json','["臣少也，豪举泛星槎。", "飘逸吐天葩。", "穆陵误奖推儒宿，龙泉曾唤做行家。", "今耄矣，文跌宕，字麻茶。", "同队者、多为公与相。", "广坐里、都无兄与丈。", "生有限，望犹奢。", "补还瞎子重开卷，放教跛子出看花。", "地行仙，疑是汝，不争些。"]'),
('song-ci-778','最高楼','刘克庄','宋','宋词','song-ci','最高楼','[]','金闺彦，荷蒉过山前。',100,'宋词/ci.song.14000.json','["金闺彦，荷蒉过山前。", "把钓坐溪边。", "呼来每得天颜笑，放归犹作地行仙。", "尽教人，瞋避俗，谤逃禅。", "且缄了、淳夫三味口。", "更袖了、坡公三制手。", "宁殿后，不争先。", "小於卫武二十岁，大於绛老两三年。", "这高名，并上寿，几人全。"]'),
('song-ci-779','风入松','刘克庄','宋','宋词','song-ci','风入松','[]','橐泉梦断夜初长。',88,'宋词/ci.song.14000.json','["橐泉梦断夜初长。", "别馆凄凉。", "细思二十年前事，叹人琴、已矣俱亡。", "改尽潘郎鬓发，消残荀令衣香。", "多年布被冷如霜。", "到处同床。", "箫声一去无消息，但回首、天海茫茫。", "旧日风烟草树，而今总断人肠。"]'),
('song-ci-780','风入松','刘克庄','宋','宋词','song-ci','风入松','[]','归鞍尚欲小徘徊。',88,'宋词/ci.song.14000.json','["归鞍尚欲小徘徊。", "逆境难排。", "人言酒是消忧物，奈病馀、孤负金罍。", "萧瑟捣衣时候，凄凉鼓缶情怀。", "远林摇落晚风哀。", "野店犹开。", "多情惟是灯前影，伴此翁、同去同来。", "逆旅主人相问，今回老似前回。"]'),
('song-ci-781','风入松','刘克庄','宋','宋词','song-ci','风入松','[]','残更难睚抵年长。',88,'宋词/ci.song.14000.json','["残更难睚抵年长。", "晓月凄凉。", "芙蓉院落深深闭，叹芳卿、今在今亡。", "绝笔无求凰曲，痴心有返魂香。", "起来休镊鬓边霜。", "半被堆床。", "定归兜率蓬莱去，奈人间、无路茫茫。", "缘断漫三弹指，忧来欲九回肠。"]'),
('song-ci-782','风入松','刘克庄','宋','宋词','song-ci','风入松','[]','攀翻宰树暂徘徊。',88,'宋词/ci.song.14000.json','["攀翻宰树暂徘徊。", "草草安排。", "昔人徒步陈鸡絮，愧公家、仆马觥罍。", "华表旧愁满目，黄粱残梦伤怀。", "欲将庄列等欢哀。", "对卷慵开。", "凭高指点虚无路，问何年、辽鹤归来。", "宿酒得风渐解，小舆待月同回。"]'),
('song-ci-783','临江仙','刘克庄','宋','宋词','song-ci','临江仙','[]','玉笛钿车当日事，东涂西抹都曾。',70,'宋词/ci.song.14000.json','["玉笛钿车当日事，东涂西抹都曾。", "等闲曲子压和凝。", "纵游非草草，已醉强惺惺。", "今向三家村送老，身如罢讲吴僧。", "高楼百尺不须登。", "半炉烧叶火，一盏勘书灯。"]'),
('song-ci-784','临江仙','刘克庄','宋','宋词','song-ci','临江仙','[]','落魄长官江海客，少豪万里寻春。',70,'宋词/ci.song.14000.json','["落魄长官江海客，少豪万里寻春。", "而今樵悴向溪滨。", "断无觞咏兴，惟有簿书尘。", "手插海棠三百本，等闲妆点芳辰。", "他年绛雪映红云。", "丁宁风与月，记取种花人。"]'),
('song-ci-785','临江仙','刘克庄','宋','宋词','song-ci','临江仙','[]','去岁越王台上饮，席间二客如龙。',70,'宋词/ci.song.14000.json','["去岁越王台上饮，席间二客如龙。", "凭高吊古壮怀同。", "马嘶千嶂暮，乐奏半天中。", "今岁三家村市里，故人各自西东。", "菊花时节酒樽空。", "可怜双雪鬓，禁得几秋风。"]'),
('song-ci-786','临江仙','刘克庄','宋','宋词','song-ci','临江仙','[]','不见仙湖能几日，尘沙变尽形容。',70,'宋词/ci.song.14000.json','["不见仙湖能几日，尘沙变尽形容。", "夜来月冷露华浓。", "都忘茅屋下，但记画船中。", "两岸绿阴犹未合，更须补竹添松。", "最怜几树木芙蓉。", "手栽才数尺，别后为谁红。"]'),
('song-ci-787','浪淘沙','刘克庄','宋','宋词','song-ci','浪淘沙','[]','去岁诣公车。',64,'宋词/ci.song.14000.json','["去岁诣公车。", "天语勤渠。", "绛纱玉斧照寒儒。", "恰似昔人曾梦到，帝所清都。", "骨相太清臞。", "谪堕须臾。", "今年黄敕换称呼。", "只为此翁霜鬓秃，老不中书。"]'),
('song-ci-788','浪淘沙','刘克庄','宋','宋词','song-ci','浪淘沙','[]','早岁类寒蛩。',64,'宋词/ci.song.14000.json','["早岁类寒蛩。", "晚节遭逢。", "曾开黄卷侍重瞳。", "归去青藜光照窗，阶药翻红。", "出昼颇匆匆。", "主眷犹浓。", "除官全似紫阳翁。", "换个新衔头面改，又似包公。"]'),
('song-ci-789','浪淘沙','刘克庄','宋','宋词','song-ci','浪淘沙','[]','纸帐素屏遮。',64,'宋词/ci.song.14000.json','["纸帐素屏遮。", "全似僧家。", "无端霜月闯窗纱。", "唤起玉关征戍梦，几叠寒笳。", "岁晚客天涯。", "短发苍华。", "今年衰似去年些。", "诗酒新来俱倚阁，孤负梅花。"]'),
('song-ci-790','浪淘沙','刘克庄','宋','宋词','song-ci','浪淘沙','[]','叠嶂碧周遮。',64,'宋词/ci.song.14000.json','["叠嶂碧周遮。", "游子思家。", "掩藏白发赖乌纱。", "落日倚楼千万恨，社鼓城笳。", "老去淡生涯。", "虚掷年华。", "腊茶盂子太清些。", "待得痴儿公事毕，谢了梅花。"]'),
('song-ci-791','浪淘沙','刘克庄','宋','宋词','song-ci','浪淘沙','[]','目力已茫茫。',64,'宋词/ci.song.14000.json','["目力已茫茫。", "缝菊为囊。", "论衡何必帐中藏。", "却爱素馨清鼻观，采伴禅床。", "风露送新凉。", "山麝开房。", "旋吹银烛闭华堂。", "无奈纱厨遮不住，一地闻香。"]'),
('song-ci-792','凤凰阁','刘克庄','宋','宋词','song-ci','凤凰阁','[]','元规端委，得似幼舆丘壑。',83,'宋词/ci.song.14000.json','["元规端委，得似幼舆丘壑。", "人言此辈宜高阁。", "几载种天随菊，采庞公药。", "龙尾道、难安汗脚。", "浮荣菌蕣，选甚庶官从橐。", "对床句、子真佳作。", "安用羡伊结驷，叹侬罗雀。", "呼便了、沽来共酌。"]'),
('song-ci-793','法驾导引','刘克庄','宋','宋词','song-ci','法驾导引','[]','樵柯烂，丹灶熟，一跳出红尘。',72,'宋词/ci.song.14000.json','["樵柯烂，丹灶熟，一跳出红尘。", "斗紫一双龙奋贽，帝青九万里为程。", "赤脚踏层云。", "鞭鸾上，骑麟下，彷佛睹昆仑。", "洒马鬃泉苏赤地，翻蟾滴水涨沧溟。", "笑杀懵仙人。"]'),
('song-ci-794','一翦梅','刘克庄','宋','宋词','song-ci','一翦梅','[]','陌上行人怪府公。',72,'宋词/ci.song.14000.json','["陌上行人怪府公。", "还是诗穷。", "还是文穷。", "下车上马太匆匆。", "来是春风。", "去是秋风。", "阶衔免得带兵农。", "嬉到昏钟。", "睡到斋钟。", "不消提岳与知宫。", "唤作山翁。", "唤作溪翁。"]'),
('song-ci-795','一翦梅','刘克庄','宋','宋词','song-ci','一翦梅','[]','束緼宵行十里强。',72,'宋词/ci.song.14000.json','["束緼宵行十里强。", "挑得诗囊。", "抛了衣囊。", "天寒路滑马蹄僵。", "元是王郎。", "来送刘郎。", "酒酣耳热说文章。", "惊倒邻墙。", "推倒胡床。", "旁观拍手笑疏狂。", "疏又何妨。", "狂又何妨。"]'),
('song-ci-796','踏莎行','刘克庄','宋','宋词','song-ci','踏莎行','[]','日月跳丸，光阴脱兔。',68,'宋词/ci.song.14000.json','["日月跳丸，光阴脱兔。", "登临不用深怀古。", "向来吹帽插花人，尽随残照西风去。", "老矣征衫，飘然客路。", "炊烟三两人家住。", "欲携斗酒答秋光，山深无觅黄花处。"]'),
('song-ci-797','踏莎行','刘克庄','宋','宋词','song-ci','踏莎行','[]','驱鹊营桥，呼蟾出海，朝朝暮暮遥相望。',68,'宋词/ci.song.14000.json','["驱鹊营桥，呼蟾出海，朝朝暮暮遥相望。", "谁知风雨此时来，银河便有些波浪。", "玉兔迷离，金鸡嘲晰，二星无语空惆怅。", "元来上界也多魔，天孙长怨牵牛旷。"]'),
('song-ci-798','玉楼春','刘克庄','宋','宋词','song-ci','玉楼春','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','年年跃马长安市。',64,'宋词/ci.song.14000.json','["年年跃马长安市。", "客舍似家家似寄。", "青钱换酒日无何，红烛呼庐宵不寐。", "易挑锦妇机中字。", "难得玉人心下事。", "男儿西北有神州，莫滴水西桥畔泪。"]'),
('song-ci-799','鹊桥仙','刘克庄','宋','宋词','song-ci','鹊桥仙','[]','金风淅淅，银河淡淡，长少群贤毕会。',68,'宋词/ci.song.14000.json','["金风淅淅，银河淡淡，长少群贤毕会。", "平生心事曲生知，怪此夕、惺惺相对。", "玄花生眼，新霜点鬓，不肯遮藏老态。", "人间何处有仙方，擘划得、二三百岁。"]'),
('song-ci-800','鹊桥仙','刘克庄','宋','宋词','song-ci','鹊桥仙','[]','御屏录了，冰衔换了，酷似香山居士。',68,'宋词/ci.song.14000.json','["御屏录了，冰衔换了，酷似香山居士。", "草堂丹灶莫留他，且领取、忠州刺史。", "移来芳树，摘来珍果，压尽来禽青李。", "三千年一荐金盘，又不是、玄都栽底。"]'),
('song-ci-801','鹊桥仙','刘克庄','宋','宋词','song-ci','鹊桥仙','[]','阁中芸冷，观中桃谢，谁问贞元朝士。',68,'宋词/ci.song.14000.json','["阁中芸冷，观中桃谢，谁问贞元朝士。", "吾宗一句好书绅，但记取、毋污青史。", "不交平勃，不游田窦，也不朋他牛李。", "平章此去似何人，似洛社、戴花舞底。"]'),
('song-ci-802','鹊桥仙','刘克庄','宋','宋词','song-ci','鹊桥仙','[]','出通明殿，入耆英社，谁似侍郎洪福。',68,'宋词/ci.song.14000.json','["出通明殿，入耆英社，谁似侍郎洪福。", "掌中元自有三珠，更检校、诸孙夜读。", "管他莱相，管他鹤相，留我本来面目。", "希夷一枕未曾醒，笑人世，几回翻局。"]'),
('song-ci-803','鹊桥仙','刘克庄','宋','宋词','song-ci','鹊桥仙','[]','俱登瀛馆，俱还洛社，各自健如黄犊。',68,'宋词/ci.song.14000.json','["俱登瀛馆，俱还洛社，各自健如黄犊。", "不消外监与留台，也不要、嵩山崇福。", "我如原父，君如贡父，且把汉书重读。", "韩公当局等闲过，又看到、温公当局。"]'),
('song-ci-804','鹊桥仙','刘克庄','宋','宋词','song-ci','鹊桥仙','[]','去年无麦，今年多稼，尽是君侯心地。',67,'宋词/ci.song.14000.json','["去年无麦，今年多稼，尽是君侯心地。", "向来寺寺总拘桩，今有不拘桩底寺。", "省仓展日，米场镌价，万落千村蒙惠。", "更将补纳放宽些，便是个、西京循史。"]'),
('song-ci-805','鹊桥仙','刘克庄','宋','宋词','song-ci','鹊桥仙','[]','香芸辟蠹，青藜烛阁，天上宝书万轴。',68,'宋词/ci.song.14000.json','["香芸辟蠹，青藜烛阁，天上宝书万轴。", "前回读得未精详，更罚走、一遭重读。", "松风如故，丹炉如故，坐阅人间陵谷。", "回头调戏窃桃儿，且宁耐、等他桃熟。"]'),
('song-ci-806','鹊桥仙','刘克庄','宋','宋词','song-ci','鹊桥仙','[]','有时块坐，有时扶起，门外草深三尺。',68,'宋词/ci.song.14000.json','["有时块坐，有时扶起，门外草深三尺。", "山禽肯唤我为哥，句句道、哥行不得。", "此儿害跛，群儿拍手，次第加公九锡。", "不消长尘短辕车，但乞取、一枝鹤膝。"]'),
('song-ci-807','鹊桥仙','刘克庄','宋','宋词','song-ci','鹊桥仙','[]','女孙笄珥，男孙袍笏，少长今朝咸集。',68,'宋词/ci.song.14000.json','["女孙笄珥，男孙袍笏，少长今朝咸集。", "且留晚节伴寒香，莫要似、春华性急。", "大招吟了，巫咸下了，未爱修门重入。", "我侬不做佛漳闽，免大雪、庭中呆立。"]'),
('song-ci-808','鹊桥仙','刘克庄','宋','宋词','song-ci','鹊桥仙','[]','一封奏御，九重知己，不假吹嘘送上。',68,'宋词/ci.song.14000.json','["一封奏御，九重知己，不假吹嘘送上。", "从今稳稳到蓬莱，三万里、没些风浪。", "臣年虽老，臣卿尚少，一片丹心葵向。", "何须远比马宾王，且做取、本朝种放。"]'),
('song-ci-809','鹊桥仙','刘克庄','宋','宋词','song-ci','鹊桥仙','[]','我如龚胜，君如龚舍，拂袖同归乡里。',68,'宋词/ci.song.14000.json','["我如龚胜，君如龚舍，拂袖同归乡里。", "共骑竹马有谁存，总唤入、耆英社里。", "苍华尚黑，黄婆方旺，争问翁年今几。", "一门两个老人星，直看见、孙儿生子。"]'),
('song-ci-810','鹊桥仙','刘克庄','宋','宋词','song-ci','鹊桥仙','[]','蒲鞭渐弛，缿筒渐少，安用知他帘外。',67,'宋词/ci.song.14000.json','["蒲鞭渐弛，缿筒渐少，安用知他帘外。", "从今也莫察渊鱼，做到不忍欺田地。", "四民香火，五营笳吹，来献一杯寿水。", "大家赞祝太夫人，长伴取、鲁侯燕喜。"]'),
('song-ci-811','柳梢青','刘克庄','宋','宋词','song-ci','柳梢青','[]','申白苛留。',61,'宋词/ci.song.14000.json','["申白苛留。", "绮园浪出，老不知羞。", "输与先生，一枝鹤膝，一领羊裘。", "便教赐履营丘。", "争似把、渔竿到头。", "冷落磻溪，张皇牧野，著甚来由。"]'),
('song-ci-812','鹧鸪天','刘克庄','宋','宋词','song-ci','鹧鸪天','[]','前度看花白发郎。',64,'宋词/ci.song.14000.json','["前度看花白发郎。", "平生痼疾是清狂。", "幸然无事污青史，省得教人奏赤章。", "游侠窟，少年场。", "输他群谢与诸王。", "居人不识庚桑楚，弟子谁从魏伯阳。"]'),
('song-ci-813','鹧鸪天','刘克庄','宋','宋词','song-ci','鹧鸪天','[]','诗变齐梁体已浇。',64,'宋词/ci.song.14000.json','["诗变齐梁体已浇。", "香奁新制出唐朝。", "纷纷竞奏桑间曲，寂寂谁知爨下焦。", "挥彩笔，展红绡。", "十分峭措称妖娆。", "可怜才子如公瑾，未有佳人敌小乔。"]'),
('song-ci-814','卜算子','刘克庄','宋','宋词','song-ci','卜算子','[]','尽是手成持，合得天饶借。',52,'宋词/ci.song.14000.json','["尽是手成持，合得天饶借。", "风雨於花有底雠，著意相陵藉。", "做暖逼教开，做冷催教谢。", "不负明年花下人，只负栽花者。"]'),
('song-ci-815','卜算子','刘克庄','宋','宋词','song-ci','卜算子','[]','片片蝶衣轻，点点猩红小。',52,'宋词/ci.song.14000.json','["片片蝶衣轻，点点猩红小。", "道是天公不惜花，百种千般巧。", "朝见树头繁，暮见枝头少。", "道是天公果惜花，雨洗风吹了。"]'),
('song-ci-816','卜算子','刘克庄','宋','宋词','song-ci','卜算子','[]','乱似盎中丝，密似风中絮。',52,'宋词/ci.song.14000.json','["乱似盎中丝，密似风中絮。", "行遍茫茫禹迹来，底是无愁处。", "好客挽难留，俗事推难去。", "惟有翻身入醉乡，愁欲来无路。"]'),
('song-ci-817','卜算子','刘克庄','宋','宋词','song-ci','卜算子','[]','开阁广延贤，负扆勤求旧。',52,'宋词/ci.song.14000.json','["开阁广延贤，负扆勤求旧。", "应念南宫老舍人，闲袖丝纶手。", "两制必当仁，五福无过寿。", "且喜新年不要□，天要开元祐。"]'),
('song-ci-818','卜算子','刘克庄','宋','宋词','song-ci','卜算子','[]','东甽宁馨儿，南国循良守。',52,'宋词/ci.song.14000.json','["东甽宁馨儿，南国循良守。", "先把炉熏祝帝尧，次祝君侯寿。", "广致米商船，多酿兵厨酒。", "客有须眉似盖延，许至华堂否。"]'),
('song-ci-819','卜算子','刘克庄','宋','宋词','song-ci','卜算子','[]','已怪社愆期，尚喜巢如故。',52,'宋词/ci.song.14000.json','["已怪社愆期，尚喜巢如故。", "过了清明未肯来，莫被春寒误。", "常傍画檐飞，忽委空梁去。", "忘却王家与谢家，别有衔泥处。"]'),
('song-ci-820','卜算子','刘克庄','宋','宋词','song-ci','卜算子','[]','老圃献花来，异域移根至。',52,'宋词/ci.song.14000.json','["老圃献花来，异域移根至。", "相对炎官火伞中，便有清凉意。", "淡薄古梳妆，娴雅仙标致。", "欲起涪翁再品花，压了山矾弟。"]'),
('song-ci-821','朝天子','刘克庄','宋','宋词','song-ci','朝天子','[]','宿雨频飘洒。',55,'宋词/ci.song.14000.json','["宿雨频飘洒。", "欢喜西畴耕者。", "终朝连夜。", "有珠玑鸣瓦。", "渐白水、青秧鸥鹭下。", "老学种花兼学稼。", "心两挂。", "这几树、海棠休也。"]'),
('song-ci-822','清平乐','刘克庄','宋','宋词','song-ci','清平乐','[]','纤云扫迹。',54,'宋词/ci.song.14000.json','["纤云扫迹。", "万顷玻璃色。", "醉跨玉龙游八极。", "历历天青海碧。", "水晶宫殿飘香。", "群仙方按霓裳。", "消得几多风露，变教人世清凉。"]'),
('song-ci-823','清平乐','刘克庄','宋','宋词','song-ci','清平乐','[]','风高浪快。',54,'宋词/ci.song.14000.json','["风高浪快。", "万里骑蟾背。", "曾识姮娥真体态。", "素面元无粉黛。", "身游银阙珠宫。", "俯看积气濛濛。", "醉里偶摇桂树，人间唤作凉风。"]'),
('song-ci-824','清平乐','刘克庄','宋','宋词','song-ci','清平乐','[]','宫腰束素。',54,'宋词/ci.song.14000.json','["宫腰束素。", "只怕能轻举。", "好筑避风台护取。", "莫遣惊鸿飞去。", "一团香玉温柔。", "笑颦俱有风流。", "贪与萧郎眉语，不知舞错伊州。"]'),
('song-ci-825','清平乐','刘克庄','宋','宋词','song-ci','清平乐','[]','休弹别鹤。',54,'宋词/ci.song.14000.json','["休弹别鹤。", "泪与弦俱落。", "欢事中年如水薄。", "怀抱那堪作恶。", "昨宵月露高楼。", "今朝烟雨孤舟。", "除是无身方了，有身长有闲愁。"]'),
('song-ci-826','清平乐','刘克庄','宋','宋词','song-ci','清平乐','[]','冰轮万里。',54,'宋词/ci.song.14000.json','["冰轮万里。", "云卷天如洗。", "先向海山生大士。", "却诞卯金之子。", "冰盆荔子堪尝。", "胆瓶茉莉尤香。", "震旦人人炎热，补陀夜夜清凉。"]'),
('song-ci-827','清平乐','刘克庄','宋','宋词','song-ci','清平乐','[]','人间喘汗。',54,'宋词/ci.song.14000.json','["人间喘汗。", "无计翻银汉。", "有个至人来震旦。", "宴坐补陀岩畔。", "吾闻福寿难量。", "待看海底生桑。", "乞取净瓶一滴，普教大地清凉。"]'),
('song-ci-828','好事近','刘克庄','宋','宋词','song-ci','好事近','[]','老不计生朝，惭愧阿连书尺。',53,'宋词/ci.song.14000.json','["老不计生朝，惭愧阿连书尺。", "雪鬓霜髭不管，管眼腰黄赤。", "待将心事自笺天，莫费子公力。", "乞赐先生处士，换一张黄敕。"]'),
('song-ci-829','菩萨蛮','刘克庄','宋','宋词','song-ci','菩萨蛮','[]','小鬟解事高烧烛。',52,'宋词/ci.song.14000.json','["小鬟解事高烧烛。", "群花围绕樗蒲局。", "道是五陵儿。", "风骚满肚皮。", "玉鞭鞭玉马。", "戏走章台下。", "笑杀灞桥翁。", "骑驴风雪中。"]'),
('song-ci-830','忆秦娥','刘克庄','宋','宋词','song-ci','忆秦娥','[]','游人绝。',56,'宋词/ci.song.14000.json','["游人绝。", "绿阴满野芳菲歇。", "芳菲歇。", "养蚕天气，采茶时节。", "枝头杜宇啼成血。", "陌头杨柳吹成雪。", "吹成雪。", "淡烟微雨，江南三月。"]'),
('song-ci-831','忆秦娥','刘克庄','宋','宋词','song-ci','忆秦娥','[]','修禊节。',56,'宋词/ci.song.14000.json','["修禊节。", "晋人风味终然别。", "终然别。", "当时宾主，至今清绝。", "等闲写就兰亭帖。", "岂知留与人闲说。", "人闲说。", "永和之岁，暮春之月。"]'),
('song-ci-832','忆秦娥','刘克庄','宋','宋词','song-ci','忆秦娥','[]','泥滑滑。',56,'宋词/ci.song.14000.json','["泥滑滑。", "一声声唤征鞍发。", "征鞍发。", "客亭杨柳，不禁攀折。", "荀郎衣上香初歇。", "萧郎心下书难说。", "书难说。", "霎时吹散，一生愁绝。"]'),
('song-ci-833','忆秦娥','刘克庄','宋','宋词','song-ci','忆秦娥','[]','春酲薄。',56,'宋词/ci.song.14000.json','["春酲薄。", "梦中球马豪如昨。", "豪如昨。", "月明横笛，晓寒吹角。", "古来成败难描摸。", "而今却悔当时错。", "当时错。", "铁衣犹在，不堪重著。"]'),
('song-ci-834','忆秦娥','刘克庄','宋','宋词','song-ci','忆秦娥','[]','梅谢了。',56,'宋词/ci.song.14000.json','["梅谢了。", "塞垣冻解鸿归早。", "鸿归早。", "凭伊问讯，大梁遗老。", "浙河西面边声悄。", "淮河北去炊烟少。", "炊烟少。", "宣和宫殿，冷烟衰草。"]'),
('song-ci-835','西江月','刘克庄','宋','宋词','song-ci','西江月','[]','思邈方书去失，休文老病来攻。',58,'宋词/ci.song.14000.json','["思邈方书去失，休文老病来攻。", "新年筋力太龙锺。", "腰似铁锚儿重。", "雅拜怎生搢笏，徐行也要扶筇。", "田翁邀饮不能从。", "难伴诸公上雍。"]'),
('song-ci-836','朝中措','刘克庄','宋','宋词','song-ci','朝中措','[]','恰为仙佛做生辰。',57,'宋词/ci.song.14000.json','["恰为仙佛做生辰。", "公又绂麒麟。", "黑白几枰屡变，丹青百奏如新。", "都门饯底，洛中画底，莫是前身。", "虽老不扶灵寿，有时更上蒲轮。"]'),
('song-ci-837','朝中措','刘克庄','宋','宋词','song-ci','朝中措','[]','受持鼻祖五千言。',57,'宋词/ci.song.14000.json','["受持鼻祖五千言。", "留得谷神存。", "伴我赋诗茅屋，饶渠待诏金门。", "此翁岁晚，有书充栋，有酒盈樽。", "君看多花早落，孰如仙李蟠根。"]'),
('song-ci-838','朝中措','刘克庄','宋','宋词','song-ci','朝中措','[]','仙风道骨北山翁。',57,'宋词/ci.song.14000.json','["仙风道骨北山翁。", "万卷著胸中。", "涣若宦情冰释，作□醉面桃红。", "千林冻槁，一枝雪艳，消息先通。", "颜色□青精饭，姓名在碧纱笼。"]'),
('song-ci-839','朝中措','刘克庄','宋','宋词','song-ci','朝中措','[]','海天万顷碧玻璃。',57,'宋词/ci.song.14000.json','["海天万顷碧玻璃。", "风露洗炎曦。", "鹦鹉绿毛导从，蟾□雪色追随。", "分明来处，补陀大士，先后同时。", "觅取善财童子，膝边要个孙儿。"]'),
('song-ci-840','水调歌头','刘克庄','宋','宋词','song-ci','水调歌头','[]','君看郭西景，浑不减孤山。',114,'宋词/ci.song.14000.json','["君看郭西景，浑不减孤山。", "飞楼突兀百尺，轮奂侈前观。", "绝唱新词寡和，堕泪旧碑无恙，往事付惊澜。", "不见辽鹤返，惟对水鸥闲。", "又何必，珠翠盛，管弦欢。", "唾壶麈尾潇洒，领客上高寒。", "丞相功存宗庙，祭酒义兼家国，世事尚相关。", "风月寓意耳，莫作晋人看。"]'),
('song-ci-841','贺新郎','刘克庄','宋','宋词','song-ci','贺新郎','[]','辜负东风约。',142,'宋词/ci.song.14000.json','["辜负东风约。", "忆曾将、淮南草木，笔端笼络。", "后土祠中明月夜，忽有瑶姬跨鹤。", "迥不比、水仙低弱。", "天上人间惟一本，倒千锺、琼露花前酌。", "追往事，怎忘却。", "移根应费仙家药。", "漫回头、关山信断，堡城笳作。", "问讯而今平安否，莫遣玉箫惊落。", "但画卷、依稀描著。", "白发愧无渡江曲，与君家、子敬相酬酢。", "新旧恨，两交错。"]'),
('song-ci-842','满江红','刘克庄','宋','宋词','song-ci','满江红','[]','晓色朦胧，佳色在、黄堂深处。',115,'宋词/ci.song.14000.json','["晓色朦胧，佳色在、黄堂深处。", "记当日、霓旌飞下，鸾翔凤翥。", "兰省旧游隆注简，竹符新剖宽忧顾。", "有江南、千里好溪山，留君住。", "牙板唱，花裀舞。", "云液滑，霞觞举。", "顾朱颜绿鬓，年年如许。", "见说相门须出相，何时再筑沙堤路。", "看便飞、丹诏日边来，朝天去。"]'),
('song-ci-843','水调歌头','刘克庄','宋','宋词','song-ci','水调歌头','[]','风露洗玉宇，星斗灿银潢。',114,'宋词/ci.song.14000.json','["风露洗玉宇，星斗灿银潢。", "云间笙鹤来下，人世变凄凉。", "九转金丹成后，一朵红云深处，玉立侍虚皇。", "却笑跨夺子，草草梦黄粱。", "君记否，齐桓□，鲁灵光。", "中原公案未了，直下欠人当。", "试问玉门关外，何似金銮殿上，此段及平章。", "富贵倘来耳，万代姓名香。"]'),
('song-ci-844','乳燕飞・贺新郎','刘克庄','宋','宋词','song-ci','乳燕飞・贺新郎','[]','风流八十，是人间妆点，孩儿眉额。',120,'宋词/ci.song.14000.json','["风流八十，是人间妆点，孩儿眉额。", "再著三星添上面，又是一般奇特。", "且置零头，举将成数，算起君须识。", "从今十倍，恰当彭祖八百。", "更把百倍添来，庄椿身世，又十头添撇。", "况迈非熊年纪在，管取方来勋业。", "子既生孙，孙还又子，堆几床牙笏。", "瑶池会宴，饱看几度桃实。"]'),
('song-ci-845','水龙吟','刘克庄','宋','宋词','song-ci','水龙吟','[]','昔人风调谁高，二疏盛日还乡里。',126,'宋词/ci.song.14000.json','["昔人风调谁高，二疏盛日还乡里。", "公卿祖道，百城围尽，争传佳事。", "闻自垂车日，都门外、送车凡几。", "今世无工，尽置之勿道，焜煌处、独青史。", "佳甚东阳山水。", "是昔时、钓游某地。", "风流脱似，洛中耆老，一人而已。", "好为霞觞釂，正庭阶、彩衣荣侍。", "便明朝有诏，启门解说，值先生醉。"]'),
('song-ci-846','买陂塘・摸鱼儿','赵癯斋','宋','宋词','song-ci','买陂塘・摸鱼儿','[]','闻掀髯、岭头长啸，梅花一夜香吐。',140,'宋词/ci.song.14000.json','["闻掀髯、岭头长啸，梅花一夜香吐。", "正看鸣凤朝阳影，何事惊鸿翩举。", "来又去。", "但赢得、儿童拍手笑无据。", "人间何处。", "有九曲栽芹，一峰横砚，江上听春雨。", "功名事，不信朝鳞暮羽。", "九关虎豹如许。", "午桥见有闲风月，正自不妨嘉趣。", "君记取。", "人尽道、东山安石难留住。", "伏龙三顾。", "待报了君恩，勋铭彝鼎，归作子期侣。"]'),
('song-ci-847','贺新郎','程正同','宋','宋词','song-ci','贺新郎','[]','久矣无循吏。',142,'宋词/ci.song.14000.json','["久矣无循吏。", "自当年、弘宽去后，风流谁继。", "律令喜为鹰击勇，无复柔桑驯雉。", "何幸见、真儒小试。", "手种海棠三百本，有几多、遗爱人须记。", "潘岳县，未为贵。", "文章政事通枫陛。", "看傅岩、霖雨岁旱，要须均施。", "玉色温其山似立，气禀新秋清厉。", "便好据、经纶要地。", "却笑庞才非百里，骤天衢、自合还天骥。", "卮酒祝，八千岁。"]'),
('song-ci-848','沁园春','程正同','宋','宋词','song-ci','沁园春','[]','富敌陶猗，才卑贾马，气吞曹刘。',139,'宋词/ci.song.14000.json','["富敌陶猗，才卑贾马，气吞曹刘。", "更妓娱安石，东山名胜，樽盈文举，北海风流。", "事冷千年，身兼八子，豪举伊谁与匹俦。", "应还笑，为天将降任，未欲东周。", "优游。", "宁久淹留。", "管蓬矢桑弧志早酬。", "有棠棣联芳，庭萱不老，砌兰擢秀，蟾桂传秋。", "要颂椿龄，若将柏叶，婢膝奴颜应合羞。", "直须是，功名期会，同跨鳌头。"]'),
('song-ci-849','满庭芳','程正同','宋','宋词','song-ci','满庭芳','[]','五柳先生，宦情无几，赋成归去来兮。',119,'宋词/ci.song.14000.json','["五柳先生，宦情无几，赋成归去来兮。", "吾归何所，任运且随时。", "曾向高人问道，清妙处、已悟希夷。", "谁能羡，胸中芥子，容易纳须弥。", "竹林，新职事，神交狂客，志慕天随。", "但能乐天知命，夫复何疑。", "多谢故人念我，平安报、不必纲维。", "饮君酒，愿君同寿，此外本无为。"]'),
('song-ci-850','思越人・朝天子','程正同','宋','宋词','song-ci','思越人・朝天子','[]','曾把隋珠抵鹊来。',64,'宋词/ci.song.14000.json','["曾把隋珠抵鹊来。", "拓弓花下不虚开。", "醉馀戏把行人弹，堪笑齐王谩筑台。", "穿兔手，落雕材。", "狭斜衢路共徘徊。", "流星一点高飞处，笑坐金鞍歌落梅。"]'),
('song-ci-851','朝中措','程正同','宋','宋词','song-ci','朝中措','[]','少年不入利名场。',57,'宋词/ci.song.14000.json','["少年不入利名场。", "花柳作家乡。", "一片由甲口觜，几多耍俏心肠。", "周郎学识，秦郎风度，柳七文章。", "聊借生绡一幅，与君写尽行藏。"]'),
('song-ci-852','临江仙','阳枋','宋','宋词','song-ci','临江仙','[]','乐意相关莺对语，春风遍满天涯。',70,'宋词/ci.song.14000.json','["乐意相关莺对语，春风遍满天涯。", "生香不断树交花。", "个中皆实理，何处是浮华。", "收敛回来还夜气，一轮明月千家。", "看梅休用隔窗纱。", "清光辉皎洁，疏影自横斜。"]'),
('song-ci-853','念奴娇','阳枋','宋','宋词','song-ci','念奴娇','[]','白尽蒹葭，衰从蒲柳，我只松筠节。',28,'宋词/ci.song.14000.json','["白尽蒹葭，衰从蒲柳，我只松筠节。", "君民尧舜，老翁揩眼勋业。"]'),
('song-ci-854','清夜游','周端臣','宋','宋词','song-ci','清夜游','[]','西园昨夜，又一番、阑风伏雨。',119,'宋词/ci.song.14000.json','["西园昨夜，又一番、阑风伏雨。", "清晨按行处。", "有新绿照人，乱红迷路。", "归吟窗低，但瓶几留连春住。", "窥晴小蝶翩翩，等闲飞来似相妒。", "迟暮。", "家山信杳，奈锦字难凭，清梦无据。", "春尽江头，啼鹃最凄苦。", "蔷薇几度花开，误风前、翠樽谁举。", "也应念、留滞周南，思归未赋。"]'),
('song-ci-855','春归怨','周端臣','宋','宋词','song-ci','春归怨','[]','问春为谁来、为谁去，匆匆太速。',127,'宋词/ci.song.14000.json','["问春为谁来、为谁去，匆匆太速。", "流水落花，夕阳芳草，此恨年年相触。", "细履名园，闲看嘉树，蔼翠阴成簇。", "争知也被韶华，换却诗人鬓边绿。", "小花深院静，旋引清尊，自歌新曲。", "燕子不归来，风絮乱吹帘竹。", "误文姬、凝望久，心事想劳频卜。", "但门掩黄昏，数声啼鴂，又唤起、相思一掬。"]'),
('song-ci-856','木兰花慢','周端臣','宋','宋词','song-ci','木兰花慢','[]','霭芳阴未解，乍天气、过元宵。',126,'宋词/ci.song.14000.json','["霭芳阴未解，乍天气、过元宵。", "讶客袖犹寒，吟窗易晓，春色无聊。", "梅梢。", "尚留顾藉，滞东风、未肯雪轻飘。", "知道诗翁欲去，递香要送兰桡。", "清标。", "会上丛霄。", "千里阻、九华遥。", "料今朝别后，他时有梦，应梦今朝。", "河桥。", "柳愁未醒，赠行人、又恐越魂销。", "留取归来系马，翠长千缕柔条。"]'),
('song-ci-857','玉楼春','周端臣','宋','宋词','song-ci','玉楼春','[]','华堂帘幕飘香雾。',64,'宋词/ci.song.14000.json','["华堂帘幕飘香雾。", "一搦楚腰轻束素。", "翩跹舞态燕还惊，绰约妆容花尽妒。", "樽前谩咏高唐赋。", "巫峡云深留不住。", "重来花畔倚阑干，愁满阑干无倚处。"]'),
('song-ci-858','六桥行','周端臣','宋','宋词','song-ci','六桥行','[]','芙蓉苑。',123,'宋词/ci.song.14000.json','["芙蓉苑。", "记试酒清狂，亸鞭游遍。", "翠红照眼。", "凝芳露、洗出青霞一片。", "垂杨两岸。", "窥镜底、新妆深浅。", "应料似、锦帐行春，三千粉春矜艳。", "邂逅系马堤边，念玉笋轻攀，笑簪同欢。", "岁华暗换。", "西风路、几许愁肠凄断。", "仙城梦黯。", "还又是、六桥秋晚。", "凝望处，烟淡云寒，人归雁远。"]'),
('song-ci-859','六桥行','周端臣','宋','宋词','song-ci','六桥行','[]','苏堤路。',123,'宋词/ci.song.14000.json','["苏堤路。", "正密柳烘烟，嫩莎收雨。", "野芳竞吐。", "山如画、隐隐云藏山坞。", "六桥徙倚。", "喧处处、行春箫鼓。", "鸥影外、一片湖光，夷犹彩舟来去。", "凝想禊饮花前，爱裙幄围香，款留连步。", "旧踪未改，还曾记、揽结亭边芳树。", "愁情几许。", "更多似、一天飞絮。", "空自有、花畔黄鹂，知人笑语。"]'),
('song-ci-860','少年游','周端臣','宋','宋词','song-ci','少年游','[]','四山烟霭未分明。',60,'宋词/ci.song.14000.json','["四山烟霭未分明。", "宿雨破新晴。", "万顷湖光，一堤柳色，人在画图行。", "清明过了春无几，花事已飘零。", "莫待斜阳，便寻归棹，家隔两重城。"]'),
('song-ci-861','喜迁莺令・喜迁莺','周端臣','宋','宋词','song-ci','喜迁莺令・喜迁莺','[]','青嶂绕，翠堤斜。',57,'宋词/ci.song.14000.json','["青嶂绕，翠堤斜。", "晴绮散馀霞。", "一湖春水碧无瑕。", "可惜画船遮。", "燕交飞，莺对语。", "风软香尘凝路。", "一年春事又扬花。", "诗酒□韶华。"]'),
('song-ci-862','贺新郎','周端臣','宋','宋词','song-ci','贺新郎','[]','怕听黄昏雨。',141,'宋词/ci.song.14000.json','["怕听黄昏雨。", "到黄昏、陡顿潇潇，雨声不住。", "香冷罗衾愁无寐，难奈凄凄楚楚。", "暗试把、佳期重数。", "楼外一行征雁过，更偏来、撩理芳心苦。", "心自苦，向谁诉。", "菱花憔悴羞人觑。", "欢红低翠黯，不似旧家眉妩。", "目断阳台幽梦阻，孤负朝朝暮暮。", "怕泪落、瑶筝慵拊。", "手拈梅花春又近，料人间、别有安排处。", "云碧袖，为君舞。"]'),
('song-ci-863','沁园春','赵福元','宋','宋词','song-ci','沁园春','[]','一剑凌风，跨六鳌头，登群玉峰。',139,'宋词/ci.song.14000.json','["一剑凌风，跨六鳌头，登群玉峰。", "听金童宣敕，琼胎掇送，大唐进士，圣宋仙翁。", "琪树玲珑，宝花散漫，香霭天枝绕绛空。", "后五日，有竹湖公相，梦叶非熊。", "峥嵘得子如龙。", "傲南墅修篁皓鹤中。", "似银瓶碾月，一清彻底，玉虹贯斗，千丈蟠胸。", "洛殿催班，燃灯赐对，九万鹏程瞬息通。", "蟠桃宴，与蟾宫双桂，长伴乔松。"]'),
('song-ci-864','沁园春','赵福元','宋','宋词','song-ci','沁园春','[]','斗柄御寅，序启苍涂，气转洪钧。',139,'宋词/ci.song.14000.json','["斗柄御寅，序启苍涂，气转洪钧。", "正乾坤交泰，圣贤相遇，风声虎啸，雾滃龙兴。", "华渚流虹，璇枢绕电，期迈三朝嵩降申。", "真希有，庆吾皇万岁，重臣千春。", "枫震宠数来频。", "绾叠组累累辉楚城。", "看袍将赐锦，带仍佩玉，十行丹诏，单骑红尘。", "入赞中兴，泰阶上宰，寿域八荒歌太平。", "运化笔，管烘□桃李，又一番新。"]'),
('song-ci-865','沁园春','赵福元','宋','宋词','song-ci','沁园春','[]','珠斗阑干，银河清浅，梦籋帝关。',139,'宋词/ci.song.14000.json','["珠斗阑干，银河清浅，梦籋帝关。", "见六丁拥道，一声传跸，翠幢舞凤，彩扇交鸾。", "寿祝天齐，神夸岳降，报到明朝重整班。", "璇星烂，有赤松黄石，雾凑苍坛。", "仙风绿鬓朱颜。", "才奏罢呼麟游海山。", "命飞琼步月，瑶台凝净，云英捣雪，玉杵光寒。", "鹤立芝庭，龟迎荷□，鼎看翩翩彩袖翻。", "留春醉，醉何须归去，常在人寰。"]'),
('song-ci-866','减字木兰花','赵福元','宋','宋词','song-ci','减字木兰花','[]','吮煤弄笔。',52,'宋词/ci.song.14000.json','["吮煤弄笔。", "草圣寰中君第一。", "电脚摇光。", "骤雨旋风声满堂。", "豪厘巧辨。", "唤起羲之当北面。", "醉眼摩娑。", "错认书颠作酒颠。"]'),
('song-ci-867','鹧鸪天','赵福元','宋','宋词','song-ci','鹧鸪天','[]','裙曳湘波六幅缣。',64,'宋词/ci.song.14000.json','["裙曳湘波六幅缣。", "风流体段总无嫌。", "歌翻檀口朱缨小，拍弄红牙玉笋纤。", "腔子里，字儿添。", "嘲撩风月性多般。", "忔憎声里金珠迸，惊起梁尘落无帘。"]'),
('song-ci-868','念奴娇','李亿','宋','宋词','song-ci','念奴娇','[]','镜鸾分影，望天涯肠断，悄无红叶。',120,'宋词/ci.song.14000.json','["镜鸾分影，望天涯肠断，悄无红叶。", "几度秋风吹翠被，一缕幽香难灭。", "燕卜新梁，花移别槛，回首春如客。", "欢情何在，绿杨空销愁色。", "可是今古风流，小乔姝丽，只许周郎得。", "金谷珠帘空百尺，不碍梦魂飞入。", "钗股盟深，旧缘未断，月有重圆日。", "蓝桥路近，乘云先问消息。"]'),
('song-ci-869','菩萨蛮','李亿','宋','宋词','song-ci','菩萨蛮','[]','画楼酒醒春心悄。',52,'宋词/ci.song.14000.json','["画楼酒醒春心悄。", "残月悠悠芳梦晓。", "娇汗浸低鬟。", "屏山云雨阑。", "香车河汉路。", "又是匆匆去。", "鸾扇护明妆。", "含情看绿杨。"]'),
('song-ci-870','徵招','李亿','宋','宋词','song-ci','徵招','[]','翠壶浸雪明谣夜，初疑玉虬飞动。',116,'宋词/ci.song.14000.json','["翠壶浸雪明谣夜，初疑玉虬飞动。", "莫弄紫箫吹，堕寒琼惊梦。", "把红炉对拥。", "怕清魄，不禁霜重。", "爱护殷勤，待长留作，道人香供。", "尘暗古南州，风流远、谁寻故枝么凤。", "谩举目销凝，对愁云曚暡。", "向霞扉月洞。", "且嚼蕊、细开春瓮。", "这奇绝，好唤苍髯，与竹君来共。"]'),
('song-ci-871','满庭芳','刘颉','宋','宋词','song-ci','满庭芳','[]','莺老梅黄，水寒烟淡，断香谁与添温。',118,'宋词/ci.song.14000.json','["莺老梅黄，水寒烟淡，断香谁与添温。", "宝缸初上，花影伴芳尊。", "细细轻帘半卷，凭阑对、山色黄昏。", "人千里，小楼幽草，何处梦王孙。", "十年，羁旅兴，舟前水峄，马上烟村。", "记小亭香墨，题恨犹存。", "几夜江湖旧梦，空凄怨、多少销魂。", "归鸦被，角声惊起，微雨暗重门。"]'),
('song-ci-872','贺新郎','冯取洽','宋','宋词','song-ci','贺新郎','[]','九日明朝是。',141,'宋词/ci.song.14000.json','["九日明朝是。", "问宜轩何事，今朝众宾交至。", "长记每年八月八，曾庆饮仙出世。", "直推到、於今何意。", "要待千崖秋气爽，向东篱、试探花开未。", "挝急鼓，舞长袂。", "主人臭味花相似。", "笑争春、红紫低昂，转头扫地。", "独占西风摇落候，旋屑黄金点缀。", "做得个、秋花元帅。", "旧说东阳流菊水，饮之者、寿过百馀岁。", "泛此酒，劝公醉。"]'),
('song-ci-873','贺新郎','冯取洽','宋','宋词','song-ci','贺新郎','[]','自愿卑栖翼。',141,'宋词/ci.song.14000.json','["自愿卑栖翼。", "似沧洲、白鸟悠悠，静依拳石。", "聊寄一梯云木表，俯视霁虹千尺。", "乐江上、山间声色。", "镜样清流环样绕，笑赐湖、一曲夸唐敕。", "尘外趣，有谁识。", "飞来妙墨痕犹湿。", "走盘珠流出，不火食人胸膈。", "三叹阳春知和寡，但觉光生虚室。", "何处觅，倚歌箫客。", "他日玉林来得否，待平分、风月供吟笔。", "添一友，共闲逸。"]'),
('song-ci-874','贺新郎','冯取洽','宋','宋词','song-ci','贺新郎','[]','句里思黄九。',142,'宋词/ci.song.14000.json','["句里思黄九。", "笑王郎、不奈寒芳，腰围如柳。", "得似江郎饶雅趣，时揽黄花诳口。", "吐妙语、与之争秀。", "闲绕珍从吟不尽，尽风前、露下栾栾瘦。", "香自足，岂劳嗅。", "一尊问我能同否。", "叹双溪、冷落篱边，傲霜犹有。", "浩唱云笺金缕调，兴发小槽珠酒。", "待唤醒、早春梅友。", "独恨爱花人易老，漫一年，好景还依旧。", "东望处，立良久。"]'),
('song-ci-875','贺新郎','冯取洽','宋','宋词','song-ci','贺新郎','[]','梦折营门柳。',142,'宋词/ci.song.14000.json','["梦折营门柳。", "送君归、暂戏斑衣，又拢征袖。", "到得皇州风景异，只有湖山似旧。", "把感慨、寓之杯酒。", "雨抹晴妆西子样，且平章、剩赋诗千首。", "富与贵，本来有。", "青油幕底筹攻守。", "拥貔貅、朝气凌云，夜锋冲斗。", "蜀祲淮氛犹在眼，一扫正须健帚。", "又何惜、驱弛奔走。", "快展韬铃资世用，看归来、金印悬双肘。", "倾玉斝，为亲寿。"]'),
('song-ci-876','贺新郎','冯取洽','宋','宋词','song-ci','贺新郎','[]','那得身无事。',141,'宋词/ci.song.14000.json','["那得身无事。", "问双溪老子，而今万缘空否。", "正使尘牢偿未了，毕竟难昏灵府。", "已笑唾、功名如土。", "五十九年风雨过，算非非、是是何须数。", "垂老也，信缘度。", "绿阴朱夏回清暑。", "叹病来、觞怯流霞，扇闲白羽。", "方念生初增感慨，谁寄乐章新语。", "知是我、花庵庵主。", "一别三年惟梦见，定何时、相对倾琼醑。", "惊世路，有豺虎。"]'),
('song-ci-877','贺新郎','冯取洽','宋','宋词','song-ci','贺新郎','[]','知彼须知此。',142,'宋词/ci.song.14000.json','["知彼须知此。", "问筹边、攻守规模，云何则是。", "景色愔愔犹日暮，壮士无由吐气。", "又安得、将如廉李。", "燕坐江沱甘自蹙，笑腐儒、枉楦朝家紫。", "用与舍，徒为耳。", "黄芦白苇迷千里。", "叹长淮、篱落空疏，仅馀残垒。", "读父兵书宁足恃，击楫谁盟江水。", "有识者、知其庸矣。", "多少英雄沈草野，岂堂堂、吾国无君子。", "起诸葛，总戎事。"]'),
('song-ci-878','贺新郎','冯取洽','宋','宋词','song-ci','贺新郎','[]','问讯花庵主。',142,'宋词/ci.song.14000.json','["问讯花庵主。", "这一宗、拍板门槌，是谁亲付。", "逢翰墨场聊作戏，那个是真实语。", "算惟有、青山堪住。", "玉立林幽真脱洒，又何妨、白石和泉煮。", "底用判，云游据。", "朝三暮四从渠赋。", "且随缘、家养园收，自然成趣。", "此外盘蜗馀一室，人我两俱无负。", "要参到、道心微处。", "尽作逃禅逃得密，也难遮、拨草来寻路。", "应为拨，懒残芋。"]'),
('song-ci-879','贺新郎','冯取洽','宋','宋词','song-ci','贺新郎','[]','二老交相访。',142,'宋词/ci.song.14000.json','["二老交相访。", "正不妨、勃窣媻姗，舍车而杖。", "忆在蓉村新雨过，门外春流浩荡。", "中有个、列仙臞相。", "把酒论诗饶胜韵，更柳边、花底同心赏。", "临别句，几回唱。", "忽传风驭来溪上。", "遣儿曹、策马郊迎，老怀欣畅。", "争讶金华佳父子，飞下蓬莱崑阆。", "有四士、追随仙仗。", "我爱君如何次道，便令人、直欲倾家酿。", "歌妙曲，郑声放。"]'),
('song-ci-880','贺新郎','冯取洽','宋','宋词','song-ci','贺新郎','[]','往事休寻访。',142,'宋词/ci.song.14000.json','["往事休寻访。", "幸老来、筋力差强，未须扶杖。", "收脚八风波外立，一片虚空荡荡。", "误寿者、本来无相。", "今日不知何日也，便戊申、重见何须赏。", "大梦曲，此时唱。", "团栾儿女溪堂上。", "且一觞、一咏陶然，此情堪畅。", "漫说神仙华屋好，缥缈峤壶蓬阆。", "这浮幻、也难凭仗。", "何似熏风来岁岁，蔼一家、和气如春酿。", "婚嫁了，尽闲放。"]'),
('song-ci-881','沁园春','冯取洽','宋','宋词','song-ci','沁园春','[]','我爱□君，结屋并山，友松竹梅。',139,'宋词/ci.song.14000.json','["我爱□君，结屋并山，友松竹梅。", "有倦游孤剑，暂悬素壁，醉吟行履，时印苍苔。", "得失不惊，知恬交养，浩浩胸中何壮哉。", "须知道，似骅骝万里，道路方开。", "相期湖上舒怀。", "莫放过花枝与酒杯。", "况上天已办，河东新赋，圜桥乐得，海内英才。", "矍铄溪翁，据鞍一笑，画饼功名赋倘来。", "长堤上，正柳花荷气，尽可追陪。"]'),
('song-ci-882','沁园春','冯取洽','宋','宋词','song-ci','沁园春','[]','人事好乖，云散风流，暗思去年。',139,'宋词/ci.song.14000.json','["人事好乖，云散风流，暗思去年。", "记竹舆伊轧，报临村里，筇枝颠倒，忙返溪边。", "翦韭新炊，寻桃小酌，取次欢谣俱可编。", "难忘处，是阳春一曲，群唱尊前。", "新晴又放花天。", "况家酿堪携不用钱。", "想有人如玉，已过南市，无人伴我，重醉西阡。", "旧约难凭，新词堪赋，乐事赏心那得全。", "归来也，命儿将此意，写以朱弦。"]'),
('song-ci-883','沁园春','冯取洽','宋','宋词','song-ci','沁园春','[]','一雨霈然，六合全清，空无点埃。',139,'宋词/ci.song.14000.json','["一雨霈然，六合全清，空无点埃。", "喜秋容新沐，为谁媚妩，凉蟾留照，正尔徘徊。", "蜡屐清游，渔蓑淡话，富贵於予何有哉。", "双溪上，总旧盟鸥鹭，来往无猜。", "烟霞竹石松梅。", "更无数幽花陆续开。", "渐黄鸡啄黍，肥堪一箸，浮蛆拍瓮，美可三杯。", "儿解应门，翁方索句，俗客来时莫放来。", "青山好，尽从今日日，闼不妨排。"]'),
('song-ci-884','沁园春','冯取洽','宋','宋词','song-ci','沁园春','[]','举世纷纷，风靡波流，名氛利埃。',139,'宋词/ci.song.14000.json','["举世纷纷，风靡波流，名氛利埃。", "有幽人嘉遁，长年修洁，寒花作伴，竟日徘徊。", "餐荐夕英，杯迎朝露，世味何如此味哉。", "扬扬蝶，尽弄芳来往，我又奚猜。", "双溪约玉林梅。", "拟真到庄门一扣开。", "奈衢山风急，勒教回驾，横圹水弱，未许浮杯。", "恨结停云，神驰落月，白雪风前忽堕来。", "教儿唱，侑蓑翁一醉，无闷堪排。"]'),
('song-ci-885','沁园春','冯取洽','宋','宋词','song-ci','沁园春','[]','问讯柳溪，溪上柳容，胡为带埃。',139,'宋词/ci.song.14000.json','["问讯柳溪，溪上柳容，胡为带埃。", "叹阳春陡变，孰为披拂，赏音难遇，谁与徘徊。", "好在湖山，吾容不辱，寄径垂条岂偶哉。", "休摇荡，且深根宁极，免俗人猜。", "何妨傍竹依梅。", "待青眼春回一笑开。", "尽攀丝弄叶，效颦施黛，笼鞯拂帽，藉阴传杯。", "未碍飞绵，一高千丈，风力微时稳下来。", "天难问，便陶门汉苑，一任安排。"]'),
('song-ci-886','沁园春','冯取洽','宋','宋词','song-ci','沁园春','[]','禀气之中，具圣之和，生逢令辰。',139,'宋词/ci.song.14000.json','["禀气之中，具圣之和，生逢令辰。", "算三春仲月，方才破二，百年大齐，恰则平分。", "立玉林深，散花庵小，中有け然自在身。", "诗何似，似苏州闲远，庾府清新。", "青鞋布袜乌巾。", "试勇往蓉溪一问津。", "有心香一瓣，心声一阕，更携阿艾，同寿灵椿。", "劫劫长存，生生不息，宁极深根秋又春。", "聊添我，作风流二老，岁岁寻盟。"]'),
('song-ci-887','沁园春','冯取洽','宋','宋词','song-ci','沁园春','[]','有孤竹君，音节拂云，谥曰洞箫。',139,'宋词/ci.song.14000.json','["有孤竹君，音节拂云，谥曰洞箫。", "纵柳郎填就，周郎顾罢，欠伊品藻，律也难调。", "惭愧何郎。", "呜呜袅袅，翻入颚唇齿舌喉。", "谁知道，是郭郎亲授，共贯同条。", "后来一辈枵枵。", "甚声响都如鹦鹉娇。", "叹秦青已往，嘉荣何在，念奴骨朽，李八魂消。", "试向尊前，听君一曲。", "前辈风流未觉凋。", "冯郎老，但点头咽唾，拼解金貂。"]'),
('song-ci-888','水调歌头','冯取洽','宋','宋词','song-ci','水调歌头','[]','林叶润而密，莺语老犹娇。',114,'宋词/ci.song.14000.json','["林叶润而密，莺语老犹娇。", "懒翁哪记生日，兀兀度昏朝。", "勘破富贫贵贱，参透死生寿夭，至竟本同条。", "胸次绝疑碍，物外自超遥。", "又何尝，贪七贵，慕三乔。", "溪山吾所自有，宜钓更堪樵。", "窃笑傍门小法，休觅驻颜大药，揠长只伤苗。", "造化大炉耳，愚智一齐销。"]'),
('song-ci-889','水调歌头','冯取洽','宋','宋词','song-ci','水调歌头','[]','雪霁春已半，露重午方喧。',114,'宋词/ci.song.14000.json','["雪霁春已半，露重午方喧。", "一筇拄上高绝，便觉眼前宽。", "指点数家楼阁，检校一村花柳，绿水接青烟。", "峦岫竞围绕，风日更清妍。", "闹媒蜂，纷使蝶，菜花繁。", "少年正尔行乐，谁复顾华颠。", "自有此丘此坂，那得游人箫鼓，暖响出中天。", "归步不妨晚，恰则月初弦。"]'),
('song-ci-890','念奴娇','冯取洽','宋','宋词','song-ci','念奴娇','[]','高堂素壁，漫生绡十幅，图张消暑。',120,'宋词/ci.song.14000.json','["高堂素壁，漫生绡十幅，图张消暑。", "不奈火云烧六合，逃也略无逃处。", "小派秋声，巨籭凉点，吸欻来何许。", "故人词翰，此时飞落蓬户。", "何幸一笑掀髯，停杯浩唱，三叹遗音古。", "雪碗冰瓯无表里，更贮三危鲜露。", "咀咽生香，清寒入梦，展转忘宵曙。", "对床误喜，与君同听风雨。"]'),
('song-ci-891','金菊对芙蓉','冯取洽','宋','宋词','song-ci','金菊对芙蓉','[]','宝镜缘空，玉簪点水，荡摇千顷寒光。',120,'宋词/ci.song.14000.json','["宝镜缘空，玉簪点水，荡摇千顷寒光。", "正江妃月姊，斗理明妆。", "扶阑一笑开诗眼，少容我、吟讽其旁。", "一川风露，满怀冰雪，云海弥茫。", "不妨倚醉乘狂。", "问天公觅取，几曲渔乡。", "听小楼哀管，偷弄初凉。", "夜深欢极忘归去，锦江酿透碧筒香。", "对花无语，花应笑我，不似张郎。"]'),
('song-ci-892','木兰花慢','冯取洽','宋','宋词','song-ci','木兰花慢','[]','叹年光婉晚，蒲柳质、易惊秋。',122,'宋词/ci.song.14000.json','["叹年光婉晚，蒲柳质、易惊秋。", "况念远怀人，停云幂幂，时雨飕飕。", "西风堕来雁信，似知予、竟日倚溪楼。", "报道归调汤剂，不知谁护衣篝。", "悠然富贵不须求。", "安乐万缘休。", "但饱饭煎茶，婆娑永日，也胜闲愁。", "寒花自便寂寞，怕纷纷、蝶引与蜂勾。", "莫问障从何起，祗凭心有天游。"]'),
('song-ci-893','摸鱼儿','冯取洽','宋','宋词','song-ci','摸鱼儿','[]','叹刘郎、那回轻别，霏霏三落红雨。',140,'宋词/ci.song.14000.json','["叹刘郎、那回轻别，霏霏三落红雨。", "玄都观里应遗恨，一抹断烟残缕。", "愁望处。", "想雾暗云深，忘却来时路。", "新花旧主。", "记客羽流商，裁红翦翠，山径日将暮。", "空枝上，时有幽禽对语。", "声声如问来否。", "人生行乐须闻健，衰老念谁免此。", "吾所与。", "在溪上深深，锦绣千花坞。", "何时定去。", "但对酒思君，呼儿为我，频唱小桃句。"]'),
('song-ci-894','蝶恋花','冯取洽','宋','宋词','song-ci','蝶恋花','[]','秋到双溪溪上树。',70,'宋词/ci.song.14000.json','["秋到双溪溪上树。", "叶叶凉声，未省来何许。", "尽拓溪楼窗与户。", "倚阑清夜窥河鼓。", "那得吟朋同此住。", "独对秋芳，欲寄花无处。", "杖履相从曾有语。", "未来先自愁君去。"]'),
('song-ci-895','西江月','冯取洽','宋','宋词','song-ci','西江月','[]','老子齐头六十，新年第一今朝。',58,'宋词/ci.song.14000.json','["老子齐头六十，新年第一今朝。", "放开怀抱不须焦。", "万事付之一笑。", "烟柳效颦翠敛，露桃献笑红妖。", "已拼行乐到元宵。", "尚可追随年少。"]'),
('song-ci-896','万年歌','赵以夫','宋','宋词','song-ci','万年歌','[]','凤历开新，正微和乍转，丽景初晓。',122,'宋词/ci.song.14000.json','["凤历开新，正微和乍转，丽景初晓。", "五荚蓂舒，光映玉阶瑶草。", "在在东风语笑。", "庆此日、虹流电绕。", "鲸波静，翠涌鳌山，嵩呼声动云表。", "绛节霓旌缥缈。", "望珠星灿烂，紫微深窈。", "琬液香浮，露湿蟠桃犹小。", "叠叠仙韶九奏，知春到、人间多少。", "蓬莱外，若木扶疏，万年枝上长好。"]'),
('song-ci-897','大','赵以夫','宋','宋词','song-ci','大','[]','正绿阴浓，莺声懒，庭院轻寒烟薄。',164,'宋词/ci.song.14000.json','["正绿阴浓，莺声懒，庭院轻寒烟薄。", "天然花富贵，逞夭红殷紫，叠葩重萼。", "醉艳酣春，妍姿浥露，翠羽轻明如削。", "檀心鸦黄嫩，似离情愁绪，万丝交错。", "更银烛相辉，玉瓶微浸，宛然京洛。", "朝来风雨恶。", "拍僝僽、低张青油幕。", "便好倩、佳人插帽，贵客传笺，趁良辰、赏心行乐。", "四美难并也，须拼醉、莫辞杯勺。", "被花恼、情无著。", "长笛何处，一笑江头高阁。", "极暮水云漠漠。"]'),
('song-ci-898','孤鸾','赵以夫','宋','宋词','song-ci','孤鸾','["\u897f\u6e56"]','江南春早。',119,'宋词/ci.song.14000.json','["江南春早。", "问江上寒梅，占春多少。", "自照疏星冷，祗许春风到。", "幽香不知甚处，但迢迢、满汀烟草。", "回首谁家竹外，有一枝斜好。", "记当年、曾共花前笑。", "念玉雪襟期，有谁知道。", "唤起罗浮梦，正参横月小。", "凄凉更吹塞管，漫相思，鬓华惊老。", "待觅西湖半曲，对霜天清晓。"]'),
('song-ci-899','金盏子','赵以夫','宋','宋词','song-ci','金盏子','["\u897f\u6e56"]','得水能仙，似汉皋遗佩，碧波寒月。',122,'宋词/ci.song.14000.json','["得水能仙，似汉皋遗佩，碧波寒月。", "蓝玉暖生烟，称缟袂黄冠，素姿芳洁。", "亭亭独立风前，照冰壶澄彻。", "当时事，琴心妙处谁传，顿成愁绝。", "六出自天然，更一味清香浑胜雪。", "西湖秋菊寒泉，似坡老风流，至今人说。", "殷勤折伴梅边，听玉龙吹裂。", "丁宁道，百年兄弟，相看晚节。"]'),
('song-ci-900','天香','赵以夫','宋','宋词','song-ci','天香','[]','蜀锦移芳，巫云散彩，天孙翦取相寄。',116,'宋词/ci.song.14000.json','["蜀锦移芳，巫云散彩，天孙翦取相寄。", "金屋看承，玉台凝盼，尚忆旧家风味。", "生香绝艳，说不尽、天然富贵。", "脸嫩浑疑看损，肌柔只愁吹起。", "花神为谁著意。", "把韶华、总归姝丽。", "可是老来心事，不成春思。", "却羡宫袍仙子。", "调曲曲清平似翻水。", "笑嘱东风，殷勤劝醉。"]'),
('song-ci-901','探春慢','赵以夫','宋','宋词','song-ci','探春慢','[]','南国收寒，东郊放暖，条风初回台榭。',125,'宋词/ci.song.14000.json','["南国收寒，东郊放暖，条风初回台榭。", "小燕横钗，闹蛾低鬓，根底吴娃妖冶。", "纤手传生菜，向人道、新春来也。", "莫须沈醉樽前，这些风景无价。", "长记年年此日，迎著个牛儿，彩鞭羞打。", "飐飐金幡，星星华发，得似家山闲暇。", "都把心期事，待问讯、柳边花下。", "箫鼓声中，温存小楼深夜。"]'),
('song-ci-902','探春慢','赵以夫','宋','宋词','song-ci','探春慢','[]','屑璐飘寒，镂金献巧，妆成水晶亭榭。',125,'宋词/ci.song.14000.json','["屑璐飘寒，镂金献巧，妆成水晶亭榭。", "飞絮悠扬，散花零乱，绝胜翠娇红冶。", "粉艳嘻嘻道，尽飞上、使君鬚也。", "多情莫笑衰翁，旧时梁苑声价。", "窗外小梅羞涩，倩羯鼓尊前，慢敲轻打。", "鲸海停波，鹤谯宾月，赢得残年清暇。", "心事知谁会，但梦绕、越王城下。", "白玉青丝，且同醉吟春夜。"]'),
('song-ci-903','探春慢','赵以夫','宋','宋词','song-ci','探春慢','[]','宝胜宾春，华灯照夜，穷冬浑然如客。',125,'宋词/ci.song.14000.json','["宝胜宾春，华灯照夜，穷冬浑然如客。", "炉焰鳞红，杯深翡翠，早减三分寒力。", "一笑团栾处，恰喜得、雪消风息。", "苔枝数蕊明珠，恍疑香麝初拆。", "懊恨东君无准，甚朝做重阴，暮还晴色。", "唤燕呼莺，雕花镂叶，机巧可曾休得。", "静里无穷意，漫看尽、纷纷红白。", "且听新腔，红牙玉纤低拍。"]'),
('song-ci-904','龙山会','赵以夫','宋','宋词','song-ci','龙山会','[]','重整登高屐。',127,'宋词/ci.song.14000.json','["重整登高屐。", "群玉峰头，万里秋无极。", "远山青欲滴。", "新雁过、飘缈孤云天北。", "烟入小桥低，水痕退、寒流澄碧。", "对佳辰，惊心客里，鬓丝堪摘。", "风流晋宋诸贤，骑台龙山，俯仰皆陈迹。", "凭阑看落日。", "嗟往事、唯有黄花如昔。", "醉袖舞西风，任教笑、参差凫舄。", "但回首、东篱久负，有谁知得。"]'),
('song-ci-905','龙山会','赵以夫','宋','宋词','song-ci','龙山会','[]','九日无风雨。',127,'宋词/ci.song.14000.json','["九日无风雨。", "一笑凭高，浩气横秋宇。", "群峰青可数。", "寒城小、一水萦回如缕。", "西北最关情，漫遥指、东徐南楚。", "黯销魂，斜阳冉冉，雁声悲苦。", "今朝黄菊依然，重上南楼，草草成欢聚。", "诗朋休浪赋。", "旧题处、俯仰已随尘土。", "莫放酒行疏，清漏短、凉蟾当午。", "也全胜、白衣未至，独醒凝伫。"]'),
('song-ci-906','龙山会','赵以夫','宋','宋词','song-ci','龙山会','[]','佳节明朝九。',127,'宋词/ci.song.14000.json','["佳节明朝九。", "彩舫凌虚，共醉西风酒。", "湖光蓝滴透。", "云浪碎、巧学波纹吹皱。", "碧落杳无边，但玉削，千峰寒瘦。", "留连久，秋容似洗，月华如昼。", "回头南楚东徐，暝霭苍烟，处处空刁斗。", "山公今健否。", "功名事、付与年时交旧。", "白发苦欺人，尚堪插、黄花盈首。", "归去也、东篱好在，觅渊明友。"]'),
('song-ci-907','芙蓉月','赵以夫','宋','宋词','song-ci','芙蓉月','[]','黄叶舞碧空，临水处、照眼红苞齐吐。',115,'宋词/ci.song.14000.json','["黄叶舞碧空，临水处、照眼红苞齐吐。", "柔情媚态，伫立西风如诉。", "遥想仙家城阙，十万绿衣童女。", "云飘缈，玉娉婷，隐隐彩鸾飞舞。", "樽前更风度。", "记天香国色，曾占春暮。", "依然好在，还伴清霜凉露。", "一曲阑干敲遍，悄无语。", "空相顾。", "残月淡，酒阑时、满城钟鼓。"]'),
('song-ci-908','夜飞鹊・夜飞鹊慢','赵以夫','宋','宋词','song-ci','夜飞鹊・夜飞鹊慢','[]','微云拂斜月，万籁声沈。',129,'宋词/ci.song.14000.json','["微云拂斜月，万籁声沈。", "凉露暗坠桐阴。", "蛾眉乞得天孙巧，愔愔楼上穿针。", "佳期鹊相误，到年时此夕，欢浅愁深。", "人间儿女，说风流，直到如今。", "河汉几曾风浪，因景物牵情，自是人心。", "长记秋庭往事，钿花翦翠，钗股分金。", "道人无著，正萧然、竹枕綀衾。", "梦回时，天淡星稀，闲弄一曲瑶琴。"]'),
('song-ci-909','秋蕊香','赵以夫','宋','宋词','song-ci','秋蕊香','[]','一夜金风，吹成万粟，枝头点点明黄。',119,'宋词/ci.song.14000.json','["一夜金风，吹成万粟，枝头点点明黄。", "扶疏月殿影，雅澹道家装。", "阿谁倩、天女散浓香。", "十分熏透霓裳。", "徘徊处，玉绳低转，人静天凉。", "底事小山幽咏，浑未识清妍，空自情伤。", "忆佳人、执手诉离湘。", "招蟾魄、和酒吸秋光。", "碧云日暮何妨。", "惆怅久，瑶琴微弄，一曲清商。"]'),
('song-ci-910','角招','赵以夫','宋','宋词','song-ci','角招','[]','晓风薄。',133,'宋词/ci.song.14000.json','["晓风薄。", "苔枝上、翦成万点冰萼。", "暗香无处著。", "立马断魂，晴雪篱落。", "横溪略彴。", "恨寄驿、音书辽邈。", "梦绕扬州东阁。", "风流旧日何郎，想依然林壑。", "离索。", "引杯自酌。", "相看冷淡，一笑人如削。", "水云寒漠漠。", "底处群仙，飞来霜鹤。", "芳姿绰约。", "正月满、瑶台珠箔。", "徙倚阑干寂寞。", "尽分付，许多愁，城头角。"]'),
('song-ci-911','徵招','赵以夫','宋','宋词','song-ci','徵招','[]','玉壶冻裂琅玕折，骎骎逼人衣袂。',117,'宋词/ci.song.14000.json','["玉壶冻裂琅玕折，骎骎逼人衣袂。", "暖絮张空飞，失前山横翠。", "欲低还又起。", "似妆点、满园春意。", "记忆当时，剡中情味，一溪云水。", "天际。", "绝行人，高吟处，依稀灞桥邻里。", "更翦翦梅花，落云阶月地。", "化工真解事。", "强勾引、老来诗思。", "楚天暮，驿使不来，怅曲阑独倚。"]'),
('song-ci-912','扬州慢','赵以夫','宋','宋词','song-ci','扬州慢','[]','十里春风，二分明月，蕊仙飞下琼楼。',121,'宋词/ci.song.14000.json','["十里春风，二分明月，蕊仙飞下琼楼。", "看冰花翦翦，拥碎玉成球。", "想长日、云阶伫立，太真肌骨，飞燕风流。", "敛群芳、清丽精神，都付扬州。", "雨窗数朵，梦惊回、天际香浮。", "似阆苑花神，怜人冷落，骑鹤来游。", "为问竹西风景，长空谈、烟水悠悠。", "又黄昏羌管，孤城吹起新愁。"]'),
('song-ci-913','扬州慢','赵以夫','宋','宋词','song-ci','扬州慢','[]','粱苑吟新，高阳饮散，玉容寂寞妆楼。',121,'宋词/ci.song.14000.json','["粱苑吟新，高阳饮散，玉容寂寞妆楼。", "故人应念我，折赠水晶球。", "不须倩、东风说与，吹箫云路，解佩江流。", "似天涯、邂逅相逢，低问东州。", "为花更醉，细挼香、酒面酥浮。", "记桥月同看，帘风共笑，仙枕曾游。", "无奈乍晴还雨，江天暮、飞絮悠悠。", "莫先教偷取，春归满地清愁。"]'),
('song-ci-914','惜黄花','赵以夫','宋','宋词','song-ci','惜黄花','[]','众芳凋谢。',131,'宋词/ci.song.14000.json','["众芳凋谢。", "堪爱处、老圃寒花幽野。", "照眼如画。", "烂然满地金钱，买断金钱无价。", "古香逸韵似高人，更野服、黄冠潇洒。", "向霜夜。", "冷笑暖春，桃李夭冶。", "襟期问与谁同，记往昔、独自徘怀篱下。", "采采盈把。", "此时一段风流，赖得白衣陶写。", "而今为米负初心，且细摘、轻浮三雅。", "沈醉也。", "梦落故国茅舍。"]'),
('song-ci-915','忆旧游慢','赵以夫','宋','宋词','song-ci','忆旧游慢','[]','爱东湖六月，十里香风，翡翠铺平。',124,'宋词/ci.song.14000.json','["爱东湖六月，十里香风，翡翠铺平。", "误入红云里，似当年太乙，约我寻盟。", "叶舟荡漾寒碧，分得一襟冰。", "渐际晚轻阴，修蒲舞绿，倦柳梳青。", "娉婷。", "黯无语。", "想怨女三千，长日宫庭。", "六六阑干曲，有玉儿才貌，谁与看承。", "柔情一点无奈，频付酒杯行。", "到夜静人归，凉蟾自照鸥鹭汀。"]'),
('song-ci-916','忆旧游慢','赵以夫','宋','宋词','song-ci','忆旧游慢','[]','望红渠影里，冉冉斜阳，十里堤平。',124,'宋词/ci.song.14000.json','["望红渠影里，冉冉斜阳，十里堤平。", "唤起江湖梦，向沙鸥住处，细说前盟。", "水乡六月无暑，寒玉散清冰。", "笑老去心情，也将醉眼，镇为花青。", "亭亭。", "步明镜，似月浸华清，人在秋庭。", "照夜银河落，想粉香湿露，恩泽初承。", "十洲缥缈何许，风引彩舟行。", "尚忆得西施，馀情袅袅烟水汀。"]'),
('song-ci-917','解语花','赵以夫','宋','宋词','song-ci','解语花','[]','红香湿月，翠影停云，罗袜尘生步。',123,'宋词/ci.song.14000.json','["红香湿月，翠影停云，罗袜尘生步。", "并肩私语。", "知何事、暗遣玉容泣露。", "闲情最苦。", "任笑道、争妍似妒。", "倒银河，秋夜双星，不到佳期误。", "拟把江妃共赋。", "当时携手，烟水深处。", "明珠溅雨。", "凝脂滑、洗出一番铅素。", "凭谁说与。", "莫便化、彩鸾飞去。", "待玉童，双节来迎，为作芙蓉主。"]'),
('song-ci-918','烛影摇红','赵以夫','宋','宋词','song-ci','烛影摇红','[]','乍冷还暄，小春时候今朝转。',116,'宋词/ci.song.14000.json','["乍冷还暄，小春时候今朝转。", "三分历日二分休，镜里清霜满。", "云幕低垂不展。", "矮窗明、红麟初暖。", "老来活计，浊酒三杯，黄庭一卷。", "万里关河，朔风吹到边声远。", "倚楼脉脉数归鸿，谁会愁深浅。", "最苦山寒日短。", "但梅花、相看岁晚。", "何人金屋，巧啭歌莺，慢调筝雁。"]'),
('song-ci-919','薄媚','赵以夫','宋','宋词','song-ci','薄媚','["\u957f\u6c5f"]','桂香消，梧影瘦，黄菊迷深院。',115,'宋词/ci.song.14000.json','["桂香消，梧影瘦，黄菊迷深院。", "倚西风，看落日，长江东去如练。", "先生底事，有赋飘然。", "刚到为田园。", "独醒何为，持杯自劝。", "未能免。", "休把茱萸吟玩。", "但管年年健。", "千古事、几凭阑。", "吾生早、九十强半。", "欢娱终日，富贵何时，一笑醉乡宽。", "倒载归来，回廊月满。"]'),
('song-ci-920','沁园春','赵以夫','宋','宋词','song-ci','沁园春','[]','秋入书帏，漏箭初长，熏炉未灰。',140,'宋词/ci.song.14000.json','["秋入书帏，漏箭初长，熏炉未灰。", "向酒边陶写，韩情杜思，案头料理，汉蠹秦煨。", "天有高情，世无慧眼，刚道先生是不斋。", "人都笑，这当行铺席，又不成开。", "忘怀。", "物外徘徊。", "与鸥鹭同盟两莫猜。", "似琉璃匣里，光涵牛斗，凤凰台上，声挟风雷。", "宝汞一钱，冰衔三字，浮利浮名安在哉。", "太平也，要泥金镂玉，除是公来。"]'),
('song-ci-921','沁园春','赵以夫','宋','宋词','song-ci','沁园春','["\u957f\u6c5f"]','客问吾年，吾将老矣，今五十三。',140,'宋词/ci.song.14000.json','["客问吾年，吾将老矣，今五十三。", "似北海先生，过之又过，善财童子，参到无参。", "官路太行，世情沧海，何止嵇康七不堪。", "归来也，是休官令尹，有发瞿昙。", "千岩。", "秀色如蓝。", "新著个楼儿恰对南。", "看浮云自在，百般态度，长江无际，一碧虚涵。", "荔子江珧，莼羹鲈鲙，一曲春风酒半酣。", "凭阑处，正空流皓月，光满寒潭。"]'),
('song-ci-922','沁园春','赵以夫','宋','宋词','song-ci','沁园春','[]','自笑声来，骨相无奇，壬三甲三。',139,'宋词/ci.song.14000.json','["自笑声来，骨相无奇，壬三甲三。", "觉紫宸班里，都忘故步，维摩室内，添个新参。", "壮也不如，老之将至，今日将军战岂堪。", "江湖客，况诗肥贾岛，笔瘦王昙。", "纷纷纡紫脱蓝。", "送水北山人又水南。", "喜支离得佚，散材可寿，一丘自足，万象中涵。", "脍炙功名，膏盲富贵，举世黄梁梦正酣。", "知谁健，且茹芝商岭，饮菊胡潭。"]'),
('song-ci-923','贺新郎','赵以夫','宋','宋词','song-ci','贺新郎','[]','满酌蓬莱酒。',139,'宋词/ci.song.14000.json','["满酌蓬莱酒。", "最苦是、中年作恶，送人时候。", "一夜朔风吹石裂，惊得梅花也瘦，更衣袂、严霜寒透。", "卷起潮头无丈尺，甚扁舟、拍上三江口。", "明月冷，载归否。", "分携欲折无垂柳。", "但层楼徙倚，两眉空皱。", "海阔天高无处问，万事不堪回首。", "况目断、孤鸿去后。", "玉样松鲈今正美，想子真、微笑还招手。", "且为我，饮三斗。"]'),
('song-ci-924','贺新郎','赵以夫','宋','宋词','song-ci','贺新郎','["\u957f\u6c5f"]','葵扇秋来贱。',142,'宋词/ci.song.14000.json','["葵扇秋来贱。", "阿谁知、初回轻暑，又教题遍。", "不是琵琶知音少，无限如簧巧啭。", "倩说似、长门休怨。", "莫把蛾眉与人妒，但疏梅、淡月深深院。", "临宝鉴，欲妆懒。", "少时声价倾粱苑。", "到中年，也曾落魄，雾收云卷。", "待入汉庭金马去，洒笔长江滚滚。", "好留取、才名久远。", "过眼荣华俱尘土，听关睢、盈耳离骚婉。", "歌不足，为嗟叹。"]'),
('song-ci-925','贺新郎','赵以夫','宋','宋词','song-ci','贺新郎','["\u897f\u6e56"]','载酒阳关去。',142,'宋词/ci.song.14000.json','["载酒阳关去。", "正西湖、连天烟草，满堤晴絮。", "采翠撷芳游冶处，应和娇弦艳鼓。", "看柳外、画船无数。", "万倾琉璃浑镜净，陡风波、汹汹鱼龙舞。", "谈笑里，遽如许。", "流觞满引浇离绪。", "便东西、斜阳立马，绿波前浦。", "自是莼鲈高兴动，恰值春山杜宇。", "漫回首、软红香雾。", "咫尺佳人千里隔，望空江、明月横洲渚。", "清梦断，恨如缕。"]'),
('song-ci-926','贺新郎','赵以夫','宋','宋词','song-ci','贺新郎','[]','草色庭前绿。',142,'宋词/ci.song.14000.json','["草色庭前绿。", "掩重门、国香伴我，画帘幽独。", "无奈熏风吹绿绮，闲理离骚旧曲。", "觉鼻观、微闻清馥。", "可是花神嫌冷淡，碧丛中、炯炯骈双玉。", "相对久，各欢足。", "冰姿带露如新沐。", "想当年、夷齐二子，独清孤竹。", "千古英雄尘土尽，凛凛西山云木。", "总付与、一尊醽醁。", "学得汉宫娇姊妹，便承恩、贮向黄金屋。", "终不似，在空谷。"]'),
('song-ci-927','贺新郎','赵以夫','宋','宋词','song-ci','贺新郎','[]','碾破长空绿。',142,'宋词/ci.song.14000.json','["碾破长空绿。", "看银蟾、一轮似水，照人清独。", "缥缈风摇环佩碎，疑是英茎妙曲。", "忽散作、天花芬馥。", "帝子双双来洞户，炯肌肤、冰雪颜如玉。", "愁易老，意难足。", "楚江万顷疏汤沐。", "想佳人，依然携手，碧云修竹。", "葱蒨玲珑方寸许，清过千重夏木。", "速就我、同倾湘醁。", "追忆兰亭当日事，尽凄凉、也胜卢仝屋。", "应不到，羡金谷。"]'),
('song-ci-928','贺新郎','赵以夫','宋','宋词','song-ci','贺新郎','[]','春事浑如客。',142,'宋词/ci.song.14000.json','["春事浑如客。", "趁新晴、花骢骄骏，纻衫轻窄。", "腊瓮初倾光欲动，笑把黄甘旋擘。", "更喜得、酒朋诗敌。", "陶写襟怀觞咏里，似风流、王谢当年集。", "忘尔汝，任争席。", "疏帘画舫梅妆白。", "看斜阳、波心镜面，照伊颜色。", "飘缈笙歌天上谱，一刻千金莫惜。", "谁信道、高楼占得。", "柳外暝烟人去也，但月钩、冷浸阑干湿。", "知过了，几寒食。"]'),
('song-ci-929','汉宫春','赵以夫','宋','宋词','song-ci','汉宫春','[]','投老归来，记踏青堤上，三度逢君。',118,'宋词/ci.song.14000.json','["投老归来，记踏青堤上，三度逢君。", "寒窗冷淡活计，明月空尊。", "红红白白，又一番、春色撩人。", "谁信道，闲中天地，园林几见成尘。", "今夕偶无风雨，便满城箫鼓，来往纷纷。", "鳌山宝灯照夜，罗绮千门。", "珠帘尽卷，看娉婷、水上行云。", "应自笑，周郎少日，风流羽扇纶巾。"]'),
('song-ci-930','暗香','赵以夫','宋','宋词','song-ci','暗香','["\u897f\u6e56"]','冰花炯炯。',120,'宋词/ci.song.14000.json','["冰花炯炯。", "记那回占断，春风鳌顶。", "独抱寒香，得意西湖酒初醒。", "为问玉堂富贵，争得似、山中深靓。", "向岁晚，竹翠松苍，闲伴一枝冷。", "南浦，水万顷。", "想月湿断矶，云弄疏影。", "粉英落尽。", "孤鹤长鸣夜方永。", "将见青青似豆，又迤逦、传黄风景。", "听报道、催去也，再调玉鼎。"]'),
('song-ci-931','疏影','赵以夫','宋','宋词','song-ci','疏影','[]','晴空漠膜。',134,'宋词/ci.song.14000.json','["晴空漠膜。", "怪雪来底处，飘满篱落。", "元是花神，管领春风，幽香忽遍林壑。", "玉仙缓辔江城路，全不羡、扬州东阁。", "似天教、瑶佩琼裾，荐与翠尊冰勺。", "闻道儿童好语，丰年瑞覆斗，占取红萼。", "驿使飞驰，羹鼎安排，速趁良辰行乐。", "联镳一一清都客，也肯把、山翁同约。", "醉归来、梦断西窗，怕听丽谯悲角。"]'),
('song-ci-932','尾犯','赵以夫','宋','宋词','song-ci','尾犯','[]','长啸蹑高寒，回首万山，空翠零乱。',118,'宋词/ci.song.14000.json','["长啸蹑高寒，回首万山，空翠零乱。", "渺渺清秋，与斜阳天远。", "引光禄、清吟兴动，忆龙山、旧游梦断。", "夹衣初试，破帽多情，自笑霜蓬短。", "黄花长好在，一俯仰、节物惊换。", "紫蟹青橙，觅东篱幽伴。", "感今古、风凄霜冷，想关河、烟昏月淡。", "举杯相属，殷勤更把茱萸看。"]'),
('song-ci-933','燕春台','赵以夫','宋','宋词','song-ci','燕春台','[]','绣地残英，画空飞絮，东风又送春归。',121,'宋词/ci.song.14000.json','["绣地残英，画空飞絮，东风又送春归。", "雨足郊坰，相将翠密成帷。", "燕莺犹恋芳菲。", "向枝头、叶底依依。", "留春不住，绿波渺渺，碧草萋萋。", "锦帆开晓，彩仗迎熏，峰回路转，月淡天低。", "红云影里，群仙报道班齐。", "九奏箫韶，算人间、无此埙箎。", "步新堤。", "金鼎调羹也，梅子黄时。"]'),
('song-ci-934','燕春台','赵以夫','宋','宋词','song-ci','燕春台','[]','锦里春回，玉墀天近，东风稳送雕鞯。',121,'宋词/ci.song.14000.json','["锦里春回，玉墀天近，东风稳送雕鞯。", "祖帐移来，光流万斛金莲。", "十分香月娟娟。", "照人间、一点魁躔。", "此时新事，飞来双凤，催上甘泉。", "寻思京洛，少日芳游，柳遥禁雪，花淡宫烟。", "鳌山涌翠，通宵脆管繁弦。", "再见升平，想红云、飘缈群仙。", "看明年。", "金殿传柑宴，衮绣貂蝉。"]'),
('song-ci-935','玉烛新','赵以夫','宋','宋词','song-ci','玉烛新','["\u897f\u6e56"]','寒宽一雁落。',124,'宋词/ci.song.14000.json','["寒宽一雁落。", "正万里相思，被渠惊觉。", "春风字字吹香雪，唤起西湖盟约。", "当时醉处，仿佛记、青楼珠箔。", "又不是，南国花迟，徘徊酒边慵酌。", "家山月色依然，想竹外横枝，玉明冰薄。", "而今话昨。", "空对景、怅望美人天角。", "清尊淡薄。", "便翠羽、殷勤难托。", "休品入、三叠琴心，教人瘦却。"]'),
('song-ci-936','念奴娇','赵以夫','宋','宋词','song-ci','念奴娇','["\u897f\u6e56"]','重门翠锁，笑侯鲭断绝，又逢寒食。',120,'宋词/ci.song.14000.json','["重门翠锁，笑侯鲭断绝，又逢寒食。", "社瓮初开春浩荡，荠蕨漫山谁摘。", "榆火传新，柳绵吹老，愁绪空千忆。", "百花过了，游蜂将次成蜜。", "追思共醉西湖，诗朋馀几，俯仰成悲恻。", "月射波心光万丈，犹想当时颜色。", "黄鹄翩翩，白驹皎皎，莫待山灵勒。", "金貂箬笠，问渠还肯相易。"]'),
('song-ci-937','念奴娇','赵以夫','宋','宋词','song-ci','念奴娇','[]','尊前一笑，问梅花消息，几枝开遍。',120,'宋词/ci.song.14000.json','["尊前一笑，问梅花消息，几枝开遍。", "咳唾随风人似玉，寒夜春生酒面。", "故里天遥，殊乡岁晚，忍对骊驹宴。", "无情潮汐，可能为我留恋。", "目断雪棹烟帆，匆匆轻别，岂是如鸿燕。", "要趁盘椒供燕喜，舞袖斓斑双旋。", "屈指重来，扬鞭催去，想在金銮殿。", "云萍无据，莫辞蘸甲深劝。"]'),
('song-ci-938','念奴娇','赵以夫','宋','宋词','song-ci','念奴娇','[]','梅花度曲，被多情勾引，枝枝看遍。',120,'宋词/ci.song.14000.json','["梅花度曲，被多情勾引，枝枝看遍。", "暗忆孤山今夜月，疏影横斜镜面。", "萼绿凌风，云英怯冷，未放瑶池宴。", "人间蜂蝶，也知无计迷恋。", "闻道管领多才，清词好句，泥落空梁燕。", "好换蕊珠供彩笔，莫待随风面旋。", "千岁蟠虬，双栖么凤，咫尺蓬莱殿。", "湖边春暗，料应日日酬劝。"]'),
('song-ci-939','风流子','赵以夫','宋','宋词','song-ci','风流子','[]','忆惜少年日，吴江上、长啸步垂虹。',135,'宋词/ci.song.14000.json','["忆惜少年日，吴江上、长啸步垂虹。", "看飞出玉轮，十分端正，幻成冰壑，一碧澄空。", "当此际，醉魂游帝所，凉袂扬秋风。", "桂殿凤笙，妙音何处，莼羹鲈脍，清兴谁同。", "今宵欢娱地，千钧笔、模写拟付良工。", "无奈云沈顾兔，雨挂痴龙。", "误骚客宿吟，杯仙梦醉，负他佳节，戏我衰翁。", "毕竟孤光长在，后夜重逢。"]'),
('song-ci-940','二郎神','赵以夫','宋','宋词','song-ci','二郎神','[]','一江渌净，算阅尽、燕鸿来去。',129,'宋词/ci.song.14000.json','["一江渌净，算阅尽、燕鸿来去。", "便系日绳长，修蟾斧妙，教驻韶华未许。", "白白红红多多态，问底事、东皇无语。", "但碧草烟淡，落花流水，不堪回伫。", "晴雨。", "陡寒乍热，清阴庭户。", "任诗卷抛荒，棋秤休务，寂寞风帘舞絮。", "我酌君斟，我词君唱，谁似卿卿箫史。", "拼酩酊，断送春归，恰好听鸠呼妇。"]'),
('song-ci-941','二郎神','赵以夫','宋','宋词','song-ci','二郎神','[]','野塘暗碧，渐点点、翠钿明镜。',129,'宋词/ci.song.14000.json','["野塘暗碧，渐点点、翠钿明镜。", "想昼永珠帘，人闲金屋，时倚妆台照影。", "睡起阑干凝思处，漫数尽、归鸦栖暝。", "知月下莺黄，云边蛾绿，为谁低整。", "曾倩。", "雁传鹊报，心期千定。", "奈柳絮浮云，桃花流水，长是参差不并。", "莫怨春归，莫愁柘老，蚕已三眠将醒。", "肠断句，枉费丹青，漠漠水遥烟回。"]'),
('song-ci-942','木兰花慢','赵以夫','宋','宋词','song-ci','木兰花慢','[]','玉梅吹霁雪，觉和气、满南州。',123,'宋词/ci.song.14000.json','["玉梅吹霁雪，觉和气、满南州。", "更连夕晴光，一番小雨，朝霭全收。", "人情不知底事，但黄童白叟总追游。", "驾海千寻彩岫，涨空万点星球。", "风流。", "秀色明眸。", "金莲步、度轻柔。", "任往来燕席，香风引舞，清官随讴。", "何曾见痴太守，已登车、去也又迟留。", "人似多情皓月，十分照我当楼。"]'),
('song-ci-943','满江红','赵以夫','宋','宋词','song-ci','满江红','[]','倾国精神，娇无力、亭亭向谁。',114,'宋词/ci.song.14000.json','["倾国精神，娇无力、亭亭向谁。", "还知否，羞沈月姊，妒杀风姨。", "满地胭脂春欲老，平池翡翠水新肥。", "祗花王、富贵占韶光，真绝奇。", "香暗动，人未知。", "翻玉拍，度金衣。", "任轻红殷紫，对景偏宜。", "闻道洛阳夸此地，因思京国太平时。", "向沈香亭北按新词，乘醉归。"]'),
('song-ci-944','摸鱼儿','赵以夫','宋','宋词','song-ci','摸鱼儿','["\u897f\u6e56"]','古城阴、一川新浸，天然尘外幽绝。',140,'宋词/ci.song.14000.json','["古城阴、一川新浸，天然尘外幽绝。", "谁家幻出千机锦，疑是蕊仙云织。", "环燕席。", "便纵有万花，此际无颜色。", "清风两腋。", "炯玉树森前，碧筒满注，共作醉乡客。", "长堤路，还忆西湖景物。", "游船曾点空碧。", "当时总负凌云气，俯仰顿成今昔。", "愁易极。", "更对景销凝，怅望天西北。", "归来日夕。", "但展转无眠，风櫺水馆，冷浸五更月。"]'),
('song-ci-945','水龙吟','赵以夫','宋','宋词','song-ci','水龙吟','[]','塞楼吹断梅花，晓风瑟瑟添凄咽。',126,'宋词/ci.song.14000.json','["塞楼吹断梅花，晓风瑟瑟添凄咽。", "关河万里，烟尘四野，眼前都别。", "击楫功名，椎锋意气，是人都说。", "问周郎何日，小乔到手，为君赋，酹江月。", "休把愁肠暗结。", "又相将、鲁云书节。", "锦围放密，金樽任满，歌声莫歇。", "赢得朝朝，半醒半醉，佯痴佯劣。", "尽瞢腾，深入无何，管甚须鬓成雪。"]'),
('song-ci-946','水龙吟','赵以夫','宋','宋词','song-ci','水龙吟','[]','谁家明镜飞空，海天绀碧浮秋霁。',126,'宋词/ci.song.14000.json','["谁家明镜飞空，海天绀碧浮秋霁。", "西风淡荡，纤云卷尽，小星疑坠。", "宇宙冰壶，襟怀玉界，飘然仙思。", "炯灵犀一点，蟾辉万丈，长相射、清清地。", "祗又桂花长好，照人间、几番荣悴。", "年年此夕，持杯嚼露，挥毫翻水。", "宝瑟凄清，玉箫飘缈，佩环声碎。", "唤谪仙起舞，古今同梦，不知何世。"]'),
('song-ci-947','水调歌・水调','赵以夫','宋','宋词','song-ci','水调歌・水调','[]','竞渡楚乡事，夸胜锦缠头。',114,'宋词/ci.song.14000.json','["竞渡楚乡事，夸胜锦缠头。", "湖光渌净，转胜雪浪舞潜虬。", "刚道琉璃宝苑，移作水晶珠阙，鳌顶出中流。", "一钓惊天地，能动此心不。", "活千年，封万户，等虚舟。", "渺然身世，烟水浩荡一沙鸥。", "听得长淮风景，唤起离骚往恨，杜若满汀洲。", "相对老榕下，五月已先秋。"]'),
('song-ci-948','双瑞莲','赵以夫','宋','宋词','song-ci','双瑞莲','[]','千机云锦里。',116,'宋词/ci.song.14000.json','["千机云锦里。", "看并蒂新房，骈头芳蕊。", "清标艳态，两两翠裳霞袂。", "似是商量心事。", "倚绿叶、无言相对。", "天蘸水。", "彩舟过处，鸳鸯惊起。", "飘缈漾影摇香，对刘阮风流，双仙姝丽。", "闲情不断，犹恋人间欢会。", "莫待西风吹老，荐玉醴、碧筒拼醉。", "清露底。", "明月一襟归思。"]'),
('song-ci-949','桂枝香','赵以夫','宋','宋词','song-ci','桂枝香','[]','水天一色。',124,'宋词/ci.song.14000.json','["水天一色。", "正四野秋高，千古愁极。", "多少黄花密意，付他欢伯。", "楼前马戏星球过，又依稀、东徐陈迹。", "一时豪俊，风流济济，酒朋诗敌。", "画不就、江东暮碧。", "想阅尽千帆，来往潮汐。", "烟草萋迷，此际为谁心恻。", "引杯抚剑凭高处，黯消魂、目断天北。", "至今人笑，新亭坐间，泪珠空滴。"]'),
('song-ci-950','桂枝香','赵以夫','宋','宋词','song-ci','桂枝香','[]','青霄望极。',124,'宋词/ci.song.14000.json','["青霄望极。", "际万里月明，无点云色。", "一片冰壶世界，水乡先得。", "年年客里惊秋半，倚西风、鬓华吹白。", "觅闲无路，相逢且醉，好天凉夕。", "听曲曲、仙韶促拍。", "趁画舸飞空，雪浪翻激。", "行乐风流，暗省旧时京国。", "插空翠巇连星麓，但波痕、浮动金碧。", "不如归去，扁舟五湖，钓竿渔笛。"]'),
('song-ci-951','永遇乐','赵以夫','宋','宋词','song-ci','永遇乐','[]','云雁将秋，露萤照夜，凉透窗户。',128,'宋词/ci.song.14000.json','["云雁将秋，露萤照夜，凉透窗户。", "星网珠疏，月奁金小，清绝无点暑。", "天孙河鼓，东西相望，隐隐光流华渚。", "妆楼上，青瓜玉果，多少呆儿痴女。", "金针暗度，珠丝密结，便有系人心处。", "经岁离思，霎时欢爱，愁绪空万缕。", "人间天上，一般情味，枉了锦笺嘱付。", "又何似，吹笙仙子，跨黄鹤去。"]'),
('song-ci-952','鹊桥仙','赵以夫','宋','宋词','song-ci','鹊桥仙','[]','翠绡心事，红楼欢宴，深夜沈沈无暑。',68,'宋词/ci.song.14000.json','["翠绡心事，红楼欢宴，深夜沈沈无暑。", "竹边荷外再相逢，又还是、浮云飞去。", "锦笺尚湿，珠香未歇，空惹闲愁千缕。", "寻思不似鹊桥人，犹自得、一年一度。"]'),
('song-ci-953','虞美人','赵以夫','宋','宋词','song-ci','虞美人','[]','天凉来傍荷花饮。',66,'宋词/ci.song.14000.json','["天凉来傍荷花饮。", "携手看云锦。", "城头玉漏已三更。", "耳畔微闻新雁、几声声。", "兰膏影里春山秀。", "久立还成皱。", "酒阑天外月华流。", "我醉欲眠、卿且去来休。"]'),
('song-ci-954','虞美人','赵以夫','宋','宋词','song-ci','虞美人','[]','素娥冷淡愁无奈。',66,'宋词/ci.song.14000.json','["素娥冷淡愁无奈。", "小作施朱态。", "霓裾霞佩下瑶台。", "一朵绿云围绕、送春来。", "玄霜捣尽丹砂就。", "拼醉长生酒。", "羡君幽壑狎流年。", "把住西风长对、广寒仙。"]'),
('song-ci-955','荔枝香近・荔枝香','赵以夫','宋','宋词','song-ci','荔枝香近・荔枝香','[]','翡翠丛中，万点星球小。',91,'宋词/ci.song.14000.json','["翡翠丛中，万点星球小。", "怪得鼻观香清，凉馆熏风透。", "冰盘快剥轻红，滑凝水晶皱。", "风姿，姑射仙人正年少。", "红尘一骑，曾博妃子笑。", "休比葡萄，也尽压江瑶倒。", "诗情放逸，更判琼浆和月酹。", "细度冰霜新调。"]'),
('song-ci-956','西江月','赵以夫','宋','宋词','song-ci','西江月','[]','几点垂垂北斗，一床悄悄西风。',58,'宋词/ci.song.14000.json','["几点垂垂北斗，一床悄悄西风。", "山河天地点尘空。", "月殿蟾蜍欲动。", "舌本琼浆甘彻，鼻端玉蕊香通。", "棋边切莫笑衰翁。", "个里本来空洞。"]'),
('song-ci-957','一落索','赵以夫','宋','宋词','song-ci','一落索','[]','露蕊香肌娇秀。',56,'宋词/ci.song.14000.json','["露蕊香肌娇秀。", "燕脂微透。", "蕊宫仙子驾祥鸾，被风卷、霞衣皱。", "轻翦倩他红袖。", "簪来盈首。", "直须沈醉此花前，怕花到、明朝瘦。"]'),
('song-ci-958','青玉案','赵以夫','宋','宋词','song-ci','青玉案','[]','水亭横枕荷花浦。',80,'宋词/ci.song.14000.json','["水亭横枕荷花浦。", "觉水面、香来去。", "亭上佳人云态度。", "天然娇韵，十分撋就，唱尽黄金缕。", "耳边低道清无暑。", "我欲卿卿卿且住。", "自笑风情衰几许。", "一床明月，五更残梦，不到阳台路。"]'),
('song-ci-959','小重山','赵以夫','宋','宋词','song-ci','小重山','[]','一种分香自月宫。',70,'宋词/ci.song.14000.json','["一种分香自月宫。", "人间清绝处，小山丛。", "谁将仙米掷虚空。", "丹砂碎，糁遍碧云中。", "好是窦家风。", "年年秋色里，又香浓。", "风流全在主人翁。", "青青鬓，相映脸潮红。"]'),
('song-ci-960','谒金门','赵以夫','宋','宋词','song-ci','谒金门','[]','梅共雪。',53,'宋词/ci.song.14000.json','["梅共雪。", "著个玉人三绝。", "醉倒醉乡无宝屑。", "照人些子月。", "催得花王先发。", "一曲阳春圆滑。", "疑是嵬坡留锦袜。", "至今香未歇。"]'),
('song-ci-961','醉蓬莱','赵以夫','宋','宋词','song-ci','醉蓬莱','[]','正三边月静，万国年丰，菊多梅小。',120,'宋词/ci.song.14000.json','["正三边月静，万国年丰，菊多梅小。", "吐玉擎香，蔼黄都清晓。", "龙驾徐驱，貂冠夹侍，天也和人笑。", "紫陌欢谣，如今事事，胜端平好。", "玉带垂虹，衮衣华日，秋水精神，臞仙容貌。", "长对凝旒，不羡商岩老。", "胸次乾坤，掌中霖雨，造化知多少。", "便好重将，绛人甲子，数中书考。"]'),
('song-ci-962','凤归云','赵以夫','宋','宋词','song-ci','凤归云','[]','正愁予，可堪去马便骈骈。',123,'宋词/ci.song.14000.json','["正愁予，可堪去马便骈骈。", "拟折一枝。", "堤上万垂丝。", "离思无边，离席易散，落日照清漪。", "苦是禁城催鼓，虚床难寐，梦魂无路归飞。", "陡寒还热，急雨随晴，化工无准，将息偏难，更向分携处、立多时。", "吟鬓凋霜，世味嚼蜡，病骨怯朝衣。", "我有一壶风月，荔丹芝紫，约君同话心期。"]'),
('song-ci-963','芰荷香','赵以夫','宋','宋词','song-ci','芰荷香','[]','倚晴空。',119,'宋词/ci.song.14000.json','["倚晴空。", "爱湖光潋滟，楼影青红。", "彩丝金黍，水边还又相逢。", "怀沙人问，二千年、犹带酸风。", "骚人洒墨香浓。", "幽情要眇，雅调惺松。", "天上菖蒲五色，倩掺掺素手，分入雕锺。", "新欢往恨，一时付与歌童。", "斜阳正好，且留连、休要匆匆。", "应须倒尽郫筒。", "归鞭笑指，月挂苍龙。"]'),
('song-ci-964','扬州慢','郑觉斋','宋','宋词','song-ci','扬州慢','[]','弄玉轻盈，飞琼淡泞，袜尘步下迷楼。',120,'宋词/ci.song.14000.json','["弄玉轻盈，飞琼淡泞，袜尘步下迷楼。", "试新妆才了，炷沈水香球。", "记晓剪、春冰驰送，金瓶露湿，缇骑新流。", "甚天中月色，被风吹梦南州。", "尊前相见，似羞人、踪迹萍浮。", "问弄雪飘枝，无双亭上，何日重游。", "我欲缠腰骑鹤，烟霄远、旧事悠悠。", "但凭阑无语，烟花三月春愁。"]'),
('song-ci-965','念奴娇','郑觉斋','宋','宋词','song-ci','念奴娇','[]','卷帘酒醒，怕无言、慵理残妆啼粉。',120,'宋词/ci.song.14000.json','["卷帘酒醒，怕无言、慵理残妆啼粉。", "记绾同心双绣带，珠箔青楼花满。", "琢玉传情，断金订约，总是愁根本。", "谁知薄悻，肯於长处寻短。", "旧日掌上芙蓉，新来成刺，变却风流眼。", "自信华年风度在，未怕香红春晚。", "恩不相酬，怨难重合，往事冰澌泮。", "分明诀绝，股钗还我一半。"]'),
('song-ci-966','谒金门','郑觉斋','宋','宋词','song-ci','谒金门','[]','秋夜永。',53,'宋词/ci.song.14000.json','["秋夜永。", "叶叶梧桐霜冷。", "皓月窥人深院静。", "孤鸿窗外影。", "情是相思深井。", "恩是相思修绠。", "别后信音浑不定。", "银瓶何处引。"]'),
('song-ci-967','孤鸾','张榘','宋','宋词','song-ci','孤鸾','[]','塞鸿来早。',119,'宋词/ci.song.14000.json','["塞鸿来早。", "正碧瓦霜轻，玉麟寒少。", "昨夜南枝，一点阳和先到。", "黄昏半窗淡月，照青青、谢池春草。", "此际虚斋心事，与此花俱好。", "算巡檐、索共梅花笑。", "是千古风流，少陵曾道。", "争似油幢下，对一枝春小。", "江城惯听画角，且休教、玉关人老。", "好试和羹手段，向凤池春晓。"]'),
('song-ci-968','烛影摇红','张榘','宋','宋词','song-ci','烛影摇红','[]','春小寒轻，南枝一夜阳和转。',116,'宋词/ci.song.14000.json','["春小寒轻，南枝一夜阳和转。", "东君先递玉麟香，冷蕊幽芳满。", "应把朱帘暮卷。", "更何须、金猊烟暖。", "千山月淡，万里尘清，酒樽经卷。", "楼上胡床，笑谈声里机谋远。", "甲兵百万出胸中，谁谓江流浅。", "憔悴狂胡计短。", "定相将、来朝悔晚。", "功名做了，金鼎和羹，卷藏袍雁。"]'),
('song-ci-969','摸鱼儿','张榘','宋','宋词','song-ci','摸鱼儿','[]','正挑灯、共听檐雨，问谁催动行色。',140,'宋词/ci.song.14000.json','["正挑灯、共听檐雨，问谁催动行色。", "风前千点离亭恨，惟有落梅知得。", "王谢宅。", "记前度斜阳，燕子曾相识。", "花香露舄。", "无计强追随，阳关声断，回首暮云隔。", "文章贯，合上薇垣梧掖。", "征鞍底事江北。", "青衫莫对韩彭著，还是玉麟佳客。", "须记忆。", "有衿佩锵锵，正愿依重席。", "荼䕷未折。", "次第牡丹开，一樽留待，相与醉寒食。"]'),
('song-ci-970','摸鱼儿','张榘','宋','宋词','song-ci','摸鱼儿','[]','正桃花、渐蜚红雨，依稀一半春色。',140,'宋词/ci.song.14000.json','["正桃花、渐蜚红雨，依稀一半春色。", "东风十里离亭恨，杨柳丝丝如织。", "远又忆。", "向雪月梅边，陶写吟情逸。", "清愁拍拍。", "算祗暮山知，栖鸦斜照，春树渺空碧。", "文章贯，合整垂云健翼。", "翔鸾底用栖棘。", "要寻玉洞烟霞胜，聊趁麟符蜚檄。", "归骑急。", "看尘袂方清，有恩纶催入。", "凫仙倦舄。", "相与问孤山，开樽抵掌，一舸画桥侧。"]'),
('song-ci-971','青玉案','张榘','宋','宋词','song-ci','青玉案','[]','西风乱叶溪桥树。',80,'宋词/ci.song.14000.json','["西风乱叶溪桥树。", "秋在黄花羞涩处。", "满袖尘埃推不去。", "马蹄浓露，鸡声淡月，寂历荒村路。", "身名多被儒冠误。", "十载重来漫如许。", "且尽清樽公莫舞。", "六朝旧事，一江流水，万感天涯暮。"]'),
('song-ci-972','浪淘沙','张榘','宋','宋词','song-ci','浪淘沙','[]','风色转东南。',64,'宋词/ci.song.14000.json','["风色转东南。", "翠拥层峦。", "杏花疏雨逗清寒。", "锺阜石城何处是，烟霭漫漫。", "行旆已西关。", "一霎时间。", "芳樽聊复挽馀欢。", "明日断魂分付与，万叠云山。"]'),
('song-ci-973','浪淘沙','张榘','宋','宋词','song-ci','浪淘沙','[]','雨过暮天南。',64,'宋词/ci.song.14000.json','["雨过暮天南。", "高下青峦。", "小楼燕子话春寒。", "多少夕阳芳草地，雾掩烟漫。", "别恨正相关。", "心上眉间。", "离歌一曲间悲欢。", "后夜月明何处梦，锺阜容山。"]'),
('song-ci-974','水龙吟','张榘','宋','宋词','song-ci','水龙吟','[]','暮云低锁荒台，凭阑四望天垂地。',126,'宋词/ci.song.14000.json','["暮云低锁荒台，凭阑四望天垂地。", "曼花半夜，蜚香缭绕，昔人曾记。", "往事悠悠，物华非旧，江山仍丽。", "怅斜阳芳草，长安不见，谁共洒、新亭泪。", "开放青峦旧址。", "动骚人、一番词意。", "青油幕里，相忘鱼鸟，水边云际。", "却恨清游，未能追逐，区区僚底。", "问何时，脱了尘埃墨绶，为虚斋醉。"]'),
('song-ci-975','西江月','张榘','宋','宋词','song-ci','西江月','[]','春事三分之二，落花庭院轻寒。',58,'宋词/ci.song.14000.json','["春事三分之二，落花庭院轻寒。", "翠屏围梦宝熏残。", "窗外流莺声乱。", "睡起犹支雪腕，觉来慵整云鬟。", "闲拈乐府凭阑干。", "宿酒才醒一半。"]'),
('song-ci-976','孤鸾','张榘','宋','宋词','song-ci','孤鸾','[]','荆溪清晓。',118,'宋词/ci.song.14000.json','["荆溪清晓。", "问昨夜南枝，几分春到。", "一点幽芳，不待陇头音耗。", "亭亭水边月下，胜人间、等闲花草。", "此际风流谁似，有孄窝诗老。", "向虚檐、淡然索笑。", "任雪压霜欺，精神越好。", "最喜庭除，下映紫兰娇小。", "孤山好寻旧约，况和羹、用功宜早。", "移傍玉阶深处，趁天香缭绕。"]'),
('song-ci-977','水龙吟','张榘','宋','宋词','song-ci','水龙吟','[]','暮天丝雨轻寒，二分春色看看过。',126,'宋词/ci.song.14000.json','["暮天丝雨轻寒，二分春色看看过。", "梅花谢了，苍苔万点，香残粉污。", "犹喜墙头，一枝娇袅，杏腮微露。", "算几回逗晓，朱阑独倚，悄只怕、东风大。", "浮世名缰利锁。", "这区区、要须识破。", "沧波夜月，翠微云树，依然还我。", "重结鸥盟，细听莺语，自歌自和。", "问黄沙飞镞，红尘走马，又还知麽。"]'),
('song-ci-978','水龙吟','张榘','宋','宋词','song-ci','水龙吟','[]','昼长帘幕低垂，时时风度杨花过。',126,'宋词/ci.song.14000.json','["昼长帘幕低垂，时时风度杨花过。", "梁间燕子，芹随香觜，频沾泥污。", "苦被流莺，蹴翻花影，一阑红露。", "看残梅飞尽，枝头微认，青青子、些儿大。", "谁道洞门无锁。", "翠苔藓、何曾踏破。", "好天良夜，清风明月，正须著我。", "闲展蛮笺，寄情词调，唱成谁和。", "问晓山亭下，山茶经雨，早来开麽。"]'),
('song-ci-979','水龙吟','张榘','宋','宋词','song-ci','水龙吟','["\u897f\u6e56"]','先来花较开迟，怎禁风雪摧残过。',126,'宋词/ci.song.14000.json','["先来花较开迟，怎禁风雪摧残过。", "红英紫萼，从他点缀，翻成沾污。", "一点清香，几多秾艳，紧藏不露。", "伴杨花散漫，逡巡堆积，纤粟处、妆成大。", "多谢东君造化。", "把群阴、一朝除破。", "千机锦绣，露浓香软，中间坐我。", "嚼徵含商，振金敲玉，埙篪相和。", "问西湖，别有一番桃李，肯同游麽。"]'),
('song-ci-980','水龙吟','张榘','宋','宋词','song-ci','水龙吟','[]','近家添得园亭，晓山时看飞云过。',126,'宋词/ci.song.14000.json','["近家添得园亭，晓山时看飞云过。", "拥石栽梅，疏池傍竹，剪除芜污。", "更喜南墙，杏腮桃脸，含羞微露。", "算莺花世界，都来十亩，规模好、何须大。", "开放两眉上锁。", "把春前、新醅拨破。", "病酒无聊，且容觞客，无多酌我。", "底用歌喉，柳边自有，鸣禽相和。", "逗归来，折得花枝教看，似人人麽。"]'),
('song-ci-981','念奴娇','张榘','宋','宋词','song-ci','念奴娇','[]','楚湘旧俗，记包黍沈流，缅怀忠节。',120,'宋词/ci.song.14000.json','["楚湘旧俗，记包黍沈流，缅怀忠节。", "谁挽汨罗千丈雪，一洗些魂离别。", "赢得儿童，红丝缠臂，佳话年年说。", "龙舟争渡，搴旗捶鼓骄劣。", "谁念词客风流，菖蒲桃柳，忆闺门铺设。", "嚼徵含商陶雅兴，争似年时娱悦。", "青杏园林，一樽煮酒，当为浇凄切。", "南薰应解，把君愁袂吹裂。"]'),
('song-ci-982','念奴娇','张榘','宋','宋词','song-ci','念奴娇','[]','三闾何在，把离骚细读，几番击节。',120,'宋词/ci.song.14000.json','["三闾何在，把离骚细读，几番击节。", "蓠蕙椒兰纷江渚，较以艾萧终别。", "清浊同流，醉醒一梦，此恨谁能说。", "忠魂耿耿，只凭天辨优劣。", "须信千古湘流，彩丝缠黍，端为英雄设。", "堪笑儿童浮昌歜，悲愤翻为嬉悦。", "三叹灵均，竟罹谗网，我独中情切。", "薰风窗户，榴花知为谁裂。"]'),
('song-ci-983','虞美人','张榘','宋','宋词','song-ci','虞美人','["\u897f\u6e56"]','金炉鈒就裙纹折。',66,'宋词/ci.song.14000.json','["金炉鈒就裙纹折。", "香烬低云月。", "玉钿黏唾上眉心。", "不似寿阳檐下、六花清。", "翠禽飞起南枝动。", "惊破西湖梦。", "仗谁为作水龙声。", "吹绽寒葩诗眼、为君青。"]'),
('song-ci-984','虞美人','张榘','宋','宋词','song-ci','虞美人','[]','小蛮才把鸳衾折。',66,'宋词/ci.song.14000.json','["小蛮才把鸳衾折。", "妆就梳横月。", "探梅不似旧年心。", "却爱窗前纸帐、十分清。", "朔风吹起寒云动。", "午寝都无梦。", "黄昏更被竹枝声。", "唤起醒醒相对、一灯青。"]'),
('song-ci-985','虞美人','张榘','宋','宋词','song-ci','虞美人','[]','龙香浅渍罗屏褶。',66,'宋词/ci.song.14000.json','["龙香浅渍罗屏褶。", "睡思低眉月。", "闲愁闲闷不关心。", "心似窗前梅影、一般清。", "绣帏交掩流苏动。", "一觉华胥梦。", "枕山轻戛宝钗声。", "粉褪香腮零乱、鬓鸦青。"]'),
('song-ci-986','沁园春','张榘','宋','宋词','song-ci','沁园春','["\u94b1\u5858\u6c5f"]','静寿先生，笑傲四并，醉眠孄窝。',140,'宋词/ci.song.14000.json','["静寿先生，笑傲四并，醉眠孄窝。", "甚一枰棋壤，掉头不顾，同舟风紧，袖手高歌。", "太白词华，更生忠愤，为问山林老得麽。", "须知道，有淮碑未作，浯石当磨。", "年来君子无多。", "试屈指、如公能几何。", "况刍荛公论，新曾推许，冕旒异眷，行见搜罗。", "泽润生民，洗清兵甲，待挽钱塘江上波。", "功名就，访蟠桃把玩，铜狄摩挲。"]'),
('song-ci-987','凯歌','张榘','宋','宋词','song-ci','凯歌','["\u6d1e\u5ead\u6e56"]','双阁护仙境，万壑渺清秋。',114,'宋词/ci.song.14000.json','["双阁护仙境，万壑渺清秋。", "台躔光动银汉，神秀孕公侯。", "胸次千崖灏气，笔底三江流水，姓字桂香浮。", "十载洞庭月，今喜照扬州。", "捧丹诏，升紫殿，建碧油。", "胡儿深避沙漠，铃阁颺轻裘。", "点检召棠遗爱，酝酿潘舆喜色，英裔蔚文彪。", "整顿乾坤定，千岁侍宸旒。"]'),
('song-ci-988','飞雪满堆山・飞雪满群山','张榘','宋','宋词','song-ci','飞雪满堆山・飞雪满群山','[]','爱日烘晴，梅梢春动，晓窗客梦方还。',130,'宋词/ci.song.14000.json','["爱日烘晴，梅梢春动，晓窗客梦方还。", "江天万里，高低烟树，四望犹拥螺鬟。", "是谁邀滕六，酿薄暮、同云冱寒。", "却元来是，铃阁露熏，俄忽老青山。", "都尽道、年来须更好，无缘农事，雨涩风悭。", "鹅池夜半，衔枚飞渡，看樽俎折冲间。", "尽青油谈笑，琼花露、杯深量宽。", "功名做了，云台写作画图看。"]'),
('song-ci-989','绛都春','张榘','宋','宋词','song-ci','绛都春','[]','平山老柳。',118,'宋词/ci.song.14000.json','["平山老柳。", "寄多少胜游，春愁诗瘦。", "万叠翠屏，一抹江烟浑如旧。", "晴空栏槛今何有。", "寂寞文章身后。", "唤回奇事，青油上客，放怀樽酒。", "知不。", "全淮万里，羽书静，草绿长亭津堠。", "小队出郊，花底赓酬闲时候。", "和薰筹幕垂春昼。", "坐看蓉池波皱。", "主宾同会风云，盛名可久。"]'),
('song-ci-990','朝中措','张榘','宋','宋词','song-ci','朝中措','[]','谁云万事转头空。',57,'宋词/ci.song.14000.json','["谁云万事转头空。", "春寓不言中。", "底问垂杨在否，年年一度东风。", "凭高慨古，英雄亦泪，我辈情锺。", "事业正须老手，清吟留与山翁。"]'),
('song-ci-991','千秋岁','张榘','宋','宋词','song-ci','千秋岁','[]','鹤城秋晓。',87,'宋词/ci.song.14000.json','["鹤城秋晓。", "又庆生朝到。", "人与月，年年好。", "黑头公相贵，膝下欢娱笑。", "君知否。", "个般福分人间少。", "塞上西风老。", "红入霜前枣。", "日日有，平安报。", "慈颜酡晕浅，一呷金杯小。", "香缭绕。", "寿星明处台星照。"]'),
('song-ci-992','青玉案','张榘','宋','宋词','song-ci','青玉案','[]','严城寂寞山缭绕。',82,'宋词/ci.song.14000.json','["严城寂寞山缭绕。", "觉寒透、貂裘峭。", "云压江天风破晓。", "飞琼万顷，看来浑似，泽国芦花老。", "玉山不怕频频倒。", "要笔阵、纵横快挥扫。", "见说今年梅较早。", "笑将名胜，千锺万字，谁似邦侯好。"]'),
('song-ci-993','青玉案','张榘','宋','宋词','song-ci','青玉案','[]','少时贪看琼林绕。',82,'宋词/ci.song.14000.json','["少时贪看琼林绕。", "任马上、寒威峭。", "昨暮六花飞逗晓。", "拥衾慵起，鬓丝笼帽，顿觉年来老。", "朱阑翠竹枝枝倒。", "把玉甃、棱层趁风扫。", "楼上一樽须放早。", "同云收尽，红轮初上，对面狼峰好。"]'),
('song-ci-994','青玉案','张榘','宋','宋词','song-ci','青玉案','[]','龙香熏被罗屏绕。',82,'宋词/ci.song.14000.json','["龙香熏被罗屏绕。", "任窗外、风儿峭。", "鸳枕梦回鸡唱晓。", "丫鬟惊笑，琼枝低亚，错认梅花老。", "红炉兽炭装还倒。", "强梳洗、忙将黛眉扫。", "贪趁清欢争怕早。", "弓靴微湿，玉纤频袖，塑出狮儿好。"]'),
('song-ci-995','沁园春','张榘','宋','宋词','song-ci','沁园春','[]','思昔买臣，怀绶会稽，年犹五旬。',140,'宋词/ci.song.14000.json','["思昔买臣，怀绶会稽，年犹五旬。", "算初无功用，维持国事，但将富贵，夸耀时人。", "未若先生，方当强仕，掌握长淮百万军。", "难摹写，是擎天拄地，纬武经文。", "河滨。", "胡马嘶春。", "便密运机筹出万全。", "拥熊旗指授，鹰扬や啖，毡裘胆落，鼠逸狐奔。", "褒诏飞来，威名加盛，从此不须关玉门。", "归朝也，看云台画像，金鼎调元。"]'),
('song-ci-996','金缕曲・贺新郎','张榘','宋','宋词','song-ci','金缕曲・贺新郎','[]','枌社新相识。',142,'宋词/ci.song.14000.json','["枌社新相识。", "恍瞻君、丰神气貌，飘然仙白。", "笔底三江鲸浪注，胸次一瓯冰雪。", "怎不做、龙门上客。", "坎止流行元无定，敢一朝、挨却尘泥迹。", "且剩把，锦云织。", "试看自古贤侯伯。", "一时间、失虽暂失，得还终得。", "儋石空无君家事，百万付之一掷。", "渐养就、抟风鹏翼。", "任你祖鞭先著了，占鸥天、浩荡观浮没。", "挈富贵，等儿剧。"]'),
('song-ci-997','贺新凉・贺新郎','张榘','宋','宋词','song-ci','贺新凉・贺新郎','[]','襟度天为侣。',142,'宋词/ci.song.14000.json','["襟度天为侣。", "价平生、放浪江湖，浮云行住。", "倒挽峡流归笔底，衮衮二并四具。", "何尚友、沧波鸥鹭。", "藻黻皇猷君能事，况贤书、两度登天府。", "急著手，佐明主。", "晴风一舸来瓜步。", "剪灯花、樽酒论诗，顿忘羁旅。", "逗晓蛮笺传金缕，一片瑰词绮语。", "甚独茧、抽成长绪。", "当代壑翁文章伯，定不教、弹铗轻辞去。", "留共济，孤舟渡。"]'),
('song-ci-998','醉落魄・一斛珠','张榘','宋','宋词','song-ci','醉落魄・一斛珠','[]','瑶姬妙格。',67,'宋词/ci.song.14000.json','["瑶姬妙格。", "冰姿微带霜痕拆。", "一般恼杀多情客。", "风弄横枝，残月半窗白。", "孤山仙种曾移得。", "结根久傍王猷宅。", "欲笺心事呼云翮。", "为报年芳，萍梗正南北。"]'),
('song-ci-999','摸鱼儿','张榘','宋','宋词','song-ci','摸鱼儿','[]','猛思量、孄窝初度，鲁云呈瑞时节。',140,'宋词/ci.song.14000.json','["猛思量、孄窝初度，鲁云呈瑞时节。", "平山杨柳苍茫外，犹是乡关明月。", "春漏泄。", "定知有、梅花先向江南发。", "烟波梦阔。", "谩约住西风，呼将塞雁，把酒为君说。", "君看取，世道羊肠屈摺。", "依然熟路轻辙。", "林泉暂洗经纶手，桐柏夜香熏彻。", "趋魏阙。", "指天上星辰，平步仪清切。", "蟠桃未结。", "待做著功名，却寻曼倩，相与带花折。"]'),
('song-ci-0','瑞鹤仙','张榘','宋','宋词','song-ci','瑞鹤仙','[]','碧油推上客。',127,'宋词/ci.song.15000.json','["碧油推上客。", "有神机沈密，参运帷幄。", "威声际沙漠。", "庆云飞川泳，和熏三白。", "霄渊敻鬲。", "甚探梅、也来相约。", "更谁怜久客，泥深穿履，栖栖东郭。", "农麦。", "年来管好，禾黍离离，讵忘关洛。", "风高水涸。", "多少事、待韬略。", "看鹅池夜渡，黎明飞捷，儿辈愔愔未觉。", "便冲寒，铁骑横驱，汛扫六合。"]'),
('song-ci-1','沁园春','张榘','宋','宋词','song-ci','沁园春','[]','绿野归来，筇杖角巾，岂不快哉。',141,'宋词/ci.song.15000.json','["绿野归来，筇杖角巾，岂不快哉。", "有清泉白石，东西岩岫，翠阴红影，高下楼台。", "况是蕤宾，槐庭暑薄，照眼葵榴次第开。", "轻熏里，翦香蒲为寿，一笑传杯。", "栽培。", "多少英材。", "更霖雨、看看遍九垓。", "算支撑厦屋，正资梁栋，调和钧鼎，须用盐梅。", "旒冕兴思，搢绅顒望，应有天边丹诏催。", "依还是，为苍生一起，重位元台。"]'),
('song-ci-2','木兰花慢','张榘','宋','宋词','song-ci','木兰花慢','[]','豆花轻雨霁，更七日、是中秋。',122,'宋词/ci.song.15000.json','["豆花轻雨霁，更七日、是中秋。", "记分野三台，家山双阙，孕秀名流。", "平生佐时大略，有忠勤、一念等伊周。", "十载清风楚泽，三年明月扬州。", "须知万灶出貔貅。", "智勇迈前猷。", "自向来擣颖，□番平海，胆落毡裘。", "红旗指关定洛，看春融、喜色动宸旒。", "著取斑衣绣衮，揭开玉字金瓯。"]'),
('song-ci-3','好事近','张榘','宋','宋词','song-ci','好事近','[]','素壁走龙蛇，难觅醉翁真迹。',53,'宋词/ci.song.15000.json','["素壁走龙蛇，难觅醉翁真迹。", "惟有断岗衰草，是几番经历。", "紫萸黄菊又西风，同作携壶客。", "清兴未阑归去，负晴空明月。"]'),
('song-ci-4','摸鱼儿','张榘','宋','宋词','song-ci','摸鱼儿','[]','望神京、目断烟草，青天长剑频倚。',141,'宋词/ci.song.15000.json','["望神京、目断烟草，青天长剑频倚。", "香街十里朱帘月，空想当年华丽。", "堪叹处。", "渺沙霭蒹葭，咿ン雁声起。", "平山谩记。", "怅杨柳春风，晴空栏槛，陈迹总非是。", "重阳好，红叶黄华满地。", "良辰美景如此。", "青油幕府传芳斝，苒苒露琼花气。", "还更喜。", "看玉阃规恢，笑骋伊吾志。", "尘清北冀。", "便向关洛联镳，巍巍冠佩，麟阁画图里。"]'),
('song-ci-5','唐多令','张榘','宋','宋词','song-ci','唐多令','[]','斜日淡芜烟。',74,'宋词/ci.song.15000.json','["斜日淡芜烟。", "重阳又一年。", "怅垂杨、几度飞绵。", "只把晴空山色看。", "多少恨、倩谁笺。", "沙霭暗中原。", "横戈谁夜眠。", "尽今宵、且醉花边。", "准拟来秋天气好，重把菊、嗅芳妍。"]'),
('song-ci-6','贺新凉・贺新郎','张榘','宋','宋词','song-ci','贺新凉・贺新郎','[]','萸菊香凝雾。',142,'宋词/ci.song.15000.json','["萸菊香凝雾。", "记重阳、才经三日，帨悬朱户。", "紫殿玉垣称寿斝，潋滟琼花清露。", "正万里、尘清淮浦。", "地宝从来标瑞应，甚新曾、秀出金芝树。", "正此处，诞申甫。", "人间小住千秋岁。", "画堂深、彩侍怡声，慈颜笑语。", "况是加恩封大国，锦诰鸾翔凤舞。", "便娱侍、鱼轩沙路。", "御果金泥宣晓宴，卷宫帘、争看元台母。", "家庆事，耀今古。"]'),
('song-ci-7','贺新凉・贺新郎','张榘','宋','宋词','song-ci','贺新凉・贺新郎','[]','匹马锺山路。',140,'宋词/ci.song.15000.json','["匹马锺山路。", "怅年来只解，邮亭送人归去。", "季子貂裘尘渐满，犹是区区羁旅。", "谩空有、剑锋如故。", "髀肉未消仪舌在，向樽前、莫洒英雄泪。", "鞭未动，酒频举。", "西风乱叶长安树。", "叹离离、荒宫废苑，几番禾黍。", "云栈萦纡今平步，休说襄淮乐土。", "但衮衮江涛东注。", "世上岂无高卧者，奈草庐、烟销无人顾。", "笺此恨，付金缕。"]'),
('song-ci-8','满江红','张榘','宋','宋词','song-ci','满江红','[]','淮海波澄，湛桂影、半规凉月。',115,'宋词/ci.song.15000.json','["淮海波澄，湛桂影、半规凉月。", "又还是、中秋相近，垂弧时节。", "纶诰飞来宸眷重，彩衣著处慈颜悦。", "注紫清、花露入瑶卮，琼香滑。", "挥羽扇，持旄钺。", "鲸海浪，阴山雪。", "看威声到处，遐冲都折。", "沙溪远标铜柱界，关河尽补金瓯缺。", "庆君臣、千载会风云，看伊说。"]'),
('song-ci-9','浪淘沙','张榘','宋','宋词','song-ci','浪淘沙','[]','春梦草茸茸。',64,'宋词/ci.song.15000.json','["春梦草茸茸。", "愁雨愁风。", "对花须拚酒频中。", "莫遣枝头银烛暗，辜负嫣红。", "推起簿书丛。", "何苦匆匆。", "悭吟却讶少陵公。", "天定为花开一笑，日上篱东。"]'),
('song-ci-10','浪淘沙','张榘','宋','宋词','song-ci','浪淘沙','[]','烟缕暗蒙茸。',64,'宋词/ci.song.15000.json','["烟缕暗蒙茸。", "杨柳轻风。", "雨声多在夜窗中。", "春水渐生春事去，流尽残红。", "新笋绿丛丛。", "莺语匆匆。", "一樽同酹定林公。", "十里长松青未了，山北山东。"]'),
('song-ci-11','摸鱼儿','张榘','宋','宋词','song-ci','摸鱼儿','[]','正莓墙、柳绵低度，枝头红紫飞尽。',140,'宋词/ci.song.15000.json','["正莓墙、柳绵低度，枝头红紫飞尽。", "秾阴涨绿冰钿碎，浥浥麝兰成阵。", "仙骨嫩。", "悦姑射瑶姬，青幰游琼苑。", "风前有恨。", "也一似宫梅，飘香坠粉，轻点寿阳鬓。", "梨花雪，讲道全无清韵。", "何曾流到春晚。", "柔条不受真珠露，滴沥紫檀心晕。", "芳又润。", "待挼放金樽，拚作通宵饮。", "日高慵困。", "任翠幄低云，玉薰泛梦，路入醉乡稳。"]'),
('song-ci-12','木兰花慢','张榘','宋','宋词','song-ci','木兰花慢','[]','渐稠红飞尽，早秾绿、遍林梢。',123,'宋词/ci.song.15000.json','["渐稠红飞尽，早秾绿、遍林梢。", "正池馆轻寒，杨花飘絮，草色萦袍。", "天香夜浮院宇，看亭亭、雨槛渍春膏。", "趁取芳时胜赏，莫将年少轻抛。", "鞭鞘。", "驱放马啼高。", "世事一秋毫。", "便飞书倥偬，运筹闲暇，何害推敲。", "花前效颦著句，悄干镆、侧畔奏铅刀。", "何日重携樽酒，浮瓯细剪香苞。"]'),
('song-ci-13','祝英台近','张榘','宋','宋词','song-ci','祝英台近','[]','柳绵稀，桃锦淡，春事在何许。',95,'宋词/ci.song.15000.json','["柳绵稀，桃锦淡，春事在何许。", "一种秾华，天香渍冰露。", "嫩苞叠叠湘罗，红娇紫妒。", "翠葆护、西真仙侣。", "试听取。", "更饶十日看承，霞腴污尘土。", "池馆轻寒，次第少风雨。", "好趁油幕清闲，重开芳醑。", "莫孤负、莺歌蝶舞。"]'),
('song-ci-14','满江红','张榘','宋','宋词','song-ci','满江红','[]','玉垒澄秋，又还近、桂华如璧。',115,'宋词/ci.song.15000.json','["玉垒澄秋，又还近、桂华如璧。", "算六载、筹边整暇，几多功绩。", "铁壁连云东海重，惊波截断狂鲵翼。", "把向来、捣颍旧规模，平淮北。", "经济妙，谁知得。", "都总是，诗书力。", "有召公家法，范公胸臆。", "赫赫勋名俱向上，绵绵福寿宜无极。", "著莱衣、辉映衮衣荣，恢霖泽。"]'),
('song-ci-15','鹧鸪天','张榘','宋','宋词','song-ci','鹧鸪天','[]','饱挹台城白露秋。',64,'宋词/ci.song.15000.json','["饱挹台城白露秋。", "又骑黄鹄上江州。", "恩波浩荡三千里，多少人家愿借留。", "□寿斝，菊香浮。", "姓名还喜到宸旒。", "片□□□□□□，□振□□□下流。"]'),
('song-ci-16','安庆摸・摸鱼儿','张榘','宋','宋词','song-ci','安庆摸・摸鱼儿','["\u957f\u6c5f"]','渺长江、浩无今古，悠悠经几流景。',140,'宋词/ci.song.15000.json','["渺长江、浩无今古，悠悠经几流景。", "桥家松竹知何在，寂历丹枫如锦。", "行阵整。", "想斗舰连艘，谈笑烟灰冷。", "寒光万顷。", "算只有当年，暮天霜月，惨澹照山影。", "元戎队，画角梅花缓引。", "楼船飞渡波稳。", "中流击楫酬初志，此去君王高枕。", "应暗省。", "使万里尘清，谁逊周公瑾。", "勋名不泯。", "看阳蛰潜开，老龙挟雨，渊睡为民醒。"]'),
('song-ci-17','水调歌头','刘克逊','宋','宋词','song-ci','水调歌头','[]','解变西崑体，一赋冠群英。',114,'宋词/ci.song.15000.json','["解变西崑体，一赋冠群英。", "清风峡畔，至今堂已读书名。", "富贵轻於尘土，孝义高於山岳，惜不大其成。", "陵谷纵迁改，草木亦光荣。", "与仇香，穿阮屐，试同登。", "石龛虽窄，可容一几短檠灯。", "千仞苍崖如削，四面翠屏不断，云雾镇长生。", "最爱岩前水，犹作诵弦声。"]'),
('song-ci-18','金缕歌・贺新郎','王广文','宋','宋词','song-ci','金缕歌・贺新郎','[]','辜负东风约。',142,'宋词/ci.song.15000.json','["辜负东风约。", "忆曾将、淮南草木，笔端笼络。", "后土祠中明月夜，忽有瑶姬跨鹤。", "迥不比、水仙低弱。", "天上人间惟一本，倒千锺、琼露花前酌。", "追往事，怎忘却。", "移根应费仙家药。", "漫回头、关山信断，堡城笳作。", "问讯而今平安否，莫遣玉箫惊落。", "但画卷、依稀描著。", "白发愧无渡江曲，与吾家、子敬相酬酢。", "新旧恨，两交错。"]'),
('song-ci-19','点绛唇','宋自道','宋','宋词','song-ci','点绛唇','[]','山雨初晴，馀寒犹在东风软。',50,'宋词/ci.song.15000.json','["山雨初晴，馀寒犹在东风软。", "满庭苔藓。", "青子无人见。", "好客不来，门外芳菲遍。", "难消遣。", "流莺声啭。", "坐看芭蕉展。"]'),
('song-ci-20','蓦山溪','宋自逊','宋','宋词','song-ci','蓦山溪','[]','壶山居士，未老心先懒。',102,'宋词/ci.song.15000.json','["壶山居士，未老心先懒。", "爱学道人家，办竹几、蒲团茗碗。", "青山可买，小结屋三间，开一径，俯清溪，修竹栽教满。", "客来便请，随分家常饭。", "若肯小留连，更薄酒、三杯两盏。", "吟诗度曲，风月任招呼，身外事，不关心，自有天公管。"]'),
('song-ci-21','沁园春','宋自逊','宋','宋词','song-ci','沁园春','[]','归去来兮，田园将芜，云胡不归。',140,'宋词/ci.song.15000.json','["归去来兮，田园将芜，云胡不归。", "既有诗千首，如斯者少，行年七十，从古来稀。", "地阙东南，天倾西北，人事何缘有足时。", "江湖上，转不如前日，步步危机。", "石屏自有柴扉。", "占海岸、潮头岸一矶。", "唤彩衣孙子，携壶挈榼，白头翁媪，举桉齐眉。", "身外声名，世间梦幻，万事一酲无是非。", "书来往，都不须长语，直写心期。"]'),
('song-ci-22','贺新郎','宋自逊','宋','宋词','song-ci','贺新郎','[]','唤起东坡老。',142,'宋词/ci.song.15000.json','["唤起东坡老。", "问雪堂、几番兴废，斜阳衰草。", "一月有钱三十块，何苦抽身不早。", "又底用、北门摛藻。", "儋雨蛮烟添老色，和陶诗、翻被渊明恼。", "到底是，忘言好。", "周郎英发人间少。", "谩依然、乌鹊南飞，山高月小。", "岁月堂堂留不住，此世何时是了。", "算不满、英雄一笑。", "我有丰淮千斗酒，把新愁、旧恨都倾倒。", "三弄笛，楚天晓。"]'),
('song-ci-23','贺新郎','宋自逊','宋','宋词','song-ci','贺新郎','[]','灵鹊桥初就。',142,'宋词/ci.song.15000.json','["灵鹊桥初就。", "记迢迢、重湖风浪，去年时候。", "岁月不留人易老，万事茫茫宇宙。", "但独对、西风搔首。", "巧拙岂关今夕事，奈痴儿、呆女流传谬。", "添话柄，柳州柳。", "道人识破灰心久。", "只好风、凉月佳时，疏狂如旧。", "休笑双星经岁别，人到中年已后。", "云雨梦、可曾常有。", "雪藕调冰花熏茗，正梧桐、雨过新凉透。", "且随分，一杯酒。"]'),
('song-ci-24','满江红','宋自逊','宋','宋词','song-ci','满江红','[]','举扇西风，又十载、重游秋浦。',115,'宋词/ci.song.15000.json','["举扇西风，又十载、重游秋浦。", "对旧日、江山错愕，鬓丝如许。", "世事兴亡空感慨，男儿事业谁堪数。", "被老天、开眼看人忙，成今古。", "江上路，喧鼙鼓。", "山中地，纷豺虎。", "谩乾坤许大，著身何处。", "名利等成狂梦寐，文章亦是闲言语。", "赖双投、酒熟蟹螯肥，忘羁旅。"]'),
('song-ci-25','西江月','宋自逊','宋','宋词','song-ci','西江月','[]','何敢笑人干禄，自知无分弹冠。',58,'宋词/ci.song.15000.json','["何敢笑人干禄，自知无分弹冠。", "只将贫贱博清闲。", "留取书遮老眼。", "世上风波任险，门前路径须宽。", "心无妄想梦魂安。", "万事鹤长凫短。"]'),
('song-ci-26','昼锦堂','宋自逊','宋','宋词','song-ci','昼锦堂','[]','荷叶龟游，庭皋鹤舞，应是秋满淮涯。',122,'宋词/ci.song.15000.json','["荷叶龟游，庭皋鹤舞，应是秋满淮涯。", "昨夜将星明处，彷佛峨眉。", "干戈已净银河淡，尘沙不动翠烟微。", "邦人道，半月中秋，当歌不饮何为。", "谁知心事远，但感慨登临，白羽频挥。", "恨不明朝出塞，猎猎旌旗。", "文南一失澶渊劲，夔门三箭武关奇。", "挑灯看，龙吼传家旧剑，曾斩吴曦。"]'),
('song-ci-27','昼锦堂','黄载','宋','宋词','song-ci','昼锦堂','[]','丽景融晴，浮光起昼，玉妃信意寻春。',122,'宋词/ci.song.15000.json','["丽景融晴，浮光起昼，玉妃信意寻春。", "一笑酒杯翻手，满地祥云。", "宝台艳蹙文绡帕，郎官娇舞郁金裙。", "嫣然处，况是生香微湿，腻脸馀醺。", "暖烘肌欲透，愁日炙还销，风动成尘。", "细为品归雪调，度与朱唇。", "翠帏晚映真图画，金莲夜照越精神。", "须拚醉，回首夕阳流水，碧草如茵。"]'),
('song-ci-28','隔浦莲・隔浦莲近拍','黄载','宋','宋词','song-ci','隔浦莲・隔浦莲近拍','[]','瑶妃香透袜冷。',88,'宋词/ci.song.15000.json','["瑶妃香透袜冷。", "伫立青铜镜。", "玉骨清无汗，亭亭碧波千顷。", "云水摇扇影。", "炎天永。", "一国清凉境。", "晚妆靓。", "微酣不语，风流幽恨谁省。", "沙鸥少事，看到睡鸳双醒。", "兰棹歌遥隔浦应。", "催暝。", "藕丝萦断归艇。"]'),
('song-ci-29','洞仙歌','黄载','宋','宋词','song-ci','洞仙歌','[]','吴宫故墅，是天开图画。',105,'宋词/ci.song.15000.json','["吴宫故墅，是天开图画。", "缥缈层云出飞榭。", "隐隐楼空翠巘，水绕芜城，平畴迥，点染霜林凋谢。", "越来溪上雁，声切阑干，似觅胥门怨吴霸。", "属镂沈，香溪断，梦散云空，千年外、等是渔樵闲话。", "但极目荒台郁苍烟，衰草里、又还夕阳西下。"]'),
('song-ci-30','孤鸾','黄载','宋','宋词','song-ci','孤鸾','[]','冰心孤寂。',118,'宋词/ci.song.15000.json','["冰心孤寂。", "恋几插灵峰，半泓寒碧。", "骨瘦和衣薄，清绝成愁极。", "萧然满身是雪，怕人知、镜中消息。", "独向百花梦外，自一家春色。", "记罗浮幽梦浑如昔。", "是浸眼鲸波，倚云丹壁。", "夜醉空山酒，叫裂横霜笛。", "回头洞天未晓，但迢迢、江南千驿。", "饮散东风落月，正海山浮碧。"]'),
('song-ci-31','东风第一枝','黄载','宋','宋词','song-ci','东风第一枝','[]','迅影凋年，嫩晴贳暖，意行问讯春色。',122,'宋词/ci.song.15000.json','["迅影凋年，嫩晴贳暖，意行问讯春色。", "不知春在谁家，闯香幔拢玉勒。", "一枝竹外，似欲诉、经年相忆。", "奈情多、难剪愁来，寂寞水寒烟碧。", "吟正好、悲笳唤恨，酒正殢、夕阳催客。", "殷勤片月飞来，更随暗香细索。", "横斜瘦影，看尽未开时消息。", "为春来，还怕春多，肠断夜阑霜笛。"]'),
('song-ci-32','谒金门','王平子','宋','宋词','song-ci','谒金门','[]','书一纸。',53,'宋词/ci.song.15000.json','["书一纸。", "小砑吴笺香细。", "读到别来心下事。", "蹙残眉上翠。", "怕落傍人眼底。", "握向抹胸儿里。", "针线不忺收拾起。", "和衣和闷睡。"]'),
('song-ci-33','喜迁莺','俞文豹','宋','宋词','song-ci','喜迁莺','[]','小梅幽绝。',125,'宋词/ci.song.15000.json','["小梅幽绝。", "向冰谷深深，云阴幂幂。", "饱阅年华，惯谙冷淡，只恁清臞风骨。", "任他万红千紫，句引狂蜂游蝶。", "惟只共、竹和松，同傲岁寒霜雪。", "喜得。", "化工力。", "移根上苑，向阳和培植。", "题名还经，孤山处士，许共高人攀折。", "一枝垂欲放，只等春风披拂。", "待叶底、结青青，恰是和羹时节。"]'),
('song-ci-34','满江红','赵希迈','宋','宋词','song-ci','满江红','[]','三十年前，爱买剑、买书买画。',115,'宋词/ci.song.15000.json','["三十年前，爱买剑、买书买画。", "凡几度、诗坛争敌，酒兵取霸。", "春色秋光如可买，钱悭也不曾论价。", "任粗豪、争肯放头低，诸公下。", "今老大，空嗟讶。", "思往事，还惊诧。", "是和非未说，此心先怕。", "万事全将飞雪看，一闲且问苍天借。", "乐馀龄、泉石在膏肓，吾非诈。"]'),
('song-ci-35','八声甘州','赵希迈','宋','宋词','song-ci','八声甘州','[]','寒云飞万里，一番秋、一番搅离怀。',119,'宋词/ci.song.15000.json','["寒云飞万里，一番秋、一番搅离怀。", "向隋堤跃马，前时柳色，今度蒿莱。", "锦缆残香在否，枉被白鸥猜。", "千古扬州梦，一觉庭槐。", "歌吹竹西难问，拚菊边醉著，吟寄天涯。", "任红楼踪迹，茅屋染苍苔。", "几伤心、桥东片月，趁夜潮、流恨入秦淮。", "潮回处，引西风恨，又渡江来。"]'),
('song-ci-36','念奴娇','吴渊','宋','宋词','song-ci','念奴娇','[]','我来牛渚，聊登眺、客里襟怀如豁。',120,'宋词/ci.song.15000.json','["我来牛渚，聊登眺、客里襟怀如豁。", "谁著危亭当此处，占断古今愁绝。", "江势鲸奔，山形虎踞，天险非人设。", "向来舟舰，曾扫百万胡羯。", "追念照水然犀，男儿当似此，英雄豪杰。", "岁月匆匆留不住，鬓已星星堪镊。", "云暗江天，烟昏淮地，是断魂时节。", "栏干捶碎，酒狂忠愤俱发。"]'),
('song-ci-37','水调歌头','吴渊','宋','宋词','song-ci','水调歌头','[]','太白已仙去，诗骨此山藏。',114,'宋词/ci.song.15000.json','["太白已仙去，诗骨此山藏。", "胸中锦绣如屋，都乞与东皇。", "碎翦杏花千树，浓抹胭脂万点，妖艳断人肠。", "晓露沐春色，晴日涨风光。", "孤村路，逢休暇，共徜徉。", "酒旗斜处，□□一簇几红妆。", "暂息江头烽火，无奈鬓边霜雪，聊复放疏狂。", "倚俟玉壶竭，未肯宝鞭扬。"]'),
('song-ci-38','沁园春','吴渊','宋','宋词','song-ci','沁园春','[]','喜我新归，逢戎初度，关情更深。',139,'宋词/ci.song.15000.json','["喜我新归，逢戎初度，关情更深。", "正昼掩柴扉，□寻隐遁，□舒槐府，戎正经纶。", "白石清泉，紫枢黄阁，□□□□□□□。", "□□□，□弟为宰相，兄作闲人。", "南园借我登临。", "都不怕近前丞相瞋。", "但曳履扶筇，堪怜独步，携壶载酒，每叹孤斟。", "七Α开颜，六旬屈指，风雨对床频上心。", "殷勤祝，道何时回首，及早抽身。"]'),
('song-ci-39','沁园春','吴渊','宋','宋词','song-ci','沁园春','[]','十月江南，一番春信，怕凭玉栏。',140,'宋词/ci.song.15000.json','["十月江南，一番春信，怕凭玉栏。", "正地连边塞，角声三弄，人思乡国，愁绪千般。", "草草村墟，疏疏篱落，犹记花间曾卓庵。", "茶瓯罢，问几回吟绕，冷淡相看。", "堪怜。", "影落溪南。", "又月午无人更漏三。", "虽虚林幽壑，数枝偏瘦，已存鼎鼐，一点微酸。", "松竹交盟，雪霜心事，断是平生不肯寒。", "林逋在，倩诗人此去，为语湖山。"]'),
('song-ci-40','满江红','吴渊','宋','宋词','song-ci','满江红','[]','秋后锺山，苍翠色、可供餐食。',118,'宋词/ci.song.15000.json','["秋后锺山，苍翠色、可供餐食。", "登临处、怨桃旧曲，催梅新笛。", "江近苹风随汛落，峰高松露和云滴。", "叹头童、齿豁已成翁，犹为客。", "老怀抱，非畴昔。", "欢意思，须寻觅。", "人间世、假饶百岁，苦无多日。", "已没风云豪志气，只思烟水闲踪迹。", "问何年、同老转溪滨，渔钩掷。"]'),
('song-ci-41','满江红','吴渊','宋','宋词','song-ci','满江红','[]','投老未归，太仓粟、尚教蚕食。',118,'宋词/ci.song.15000.json','["投老未归，太仓粟、尚教蚕食。", "家山梦、秋江渔唱，晚风牛笛。", "别墅流风惭莫继，新亭老泪空成滴。", "笑当年、君作主人翁，同为客。", "紫燕泊，犹如昔。", "青鬓改，难重觅。", "记携手、同游此处，恍如前日。", "且更开怀穷乐事，可怜过眼成陈迹。", "把忧边、忧国许多愁，权抛掷。"]'),
('song-ci-42','满江红','曾寓轩','宋','宋词','song-ci','满江红','[]','细数班行，阿谁是、调元手段。',115,'宋词/ci.song.15000.json','["细数班行，阿谁是、调元手段。", "君不见、当涂往岁，饥民流散。", "天幸立庵来歇马，留心济粜无遗算。", "未须臾、千里复安居，无愁叹。", "公与相，天皆愿。", "天施报，如符券。", "看青州阴骘，富公公案。", "已筑新堤旌异数，便膺虚席非常眷。", "待明年、弧失再垂门，蒙宣劝。"]'),
('song-ci-43','沁园春','曾寓轩','宋','宋词','song-ci','沁园春','[]','运在东南，千古金陵，帝王旧州。',140,'宋词/ci.song.15000.json','["运在东南，千古金陵，帝王旧州。", "看地雄江左，蟠龙踞虎，事专阃外，缓带轻裘。", "惟断乃成，非贤罔任，真是富韩文范俦。", "难兄弟，久齐名天壤，谁劣谁优。", "冕旒。", "似欲兼收。", "命四辈传宣难借留。", "记适遵昆季，迭行沙路，育充伯仲，并在金瓯。", "或后或先，相推相逊，等是延陵德泽流。", "称觞了，便促装西上，同奉宸游。"]'),
('song-ci-44','南乡子','吴淇','宋','宋词','song-ci','南乡子','[]','十日借春留。',66,'宋词/ci.song.15000.json','["十日借春留。", "芍药荼䕷不解愁。", "检点笙歌催酿酒，西州。", "有谪仙人烂熳游。", "白鹭自芳洲。", "咫尺红云最上头。", "万古沧江波不尽，风流。", "谁似监州旧姓牟。"]'),
('song-ci-45','喜迁莺','杜东','宋','宋词','song-ci','喜迁莺','[]','生申华席。',126,'宋词/ci.song.15000.json','["生申华席。", "便占却新春，前头五日。", "椒颂梅英，金幡彩缕，好个早春天色。", "使君以仁得寿，和气融春无极。", "人总道，是阳春有脚，恩浮南国。", "应看，丹诏下，昨夜天边，初报春消息。", "日转黄麾，风生绛伞，春殿龙颜咫尺。", "共庆一堂嘉会，万宇同沾春泽。", "祝眉寿，便从今细数，好春千亿。"]'),
('song-ci-46','清平乐','赵汝迕','宋','宋词','song-ci','清平乐','[]','初莺细雨。',54,'宋词/ci.song.15000.json','["初莺细雨。", "杨柳低愁缕。", "烟浦花桥如梦里。", "犹记倚楼别语。", "小屏依旧围香。", "恨抛薄醉残妆。", "判却寸心双泪，为他花月凄凉。"]'),
('song-ci-47','瑞鹤仙','楼采','宋','宋词','song-ci','瑞鹤仙','[]','冻痕销梦草。',127,'宋词/ci.song.15000.json','["冻痕销梦草。", "又招得春归，旧家池沼。", "园扉掩寒峭。", "倩谁将花信，遍传深窈。", "追游趁早。", "便栽却、轻衫短帽。", "任残梅、飞满溪桥，和月醉眠清晓。", "年小。", "青丝纤手，彩胜娇鬟，赋情谁表。", "南楼信杳。", "江云重，雁归少。", "记冲香嘶马，流红回岸，几度绿杨残照。", "想暗黄，依旧东风，灞陵古道。"]'),
('song-ci-48','玉漏迟','楼采','宋','宋词','song-ci','玉漏迟','[]','絮花寒食路。',115,'宋词/ci.song.15000.json','["絮花寒食路。", "晴丝罥日，绿阴吹雾。", "客帽欺风，愁满画船烟浦。", "彩柱秋千散后，怅尘锁、燕帘莺户。", "从间阻。", "梦云无准，鬓霜如许。", "夜永绣阁藏娇，记掩扇传歌，翦灯留语。", "月约星期，细把花须频数。", "弹指一襟幽恨，谩空趁、啼鹃声诉。", "深院宇。", "黄昏杏花微雨。"]'),
('song-ci-49','法曲献仙音','楼采','宋','宋词','song-ci','法曲献仙音','[]','花匣么弦，象奁双陆，旧日留欢情意。',113,'宋词/ci.song.15000.json','["花匣么弦，象奁双陆，旧日留欢情意。", "梦到银屏，恨裁兰烛，香篝夜阑鸳被。", "料燕子重来地。", "桐阴锁窗绮。", "倦梳洗。", "晕芳钿、自羞鸾镜，罗袖冷，烟柳画栏半倚。", "浅雨压荼䕷，指东风、芳事馀几。", "院落黄昏，怕春莺、惊笑憔悴。", "倩柔红约定，唤取玉箫同醉。"]'),
('song-ci-50','好事近','楼采','宋','宋词','song-ci','好事近','[]','人去玉屏间，逗晓柳丝风急。',53,'宋词/ci.song.15000.json','["人去玉屏间，逗晓柳丝风急。", "帘外杏花细雨，罥春红愁湿。", "单衣初试麴尘罗，中酒病无力。", "应是绣床慵困，倚秋千斜立。"]'),
('song-ci-51','二郎神','楼采','宋','宋词','song-ci','二郎神','[]','露床转玉，唤睡醒、绿云梳晓。',129,'宋词/ci.song.15000.json','["露床转玉，唤睡醒、绿云梳晓。", "正倦立银屏，新宽衣带，生怯轻寒料峭。", "闷绝相思无人问，但怨入、墙阴啼鸟。", "嗟露屋锁春，晴风喧昼，柳轻梅小。", "人悄。", "日长谩忆，秋千嬉笑。", "怅烬冷炉薰，花深莺静，帘箔微红醉袅。", "带结留诗，粉痕销帕，情远窃香年少。", "凝恨极，尽日凭高目断，淡烟芳草。"]'),
('song-ci-52','玉楼春','楼采','宋','宋词','song-ci','玉楼春','[]','东风破晓寒成阵。',64,'宋词/ci.song.15000.json','["东风破晓寒成阵。", "曲锁沈香簧语嫩。", "凤钗敲枕玉声圆，罗袖拂屏金缕褪。", "云头雁影占来信。", "歌底眉尖萦浅晕。", "淡烟疏柳一帘春，细雨遥山千叠恨。"]'),
('song-ci-53','失调名','楼采','宋','宋词','song-ci','失调名','[]','珠蹙花舆，翠翻莲额。',10,'宋词/ci.song.15000.json','["珠蹙花舆，翠翻莲额。"]'),
('song-ci-54','失调名','楼采','宋','宋词','song-ci','失调名','[]','汗粉难融，袖香新窃。',10,'宋词/ci.song.15000.json','["汗粉难融，袖香新窃。"]'),
('song-ci-55','好事近','雷应春','宋','宋词','song-ci','好事近','[]','梅片作团飞，雨外柳丝金湿。',53,'宋词/ci.song.15000.json','["梅片作团飞，雨外柳丝金湿。", "客子短篷无据，倚长风挂席。", "回头流水小桥东，烟扫画楼出。", "楼上有人凝伫，似旧家曾识。"]'),
('song-ci-56','沁园春','雷应春','宋','宋词','song-ci','沁园春','[]','问讯故园，今如之何，还胜昔无。',139,'宋词/ci.song.15000.json','["问讯故园，今如之何，还胜昔无。", "想旧耘兰蕙，依然葱茜，新栽杨柳，亦已扶疏。", "韭本千畦，芋根一亩，雨老烟荒谁为锄。", "难忘者，是竹吾爱甚，梅汝知乎。", "茅亭低压平湖。", "有狎鹭驯鸥尚可呼。", "把绛纱准拟，新官到也，寒毡收拾，贱子归欤。", "略整柴门，更芟草径，惟有幽人解枉车。", "丁宁著，与做添棋局，砌换茶垆。"]'),
('song-ci-57','西江月','包荣父','宋','宋词','song-ci','西江月','[]','雅意浯亭宽碧，何心禁路宽华。',58,'宋词/ci.song.15000.json','["雅意浯亭宽碧，何心禁路宽华。", "芝兰玉树侍臣家。", "一段洛滨图画。", "庆事两年亲见，今年福寿堪夸。", "更从头上人添些。", "却是八千岁也。"]'),
('song-ci-58','千秋岁','游文仲','宋','宋词','song-ci','千秋岁','[]','今年为寿，都道是、不比寻常时节。',120,'宋词/ci.song.15000.json','["今年为寿，都道是、不比寻常时节。", "预庆我公八帙，来献新词一阕。", "算得年时，恰当尚父，入相周西伯。", "亲逢盛事，宗孙也五十八。", "一门富贵荣华，盈床牙笏，何待拈来说。", "且上祝龟龄鹤算，从此千千百百。", "笑道儿时，风流丹篆，写向龙驹额。", "更将彩笔，十字头上添一丿。"]'),
('song-ci-59','念奴娇','刘清夫','宋','宋词','song-ci','念奴娇','[]','乱山深处，见寒梅一朵，皎然如雪。',120,'宋词/ci.song.15000.json','["乱山深处，见寒梅一朵，皎然如雪。", "的皪妍姿羞半吐，斜映小窗幽绝。", "玉染香腮，酥凝冷艳、容态天然别。", "故人虽远，对花谁肯轻折。", "疑是姑射神仙，幔亭宴罢，迤逦停瑶节。", "爱此溪山供秀润，饱玩洞天风月。", "万石丛中，百花头上，谁与争高洁。", "粗桃俗李，不须连夜催发。"]'),
('song-ci-60','沁园春','刘清夫','宋','宋词','song-ci','沁园春','[]','浅碧芙蓉，素艳亭亭，前身阿娇。',139,'宋词/ci.song.15000.json','["浅碧芙蓉，素艳亭亭，前身阿娇。", "记湘滨露冷，酥容倍洁，华清水滑，酒晕全消。", "瑶剪丰肥，云翻碎萼，白羽鲜明时自摇。", "风流处，是古香幽韵，时度仙飙。", "琼枝璧月清标。", "对千朵婵娟倾翠瓢。", "况水晶台榭，低迷净绿，冰霜词调，隐约轻桡。", "细认金房，锺奇孕秀，已觉青衿横素腰。", "西风晚，看花开十丈，玉井非遥。"]'),
('song-ci-61','金菊对芙蓉','刘清夫','宋','宋词','song-ci','金菊对芙蓉','[]','浅拂春山，慢横秋水，玉纤闲理丝桐。',121,'宋词/ci.song.15000.json','["浅拂春山，慢横秋水，玉纤闲理丝桐。", "按清冷繁露，淡伫悲风。", "素弦瑶轸调新韵，颤翠翘、金簇芙蓉。", "叠蠲重锁，轻挑慢摘，特地情浓。", "泛商刻羽无穷。", "似和鸣鸾凤，律应雌雄。", "问高山流水，此意谁同。", "个中只许知音听，有茂陵、车马雍容。", "画帘人静，琴心三叠，时倒金锺。"]'),
('song-ci-62','水调歌头','刘清夫','宋','宋词','song-ci','水调歌头','[]','残腊卷愁去，春至莫闲愁。',114,'宋词/ci.song.15000.json','["残腊卷愁去，春至莫闲愁。", "荣枯会有成说，无处著机谋。", "身世石中敲火，富贵草头垂露，何用苦贪求。", "三尺布衣剑，千载赤松游。", "忆亲朋，方丱角，总白头。", "羊肠世路巇崄，莫莫且休休。", "选甚范侯高爵，遮莫陶公钜产，争似五湖舟。", "万事付蜗角，止坎谩乘流。"]'),
('song-ci-63','玉楼春','刘清夫','宋','宋词','song-ci','玉楼春','[]','柳梢绿小眉如印。',64,'宋词/ci.song.15000.json','["柳梢绿小眉如印。", "乍暖还寒犹未定。", "惜花长是为花愁，殢酒却嫌添酒病。", "蝇头蜗角都休竞。", "万古豪华同一尽。", "东君晓夜促归期，三十六番花递信。"]'),
('song-ci-64','贺新郎','祝穆','宋','宋词','song-ci','贺新郎','[]','此木生林野。',142,'宋词/ci.song.15000.json','["此木生林野。", "自唐家、丝纶置阁，托根其下。", "长伴词臣挥帝制，因号紫微堪诧。", "常缥缈、紫微仙驾。", "料想紫微垣降种。", "紫微郎、况是名同者。", "兼二美，作佳话。", "一株乃肯临茅舍。", "肌肤薄、长身挺立，扶疏潇洒。", "定怯麻姑爬痒爪，只许素商陶冶。", "擎绛雪、柔枝低亚。", "我忆香山东坡老，只小诗、便为增声价。", "后当有，继风雅。"]'),
('song-ci-65','沁园春','祝穆','宋','宋词','song-ci','沁园春','[]','自有东阳，锦水城山，几千百年。',139,'宋词/ci.song.15000.json','["自有东阳，锦水城山，几千百年。", "记往时仅说，拥麾刻郡，而今创见，持橐甘泉。", "地脉方兴，天荒欲破，还为盐梅生钜贤。", "清和候，正风薰日永，作地行仙。", "题舆小驻樵川。", "常只恐祖生先著鞭。", "算谁从井落，重新疆理，谁从襄岘，一洗腥膻。", "幕府归来，未应袖手，行有诏书来九天。", "勋名就，使吾乡夸诧，盛事流传。"]'),
('song-ci-66','念奴娇','周文谟','宋','宋词','song-ci','念奴娇','[]','棋声特地，把十年心事，恍然惊觉。',120,'宋词/ci.song.15000.json','["棋声特地，把十年心事，恍然惊觉。", "杨柳楼头歌舞地，长记一枝纤弱。", "破镜重圆，玉环犹在，鹦鹉言如昨。", "秦筝别后，知他几换弦索。", "谁念顾曲周郎，樽前重见，千种愁难著。", "犹胜玄都人去后，空怨残红零落。", "绿叶成阴，桃花结子，枉恨东风恶。", "盈盈泪眼，见人欲下还阁。"]'),
('song-ci-67','八声甘州','李好古1','宋','宋词','song-ci','八声甘州','[]','壮东南、飞观切云高，峻堞缭波长。',116,'宋词/ci.song.15000.json','["壮东南、飞观切云高，峻堞缭波长。", "望蔽空楼橹，重关警柝，跨水飞梁。", "百万貔貅夜筑，形胜隐金汤。", "坐落诸蕃胆，扁榜安江。", "游子凭阑凄断，百年故国，飞鸟斜阳。", "恨当时肉食，一掷赌封疆。", "骨冷英雄何在，望荒烟、残戌触悲凉。", "无言处，西楼画角，风转牙樯。"]'),
('song-ci-68','八声甘州','李好古1','宋','宋词','song-ci','八声甘州','[]','古扬州、壮丽压长淮，形胜绝东南。',116,'宋词/ci.song.15000.json','["古扬州、壮丽压长淮，形胜绝东南。", "问竹西歌吹，蜀冈何许，杨柳鬖鬖。", "行乐谁家年少，两两更三三。", "知我江南客，走马来看。", "过却长亭烟树，云山点点，烟浪漫漫。", "料桐花飞尽，夜合绕阑干。", "倦绣闲庭昼永，望天涯、芳草忆征鞍。", "平安使，吴笺谩遣，欲寄愁难。"]'),
('song-ci-69','江城子','李好古1','宋','宋词','song-ci','江城子','[]','从来难翦是离愁。',86,'宋词/ci.song.15000.json','["从来难翦是离愁。", "这些愁。", "几时休。", "才趁风樯，千里到扬州。", "见说苍茫云海外，天杳杳，水愁愁。", "男儿三十敞貂裘。", "强追游。", "梦魂羞。", "可解筹边，谈笑觅封侯。", "休傍塞垣酾酒去，伤望眼，怕层楼。"]'),
('song-ci-70','江城子','李好古1','宋','宋词','song-ci','江城子','[]','平沙浅草接天长。',88,'宋词/ci.song.15000.json','["平沙浅草接天长。", "路茫茫。", "几兴亡。", "昨夜波声，洗岸骨如霜。", "千古英雄成底事，徒感慨，谩悲凉。", "少年有意伏中行。", "馘名王。", "扫沙场。", "击楫中流，曾记泪沾裳。", "欲上《治安》双阙远，空怅望，过维扬。"]'),
('song-ci-71','水调歌头','李好古1','宋','宋词','song-ci','水调歌头','[]','历历江南树，半在水云间。',114,'宋词/ci.song.15000.json','["历历江南树，半在水云间。", "不须回首，且来著眼向淮山。", "过尽金山晕碧，望断焦山空翠，杨柳绕江边。", "此意无人会，独自久凭阑。", "夜吹箫，朝问法，记坡仙。", "只今何许，当时三峡倒词源。", "水调翻成新唱，高压风流前辈，使我百忧宽。", "有酒更如海，容我醉时眠。"]'),
('song-ci-72','酹江月・念奴娇','李好古1','宋','宋词','song-ci','酹江月・念奴娇','[]','西风横荡，渐霜馀黄落，空山乔木。',120,'宋词/ci.song.15000.json','["西风横荡，渐霜馀黄落，空山乔木。", "照水依然冰雪在，耿耿梅花幽独。", "抖擞征尘，扶携短策，步绕沧浪曲。", "怅然心事，浮生翻覆陵谷。", "试向商乐亭前，冷风台上，把酒招黄鹄。", "四十男儿当富贵，谁念漂零南北。", "百亩春耕，三间云卧，此计何时卜。", "功名休问，卖书归买黄犊。"]'),
('song-ci-73','酹江月・念奴娇','李好古1','宋','宋词','song-ci','酹江月・念奴娇','[]','平生英气，叹年来、都付山林泉石。',120,'宋词/ci.song.15000.json','["平生英气，叹年来、都付山林泉石。", "不作云霄轩冕梦，只拟纶竿蓑笠。", "见说湖阴，飞飞鸥鹭，半是君曾识。", "梅花时节，试来相与寻觅。", "休谩汨没尘埃，浮生能几，镜里催华发。", "趁取尊前强健在，莫负花前倾碧。", "自遣长须，亲题短句，去约萧闲客。", "休教惆怅，梅花飞尽寒食。"]'),
('song-ci-74','贺新郎','李好古1','宋','宋词','song-ci','贺新郎','[]','人物风流远。',142,'宋词/ci.song.15000.json','["人物风流远。", "忆当年、江东跌宕，知音南阮。", "惯倚胡床闲寄傲，妥腹难凭琴桉。", "妙制拥、银蟾光满。", "千古不传谁好事，忽茂陵、金碗人间见。", "轻擘动，思无限。", "长安钗鬓春横乱。", "仿规模、红条带拨，媚深情浅。", "安识高山流水趣，儿女空传恩怨。", "使得似、支郎萧散。", "听到三闾沈绝处，惨悲风、摇落寒江岸。", "不肠断，也肠断。"]'),
('song-ci-75','清平乐','李好古1','宋','宋词','song-ci','清平乐','[]','清淮北去。',54,'宋词/ci.song.15000.json','["清淮北去。", "千里扬州路。", "过却瓜州杨柳树。", "烟水重重无数。", "柁楼才转前湾。", "云山万点江南。", "点点尽堪肠断，行人休望长安。"]'),
('song-ci-76','清平乐','李好古1','宋','宋词','song-ci','清平乐','[]','瓜州渡口。',54,'宋词/ci.song.15000.json','["瓜州渡口。", "恰恰城如斗。", "乱絮飞钱迎马首。", "也学玉关榆柳。", "面前直控金山。", "极知形胜东南。", "更愿诸公著意，休教忘了中原。"]'),
('song-ci-77','浣溪沙','李好古1','宋','宋词','song-ci','浣溪沙','[]','为怯赪云挟暑飞。',48,'宋词/ci.song.15000.json','["为怯赪云挟暑飞。", "嫩凉故故著征衣。", "江风吹雨过楼西。", "未必男儿生不遇，时来咳唾是珠玑。", "功名终岂壮心违。"]'),
('song-ci-78','菩萨蛮','李好古1','宋','宋词','song-ci','菩萨蛮','[]','东园映叶梅如豆。',52,'宋词/ci.song.15000.json','["东园映叶梅如豆。", "西园扑地花铺绣。", "春水晓来深。", "日华娇漾金。", "带烟穿径竹。", "步入飞虹曲。", "何处早莺啼。", "曲桥西复西。"]'),
('song-ci-79','菩萨蛮','李好古1','宋','宋词','song-ci','菩萨蛮','[]','东风一夜都吹损。',52,'宋词/ci.song.15000.json','["东风一夜都吹损。", "昼长春殢佳人困。", "满地委香钿。", "人情谁肯怜。", "诗人犹爱惜。", "故故频收拾。", "云彩缕丝丝。", "娇娆忆旧时。"]'),
('song-ci-80','菩萨蛮','李好古1','宋','宋词','song-ci','菩萨蛮','[]','纳红销翠春风里。',52,'宋词/ci.song.15000.json','["纳红销翠春风里。", "精神一撮金莲底。", "不是睡杨妃。", "绿珠娇小儿。", "一般娇绝处。", "半带疏疏雨。", "不解吐繁香。", "却教人断肠。"]'),
('song-ci-81','酹江月・念奴娇','阮秀实','宋','宋词','song-ci','酹江月・念奴娇','[]','汉庭用老，想君王、也忆潜郎白首。',120,'宋词/ci.song.15000.json','["汉庭用老，想君王、也忆潜郎白首。", "底事煌煌金玉节，奔走天涯许久。", "江右风流，湖南清绝，要借诗翁手。", "明年七十，人间此事希有。", "固是守约堂间，鲂斋亭下，要种归来柳。", "只恐夜深思贾傅，便有锋车迎候。", "寿岳峰前，寿星池畔，且寿长沙酒。", "期颐三万，祖风应管依旧。"]'),
('song-ci-82','昼锦堂','刘子寰','宋','宋词','song-ci','昼锦堂','[]','思纵步，时自驻篮舆，策杖荒郊。',59,'宋词/ci.song.15000.json','["思纵步，时自驻篮舆，策杖荒郊。", "为有柔荑可坐，野菜时挑。", "思忆家山行乐处，片心时逐野云飘。", "歌长铗、遥寄故人，归路赋隐辞招。"]'),
('song-ci-83','解语花','刘子寰','宋','宋词','song-ci','解语花','[]','龙沙殿腊，兔苑留寒，花照冰壶夜。',124,'宋词/ci.song.15000.json','["龙沙殿腊，兔苑留寒，花照冰壶夜。", "乱山平野。", "装珠树满眼，买春无价。", "墙头苑下。", "浑不见、桃夭杏冶。", "疑趁风、庾岭寒梅，触处都飘谢。", "吹面峭寒未怕。", "览瑶池万里，飞观高榭。", "霓旌鹤驾。", "歌黄竹、胜跃踏青骄马。", "峰峦似画。", "但点缀、片时相借。", "惊望中、玉宇琼楼，残溜空鸳瓦。"]'),
('song-ci-84','玉漏迟','刘子寰','宋','宋词','song-ci','玉漏迟','[]','翠草侵园径。',115,'宋词/ci.song.15000.json','["翠草侵园径。", "阴阴夏木，鸣鸠相应。", "纵目江天，窈窈雨昏烟暝。", "屋角黄梅乍熟，听落颗、时敲金井。", "深院静。", "闲阶自长，花砖苔晕。", "楼居簟枕清凉，尽永日阑干，与谁同凭。", "旧社鸥盟，零落断无音信。", "辽鹤追思旧事，向华表、空吟遗恨。", "萦念损。", "休怪暮年多病。"]'),
('song-ci-85','玉漏迟','刘子寰','宋','宋词','song-ci','玉漏迟','[]','暮天初过。',44,'宋词/ci.song.15000.json','["暮天初过。", "雨凄清，顿觉今年秋早。", "夜景虚明，仿佛露华清晓。", "蕙草繁花竞吐，向暗里、幽香缥缈。"]'),
('song-ci-86','醉蓬莱','刘子寰','宋','宋词','song-ci','醉蓬莱','[]','访莺花陈迹，姚魏遗风，绿阴成幄。',120,'宋词/ci.song.15000.json','["访莺花陈迹，姚魏遗风，绿阴成幄。", "尚有馀香，付宝阶红药。", "淮海维阳，物华天产，未觉输京洛。", "时世新妆，施朱傅粉，依然相若。", "束素腰纤，捻红唇小，鄣袖娇看，倚阑柔弱。", "玉佩琼琚，劝王孙行乐。", "况是韶华，为伊挽驻，未放离情薄。", "顾盼阶前，留连醉里，莫教零落。"]'),
('song-ci-87','阮郎归','刘子寰','宋','宋词','song-ci','阮郎归','[]','长条袅袅串红绡。',56,'宋词/ci.song.15000.json','["长条袅袅串红绡。", "无风时自摇。", "十分妖艳更苗条。", "殢春情态娇。", "风影舞，露痕潮。", "买来和蝶饶。", "故园愁绝楚宫腰。", "相逢恨怎销。"]'),
('song-ci-88','好事近','刘子寰','宋','宋词','song-ci','好事近','[]','秋色到东篱，一种露红先占。',53,'宋词/ci.song.15000.json','["秋色到东篱，一种露红先占。", "应念金英冷淡，摘胭脂浓染。", "依稀十月小桃花，霜蕊破霞脸。", "何事渊明风致，却十分妖艳。"]'),
('song-ci-89','齐天乐','刘子寰','宋','宋词','song-ci','齐天乐','["\u897f\u6e56"]','雅歌堂下新堤路。',123,'宋词/ci.song.15000.json','["雅歌堂下新堤路。", "柳外行人相语。", "碧藕开花，金桃结子，三见使君初度。", "楼台北渚。", "似画出西湖，水云深处。", "彩鹢双飞，水亭开宴近重午。", "溪蒲堪荐绿醑。", "幔亭何惜，为曾孙留住。", "碧水吟哦，沧洲梦想，未放舟横野渡。", "维申及甫。", "正夹辅中兴，擎天作柱。", "愿祝嵩高，岁添长命缕。"]'),
('song-ci-90','花发沁园春','刘子寰','宋','宋词','song-ci','花发沁园春','[]','换谱伊凉，选歌燕赵，一番乐事重起。',128,'宋词/ci.song.15000.json','["换谱伊凉，选歌燕赵，一番乐事重起。", "花新笑靥，柳软纤腰，济楚众芳围里。", "年年佳会。", "长是傍、清明天气。", "正魏紫衣染天香，蜀妆红破春睡。", "一簇猩罗凤翠。", "遍东园西城，点检芳事。", "铃斋吏散，昼馆人稀，几阕管弦清脆。", "人生适意。", "流转共、风光游戏。", "到遇景，取次成欢，怎教良夜休醉。"]'),
('song-ci-91','玉楼春','刘子寰','宋','宋词','song-ci','玉楼春','[]','今来古往吴京道。',64,'宋词/ci.song.15000.json','["今来古往吴京道。", "岁岁荣枯原上草。", "行人几度到江滨，不觉身随风树老。", "蒲花易晚芦花早。", "客里光阴如过鸟。", "一般垂柳短长亭，去路不如归路好。"]'),
('song-ci-92','沁园春','刘子寰','宋','宋词','song-ci','沁园春','[]','云壑泉泓，小者如杯，大者如罂。',139,'宋词/ci.song.15000.json','["云壑泉泓，小者如杯，大者如罂。", "更石筵平莹，宽容数客，淙流回激，环绕飞觥。", "三涧交流，两崖悬瀑，捣雪飞霜落翠屏。", "经行处，有丹荑碧草，古木苍藤。", "徘徊却倚山楹。", "笑山水娱人若有情。", "见傍回侧转，峰峦叠叠，欲穷还有，岩谷层层。", "仰视云间，茅茨鸡犬，疑是仙家来避秦。", "青林表，望烟霞缥缈，隐隐鸾笙。"]'),
('song-ci-93','贺新郎','刘子寰','宋','宋词','song-ci','贺新郎','[]','柱杖凌高绝。',141,'宋词/ci.song.15000.json','["柱杖凌高绝。", "望千山隐隐，波澜动摇天末。", "下有白云平远壑，涌起潮头喷雪。", "浸绝岛、孤峰出没。", "赤县神州何处是，但风烟、杳杳迷空阔。", "呼不见，古人物。", "碧松枝下青瑶石。", "举头看、长空湛湛，淡琉璃色。", "上界屋辰多官府，夸父忙鞭日月。", "任兔走、乌飞超忽。", "宇宙茫茫如许大，百年间、何用争优劣。", "身世事，一毛发。"]'),
('song-ci-94','满江红','刘子寰','宋','宋词','song-ci','满江红','[]','云壑飞泉，蒲根下、悬流陆续。',115,'宋词/ci.song.15000.json','["云壑飞泉，蒲根下、悬流陆续。", "堪爱处、石池湛湛，一方寒玉。", "暑际直当磐石坐，渴来自引悬瓢掬。", "听泠泠、清响泻琮琤，胜丝竹。", "寒照胆，消炎燠。", "清彻骨，无尘俗。", "笑幽人忻玩，滞留空谷。", "静坐时看松鼠饮，醉眠不碍山禽浴。", "唤仙人、伴我酌琼瑶，餐秋菊。"]'),
('song-ci-95','霜天晓角','刘子寰','宋','宋词','song-ci','霜天晓角','[]','横阴漠漠。',53,'宋词/ci.song.15000.json','["横阴漠漠。", "似觉罗衣薄。", "正是海棠时候，纱窗外、东风恶。", "惜春春寂寞。", "寻花花冷落。", "不会这些情味，元不是、念离索。"]'),
('song-ci-96','洞仙歌','刘子寰','宋','宋词','song-ci','洞仙歌','[]','风餍雨足，也解为花地。',102,'宋词/ci.song.15000.json','["风餍雨足，也解为花地。", "收拾浮云放新霁。", "爱调亭小翠，点滴猩红，新妆了，妃子朝来睡起。", "遥知春有主，整顿欢娱，兴在新亭锦围底。", "便选歌燕赵，授简邹枚，须记作他日，城山盛事。", "笑东君不用管杨花，任飞去天涯，在东风里。"]'),
('song-ci-97','醉蓬莱','刘子寰','宋','宋词','song-ci','醉蓬莱','[]','正霜浮菊浅，露染枫深，九秋佳景。',120,'宋词/ci.song.15000.json','["正霜浮菊浅，露染枫深，九秋佳景。", "梅报南枝，一点和羹信。", "峻岳生申，太山瞻鲁，瑞启千年运。", "飞帛奎文，仪皇韶祉，明良相庆。", "岁值丰登，道方开泰，塞骑尘收，海鲸波静。", "几斗璇枢，仰三阶平正。", "保定乾坤，亲扶日月，万宇同歌咏。", "比寿彭聃，侔勋周召，致君尧舜。"]'),
('song-ci-98','醉蓬莱','刘子寰','宋','宋词','song-ci','醉蓬莱','[]','正花深绣阁，带拂流酥，暖帘初试。',120,'宋词/ci.song.15000.json','["正花深绣阁，带拂流酥，暖帘初试。", "窈窕笙歌，拥新鲜珠翠。", "艳菊留金，早梅催粉，趁得瑶池会。", "画馆凝香，仙家正住，芙蓉城里。", "裼寝开祥，玉枝祝寿，列院欢娱，满堂佳瑞。", "福寿双星，现碧霄云际。", "京兆时妆，如皋乐事，占世间荣贵。", "象服鱼轩，疏封大国，齐眉千岁。"]'),
('song-ci-99','霜天晓角','刘子寰','宋','宋词','song-ci','霜天晓角','[]','满前儿女。',51,'宋词/ci.song.15000.json','["满前儿女。", "今日都欢聚。", "今也阿弥八十，儿也五十五。", "瓷瓯并瓦注。", "山歌和社舞。", "但管年年强健，妆成个、西王母。"]'),
('song-ci-100','沁园春','刘子寰','宋','宋词','song-ci','沁园春','[]','长寿真人，玉佩琼裾，霞衣月裳。',139,'宋词/ci.song.15000.json','["长寿真人，玉佩琼裾，霞衣月裳。", "趁桃迎初度，千年方熟，蒲经端午，三日留春。", "兰杜绥旌，芙蓉搴盖，飞下清源云水乡。", "摛烟雾，引天机组织，官样文章。", "丁年璧水横翔。", "馀剩馥残膏沾四方。", "仰平生声望，九霄星斗，方来事业，万里风樯。", "经世规模，出尘丰骨，须合盛之白玉堂。", "轩腾去，看雍容槐棘，福艾耆庞。"]'),
('song-ci-101','谒金门','姚镛','宋','宋词','song-ci','谒金门','[]','吟院静。',53,'宋词/ci.song.15000.json','["吟院静。", "迟日自行花影。", "熏透水沈云满鼎。", "晚妆窥露井。", "飞絮游丝无定。", "误了莺莺相等。", "欲唤海棠教睡醒。", "奈何春不肯。"]'),
('song-ci-102','霓裳中序第一','尹焕','宋','宋词','song-ci','霓裳中序第一','[]','青颦粲素靥。',125,'宋词/ci.song.15000.json','["青颦粲素靥。", "海国仙人偏耐热。", "餐尽香风露屑。", "便万里凌空，肯凭莲叶。", "盈盈步月。", "悄似怜、轻去瑶阙。", "人何在，忆渠痴小，点点爱轻撅。", "愁绝。", "旧游轻别。", "忍重看、锁香金箧。", "凄凉清夜簟席。", "杳杳诗魂，真化风蝶。", "冷香清到骨。", "梦十里、梅花霁雪。", "归来也，恹恹心事，自共素娥说。"]'),
('song-ci-103','眼儿媚','尹焕','宋','宋词','song-ci','眼儿媚','[]','垂杨袅袅蘸清漪。',58,'宋词/ci.song.15000.json','["垂杨袅袅蘸清漪。", "明绿染春丝。", "市桥系马，旗亭沽酒，无限相思。", "云梳雨洗风前舞，一好百般宜。", "不知为甚，落花时节，都是颦眉。"]'),
('song-ci-104','唐多令','尹焕','宋','宋词','song-ci','唐多令','[]','苹末转清商。',74,'宋词/ci.song.15000.json','["苹末转清商。", "溪声供夕凉。", "缓传杯、催唤红妆。", "慢绾乌云新浴罢，裙拂地、水沈香。", "歌短旧情长。", "重来惊鬓霜。", "怅绿阴、青子成双。", "说著前欢佯不睬，扬莲子、打鸳鸯。"]'),
('song-ci-105','沁园春','夏元鼎','宋','宋词','song-ci','沁园春','[]','大道无名，金丹有验，工夫片时。',139,'宋词/ci.song.15000.json','["大道无名，金丹有验，工夫片时。", "似婴儿娇俊，不离门户，盈盈姹女，缓步深帏。", "二八当年，黄婆匹配，隔碍潜通势似危。", "须臾见，见灵明宝藏，一点星飞。", "其时。", "似执躬圭。", "深保护阴阳造化儿。", "转南辰北斗，回风混合，雷轰雨骤，只许天知。", "梦幻浮生，天长地久，云路著鞭休要迟。", "金不坏，合朋合德，三教同归。"]'),
('song-ci-106','沁园春','夏元鼎','宋','宋词','song-ci','沁园春','[]','太极才分，鸿濛凿破，云收雾开。',139,'宋词/ci.song.15000.json','["太极才分，鸿濛凿破，云收雾开。", "见曦魂蟾魄，升沈昼夜，光含万象，机应丹台。", "火里栽莲，水中捉月，两个人人暗去来。", "鹊桥畔，任传神送气，巽户轰雷。", "微哉。", "火候休猜。", "无师授徒劳颜闵材。", "问从头下手，收因结果，争魂夺命，何处胚胎。", "小法旁门，幸勤一世，谩道修真不惹埃。", "争如我，水晶宫里，独步琼阶。"]'),
('song-ci-107','沁园春','夏元鼎','宋','宋词','song-ci','沁园春','[]','天下江山，无如甘露，多景楼前。',137,'宋词/ci.song.15000.json','["天下江山，无如甘露，多景楼前。", "有谪仙公子，依山傍水，结茅筑圃，花竹森然。", "四季风光，一生乐事，真个壶中别有天。", "亭台巧，一琴一鹤，泥絮心田。", "不须块坐参禅。", "也不要区区学挂冠。", "但对境无心，山林钟鼎，流行坎止，闹里偷闲。", "向上玄关，南辰北斗，昼夜璇玑炼火还。", "分明见，本来面目，不是游魂。"]'),
('song-ci-108','水调歌头','夏元鼎','宋','宋词','song-ci','水调歌头','[]','采取铅须密，诚意辨妍媸。',112,'宋词/ci.song.15000.json','["采取铅须密，诚意辨妍媸。", "休教错认，夺来鼎内及其时。", "二物分明真伪，一得还君永得，此事契天机。", "记取元阳动，妙用在虚危。", "法寅申，行子午，总皆非。", "自然时节，梦里也教知。", "不属精津气血，不是肺肝心肾，真土亦非脾。", "言下泄多矣，凡辈奈无知。"]'),
('song-ci-109','水调歌头','夏元鼎','宋','宋词','song-ci','水调歌头','[]','要识刀圭诀，一味水银铅。',112,'宋词/ci.song.15000.json','["要识刀圭诀，一味水银铅。", "驴名马字，九三四八万千般。", "愚底转生分别，划地唤爷作父，荆棘满心田。", "去道日以远，至老昧蹄筌。", "譬如人，归故国，上轻帆。", "顺风得路，夜里也行船。", "岂问经州过县，管取投明须到，舟子自能牵。", "悟道亦如此，半句不相干。"]'),
('song-ci-110','水调歌头','夏元鼎','宋','宋词','song-ci','水调歌头','[]','耳目身之宝，固塞勿飞扬。',112,'宋词/ci.song.15000.json','["耳目身之宝，固塞勿飞扬。", "存无守有，中间无念以为常。", "把定玄关一窍，视听尽收归里，坎兑互堤防。", "寤寐神依抱，形气两相忘。", "圆陀陀，光烁烁，貌堂堂。", "分明真我，罔象里全彰。", "此即非空非色，自是本来面目，阴鼎炼元阳。", "出世真如佛，馀二莫思量。"]'),
('song-ci-111','水调歌头','夏元鼎','宋','宋词','song-ci','水调歌头','[]','真一北方气，玄武产先天。',112,'宋词/ci.song.15000.json','["真一北方气，玄武产先天。", "自然感合，蛇儿却把黑龟缠。", "便是蟾乌遇朔，亲见虎龙吞啖，顷刻过昆仑。", "赤黑达表里，炼就水银铅。", "有中无，无中有，两玄玄。", "生身来处，逆顺圣凡分。", "下士闻之大笑，不笑不足为道，难为俗人论。", "士塞命门了，去住管由君。"]'),
('song-ci-112','水调歌头','夏元鼎','宋','宋词','song-ci','水调歌头','[]','律应黄锺候，天地尚胚浑。',112,'宋词/ci.song.15000.json','["律应黄锺候，天地尚胚浑。", "腾腾一气，家园平地一枝春。", "下手依时急采，莫放中宫芽溢，害里却生恩。", "火候精勤处，加减武和文。", "定浮沈，明主客，别疏亲。", "真铅留汞，造化合乾坤。", "此是身中灵宝，谁信龙从火出，二八共成斤。", "些子希夷法，只在弄精魂。"]'),
('song-ci-113','水调歌头','夏元鼎','宋','宋词','song-ci','水调歌头','[]','擒得铅归舍，进火莫教迟。',112,'宋词/ci.song.15000.json','["擒得铅归舍，进火莫教迟。", "抽添沐浴，临炉一意且防危。", "只为婴儿未壮，全藉黄婆养育，丁老共扶持。", "火力频加减，外药亦如之。", "汞生芽，铅作祖，土刀圭。", "火生於木，炎盛汞还飞。", "要得水银真死，须待阴浮阳伏，杂类降灰池。", "用铅终不用，古语岂吾欺。"]'),
('song-ci-114','水调歌头','夏元鼎','宋','宋词','song-ci','水调歌头','[]','要蹑天仙步，金丹是法身。',112,'宋词/ci.song.15000.json','["要蹑天仙步，金丹是法身。", "不知谓气，须还识后自然真。", "大道从花孕子，点出个中阴魄，乌兔合阳魂。", "北斗随罡转，天地正氤氲。", "采依时，炼依法，莫辞勤。", "立跻圣域，从此脱沈沦。", "夜气正当过半，龙虎自然蛰动，势欲撼乾坤。", "片饷工夫耳，庄算八千春。"]'),
('song-ci-115','水调歌头','夏元鼎','宋','宋词','song-ci','水调歌头','[]','神气精三药，举世没人知。',112,'宋词/ci.song.15000.json','["神气精三药，举世没人知。", "气随精化，镇常神逐气无归。", "心地不明天巧，业识更缠地网，背却上天梯。", "今古多豪杰，生死醉如泥。", "树头珠，潭底日，显金机。", "两般识破，性命更何疑。", "活捉金精入木，炼就当初真一，方表丈夫儿。", "信取玄中趣，端的世间稀。"]'),
('song-ci-116','水调歌头','夏元鼎','宋','宋词','song-ci','水调歌头','[]','闻道不嫌晚，悟了莫悠悠。',112,'宋词/ci.song.15000.json','["闻道不嫌晚，悟了莫悠悠。", "遇时不炼，今生乌兔恐难留。", "些子乾坤简易，不问在朝居市，达者尽堪修。", "火候无斤两，大药本非遥。", "守旁门，囚冷屋，望升超。", "迷迷相授，生死不相饶。", "未识先天一气，孰辨五行生克，不向眼前求。", "试道工夫易，福薄又难消。"]'),
('song-ci-117','水调歌头','夏元鼎','宋','宋词','song-ci','水调歌头','[]','我有一竿竹，偏会取根源。',112,'宋词/ci.song.15000.json','["我有一竿竹，偏会取根源。", "从来汲水桔槔，直挈上西天。", "不许常人著手，管定竿头先折，提桶落寒泉。", "拨得机关转，北斗向南看。", "仗回风，乘偃月，勿波澜。", "麻姑此日，西北见张骞。", "选佛妙高峰顶，饮罢醍醐似醉，独坐玩婵娟。", "水湛月明处，太极更无前。"]'),
('song-ci-118','西江月','夏元鼎','宋','宋词','song-ci','西江月','[]','四十修真学道，金鱼要换金丹。',58,'宋词/ci.song.15000.json','["四十修真学道，金鱼要换金丹。", "龟龄鹤算不知年。", "行满身冲霄汉。", "此事希夷玄奥，功参造化难言。", "眼前有药耀山川。", "好把元阳修炼。"]'),
('song-ci-119','西江月','夏元鼎','宋','宋词','song-ci','西江月','[]','面目本来是道，阴阳造化成丹。',58,'宋词/ci.song.15000.json','["面目本来是道，阴阳造化成丹。", "骑牛寻犊不知原。", "真是三家村汉。", "古圣立言设象，后人得象忘言。", "且如乾画必三川。", "舍此如何烹炼。"]'),
('song-ci-120','西江月','夏元鼎','宋','宋词','song-ci','西江月','[]','太一画前是道，全凭龙虎成丹。',58,'宋词/ci.song.15000.json','["太一画前是道，全凭龙虎成丹。", "九还七返保长年。", "好个逍遥闲汉。", "日诣金门玉殿，青衣引赞无言。", "回风混合万神安。", "功向虚无中炼。"]'),
('song-ci-121','西江月','夏元鼎','宋','宋词','song-ci','西江月','[]','举世沈迷大道，傍门小法求丹。',58,'宋词/ci.song.15000.json','["举世沈迷大道，傍门小法求丹。", "咽津纳气等成仙。", "真个无知痴汉。", "何异雄鸡抱卵，梦同哑子交言。", "阴阳非类隔天渊。", "总是盲修瞎炼。"]'),
('song-ci-122','西江月','夏元鼎','宋','宋词','song-ci','西江月','[]','不死谷神妙道，杳冥中有还丹。',58,'宋词/ci.song.15000.json','["不死谷神妙道，杳冥中有还丹。", "坤牛乾马运无边。", "却是修行真汉。", "脱去名缰利锁，金童玉女传言。", "工夫片饷彻玄关。", "水火从教法炼。"]'),
('song-ci-123','西江月','夏元鼎','宋','宋词','song-ci','西江月','[]','大隐居尘奉道，衰颜能返朱丹。',58,'宋词/ci.song.15000.json','["大隐居尘奉道，衰颜能返朱丹。", "要须有主种三田。", "方免驱驰淮汉。", "天下江山第一，昆仑景胜何言。", "希夷妙处集真仙。", "默默重帘修炼。"]'),
('song-ci-124','西江月','夏元鼎','宋','宋词','song-ci','西江月','[]','万里担簦访道，要知一点灵丹。',58,'宋词/ci.song.15000.json','["万里担簦访道，要知一点灵丹。", "日乌月兔在朝元。", "岂在迢迢云汉。", "罔象求珠易得，离明契后难言。", "五金八石是虚传。", "争似阳修阴炼。"]'),
('song-ci-125','西江月','夏元鼎','宋','宋词','song-ci','西江月','[]','达磨西来说道，十年面壁安丹。',58,'宋词/ci.song.15000.json','["达磨西来说道，十年面壁安丹。", "争知水火不交煎。", "因果谩成罗汉。", "仰箭射空力尽，依然坠地何言。", "虚空拶破强参禅。", "肯把金丹烧炼。"]'),
('song-ci-126','西江月','夏元鼎','宋','宋词','song-ci','西江月','[]','几载鸡窗求道，费他兔楮铅丹。',58,'宋词/ci.song.15000.json','["几载鸡窗求道，费他兔楮铅丹。", "经书子史尽蹄筌。", "鹿走徒嗟秦汉。", "百代兴亡瞬息，徒留纸上陈言。", "谁知太始道常存。", "乌兔仙家修炼。"]'),
('song-ci-127','西江月','夏元鼎','宋','宋词','song-ci','西江月','[]','行处青牛引道，飞来鹤顶呈丹。',58,'宋词/ci.song.15000.json','["行处青牛引道，飞来鹤顶呈丹。", "谈玄玉局在西川。", "此日方当龙汉。", "千载寂寥吾道，可怜平叔多言。", "画蛇添足悟真篇。", "付与谁人修炼。"]'),
('song-ci-128','水调歌头','夏元鼎','宋','宋词','song-ci','水调歌头','[]','三三乾妙画，佑圣诞弥尘。',114,'宋词/ci.song.15000.json','["三三乾妙画，佑圣诞弥尘。", "北方壬癸，水生於坎产元精。", "一数先天有象，元始化生相应，灵气属阳神。", "寿永齐天地，万物尽回春。", "说龟蛇，名黑杀，蕴深仁。", "阴中阳长，要知害里却生恩。", "此意宜参造化，正是金丹大道，不在咽精津。", "富贵公方逼，肯问出人伦。"]'),
('song-ci-129','水调歌头','夏元鼎','宋','宋词','song-ci','水调歌头','[]','人身藏宇宙，乌兔走西东。',114,'宋词/ci.song.15000.json','["人身藏宇宙，乌兔走西东。", "昼舒夜卷，不拘春夏与秋冬。", "存想非心非肾，吐纳非精非气，子午谩行功。", "一点真灵宝，混合自回风。", "感婴儿，交姹女，爱丁公。", "黄婆匹配，一时辰内上仙宫。", "恍惚无中有象，阳火阴符密契，大道属鸿濛。", "火候能调理，天地与无穷。"]'),
('song-ci-130','西江月','夏元鼎','宋','宋词','song-ci','西江月','[]','甘露醴泉天降，琼浆玉液仙方。',58,'宋词/ci.song.15000.json','["甘露醴泉天降，琼浆玉液仙方。", "一壶馥郁喷天香。", "麴糵人间怎酿。", "要使周天火候，不应错认风光。", "浮沈清浊自斟量。", "日醉蓬莱方丈。"]'),
('song-ci-131','西江月','夏元鼎','宋','宋词','song-ci','西江月','[]','万汇阳春吐秀，争如雀舌含英。',58,'宋词/ci.song.15000.json','["万汇阳春吐秀，争如雀舌含英。", "先天一气社前升。", "啖出昆仑峰顶。", "要得丁公煅炼，飞成宝屑窗尘。", "蜜脾神用脱金形。", "送与仙翁体认。"]'),
('song-ci-132','贺新郎','夏元鼎','宋','宋词','song-ci','贺新郎','[]','天上神仙路。',141,'宋词/ci.song.15000.json','["天上神仙路。", "问谁能、超凡入圣，平虚交付。", "三岛十洲无限景，稳驾鸾舆鹤驭。", "更驯伏、木龙金虎。", "造化小儿真剧戏，炼阳精、要戴乾为父。", "须定力，似愚鲁。", "三旬一遇交乌兔。", "便丹成、天长地久，桑田变否。", "四象五行攒簇处，全藉黄婆真土。", "无私授、人多胡做。", "堪叹红尘声利客，向花朝月夕寻妆妇。", "应不解，乘槎去。"]'),
('song-ci-133','满江红','夏元鼎','宋','宋词','song-ci','满江红','[]','人世何为，江湖上、渔蓑堪老。',115,'宋词/ci.song.15000.json','["人世何为，江湖上、渔蓑堪老。", "鸣榔处，汪汪万顷，清波无垢。", "欸乃一声虚谷应，夷犹短棹关心否。", "向晚来、垂钓傍寒汀，牵星斗。", "砂碛畔，蒹葭茂。", "烟波际，盟鸥友。", "喜清风明月，多情相守。", "紫绶金章朝路险，青蓑箬笠沧溟浩。", "舍浮云、富贵乐天真，酾江酒。"]'),
('song-ci-134','满庭芳','夏元鼎','宋','宋词','song-ci','满庭芳','[]','久视长生，登仙大道，思量无甚神通。',117,'宋词/ci.song.15000.json','["久视长生，登仙大道，思量无甚神通。", "正心诚意，儒释道俱同。", "虽是无为清净，依然要、八面玲珑。", "朝朝见，日乌月兔，造化运西东。", "黄婆能匹配，天机玄妙，朔会相逢。", "正三旬一遇，消息无穷。", "不待存心想肾，非关是、打坐谈空。", "君知否，灵明宝藏，收在水晶宫。"]'),
('song-ci-135','西河','王野','宋','宋词','song-ci','西河','[]','天下事。',124,'宋词/ci.song.15000.json','["天下事。", "问天怎忍如此。", "陵图谁把献君王，结愁未已。", "少豪气概总成尘，空馀白骨黄苇。", "千古恨，吾老矣。", "东游曾吊淮水。", "绣春台上一回登，一回搵泪。", "醉归抚剑倚西风，江涛犹壮人意。", "只今袖手野色里。", "望长淮、犹二千里。", "纵有英心谁寄。", "近新来、又报胡尘起。", "绝域张骞归来未。"]'),
('song-ci-136','六州歌头','王野','宋','宋词','song-ci','六州歌头','["\u957f\u6c5f"]','龙蟠虎踞，今古帝王州。',180,'宋词/ci.song.15000.json','["龙蟠虎踞，今古帝王州。", "水如淮，山似洛，凤来游。", "五云浮。", "宇宙无终极，千载恨，六朝事，同一梦休。", "更莫问闲愁。", "风景悠悠。", "得似青溪曲，著我扁舟。", "对残烟衰草，满目是清秋。", "白鹭汀洲。", "夕阳收。", "黄旗紫盖，中兴运，锺王气，护金瓯。", "驻游跸，开行殿，夹朱楼。", "送华輈。", "万里长江险，集鸿雁，列貔貅。", "扫关河，清海岱，志应酬。", "机会何常，鹤唳风声处，天意人谋。", "臣今虽老，未遣壮心休。", "击楫中流。"]'),
('song-ci-137','沁园春','王野','宋','宋词','song-ci','沁园春','[]','月地云阶，碧山丹水，春满北园。',141,'宋词/ci.song.15000.json','["月地云阶，碧山丹水，春满北园。", "正慈闱初度，酡颜绿发，黄堂称寿，画戟朱幡。", "戏彩斓斑，安舆游衍，未数当时莱与潘。", "今朝好，把一家和气，散在千门。", "潜藩。", "误玷君恩。", "人尚说、淳熙前状元。", "幸物情如旧，亲年未老，且开玉帐，共祝金樽。", "罗绮飘香，管弦度曲，晚岁欢娱谁与论。", "亭峰宴，似仙家大姥，尽见曾孙。"]'),
('song-ci-138','水调歌头','哀长吉','宋','宋词','song-ci','水调歌头','[]','紫陌风光好，绣阁绮罗香。',114,'宋词/ci.song.15000.json','["紫陌风光好，绣阁绮罗香。", "相将人月圆夜，早庆贺新郎。", "先自少年心意，为惜殢人娇态，久俟愿成双。", "此夕于飞乐，共学燕归梁。", "索酒子，迎仙客，醉红妆。", "诉衷情处，些儿好语意难忘。", "但愿千秋岁里，结取万年欢会，恩爱应天长。", "行喜长春宅，兰玉满庭芳。"]'),
('song-ci-139','齐天乐','哀长吉','宋','宋词','song-ci','齐天乐','[]','青鸾海上传芳信。',121,'宋词/ci.song.15000.json','["青鸾海上传芳信。", "蓝田路入仙境。", "万卷书传，六奇计运，冰玉炯然清润。", "帷褰凤锦。", "□镜启鸾台，烟横鸳枕。", "一笑相迎，一双两好恰厮称。", "风流人在仙隐。", "更一县、陶柳春近。", "梦想金桃，宴分玉果，指日送尝汤饼。", "枌榆接畛。", "管此去亲盟，镇长交聘。", "自古朱陈，一村惟两姓。"]'),
('song-ci-140','朝中措','哀长吉','宋','宋词','song-ci','朝中措','[]','自从佳偶共黄姑。',57,'宋词/ci.song.15000.json','["自从佳偶共黄姑。", "几见设门弧。", "方喜阶庭联玉，又闻老蚌生珠。", "一门三秀，贾家虎子，薛氏鸾雏。", "从此公侯衮衮，看看百子成图。"]'),
('song-ci-141','西江月','哀长吉','宋','宋词','song-ci','西江月','[]','百和香凝宝络，长生酒满金尊。',58,'宋词/ci.song.15000.json','["百和香凝宝络，长生酒满金尊。", "葱葱佳气霭庭萱。", "同把椿龄祝愿。", "玉树已生谢砌，孙枝复长于门。", "伫看百子共千孙。", "此去公侯衮衮。"]'),
('song-ci-142','瑞鹤仙','哀长吉','宋','宋词','song-ci','瑞鹤仙','[]','天基佳节后。',127,'宋词/ci.song.15000.json','["天基佳节后。", "又诗咏嵩生，贤歌天佑。", "千龄运非偶。", "庆一堂风虎，云龙感召，相门华胄。", "盛少屈、一钱太守。", "听吏歌、一迳棠阴，民颂两岐麦秀。", "知否。", "海峰天柱，道骨仙风，总天所授。", "席虚机右。", "金瓯下，署名久。", "伫泥封飞下，沙堤归去，指日家声复旧。", "年年献、金鉴千秋，玉卮万寿。"]'),
('song-ci-143','瑞鹤仙','哀长吉','宋','宋词','song-ci','瑞鹤仙','[]','小春天未雪。',127,'宋词/ci.song.15000.json','["小春天未雪。", "见两蕊三花，放梅时节。", "昴宿孕人杰。", "对梅花雪片，平分风月。", "冰清玉洁。", "天赋与、仙风道骨。", "更等闲、来访刘仙，觅取秘传真诀。", "闻说。", "辉联台宿，瑞应文昌，世承阀阅。", "相门事业。", "有祖父、旧风烈。", "管泥封飞下，沙堤归来，光复青毡旧物。", "庆家传、八叶联芳，又添一叶。"]'),
('song-ci-144','沁园春','黄师参','宋','宋词','song-ci','沁园春','[]','谷口高人，偶溯明河，近尺五天。',139,'宋词/ci.song.15000.json','["谷口高人，偶溯明河，近尺五天。", "见紫霄宫阙，空中突兀，玉皇姬侍，云里蹁跹。", "滴露研朱，披肝作纸，细写灵均孤愤篇。", "排云叫，奈大钧不管，沙界三千。", "语高天上惊传。", "早斥去人间伴谪仙。", "念赤城丹籍，香名空在，蓬莱弱水，欲到无缘。", "还倚枯槎，飘然归去，回首清都若个边。", "家山好，有一湾风月，小小渔船。"]'),
('song-ci-145','祝英台近','李义山','宋','宋词','song-ci','祝英台近','[]','夏初临，春正满，花事在红药。',95,'宋词/ci.song.15000.json','["夏初临，春正满，花事在红药。", "一阵光风，香雾喷珠箔。", "画堂旧日张家，梦中玉燕，早拂晓、飞来帘幕。", "酒深酌。", "曾记走马长安，功名戏樊郭。", "螺浦如杯，豪气怎生著。", "直须用了圮编，封侯万户，却归共、赤松翁约。"]'),
('song-ci-146','风瀑竹','牟子才','宋','宋词','song-ci','风瀑竹','[]','阁住杏花雨。',141,'宋词/ci.song.15000.json','["阁住杏花雨。", "便新晴、等闲勾引，香车成雾。", "璧月光中箫凤远，袅袅馀音如缕。", "诮一似、群仙府。", "天意乍随人意好，渐星桥、度汉珠还浦。", "又何啻、列千炬。", "晚来乍觉阴盘固。", "笑人间、玉瓶瑶瑟，锦茵雕俎。", "无限升平宣政曲，回首中原何处。", "慨鸣镝、已无宫武。", "扑面胡尘浑未扫，强欢讴、还肯轩昂否。", "萦旧恨，为谁赋。"]'),
('song-ci-147','水调歌头','戴翼','宋','宋词','song-ci','水调歌头','[]','嵩岳周王佐，昴宿汉宗臣。',114,'宋词/ci.song.15000.json','["嵩岳周王佐，昴宿汉宗臣。", "从来间世英杰，出则致升平。", "况我皇华直指，元是福星出现，来此活生灵。", "五百岁初度，十一郡欢忻。", "挽西江，苏涸辙，洗尘埃。", "笑谈顷刻间宜，宇宙变为春。", "泽满赣川无限，福与崆峒齐耸，颂咏几多人。", "潋滟一卮寿，愿早秉洪钧。"]'),
('song-ci-148','水调歌头','戴翼','宋','宋词','song-ci','水调歌头','[]','渤海卖刀剑，河汉洗戎兵。',114,'宋词/ci.song.15000.json','["渤海卖刀剑，河汉洗戎兵。", "千金六月一雨，万陇稼云横。", "时节可人如许，天意开祥有在，申月岳生申。", "五百岁初度，千万户欢声。", "栋梁材，霖雨手，庙堂身。", "日边褒玺已到，岂久试鱼城。", "快上承明步武，展尽玉堂事业，再使旧毡青。", "公寿更天远，鼻祖等长生。"]'),
('song-ci-149','水调歌头','徐经孙','宋','宋词','song-ci','水调歌头','[]','客问矩山老，何事得优游。',114,'宋词/ci.song.15000.json','["客问矩山老，何事得优游。", "追数平生出处，为客赋歌头。", "三十五时侥幸，四十三年仕宦，七十□归休。", "顶踵皆君赐，天地德难酬。", "书数册，棋两局，酒三瓯。", "此是日中受用，谁劣又谁优。", "寒则拥炉曝背，暖则寻花问柳，乘兴狎沙鸥。", "知足又知止，客亦许之不。"]'),
('song-ci-150','百字令・念奴娇','徐经孙','宋','宋词','song-ci','百字令・念奴娇','[]','八旬加二，荷君天垂祐，扶持老拙。',120,'宋词/ci.song.15000.json','["八旬加二，荷君天垂祐，扶持老拙。", "目送新来檐外燕，手拣好花轻折。", "比似去年，十分强健，日看朱诗说。", "篇三百五，岁前尽有披阅。", "天教两子供官，一男留养，左右相娱悦。", "五见孙枝三弄授，童冠参差袍笏。", "四侍鳌峰，拿舟在即，次五今圆月。", "曾孙淳老，想能随叔嬉劣。"]'),
('song-ci-151','哨遍','徐经孙','宋','宋词','song-ci','哨遍','[]','江山风月，耳目声色。',109,'宋词/ci.song.15000.json','["江山风月，耳目声色。", "取之无禁，用之不竭。", "造物之无尽藏，月白风清，有客有酒。", "踞虎登龙，放舟中流。", "听其所止而休焉。", "归去来兮，昨非今是。", "旧菊都荒，新松老矣。", "吾年今已如此。", "归去来兮，忘我忘世。", "草木欣荣，幽人感此。", "吾生行且休矣。"]'),
('song-ci-152','乳燕飞・贺新郎','徐经孙','宋','宋词','song-ci','乳燕飞・贺新郎','[]','一雨炎□洗。',142,'宋词/ci.song.15000.json','["一雨炎□洗。", "似天知、溪山佳处，玳筵珠履。", "六十年前今朝庆，门左桑弧蓬矢。", "也似恁、郁葱佳气。", "绿鬓童颜春未老，问寿星、模样君真是。", "新甲子，从头起。", "应门有子能承志。", "总人间、皱眉底事，不关君耳。", "看不日孙枝毓秀，衮衮教人满意。", "更又报、门阑多喜。", "饱受人生真富贵，便蟠桃、三熟堪弹指。", "知几个，千秋岁。"]'),
('song-ci-153','鹧鸪天','徐经孙','宋','宋词','song-ci','鹧鸪天','[]','安分随缘事事宜。',64,'宋词/ci.song.15000.json','["安分随缘事事宜。", "平生快活过年时。", "长歌赤壁动坡赋，又咏归来元亮词。", "开八帙，望期颐。", "人生如此古犹稀。", "香飘金粟如来供，岁岁今朝荐酒卮。"]'),
('song-ci-154','八声甘州','冯去非','宋','宋词','song-ci','八声甘州','[]','买扁舟、载月过长桥，回首梦耶非。',119,'宋词/ci.song.15000.json','["买扁舟、载月过长桥，回首梦耶非。", "问往日三高，清风万古，继者伊谁。", "惟有茶烟轻扬，零露湿莼丝。", "西子知何处，鸿怨蛩悲。", "遥想家山好在，正倚天青壁，石瘦云肥。", "甚抛奇亸秀，猿鹤互猜疑。", "归去好、散人相国，迥升沈、毕竟总尘泥。", "须还我，松间旧隐，竹上新诗。"]'),
('song-ci-155','点绛唇','冯去非','宋','宋词','song-ci','点绛唇','[]','秋满孤篷，翠蒲红蓼留人住。',50,'宋词/ci.song.15000.json','["秋满孤篷，翠蒲红蓼留人住。", "一帘香缕。", "边影惊鸿度。", "小据胡床，旧事新情绪。", "凭谁诉。", "蜡灯犀尘。", "拟共西风语。"]'),
('song-ci-156','喜迁莺','冯去非','宋','宋词','song-ci','喜迁莺','[]','凉生遥渚。',126,'宋词/ci.song.15000.json','["凉生遥渚。", "正绿芰擎霜，黄花招雨。", "雁外渔村，蛩边蟹舍，绛叶满秋来路。", "世事不离双鬓，远梦偏欺孤旅。", "送望眼，但凭舷微笑，书空无语。", "慵觑。", "清镜里，十载征尘，长把朱颜污。", "借箸青油，挥毫紫塞，旧事不堪重举。", "间阔故山猿鹤，冷落同盟鸥鹭。", "倦游也，便樯云柁月，浩歌归去。"]'),
('song-ci-157','酹江月・念奴娇','熊大经','宋','宋词','song-ci','酹江月・念奴娇','[]','人生八十，自儿时祝愿，这般年数。',120,'宋词/ci.song.15000.json','["人生八十，自儿时祝愿，这般年数。", "滴露研朱轻点笔，个个眉心丹字。", "萱草丛边，梅花香里，真有人如此。", "红颜青鬓，儿时依旧相似。", "堪笑生子愚痴，投身枳棘，欲了官中事。", "万叠关山遥望眼，遐瞬白云飞处。", "膝下称觞，门前问寝，幸有嵩谟子。", "更望此去，十分好学彭祖。"]'),
('song-ci-158','喜迁莺','张□□','宋','宋词','song-ci','喜迁莺','[]','英声初发。',125,'宋词/ci.song.15000.json','["英声初发。", "记舍选齐驱，祖鞭先著。", "风月平分，尊罍谈旧，各已苍颜白发。", "屈指待拚一醉，祝生申嵩岳。", "怎知道，为清湘□润，暂移贤杰。", "休说。", "予心渴，里巷争先，拟持杯阶闼。", "毕竟人间，赏心乐事，种种尽归缘法。", "拈取瑞香一瓣，爇向湘山名刹。", "无量寿，和一身见在，两尊菩萨。"]'),
('song-ci-159','失调名','赵某','宋','宋词','song-ci','失调名','[]','□□□□皆乃，□□流垂□，断崖依旧横碧。',82,'宋词/ci.song.15000.json','["□□□□皆乃，□□流垂□，断崖依旧横碧。", "□□独有千古文章，铿鍧炳耀，不与名□。", "□□□□□□，□□□□，□尽□□远□。", "□□□□□□，不□□拳石。", "举杯相属，坐还有此客。"]'),
('song-ci-160','壶中天・念奴娇','翁定','宋','宋词','song-ci','壶中天・念奴娇','[]','昔时彭祖，闻道有、八百穹崇遐寿。',120,'宋词/ci.song.15000.json','["昔时彭祖，闻道有、八百穹崇遐寿。", "屈指我公今几许，历岁才方七九。", "七百修龄，更三十七，犹是公之有。", "此逢诞节，盍须来献尊酒。", "好是子舍孙枝，居官领荐，迭复青毡旧。", "陶令解龟何太早，去作幔亭仙友。", "只恐九重，思贤梦觉，未屈调羹手。", "周公居左，鲁公还是居右。"]'),
('song-ci-161','菩萨蛮','留元崇','宋','宋词','song-ci','菩萨蛮','[]','江头日落孤帆起。',52,'宋词/ci.song.15000.json','["江头日落孤帆起。", "归心拍拍东流水。", "山远不知名。", "为谁迢递青。", "危桥来处路。", "尚带潇湘雨。", "楚尾与吴头。", "一生离别愁。"]'),
('song-ci-162','酹江月・念奴娇','沈刚孙','宋','宋词','song-ci','酹江月・念奴娇','[]','我来访古。',120,'宋词/ci.song.15000.json','["我来访古。", "把尘襟、都付一声鸣橹。", "笑把瑶觞波浩荡，却忆长鲸吞吐。", "坐挹高风，骨清毛冷，不作嚣尘语。", "客星何在，谩留遗像江渚。", "试问泽畔羊裘，当时何事，笑禹弇宫武。", "金印貂禅谁不爱，只为汉颜巢许。", "幸有高台，较他箕颍，未肯轻输与。", "酒酣长啸，翩然谁共飞举。"]'),
('song-ci-163','念奴娇','王澜','宋','宋词','song-ci','念奴娇','["\u957f\u6c5f"]','凭高远望，见家乡、只在白云深处。',121,'宋词/ci.song.15000.json','["凭高远望，见家乡、只在白云深处。", "镇日思归归未得，孤负殷勤杜宇。", "故国伤心，新亭泪眼，更洒潇潇雨。", "长江万里，难将此恨流去。", "遥想江口依然，鸟啼花谢，今日谁为主。", "燕子归来，雕梁何处，底事呢喃语。", "最苦金沙，十万户尽，作血流漂杵。", "横空剑气，要当一洗残虏。"]'),
('song-ci-164','满江红','吴潜','宋','宋词','song-ci','满江红','[]','红玉阶前，问何事、翩然引去。',114,'宋词/ci.song.15000.json','["红玉阶前，问何事、翩然引去。", "湖海上、一汀鸥鹭，半帆烟雨。", "报国无门空自怨，济时有策从谁吐。", "过垂虹亭下系扁舟，鲈堪煮。", "拚一醉，留君住。", "歌一曲，送君路。", "遍江南江北，欲归何处。", "世事悠悠浑未了，年光冉冉今如许。", "试举头、一笑问青天，天无语。"]'),
('song-ci-165','满江红','吴潜','宋','宋词','song-ci','满江红','[]','露驿星程，又还控、西风征辔。',115,'宋词/ci.song.15000.json','["露驿星程，又还控、西风征辔。", "原自有、孔璋书檄，元龙豪气。", "蜀道尚惊鼙鼓后，神州正在干戈里。", "佐元戎，一柱稳擎天，襄之水。", "功名事，山林计。", "人易老，时难值。", "看新丝一发，甚吾衰矣。", "转首从游十五载，关心契阔三千里。", "便秋空、边雁落江南，书来未。"]'),
('song-ci-166','满江红','吴潜','宋','宋词','song-ci','满江红','[]','十二年前，曾上到、绣春台顶。',115,'宋词/ci.song.15000.json','["十二年前，曾上到、绣春台顶。", "双脚健、不烦筇杖，透岩穿岭。", "老去渐消狂气习，重来依旧佳风景。", "想牧之、千载尚神游，空山冷。", "山之下，江流水。", "江之外，淮山暝。", "望中原何处，虎狼犹梗。", "句蠡规模非浅近，石苻事业真俄顷。", "问古今、宇宙竟如何，无人省。"]'),
('song-ci-167','满江红','吴潜','宋','宋词','song-ci','满江红','[]','万里西风，吹我上、滕王高阁。',115,'宋词/ci.song.15000.json','["万里西风，吹我上、滕王高阁。", "正槛外、楚山云涨，楚江涛作。", "何处征帆木末去，有时野鸟沙边落。", "近帘钩、暮雨掩空来，今犹昨。", "秋渐紧，添离索。", "天正远，伤飘泊。", "叹十年心事，休休莫莫。", "岁月无多人易老，乾坤虽大愁难著。", "向黄昏、断送客魂消，城头角。"]'),
('song-ci-168','满江红','吴潜','宋','宋词','song-ci','满江红','[]','柳带榆钱，又还过、清明寒食。',115,'宋词/ci.song.15000.json','["柳带榆钱，又还过、清明寒食。", "天一笑、满园罗绮，满城箫笛。", "花树得晴红欲染，远山过雨青如滴。", "问江南、池馆有谁来，江南客。", "乌衣巷，今犹昔。", "乌衣事，今难觅。", "但年年燕子，晚烟斜日。", "抖擞一春尘土债，悲凉万古英雄迹。", "且芳尊、随分趁芳时，休虚掷。"]'),
('song-ci-169','满江红','吴潜','宋','宋词','song-ci','满江红','[]','拟卜三椽，问何处、水回山曲。',115,'宋词/ci.song.15000.json','["拟卜三椽，问何处、水回山曲。", "朝暮景、清风当户，白云藏屋。", "更得四时瓶贮酒，未输一品腰围玉。", "待千章、手种未成阴，周遮绿。", "且休殢，陶令菊。", "也休羡，子猷竹。", "算百年一梦，谁荣谁辱。", "唤客烹茶闲话了，呼童取枕佳眠足。", "但晨香、一炷愿天公，时丰熟。"]'),
('song-ci-170','满江红','吴潜','宋','宋词','song-ci','满江红','[]','岳后湘灵，曾孕个、擎天人物。',115,'宋词/ci.song.15000.json','["岳后湘灵，曾孕个、擎天人物。", "临古岘、纶巾羽扇，笑驱胡羯。", "护塞十年高叔子，出师一表侪诸葛。", "有孤忠、分付与佳儿，真衣钵。", "刘家骥，驰空阔。", "薛家凤，飞横绝。", "比君家兄弟，可能豪杰。", "草木声名如电扫，毡裘心胆闻风折。", "待安排、江汉一篇诗，归来说。"]'),
('song-ci-171','满江红','吴潜','宋','宋词','song-ci','满江红','[]','细阅浮生，为甚底、区区碌碌。',115,'宋词/ci.song.15000.json','["细阅浮生，为甚底、区区碌碌。", "算只是、信缘随分，早寻归宿。", "造物小儿忺簸弄，翻云覆雨难擐触。", "谩一堆、岁月鬓边来，跳丸速。", "田二顷，非无粟。", "官四品，非无禄。", "更不知足后，待何时足。", "恰好园池原自有，近来新创三椽屋。", "且饥时、吃饭困时眠，平为福。"]'),
('song-ci-172','满江红','吴潜','宋','宋词','song-ci','满江红','[]','举世悠悠，何妨任、流行坎止。',115,'宋词/ci.song.15000.json','["举世悠悠，何妨任、流行坎止。", "算是处、鲜鱼羹饭，吃来都美。", "暇日扁舟清霅上，倦时一枕薰风里。", "试回头、堆案省文书，徒劳尔。", "南浦路，东溪水。", "离索恨，飘零意。", "况星星鬓影，近来如此。", "万事尽由天倒断，三才自有人撑抵。", "但多吟、康节醉中诗，频相寄。"]'),
('song-ci-173','满江红','吴潜','宋','宋词','song-ci','满江红','[]','岁岁登高，算难得、今年美景。',115,'宋词/ci.song.15000.json','["岁岁登高，算难得、今年美景。", "尽敛却、雨霾风障，雾沈云暝。", "远岫四呈青欲滴，长空一抹明於镜。", "更天教、老子放眉头，边烽静。", "数本菊，香能劲。", "数朵桂，香尤胜。", "向尊前一笑，几多清兴。", "安得便如彭泽去，不妨且作山翁酩。", "尽古今、成败共兴亡，都休省。"]'),
('song-ci-174','满江红','吴潜','宋','宋词','song-ci','满江红','[]','日薄寒空，正泽国、一汀霜叶。',115,'宋词/ci.song.15000.json','["日薄寒空，正泽国、一汀霜叶。", "过万里、西风塞雁，数声哀咽。", "耿耿有怀天可讯，悠悠此恨谁能说。", "倚阑干、老泪落关山，平芜隔。", "提短剑，腰长铗。", "昔壮志，今华发。", "有江湖征棹，水云深阔。", "要斩鼪鼯埋九地，可怜乌兔驰双辙。", "羡渠侬、健笔扫磨崖，文章别。"]'),
('song-ci-175','满江红','吴潜','宋','宋词','song-ci','满江红','[]','乍雨还晴，正轻暖轻寒帘幕。',114,'宋词/ci.song.15000.json','["乍雨还晴，正轻暖轻寒帘幕。", "时怅望、故人烟水，鹭翻鸥落。", "老去可堪离恨结，新来转觉吟情薄。", "况等闲、客里送年华，成挥霍。", "天一顾，西南角。", "人万里，风埃阔。", "笑长卿归蜀，锦衣徒著。", "不是等闲螳臂怒，也休刚道鸡声恶。", "但千年、往事误平凉，今番莫。"]'),
('song-ci-176','满江红','吴潜','宋','宋词','song-ci','满江红','[]','痴霭顽阴，风扫尽、安排今夕。',115,'宋词/ci.song.15000.json','["痴霭顽阴，风扫尽、安排今夕。", "便放出、一轮金镜，皎然虚碧。", "照彻肺肝明似水，是中空洞无他物。", "倚亭皋、搔首问天公，天应识。", "人共景，都非昔。", "君共我，俱成客。", "且相逢一笑，笙歌箫笛。", "老去可怜杯酒减，醉来谩把阑干拍。", "便明朝、烟水挂征帆，还相忆。"]'),
('song-ci-177','满江红','吴潜','宋','宋词','song-ci','满江红','[]','客子愁来，闲信马、到涵空阁。',115,'宋词/ci.song.15000.json','["客子愁来，闲信马、到涵空阁。", "谁为我、敛云收雾，青天为幕。", "八万顷湖如镜静，波神护断东南角。", "望孤帆、杳杳度微茫，山邀却。", "三塞外，纷狐貉。", "三径里，悲猿鹤。", "笑鸱夷老子，占他头著。", "正使百年能几许，看来万事难描摸。", "问吴王、池馆复何如，霜枫落。"]'),
('song-ci-178','满江红','吴潜','宋','宋词','song-ci','满江红','[]','试马东风，且来问、南枝消息。',115,'宋词/ci.song.15000.json','["试马东风，且来问、南枝消息。", "正小墅、几株斜倚，数花轻拆。", "自有山中幽态度，谁知世上真颜色。", "叹君家、五岭我双溪，俱成客。", "长塞管，孤城笛。", "天未晓，人犹寂。", "有几多心事，露清月白。", "好把寒英都放了，莫教春讯能占得。", "问竹篱、茅舍景如何，惟渠识。"]'),
('song-ci-179','满江红','吴潜','宋','宋词','song-ci','满江红','[]','借问如何，春能好、客怀偏恶。',115,'宋词/ci.song.15000.json','["借问如何，春能好、客怀偏恶。", "消遣底、闲言闲语，近都慵作。", "岁月从今休点检，江湖自古多流落。", "倚危亭、目断野云边，孤舟泊。", "人事改，人情薄。", "退后步，争先著。", "且开尊洗盏，为君斟酌。", "拂拭凤凰池上景，凄凉猿鹤山中约。", "更东阳、憔悴到腰围，浑如削。"]'),
('song-ci-180','哨遍','吴潜','宋','宋词','song-ci','哨遍','[]','在晋永和，癸丑暮春，初作兰亭会。',241,'宋词/ci.song.15000.json','["在晋永和，癸丑暮春，初作兰亭会。", "集众贤，临峻岭崇山，有茂林修竹流水。", "畅幽情，纵无管弦丝竹，一觞一咏佳天气。", "於宇宙之中，游心骋目，此娱信可乐只。", "念人生相与放形骸。", "或一室晤言襟抱开。", "静躁虽殊，当其可欣，不知老至。", "然倦复何之。", "情随事改悲相系。", "俯仰间遗迹，往往俱成陈矣。", "况约境变迁，终期於尽，修龄短景都能几。", "谩古换今移，时消物化，痛哉莫大生死。", "每临文吊往一兴嗟。", "亦自悼不能喻於怀。", "算彭殇、妄虚均尔。", "今之视昔如契，后视今犹昔。", "故聊叙录时人所述，概想世殊事异。", "后之来者览斯文，将悠然、有感於此。"]'),
('song-ci-181','水调歌头','吴潜','宋','宋词','song-ci','水调歌头','["\u957f\u6c5f"]','铁瓮古形势，相对立金焦。',114,'宋词/ci.song.15000.json','["铁瓮古形势，相对立金焦。", "长江万里东注，晓吹卷惊涛。", "天际孤云来去，水际孤帆上下，天共水相邀。", "远岫忽明晦，好景画难描。", "混隋陈，分宋魏，战孙曹。", "回头千载陈迹，痴绝倚亭皋。", "惟有汀边鸥鹭，不管人间兴废，一抹度青霄。", "安得身飞去，举手谢尘嚣。"]'),
('song-ci-182','水调歌头','吴潜','宋','宋词','song-ci','水调歌头','[]','皎月亦长有，今夜独娟娟。',114,'宋词/ci.song.15000.json','["皎月亦长有，今夜独娟娟。", "浮云万里收尽，人在水晶奁。", "矫首银河澄澈，搔首金风浩荡，毛发亦冷然。", "宇宙能空阔，磨蚁正回旋。", "倩渔翁，撑舴艋，柳阴边。", "垂纶下饵，须臾钓得两三鲜。", "唤客烹鱼酾酒，伴我高吟长啸，烂醉即佳眠。", "何用骖鸾去，已是地行仙。"]'),
('song-ci-183','水调歌头','吴潜','宋','宋词','song-ci','水调歌头','[]','宛水才停棹，一舸又澄江。',114,'宋词/ci.song.15000.json','["宛水才停棹，一舸又澄江。", "岩花篱蕊开遍，时节正重阳。", "唤起沙汀渔父，揽取一天秋色，无处不潇湘。", "有酒时鲸吸，醉里是吾乡。", "济时心，忧国志，问穹苍。", "是非得失，成败何用苦论量。", "年事飞乌奔兔，世事崩崖惊浪，此别意茫茫。", "但愿身强健，努力报君王。"]'),
('song-ci-184','水调歌头','吴潜','宋','宋词','song-ci','水调歌头','[]','才惜季方去，又更别元方。',114,'宋词/ci.song.15000.json','["才惜季方去，又更别元方。", "惊心天上双凤，接翅下高冈。", "万里瞿塘烟浪，一片昭亭云月，渺渺正相望。", "夜雨连风壑，此意独凄凉。", "杜鹃声，犹不住，搅离肠。", "黄鸡白酒，吾意归兴动江乡。", "人事纷纷难料，世事悠悠难说，何处问穹苍。", "肯落儿曹泪，一笑付沧浪。"]'),
('song-ci-185','水调歌头','吴潜','宋','宋词','song-ci','水调歌头','[]','勋业竟何许，日日倚危楼。',114,'宋词/ci.song.15000.json','["勋业竟何许，日日倚危楼。", "天风吹动襟袖，身世一轻鸥。", "山际云收云合，沙际舟来舟去，野意已先秋。", "很石痴顽甚，不省古今愁。", "郗兵强，韩舰整，说徐州。", "但怜吾衰久矣，此事恐悠悠。", "欲破诸公磊块，且倩一杯浇酹，休要问更筹。", "星斗阑干角，手摘莫惊不。"]'),
('song-ci-186','沁园春','吴潜','宋','宋词','song-ci','沁园春','[]','第一江山，无边境界，压四百州。',140,'宋词/ci.song.15000.json','["第一江山，无边境界，压四百州。", "正天低云冻，山寒木落，萧条楚塞，寂寞吴舟。", "白鸟孤飞，暮鸦群注，烟霭微茫锁戌楼。", "凭阑久。", "问匈奴未灭，底事菟裘。", "回头。", "祖敬何刘。", "曾解把功名谈笑收。", "算当时多少，英雄气概，到今惟有，废垅荒丘。", "梦里光阴，眼前风景，一片今愁共古愁。", "人间事，尽悠悠且且，莫莫休休。"]'),
('song-ci-187','沁园春','吴潜','宋','宋词','song-ci','沁园春','[]','落雁横空，乱鸦投树，孤村暮烟。',140,'宋词/ci.song.15000.json','["落雁横空，乱鸦投树，孤村暮烟。", "有渔翁拖网，牧儿戴笠，行从水畔，唱过山前。", "云阁还垂，雨低欲堕，何处行人唤渡船。", "萧萧处，更柴门草店，竹外松边。", "凄然。", "倚马停鞭。", "叹客袂征衫岁月迁。", "既不缘富贵，功名系绊，非因妻子，田宅萦牵。", "只有寸心，难忘斯世，磊块轮囷知者天。", "愁无奈，且三杯浊酒，一枕酣眠。"]'),
('song-ci-188','贺新郎','吴潜','宋','宋词','song-ci','贺新郎','["\u897f\u6e56"]','说著成凄楚。',142,'宋词/ci.song.15000.json','["说著成凄楚。", "正尘飞、岷峨滟澦，兔嗥孤舞。", "颇牧禁中留不住，弹压征西幕府。", "便一舸、月汀烟渚。", "四塞三关天样险，问何人、自辟鼪鼯路。", "成败事，几今古。", "荼䕷芍药春将暮。", "最无情、飘零柳絮，搅人离绪。", "屈指秋风吹雁信，应忆西湖夜雨。", "谩岁月、消磨如许。", "上下四方男子志，肯临歧、昵昵儿曹语。", "呼大白，为君举。"]'),
('song-ci-189','贺新郎','吴潜','宋','宋词','song-ci','贺新郎','[]','扑尽征衫气。',142,'宋词/ci.song.15000.json','["扑尽征衫气。", "小夷犹、尊罍杖履，踏开花事。", "邂逅山翁行乐处，何似乌衣旧里。", "叹芳草、舞台歌地。", "百岁光阴如梦断，算古今、兴废都如此。", "何用洒，儿曹泪。", "江南自有渔樵队。", "想家山、猿愁鹤怨，问人归未。", "寄语寒梅休放尽，留取三花两蕊。", "待老子、领些春意。", "皎皎风流心自许，尽何妨、瘦影横斜水。", "烦翠羽，伴醒醉。"]'),
('song-ci-190','贺新郎','吴潜','宋','宋词','song-ci','贺新郎','[]','可意人如玉。',142,'宋词/ci.song.15000.json','["可意人如玉。", "小帘栊、轻匀淡泞，道家装束。", "长恨春归无寻处，全在波明黛绿。", "看冶叶、倡条浑俗。", "比似江梅清有韵，更临风、对月斜依竹。", "看不足，咏不足。", "曲屏半掩青山簇。", "正轻寒、夜来花睡，半敧残烛。", "缥缈九霞光里梦，香在衣裳剩馥。", "又只恐、铜壶声促。", "试问送人归去后，对一奁、花影垂金粟。", "肠易断，倩谁续。"]'),
('song-ci-191','贺新郎','吴潜','宋','宋词','song-ci','贺新郎','[]','又是春残去。',142,'宋词/ci.song.15000.json','["又是春残去。", "倚东风、寒云淡日，堕红飘絮。", "燕社鸿秋人不问，尽管吴笙越鼓。", "但短发、星星无数。", "万事惟有彭泽醉，也何妨、袖卷长沙舞。", "身与世，只如许。", "阑干拍手闲情绪。", "便明朝、苍鸥白鹭，北山南浦。", "笑指午桥桥畔路，帘幕深深院宇。", "尚趁得、柳烟花雾。", "我亦故山猿鹤怨，问何时、归棹双溪渚。", "歌一曲，恨千缕。"]'),
('song-ci-192','贺新郎','吴潜','宋','宋词','song-ci','贺新郎','[]','烟树瓜洲岸。',141,'宋词/ci.song.15000.json','["烟树瓜洲岸。", "望旌旗、猎猎摇空，故人天远。", "不似沙鸥飞得渡，直到雕鞍侧畔。", "但徙倚、危阑目断。", "自古锺情须我辈，况人间、万事思量遍。", "涛似雪，风如箭。", "扬州十里朱帘卷。", "想桃根桃叶，依稀旧家庭院。", "谁把青红吹到眼，知有醉翁局段。", "便回首、舟移帆转。", "渺渺江波愁未了，正淮山、日暮云撩乱。", "阁酒盏，倚歌扇。"]'),
('song-ci-193','贺新郎','吴潜','宋','宋词','song-ci','贺新郎','[]','笑口开能几。',142,'宋词/ci.song.15000.json','["笑口开能几。", "把年年、芳情冶思，总抛闲里。", "桃杏枝头春才半，寒食清明又是。", "但岁月、飙飞川逝。", "回首秦楼双燕语，到如今、目断斜阳外。", "将往事，试重记。", "香罗尚有相思泪。", "算人生、新愁易积，旧欢难继。", "水上流红无觅处，还隔关山万里。", "但赢得、新来憔悴。", "昨夜东风颠狂后，想馀芳、尽是飘零底。", "词写就，倩谁寄。"]'),
('song-ci-194','满庭芳','吴潜','宋','宋词','song-ci','满庭芳','[]','漠漠春阴，疏疏春雨，鹁鸠唤起春眠。',118,'宋词/ci.song.15000.json','["漠漠春阴，疏疏春雨，鹁鸠唤起春眠。", "小园人静，独自倚秋千。", "又见飘红堕雪，芳径里、都是花钿。", "年年事，闲愁闲闷，挂在绿杨边。", "寻思，都遍了，功名竹帛，富贵貂蝉。", "但身为利锁，心被名牵。", "争似依山傍水，数椽外、二顷良田。", "无萦绊，炊粳酿秫，长是好花天。"]'),
('song-ci-195','满庭芳','吴潜','宋','宋词','song-ci','满庭芳','[]','春水溶溶，春山漠漠，淡烟浅罩轻笼。',118,'宋词/ci.song.15000.json','["春水溶溶，春山漠漠，淡烟浅罩轻笼。", "危楼阑槛，掠面小东风。", "又是飞花落絮，芳草暗、万绿成丛。", "闲徙倚，百年人事，都在画船中。", "故园，无恙否，一溪翠竹，两径苍松。", "更有鱼堪钓，有秫堪舂。", "底事尘驱物役，空回首、社燕秋鸿。", "功名已，萧骚短鬓，分付与青铜。"]'),
('song-ci-196','酹江月・念奴娇','吴潜','宋','宋词','song-ci','酹江月・念奴娇','[]','红尘飞骑，报元戎小队，踏青南陌。',120,'宋词/ci.song.15000.json','["红尘飞骑，报元戎小队，踏青南陌。", "雪浪堆边呼小渡，吴楚半江分坼。", "岁月惊心，风埃迷目，相对头俱白。", "杨花撩乱，可怜如此春色。", "谁道燕燕莺莺，多情犹自，认得年时客。", "重唱江南肠断句，为我满倾云液。", "画鼓舟移，金鞍人远，一饷烟波隔。", "斜阳冉冉，依然无限凄恻。"]'),
('song-ci-197','酹江月・念奴娇','吴潜','宋','宋词','song-ci','酹江月・念奴娇','[]','晓来窗外，正南枝初放，两花三蕊。',121,'宋词/ci.song.15000.json','["晓来窗外，正南枝初放，两花三蕊。", "千古春风头上立，羞退秾桃繁李。", "姑射神游，寿阳妆褪，色界尘都洗。", "竹扉松户，平生所寄聊耳。", "堪笑强说和羹，此君心事，指高山流水。", "陇驿凄凉，却怕被、哀角城头吹起。", "此处关情，为他凝伫，淡月清霜里。", "巡檐何事，岁寒相誓而已。"]'),
('song-ci-198','酹江月・念奴娇','吴潜','宋','宋词','song-ci','酹江月・念奴娇','[]','半空楼阁，把江山图画，一时收拾。',120,'宋词/ci.song.15000.json','["半空楼阁，把江山图画，一时收拾。", "白鸟孤飞飞尽处，最好暮天秋碧。", "万里西风，百年人事，谩倚阑干拍。", "凝眸何许，扬州烟树历历。", "应念老子年来，浮名浮利，已作虚空掷。", "三径才寻归活计，又是飘零为客。", "回首平生，惊心双鬓，容易成凄恻。", "尊前一笑，且由醉帽敧侧。"]'),
('song-ci-199','八声甘州','吴潜','宋','宋词','song-ci','八声甘州','[]','任渠侬、造物自儿嬉。',118,'宋词/ci.song.15000.json','["任渠侬、造物自儿嬉。", "安能止吾归。", "有秋来竹径，春时花坞，夏里荷漪。", "何事东涂西抹，空遣鬓毛稀。", "矫首看鸿鹄，远举高飞。", "点检人间今古，问谁为赢局，底是输棋。", "谩区区成败，蚁阵与蜗围。", "便掀天卷地勋业，怕山中、拍手笑希夷。", "如何是，一尊相属，万事休知。"]'),
('song-ci-200','八声甘州','吴潜','宋','宋词','song-ci','八声甘州','[]','记高冈、两凤揽朝晖，翩翻万里来。',119,'宋词/ci.song.15000.json','["记高冈、两凤揽朝晖，翩翻万里来。", "向槐厅深处，松厅紧里，却立徘徊。", "一舸风帆烟浪，拟竖锦江桅。", "聊为玄晖老，共拂尘埃。", "我亦归来岩壑，正不妨散诞，笑口频开。", "算人间成败，何用苦惊猜。", "便江南、求田问舍，把岁寒、三友一圈栽。", "今宵酒，只消鲸吸，不要论杯。"]'),
('song-ci-201','二郎神','吴潜','宋','宋词','song-ci','二郎神','[]','小楼向晚，正柳锁、一城烟雨。',129,'宋词/ci.song.15000.json','["小楼向晚，正柳锁、一城烟雨。", "记十里吴山，绣帘朱户，曾学宫词内舞。", "浪逐东风无人管，但脉脉、岁移年度。", "嗟往事未尘，新愁还织，怎堪重诉。", "凝伫。", "问春何事，飞红飘絮。", "纵杜曲秦川，旧家都在，谁寄音书说与。", "野草凄迷，暮云深黯，浑自替人无绪。", "珠泪滴，应把寸肠万结，夜帷深处。"]'),
('song-ci-202','解连环','吴潜','宋','宋词','song-ci','解连环','[]','彩桡芳苑。',132,'宋词/ci.song.15000.json','["彩桡芳苑。", "嗟东风梦断，燕残莺懒。", "谩记得、标格精神，正云涨暮天，雨荒闲馆。", "嫩绿殷红，但回首、一川波暖。", "想娇情慧态，倚褪淡妆，画楼帘卷。", "吴歌数声冉冉。", "料移商变羽，人共天远。", "须信道、飞絮游丝，尽春去春来，景色偷换。", "扫罢蛮笺，难寄我、浓愁深怨。", "且如今，问龟问卜，望伊意转。"]'),
('song-ci-203','汉宫春','吴潜','宋','宋词','song-ci','汉宫春','[]','楼观齐雪，正霜明天净，一雁高飞。',118,'宋词/ci.song.15000.json','["楼观齐雪，正霜明天净，一雁高飞。", "江南倦客徙倚，目断双溪。", "凭阑自语，算从来、总是儿痴。", "青镜里，数丝点鬓，问渠何事忘归。", "幸有三椽茅屋，更小园随分，秋实春菲。", "几多清风皎月，美景良时。", "陶贤乐圣，尽由他、歧路危机。", "须信道，功名富贵，大都磨蚁醯鸡。"]'),
('song-ci-204','祝英台近','吴潜','宋','宋词','song-ci','祝英台近','[]','碧云开，红日丽，宫柳碎繁影。',95,'宋词/ci.song.15000.json','["碧云开，红日丽，宫柳碎繁影。", "犹记朝回，马兀梦频醒。", "天教一舸江湖，数椽涧壑，渐摆脱、世间尘境。", "已深省。", "添买竹坞千畦，荷漪两三顷。", "鹤引禽伸，日月峤壶永。", "不须瓮里思量，隙中驰骛，也莫管、玉关风景。"]'),
('song-ci-205','祝英台近','吴潜','宋','宋词','song-ci','祝英台近','[]','雾霏霏，云漠漠，新绿涨幽浦。',95,'宋词/ci.song.15000.json','["雾霏霏，云漠漠，新绿涨幽浦。", "梦里家山，春透一犁雨。", "伤心塞雁回来，问人归未，怎知道、蜗名留住。", "镜中觑。", "近年短发难簪，丝丝不禁数。", "蕙帐尘侵，凄切共谁语。", "被他轻暖轻寒，将人憔悴，正闷里、梅花残去。"]'),
('song-ci-206','祝英台近','吴潜','宋','宋词','song-ci','祝英台近','[]','旋安排，新捻合，莺谷共烟浦。',95,'宋词/ci.song.15000.json','["旋安排，新捻合，莺谷共烟浦。", "好处偏悭，一向风和雨。", "今朝捱得晴明，拖条藜杖，一齐把、春光黏住。", "且闲觑。", "水边行过幽亭，修竹净堪数。", "百舌楼罗，渐次般言语。", "从今排日追游，留连光景，但管取、笼灯归去。"]'),
('song-ci-207','摸鱼儿','吴潜','宋','宋词','song-ci','摸鱼儿','[]','满园林、瘦红肥绿，休休春事无几。',140,'宋词/ci.song.15000.json','["满园林、瘦红肥绿，休休春事无几。", "杜鹃唤起三更梦，窗外露澄风细。", "浑不寐。", "但目看、一帘夜月移花未。", "推衾自起。", "念岁月如流，容颜不驻，镜里留无计。", "人间事。", "休说贱贫富贵。", "天公长把人戏。", "萧裴曹郭今何在，空有旧闻千纸。", "君谩试。", "数青史荣名，到底三无二。", "浮生似寄。", "争似得江湖，烟蓑雨笠，不被蜗蝇系。"]'),
('song-ci-208','喜迁莺','吴潜','宋','宋词','song-ci','喜迁莺','[]','良辰佳节。',126,'宋词/ci.song.15000.json','["良辰佳节。", "问底事，十番九番为客。", "景物春妍，莺花日闹，自是情怀今别。", "只有思归魂梦，却怕杜鹃啼歇。", "消凝处，正丝杨冉冉，寸肠千折。", "谩说。", "临曲水，修竹茂林，人境成双绝。", "俯仰俱陈，彭殇等幻，何许世殊时隔。", "倚楼碧云日暮，漠漠远山千叠，沈醉好，又城头画角，一声声咽。"]'),
('song-ci-209','千秋岁','吴潜','宋','宋词','song-ci','千秋岁','[]','水晶宫里。',87,'宋词/ci.song.15000.json','["水晶宫里。", "有客闲游戏。", "溪漾绿，山横翠。", "柳纾阴不断，荷递香能细。", "撑小艇，受风多处披襟睡。", "回首看朝市。", "名利人方醉。", "蜗角上，争荣悴。", "大都由命分，枉了劳心计。", "归去也，白云一片愁空外。"]'),
('song-ci-210','声声慢','吴潜','宋','宋词','song-ci','声声慢','[]','挨晴拶暖，载酒呼朋，夷犹东圃西园。',119,'宋词/ci.song.15000.json','["挨晴拶暖，载酒呼朋，夷犹东圃西园。", "绿萼枝头，两三初破轻寒。", "平生自甘寂寞，占冷妆、不为人妍。", "林逋去，问疏影香暗，谁赋其间。", "空想故山奇事，正烟横岭曲，月浸溪湾。", "杏错桃讹，那时青子都圆。", "惟饶梦窗知处，对翠禽、依约神仙。", "休引角，怕征人、泪落塞边。"]'),
('song-ci-211','青玉案','吴潜','宋','宋词','song-ci','青玉案','[]','黄昏先自无情绪。',80,'宋词/ci.song.15000.json','["黄昏先自无情绪。", "更几阵、风和雨。", "闲把楼头更点数。", "挑残灯烬，装成香缕。", "此际凭谁诉。", "新词旧曲歌还住。", "欲说相思渺无处。", "围定寒炉人不语。", "暗蛩啾唧，征鸿嘹唳，憔悴都如许。"]'),
('song-ci-212','青玉案','吴潜','宋','宋词','song-ci','青玉案','[]','人生南北如歧路。',80,'宋词/ci.song.15000.json','["人生南北如歧路。", "惆怅方回断肠句。", "四野碧云秋日暮。", "苇汀芦岸，落霞残照，时有鸥来去。", "一杯渺渺怀今古。", "万事悠悠付寒暑。", "青箬绿蓑便野处。", "有山堪采，有溪堪钓，归计聊如许。"]'),
('song-ci-213','江城子','吴潜','宋','宋词','song-ci','江城子','[]','家园十亩屋头边。',86,'宋词/ci.song.15000.json','["家园十亩屋头边。", "正春妍。", "酿花天。", "杨柳多情，拂拂带轻烟。", "别馆闲亭随分有，时策杖，小盘旋。", "采山钓水美而鲜。", "饮中仙。", "醉中禅。", "闲处光阴，赢得日高眠。", "一品高官人道好，多少事，碎心田。"]'),
('song-ci-214','鹧鸪天','吴潜','宋','宋词','song-ci','鹧鸪天','[]','去日春山淡翠眉。',64,'宋词/ci.song.15000.json','["去日春山淡翠眉。", "到家恰好整寒衣。", "人归玉垒天应惜，舟过松江月半垂。", "千万绪，两三卮。", "送君不忍与君违。", "书来频寄西边讯，是我江南愁断时。"]'),
('song-ci-215','南柯子・南歌子','吴潜','宋','宋词','song-ci','南柯子・南歌子','[]','池水凝新碧，阑花驻老红。',62,'宋词/ci.song.15000.json','["池水凝新碧，阑花驻老红。", "有人独立画桥东。", "手把一枝杨柳、系春风。", "鹊绊游丝坠，蜂拈落蕊空。", "秋千庭院小帘栊。", "多少闲情闲绪、雨声中。"]'),
('song-ci-216','踏莎行','吴潜','宋','宋词','song-ci','踏莎行','[]','红药将残，绿荷初展。',68,'宋词/ci.song.15000.json','["红药将残，绿荷初展。", "森森竹里闲庭院。", "一炉香烬一瓯茶，隔墙听得黄鹂啭。", "陌上春归，水边人远。", "尽将前事思量遍。", "流光冉冉为谁忙，小桥伫立斜阳晚。"]'),
('song-ci-217','糖多令・唐多令','吴潜','宋','宋词','song-ci','糖多令・唐多令','[]','白鹭立孤汀。',74,'宋词/ci.song.15000.json','["白鹭立孤汀。", "行人长短亭。", "正垂杨、芳草青青。", "岁月尽抛尘土里，又隔日、是清明。", "日暮碧云生。", "魂伤老泪横。", "算浮生、较甚浮名。", "万事不禁双鬓改，谁念我、此时情。"]'),
('song-ci-218','谒金门','吴潜','宋','宋词','song-ci','谒金门','[]','溪边屋。',53,'宋词/ci.song.15000.json','["溪边屋。", "不浅不深团簇。", "野树平芜秋满目。", "有人闲意足。", "旋唤一尊醽醁。", "菱芡煮来新熟。", "归去来辞歌数曲。", "醉时无检束。"]'),
('song-ci-219','谒金门','吴潜','宋','宋词','song-ci','谒金门','[]','东风恶。',53,'宋词/ci.song.15000.json','["东风恶。", "一片梅花吹落。", "独上小楼闲濩索。", "云垂天四角。", "春自於人如昨。", "人自於春难托。", "惆怅光阴虚过却。", "情怀无处著。"]'),
('song-ci-220','谒金门','吴潜','宋','宋词','song-ci','谒金门','[]','庭垂箔。',53,'宋词/ci.song.15000.json','["庭垂箔。", "数点杨花飞落。", "倚遍阑干人寂寞。", "闲铺棋一角。", "客里春寒偏觉。", "睡起春衫偏薄。", "想得故山猿共鹤。", "笑人身计错。"]'),
('song-ci-221','鹊桥仙','吴潜','宋','宋词','song-ci','鹊桥仙','[]','扁舟昨泊，危亭孤啸，目断闲云千里。',68,'宋词/ci.song.15000.json','["扁舟昨泊，危亭孤啸，目断闲云千里。", "前山急雨过溪来，尽洗却、人间暑气。", "暮鸦木末，落凫天际，都是一团秋意。", "痴儿呆女贺新凉，也不道、西风又起。"]'),
('song-ci-222','更漏子','吴潜','宋','宋词','song-ci','更漏子','[]','柳初眠，花正好。',58,'宋词/ci.song.15000.json','["柳初眠，花正好。", "又被雨催风恼。", "红满地，绿垂堤。", "杜鹃和恨啼。", "对残春，消永昼。", "乍暖乍寒时候。", "人独自，倚危楼。", "夕阳多少愁。"]'),
('song-ci-223','海棠春','吴潜','宋','宋词','song-ci','海棠春','[]','天涯芳草迷征路。',58,'宋词/ci.song.15000.json','["天涯芳草迷征路。", "还又是、匆匆春去。", "乌兔里光阴，莺燕边情绪。", "云梢雾末，溪桥野渡，尽是春愁落处。", "把酒劝斜阳，小向花间驻。"]'),
('song-ci-224','卜算子','吴潜','宋','宋词','song-ci','卜算子','["\u897f\u6e56"]','春事到西湖，处处梅花笑。',52,'宋词/ci.song.15000.json','["春事到西湖，处处梅花笑。", "抖擞长安车马尘，眼底青山好。", "身世两悠悠，岁月间中老。", "极目烟波万顷愁，此意谁知道。"]'),
('song-ci-225','卜算子','吴潜','宋','宋词','song-ci','卜算子','[]','苕霅水能清，更有人如水。',52,'宋词/ci.song.15000.json','["苕霅水能清，更有人如水。", "秋水横边簇远山，相对盈盈里。", "溪上有鸳鸯，艇子频惊起。", "何似收归碧玉池，长在阑干底。"]'),
('song-ci-226','忆秦娥','吴潜','宋','宋词','song-ci','忆秦娥','[]','娇滴滴。',56,'宋词/ci.song.15000.json','["娇滴滴。", "婵娟影里赠横笛。", "曾横笛。", "一声肠断，一番愁织。", "隔墙频听无消息。", "龙吟海底难重觅。", "难重觅。", "梅花残了，杏花消得。"]'),
('song-ci-227','长相思','吴潜','宋','宋词','song-ci','长相思','[]','要相逢。',44,'宋词/ci.song.15000.json','["要相逢。", "恰相逢。", "画舫朱帘脉脉中。", "霎时烟霭重。", "怨东风。", "笑东风。", "落花飞絮两无踪。", "分付与眉峰。"]'),
('song-ci-228','长相思','吴潜','宋','宋词','song-ci','长相思','[]','燕高飞。',44,'宋词/ci.song.15000.json','["燕高飞。", "燕低飞。", "正是黄梅青杏时。", "榴花开数枝。", "梦归期。", "数归期。", "想见画楼天四垂。", "有人攒黛眉。"]'),
('song-ci-229','长相思','吴潜','宋','宋词','song-ci','长相思','["\u897f\u6e56"]','上帘钩。',44,'宋词/ci.song.15000.json','["上帘钩。", "下帘钩。", "夜半天街灯火收。", "有人曾倚楼。", "思悠悠。", "恨悠悠。", "只有西湖明月秋。", "知人如许悠。"]'),
('song-ci-230','柳梢青','吴潜','宋','宋词','song-ci','柳梢青','[]','衬步花茵，穿帘柳絮，堆地榆钱。',61,'宋词/ci.song.15000.json','["衬步花茵，穿帘柳絮，堆地榆钱。", "乍暖仍寒，欲晴还雨，春事都圆。", "午窗睡起厌厌。", "屋角外、初啼杜鹃。", "百种凄凉，几般烦恼，没个人怜。"]'),
('song-ci-231','柳梢青','吴潜','宋','宋词','song-ci','柳梢青','[]','断续残红，翩飞去鸟，别岸孤村。',61,'宋词/ci.song.15000.json','["断续残红，翩飞去鸟，别岸孤村。", "傍水楼台，满城钟鼓，又是黄昏。", "悠悠岁月如奔。", "正目断、边尘塞云。", "两鬓秋风，百年人事，无限消魂。"]'),
('song-ci-232','阮郎归','吴潜','宋','宋词','song-ci','阮郎归','[]','软风轻霭弄晴晖。',56,'宋词/ci.song.15000.json','["软风轻霭弄晴晖。", "鹁鸠相应啼。", "画堂人静画帘垂。", "阑干独倚时。", "闲拾句，困寻棋。", "沈吟心是非。", "荼䕷开遍柳花飞。", "惜春春不知。"]'),
('song-ci-233','诉衷情','吴潜','宋','宋词','song-ci','诉衷情','[]','几回相见见还休。',56,'宋词/ci.song.15000.json','["几回相见见还休。", "说著泪双流。", "又听画角呜咽，都和作、一团愁。", "云似絮，月如钩。", "忆凭楼。", "蕙兰情性，梅竹精神，长在心头。"]'),
('song-ci-234','霜天晓角','吴潜','宋','宋词','song-ci','霜天晓角','[]','云收雾辟。',53,'宋词/ci.song.15000.json','["云收雾辟。", "万里天空碧。", "舟过蛾眉亭下，景似旧、人非昔。", "年事如梭掷。", "世事如棋弈。", "抚掌扣舷一笑，今古恨、问谁得。"]'),
('song-ci-235','点绛唇','吴潜','宋','宋词','song-ci','点绛唇','[]','禁鼓三敲，参旗初挂阑干角。',50,'宋词/ci.song.15000.json','["禁鼓三敲，参旗初挂阑干角。", "浅屏疏箔。", "夜气侵已薄。", "欸乃吴歌，艇子当溪泊。", "休休莫。", "五湖烟浪，不是鸱夷错。"]'),
('song-ci-236','蝶恋花','吴潜','宋','宋词','song-ci','蝶恋花','[]','野树梅花香似扑。',70,'宋词/ci.song.15000.json','["野树梅花香似扑。", "小径穿幽，乐意天然足。", "回首人间名利局。", "大都一觉黄粱熟。", "别墅谁家屏簇簇。", "绮户疏窗，尚有藏春屋。", "镜断钗分何处续。", "伤心芳草庭前绿。"]'),
('song-ci-237','蝶恋花','吴潜','宋','宋词','song-ci','蝶恋花','[]','客枕梦回闻二鼓。',70,'宋词/ci.song.15000.json','["客枕梦回闻二鼓。", "冷落青灯，点滴空阶雨。", "一寸愁肠千万缕。", "更听切切寒蛩语。", "世事翻来还复去。", "造物儿戏，自古无凭据。", "利锁名缰空自苦。", "星星鬓影今如许。"]'),
('song-ci-238','天仙子','吴潜','宋','宋词','song-ci','天仙子','[]','百舌搬春春已透。',80,'宋词/ci.song.15000.json','["百舌搬春春已透。", "长驿短亭芳草昼。", "家山肠断欲归人，风宿留。", "船津候。", "一夜朱颜烦恼瘦。", "不用寻思闲宇宙。", "倦鸟入林云返岫。", "小园自有四时花，铺锦绣。", "锺醇酎。", "尽胜累累悬印绶。"]'),
('song-ci-239','如梦令','吴潜','宋','宋词','song-ci','如梦令','[]','插遍门前杨柳。',40,'宋词/ci.song.15000.json','["插遍门前杨柳。", "又是清明时候。", "岁月不饶人，鬓影星星知否。", "知否。", "知否。", "且尽一杯春酒。"]'),
('song-ci-240','如梦令','吴潜','宋','宋词','song-ci','如梦令','[]','昨日春衫初试。',40,'宋词/ci.song.15000.json','["昨日春衫初试。", "今日春寒犹殢。", "待得晚风收，独上危楼闲倚。", "闲倚。", "闲倚。", "目断半空烟水。"]'),
('song-ci-241','如梦令','吴潜','宋','宋词','song-ci','如梦令','[]','江上绿杨芳草。',40,'宋词/ci.song.15000.json','["江上绿杨芳草。", "想见故园春好。", "一树海棠花，昨夜梦魂飞绕。", "惊晓。", "惊晓。", "窗外一声啼鸟。"]'),
('song-ci-242','如梦令','吴潜','宋','宋词','song-ci','如梦令','[]','楼外残阳将暮。',40,'宋词/ci.song.15000.json','["楼外残阳将暮。", "江上孤帆何处。", "搔首立东风，又是少年情绪。", "凝伫。", "凝伫。", "一抹淡烟轻雾。"]'),
('song-ci-243','如梦令','吴潜','宋','宋词','song-ci','如梦令','[]','枝上蝶纷蜂闹。',40,'宋词/ci.song.15000.json','["枝上蝶纷蜂闹。", "几树杏花残了。", "幽鸟亦多情，片片闲归芳草。", "休扫。", "休扫。", "管甚落英还好。"]'),
('song-ci-244','如梦令','吴潜','宋','宋词','song-ci','如梦令','[]','镇日春阴漠漠。',40,'宋词/ci.song.15000.json','["镇日春阴漠漠。", "新燕乍穿帘幕。", "睡起不胜情，闲拾瑞香花萼。", "寂寞。", "寂寞。", "没个人人如昨。"]'),
('song-ci-245','如梦令','吴潜','宋','宋词','song-ci','如梦令','[]','庭院深深春寂。',40,'宋词/ci.song.15000.json','["庭院深深春寂。", "还是他乡寒食。", "闲利与闲名，谩把光阴虚掷。", "虚掷。", "虚掷。", "知道几时归得。"]'),
('song-ci-246','如梦令','吴潜','宋','宋词','song-ci','如梦令','[]','闲向园林点检。',40,'宋词/ci.song.15000.json','["闲向园林点检。", "又见小桃开遍。", "切莫便飘零，且为春光留恋。", "留恋。", "留恋。", "待我持杯深劝。"]'),
('song-ci-247','如梦令','吴潜','宋','宋词','song-ci','如梦令','[]','一饷园林绿就。',40,'宋词/ci.song.15000.json','["一饷园林绿就。", "柳外莺声初透。", "轻暖与轻寒，又是牡丹花候。", "花候。", "花候。", "岁岁年年人瘦。"]'),
('song-ci-248','如梦令','吴潜','宋','宋词','song-ci','如梦令','[]','雨过远山如洗。',40,'宋词/ci.song.15000.json','["雨过远山如洗。", "云散落霞如绮。", "嫩绿与残红，又是一般春意。", "春意。", "春意。", "只怕杜鹃催里。"]'),
('song-ci-249','望江南・忆江南','吴潜','宋','宋词','song-ci','望江南・忆江南','[]','家乡好，好处是三春。',64,'宋词/ci.song.15000.json','["家乡好，好处是三春。", "白白红红花面貌，丝丝袅袅柳腰身。", "锦绣底园林。", "行乐事，都付与闲人。", "挈榼携壶从笑傲，踏青挑菜恣追寻。", "赢得个天真。"]'),
('song-ci-250','望江南・忆江南','吴潜','宋','宋词','song-ci','望江南・忆江南','[]','家山好，好是夏初时。',64,'宋词/ci.song.15000.json','["家山好，好是夏初时。", "习习薰风回竹院，疏疏细雨洒荷漪。", "万绿结成帷。", "呼社友，长日共追随。", "瀹茗空时还酌酒，投壶罢了却围棋。", "多少得便宜。"]'),
('song-ci-251','望江南・忆江南','吴潜','宋','宋词','song-ci','望江南・忆江南','[]','家山好，好处是秋来。',64,'宋词/ci.song.15000.json','["家山好，好处是秋来。", "绿橘黄橙随市有，岩花篱菊逐时开。", "管与付尊罍。", "新筑就，别馆共闲台。", "摇手出离名利窟，掉头摆脱簿书堆。", "只在念头灰。"]'),
('song-ci-252','望江南・忆江南','吴潜','宋','宋词','song-ci','望江南・忆江南','[]','家山好，好处是三冬。',64,'宋词/ci.song.15000.json','["家山好，好处是三冬。", "梨栗甘鲜输地客，鲂鳊肥美献溪翁。", "醉滴小漕红。", "识破了，不用计穷通。", "下泽车安如驷马，市门卒稳似王公。", "一笑等鸡虫。"]'),
('song-ci-253','望江南・忆江南','吴潜','宋','宋词','song-ci','望江南・忆江南','[]','家山好，结屋在山椒。',64,'宋词/ci.song.15000.json','["家山好，结屋在山椒。", "无事琴书为伴侣，有时风月可招邀。", "安乐更相饶。", "伸脚睡，一枕日头高。", "不怕两衙催判事，那愁五鼓趣趋朝。", "此福要人消。"]'),
('song-ci-254','望江南・忆江南','吴潜','宋','宋词','song-ci','望江南・忆江南','[]','家山好，底事尚忘归。',64,'宋词/ci.song.15000.json','["家山好，底事尚忘归。", "但我醉荣还避辱，从渠把是却成非。", "跳出世关机。", "将五十，老相已相催。", "争得气来有甚底，更加官后亦何为。", "奉劝莫痴迷。"]'),
('song-ci-255','望江南・忆江南','吴潜','宋','宋词','song-ci','望江南・忆江南','[]','家山好，一室白云中。',64,'宋词/ci.song.15000.json','["家山好，一室白云中。", "时唤道人谈命蒂，也呼和尚说禅宗。", "孔佛老和同。", "淘汰尽，八面总玲珑。", "欲把捉时无把捉，道虚空后不虚空。", "且问主人公。"]'),
('song-ci-256','望江南・忆江南','吴潜','宋','宋词','song-ci','望江南・忆江南','[]','家山好，负郭有田园。',63,'宋词/ci.song.15000.json','["家山好，负郭有田园。", "蚕可充衣天赐予，耕能足食地周旋。", "骨肉尽团圆。", "旋五福，岁岁乐丰年。", "自养鸡豚腊里，新抽韭荠荐春前。", "活计不须添。"]'),
('song-ci-257','望江南・忆江南','吴潜','宋','宋词','song-ci','望江南・忆江南','[]','家山好，有底尚萦牵。',64,'宋词/ci.song.15000.json','["家山好，有底尚萦牵。", "马后乐听馀十载，眼前赤看也多年。", "滋味只如然。", "身外事，不用强探拈。", "自古几番成与败，从来百种丑和妍。", "细算不由贤。"]'),
('song-ci-258','望江南・忆江南','吴潜','宋','宋词','song-ci','望江南・忆江南','[]','家山好，好处是安居。',64,'宋词/ci.song.15000.json','["家山好，好处是安居。", "无事不须干郡县，有馀但管济乡闾。", "及早了王租。", "随日力，也著几般书。", "静里精神偏爽快，闲中光景越舒徐。", "腊月尽工夫。"]'),
('song-ci-259','望江南・忆江南','吴潜','宋','宋词','song-ci','望江南・忆江南','[]','家山好，无事挂心怀。',64,'宋词/ci.song.15000.json','["家山好，无事挂心怀。", "早课畦丁劝种菜，晚科园户漫浇花。", "祗此是生涯。", "尘世里，扰扰正如麻。", "散复聚来膻上蚁，左还右旋壁间蜗。", "只为那纷华。"]'),
('song-ci-260','望江南・忆江南','吴潜','宋','宋词','song-ci','望江南・忆江南','[]','家山好，百事尽如如。',64,'宋词/ci.song.15000.json','["家山好，百事尽如如。", "渴饮饥餐都属我，倒横直立总由渠。", "更不要贪图。", "三径里，恰好小茅庐。", "种竹梅松为老伴，养龟猿鹤助清娱。", "扣户有樵渔。"]'),
('song-ci-261','望江南・忆江南','吴潜','宋','宋词','song-ci','望江南・忆江南','[]','家山好，不是撰虚名。',64,'宋词/ci.song.15000.json','["家山好，不是撰虚名。", "世上盛衰常倚伏，天家日月也亏盈。", "退步是前程。", "且恁地，卷索了收绳。", "六宇五胡生口面，三言两语费颜情。", "赢得鬓星星。"]'),
('song-ci-262','望江南・忆江南','吴潜','宋','宋词','song-ci','望江南・忆江南','[]','家山好，凡事看来轻。',64,'宋词/ci.song.15000.json','["家山好，凡事看来轻。", "一壑尽由侬饾饤，三才不欠你称停。", "有耳莫闲听。", "静地里，点检这平生。", "著甚来由为皎皎，好无巴鼻弄醒醒。", "背后有人憎。"]'),
('song-ci-263','浪淘沙','吴潜','宋','宋词','song-ci','浪淘沙','[]','家在敬亭东。',64,'宋词/ci.song.15000.json','["家在敬亭东。", "老桧苍枫。", "浮生何必寄萍蓬。", "得似满庭芳一曲，美酒千锺。", "万事转头空。", "聚散匆匆。", "片帆稳挂晓来风。", "别后平安真信息，付与飞鸿。"]'),
('song-ci-264','浪淘沙','吴潜','宋','宋词','song-ci','浪淘沙','[]','长记去年时。',64,'宋词/ci.song.15000.json','["长记去年时。", "雪满征衣。", "佳人携手画楼西。", "今日关山千里外，此恨谁知。", "想见绿窗低。", "依旧空闺。", "惜春还是惜花飞。", "纵有游蜂偷得去，争似帘帷。"]'),
('song-ci-265','小重山','吴潜','宋','宋词','song-ci','小重山','[]','溪上秋来晚更宜。',70,'宋词/ci.song.15000.json','["溪上秋来晚更宜。", "夕阳西下处，碧云堆。", "谁家舟子采莲归。", "双白鹭，惊起背人飞。", "烟水渐凄迷。", "渔灯三数点，乍明时。", "西风一阵白苹湄。", "凝伫久，心事有谁知。"]'),
('song-ci-266','昭君怨','吴潜','宋','宋词','song-ci','昭君怨','[]','小雨霏微如线。',48,'宋词/ci.song.15000.json','["小雨霏微如线。", "人在暮秋庭院。", "衣袂带轻寒。", "睡初残。", "脉脉此情何限。", "惆怅光阴偷换。", "身世两沈浮。", "泪空流。"]'),
('song-ci-267','南乡子','吴潜','宋','宋词','song-ci','南乡子','["\u897f\u6e56"]','去岁牡丹时。',66,'宋词/ci.song.15000.json','["去岁牡丹时。", "几遍西湖把酒卮。", "一种姚黄偏韵雅，相宜。", "薄薄梳妆淡淡眉。", "回首绿杨堤。", "依旧黄鹂紫燕飞。", "人在天涯春在眼，凄迷。", "不比巫山尚有期。"]'),
('song-ci-268','虞美人','吴潜','宋','宋词','song-ci','虞美人','[]','美人一舸横秋水。',66,'宋词/ci.song.15000.json','["美人一舸横秋水。", "冉冉烟波里。", "绿杨也解织离愁。", "故向东风摇曳、不能休。", "是非得失都休计。", "只有抽身是。", "橙黄蟹熟正当时。", "想见双溪风月、待人归。"]'),
('song-ci-269','生查子','吴潜','宋','宋词','song-ci','生查子','[]','谁家白面郎，画舫朱帘挂。',48,'宋词/ci.song.15000.json','["谁家白面郎，画舫朱帘挂。", "十二列金钗，一局文楸罢。", "歌舞不知休，醉倒荷花下。", "归棹踏烟波，灯火芜城夜。"]'),
('song-ci-270','武陵春','吴潜','宋','宋词','song-ci','武陵春','[]','惨惨凄凄秋渐紧，风雨更潇潇。',58,'宋词/ci.song.15000.json','["惨惨凄凄秋渐紧，风雨更潇潇。", "强把炉薰寄寂寥。", "无语立亭皋。", "客路十年成底事，水国更停桡。", "苍鸟横飞过野桥。", "人不似、汝逍遥。"]'),
('song-ci-271','二郎神','吴潜','宋','宋词','song-ci','二郎神','[]','小亭徙倚，慢一步、立秋千影。',129,'宋词/ci.song.15000.json','["小亭徙倚，慢一步、立秋千影。", "渐夕照林梢，晚风池上，缉缉轻寒嫩冷。", "又是将他春僝僽，酿一种、花愁花病。", "空客鬓岁迁，征衫人老，倚楼看镜。", "还省。", "故园多少，紫殷红凝。", "窗外晓莺啼，抚墙金缕，烟柳慵眠乍醒。", "挑菜踏青，趁蜂随蝶，长负清明时景。", "凝伫久，蓦听棋边落子，一声声静。"]'),
('song-ci-272','满江红','吴潜','宋','宋词','song-ci','满江红','[]','为问人生，□要足、何时是足。',115,'宋词/ci.song.15000.json','["为问人生，□要足、何时是足。", "这个底、蜗名蝇利，但添拘束。", "便使积官居鼎鼎，假饶累富堆金玉。", "似浮埃、抹电转头空，休迷局。", "分已定，心能服。", "宛句畔，昭亭曲。", "有水多於竹，竹多於屋。", "闲看白云归岫去，静观倦鸟投林宿。", "那借来、拍板与门槌，休掀扑。"]'),
('song-ci-273','瑞鹤仙','吴潜','宋','宋词','song-ci','瑞鹤仙','[]','小亭山半枕。',127,'宋词/ci.song.15000.json','["小亭山半枕。", "又一番园林，春事整整。", "微阴护轻冷。", "早蜂狂蝶浪，褪黄消粉。", "阑干日永。", "数花飞、残崖断井。", "仗何人、说与东风，莫把老红吹尽。", "休省。", "烟江云嶂，楚尾吴头，自来多景。", "愁高怅远。", "身世事，但难准。", "况禁他，东兔西乌相逐，古古今今不问。", "算鸱夷、办却扁舟，个中杀稳。"]'),
('song-ci-274','贺新郎','吴潜','宋','宋词','song-ci','贺新郎','[]','一笑春无语。',142,'宋词/ci.song.15000.json','["一笑春无语。", "但园林、阴阴绿树，老红三数。", "底事东风犹自妒，片片狂飞乱舞。", "便燕懒、莺残初起。", "芍药荼䕷还又是，仗何人、说与司花女。", "将岁月，浪如许。", "悠悠倦客停江渚。", "寄扁舟、浮云荡月，棹烟帆雨。", "留得闲言闲语在，可是卿卿记取。", "待尽把、愁肠说与。", "泛梗浮萍无定准，怕吴鳞、楚雁成离阻。", "歌未了，恨如缕。"]'),
('song-ci-275','水调歌头','吴潜','宋','宋词','song-ci','水调歌头','[]','每怀天下士，要与共艰危。',114,'宋词/ci.song.15000.json','["每怀天下士，要与共艰危。", "谁知暗里摸索，得此世间奇。", "却笑当年坡老，过眼翻迷五色，遇合古难之。", "访我鸳湖上，真足慰心期。", "醉谈兵，愁论世，夜阑时。", "自怜磊块，近来鬓底两三丝。", "目送云帆西去，肠断风尘北起，老泪欲垂垂。", "骐骥思长坂，好鸟择高枝。"]'),
('song-ci-276','青玉案','吴潜','宋','宋词','song-ci','青玉案','[]','十年三过苏台路。',80,'宋词/ci.song.15000.json','["十年三过苏台路。", "还又是、匆匆去。", "迅景流光容易度。", "鹭洲鸥渚，苇汀芦岸，总是消魂处。", "苍烟欲合斜阳暮。", "付与愁人砌愁句。", "为问新愁愁底许。", "酒边成醉，醉边成梦，梦断前山雨。"]'),
('song-ci-277','水调歌头','吴潜','宋','宋词','song-ci','水调歌头','[]','榆塞脱忧责，兰径遂游嬉。',114,'宋词/ci.song.15000.json','["榆塞脱忧责，兰径遂游嬉。", "吾年逾六望七，休退已称迟。", "日日登山临水，夜夜早眠晏起，岂得不便宜。", "有酒数杯酒，无事一枰棋。", "休更□，世途恶，宦久羁。", "□深林密，去路人物两忘机。", "昨日既盟鸥鹭，今日又盟猿鹤，终久以为期。", "蜀魄不知我，犹道不如归。"]'),
('song-ci-278','水调歌头','吴潜','宋','宋词','song-ci','水调歌头','[]','有客抱幽独，高立万人头。',114,'宋词/ci.song.15000.json','["有客抱幽独，高立万人头。", "东湖千顷烟雨，占断几春秋。", "自有茂林修竹，不用买花沽酒，此乐若为酬。", "秋到天空阔，浩气与云浮。", "叹吾曹，缘五斗，尚迟留。", "练江亭下，长忆闲了钓鱼舟。", "矧更飘摇身世，又更奔腾岁月，辛苦复何求。", "咫尺桃源隔，他日拟重游。"]'),
('song-ci-279','满江红','吴潜','宋','宋词','song-ci','满江红','[]','唤出山来，把鸥鹭、盟言轻食。',115,'宋词/ci.song.15000.json','["唤出山来，把鸥鹭、盟言轻食。", "依旧是、江涛如许，雨帆烟笛。", "歌罢莫愁檀板缓，杯倾白堕琼酥滴。", "但惊心、十六载重来，征埃客。", "秋风鬓，应非昔。", "夜雨约，聊相觅。", "叹主恩未报，无多来日。", "故国千年龙虎势，神州万里鼪鼯迹。", "笑谢儿、出手便呼卢，摴蒱掷。"]'),
('song-ci-280','满江红','吴潜','宋','宋词','song-ci','满江红','[]','玛瑙冈头，左酾酒、右持螯食。',115,'宋词/ci.song.15000.json','["玛瑙冈头，左酾酒、右持螯食。", "怀旧处，磨东冶剑，弄清溪笛。", "望里尚嫌山是障，醉中要卷江无滴。", "这一堆、心事总成灰，苍波客。", "叹俯仰，成今昔。", "愁易揽，欢难觅。", "正平芜远树，落霞残日。", "自笑频招猿鹤怨，相期早混渔樵迹。", "把是非、得失与荣枯，虚空掷。"]'),
('song-ci-281','沁园春','吴潜','宋','宋词','song-ci','沁园春','[]','夜雨三更，有人敧枕，晓檐报晴。',140,'宋词/ci.song.15000.json','["夜雨三更，有人敧枕，晓檐报晴。", "算顽云痴雾，不难扫荡，青天白日，元自分明。", "权植油幢，聊张皂纛，坐听前驺鼓角鸣。", "君休诧，岂宣申南翰，成旦东征。", "鸿冥。", "哽噎秋声。", "正万里榆关未罢兵。", "幸扬州上督，为吾石友，荆州元帅，是我梅兄。", "约束鲸鲵，奠安鼪鼠，更使嵎夷海晏清。", "连宵看，怕天狼隐耀，太白沈枪。"]'),
('song-ci-282','沁园春','吴潜','宋','宋词','song-ci','沁园春','[]','笑指颓龄，循环雌甲，卦数已圆。',140,'宋词/ci.song.15000.json','["笑指颓龄，循环雌甲，卦数已圆。", "叹蜀公高洁，休官去岁，温公耆旧，入社今年。", "底事崎岖，苍颜白发，犹拥貔貅护海堧。", "君恩重，算何能报国，未许归田。", "遥怜。", "宛居山前。", "正水涨溪肥系钓船。", "纵葵榴花闹，菖蒲酒美，都成客里，争似家边。", "寄语儿曹，若为翁寿，只把鸥盟更要坚。", "翁还祝，愿欃枪日静，䆉稏云连。"]'),
('song-ci-283','沁园春','吴潜','宋','宋词','song-ci','沁园春','[]','二十年前，君王东顾，诏牧此州。',140,'宋词/ci.song.15000.json','["二十年前，君王东顾，诏牧此州。", "念昔时豪杰，犹难辟阖，如金老大，却更迟留。", "四载相望，三春又半，邂逅劭农得纵游。", "田畴事，是桑条正长，麦含初抽。", "悠悠。", "身世何求。", "算七十迎头合罢休。", "谩绕堤旌纛，牵连鹢棹，喧天鼓吹，断送龙舟。", "翠巘层边，碧云堆处，一担担来天外愁。", "如何好，且同斟绿醑，自课清讴。"]'),
('song-ci-284','宝鼎现','吴潜','宋','宋词','song-ci','宝鼎现','[]','晚风微动，净扫天地，云裾霞绮。',192,'宋词/ci.song.15000.json','["晚风微动，净扫天地，云裾霞绮。", "将海外、银蟾推上，相映华灯辉万砌。", "看舞队、向梅梢然昼，丹焰玲珑玉蕊。", "渐陆地、金莲吐遍，恰似楼台临水。", "老子欢意随人意。", "引红裙、钗宝钿翠。", "穿夜市、珠筵玳席。", "多少吴讴联越吹。", "绣幕卷、散缤纷香雾，笼定团圆锦里。", "认一点、星球挂也，士女桃源洞里。", "闻说旧日京华，般百戏、灯棚如履。", "待端门排宴，三五传宣禁侍。", "愿乐事、这回重见，喜庆新开起。", "瞻圣主、齐寿南山，势拱东南百二。"]'),
('song-ci-285','昼锦堂','吴潜','宋','宋词','song-ci','昼锦堂','[]','绮毂团成，珠玑搦就，极目灯火楼台。',122,'宋词/ci.song.15000.json','["绮毂团成，珠玑搦就，极目灯火楼台。", "七子八仙三教，耍队相挨。", "管箫笙簧相间斗，远如声韵碧霄来。", "环千炬，宝栅绛纱，云球雾衮交加。", "千里人笑乐，游妓合、脂尘香霭笼街。", "尽道今宵节物，天与安排。", "晚来风阵全收了，夜阑还放月儿些。", "休辞醉，长愿每年时候，一样情怀。"]'),
('song-ci-286','贺新郎','吴潜','宋','宋词','song-ci','贺新郎','[]','未是全衰暮。',142,'宋词/ci.song.15000.json','["未是全衰暮。", "但相思、昭亭数曲，水村烟墅。", "只比儿儿额上寿，尚有时光如许。", "况坎子、常交离午。", "须信火龙能陆战，更驱他、水虎蟠沧浦。", "昆仑顶，时飞度。", "东皇蓦向昆仑遇。", "道如今、金阶玉陛，待卿阔步。", "犹恐荆人攀恋切，未放征帆高举。", "怕公去、狐狸嗥舞。", "江汉一时谁作者，想声声、赞祝明良聚。", "天下久，望霖雨。"]'),
('song-ci-287','贺新郎','吴潜','宋','宋词','song-ci','贺新郎','[]','拍手阑干外。',142,'宋词/ci.song.15000.json','["拍手阑干外。", "想回头、人非物是，不知何世。", "万事情知都是梦，聊复推迁梦里。", "也幻出、云山烟水。", "白白红红虽褪尽，尽倡条、浪蕊皆春意。", "时可醉，醉扶起。", "瀛洲旧说神仙地。", "奈江南、猿啼鹤泪，怨怀如此。", "三五阿婆涂抹遍，多少残樱剩李。", "又过雨、亭皋初霁。", "惭愧故人相问讯，但一回、一见苍颜耳。", "谁念我，鹪鹩志。"]'),
('song-ci-288','贺新郎','吴潜','宋','宋词','song-ci','贺新郎','[]','宇宙原无外。',142,'宋词/ci.song.15000.json','["宇宙原无外。", "问当年、渠缘底事，强逃人世。", "争似刘郎栽种后，长恁玄都观里。", "何用羡、武陵溪水。", "一见桃花还一笑，领春工、千古无穷意。", "儿女恨，且收起。", "洞中空阔多闲地。", "但人间、羊肠九折，未能知此。", "我已衰翁君渐老，那复颠张醉李。", "看翻覆、雨阴风霁。", "捱得清和时候了，舣扁舟、只待归来耳。", "惟处静，解吾志。"]'),
('song-ci-289','贺新郎','吴潜','宋','宋词','song-ci','贺新郎','[]','了却儿痴外。',142,'宋词/ci.song.15000.json','["了却儿痴外。", "撰园林、亭台馆榭，谩当吾世。", "红楯朱桥相映带，人在百花丛里。", "更依约、垂杨衬水。", "桧柏芙蓉橙桂菊，也还须、收拾秋冬意。", "闲坐久，忽惊起。", "繁华寂寞千年地。", "便渊明、桃源记在，几人知此。", "双手上还银菟印，趁得东风行李。", "看鄮岭、鄞江澄霁。", "从此归欤无一欠，但君恩、天大难酬耳。", "嗟倦鸟，投林志。"]'),
('song-ci-290','贺新郎','吴潜','宋','宋词','song-ci','贺新郎','[]','雪鬓难重绿。',142,'宋词/ci.song.15000.json','["雪鬓难重绿。", "但け然、黄庭境界，抱藏龟六。", "也向无何乡里去，白堕舟边漾渌。", "算种种、尘缘都足。", "争那名缰犹系绊，尽辜他、猿鹤双溪曲。", "时又夏，暑将溽。", "虚舟飘瓦何烦歜。", "奈羊肠、千歧万折，近来纯熟。", "怅望老仙烟水外，惟把江云送目。", "想裴墅、碧梧金竹。", "安得结庐相近傍，买闲田、数亩躬耕筑。", "已梦断，大槐国。"]'),
('song-ci-291','贺新郎','吴潜','宋','宋词','song-ci','贺新郎','[]','燕子呢喃语。',141,'宋词/ci.song.15000.json','["燕子呢喃语。", "小园林、残红剩紫，已无三数。", "绿叶青枝成步障，空有蜂旋蝶舞。", "又宝扇、轻摇初暑。", "芳沼拳荷舒展尽，便回头、乱拥宫妆女。", "惊岁月，能多许。", "家山占断凫鸥渚。", "最相宜、岚烟水月，雾云霏雨。", "三岛十洲虽铁铸，难把归舟系取。", "且放我、渔樵为与。", "从此细斟昌歜酒，况神仙洞府无邀阻。", "何待结，长生缕。"]'),
('song-ci-292','贺新郎','吴潜','宋','宋词','song-ci','贺新郎','[]','碧沼横梅屋。',142,'宋词/ci.song.15000.json','["碧沼横梅屋。", "水平堤、双双翠羽，引雏偷浴。", "倚户无人深院静，犹忆棋敲嫩玉。", "还又是、朱樱初熟。", "手绾提炉香一炷，黯消魂、伫立阑干曲。", "闲转步，数修竹。", "新来有个眉峰蹙。", "自王姚、后魏都褪，只成愁独。", "凤带鸾钗宫样巧，争奈腰圈倦束。", "谩困倚、云鬟堆绿。", "淡月帘栊黄昏后，把灯花、印约休轻触。", "花烬落，泪珠簌。"]'),
('song-ci-293','贺新郎','吴潜','宋','宋词','song-ci','贺新郎','[]','宝扇驱纤暑。',142,'宋词/ci.song.15000.json','["宝扇驱纤暑。", "又凄凉、蒲觞菰忝，异乡重午。", "巧索从来无人系，惟对榴花自语。", "也何用、讴秦舞楚。", "生愧孟尝搀一日，叹三千、客汗挥成雨。", "如伯始，谩台傅。", "循环浩劫无终古。", "但坤牛、乾马抽换，是长生谱。", "安得笺天天便许，归炼金翁木父。", "问海运、争如穴处。", "一笑流行还坎止，算陈陈、往事俱灰土。", "南墅鹤，想思主。"]'),
('song-ci-294','暗香','吴潜','宋','宋词','song-ci','暗香','[]','晓霜一色。',120,'宋词/ci.song.15000.json','["晓霜一色。", "正恁时陇上，征人横笛。", "驿史不来，借问孤芳为谁折。", "休说和羹未晚，都付与、逋仙吟笔。", "算只是，野店疏篱，樵子共争席。", "寒圃，众籁寂。", "想暗里度香，万斛堆积。", "恼他鼻观，巡索还无最堪忆。", "萼绿堂前一笑，封老干、苔青莓碧。", "春漏也，应念我、要归未得。"]'),
('song-ci-295','疏影','吴潜','宋','宋词','song-ci','疏影','[]','佳人步玉。',134,'宋词/ci.song.15000.json','["佳人步玉。", "待月来弄影，天挂参宿。", "冷透屏帏，清入肌肤，风敲又听檐竹。", "前村不管深雪闭，犹自绕、枝南枝北。", "算平生、此段幽奇，占压百花曾独。", "闲想罗浮旧恨，有人正醉里，姝翠蛾绿。", "梦断魂惊，几许清凉，却是千林梅屋。", "鸡声野渡溪桥滑，又角引、戌楼悲曲。", "怎得知、清足亭边，自在杖藜巾幅。"]'),
('song-ci-296','暗香','吴潜','宋','宋词','song-ci','暗香','[]','雪来比色。',120,'宋词/ci.song.15000.json','["雪来比色。", "对澹然一笑，休喧笙笛。", "莫怪广平，铁石心肠为伊折。", "偏是三花两蕊，消万古、才人骚笔。", "尚记得，醉卧东园，天幕地为席。", "回首，往事寂。", "正雨暗雾昏，万种愁积。", "锦江路悄，媒聘音沈两空忆。", "终是茅檐竹户，难指望、凌烟金碧。", "憔悴了、羌管里，怨谁始得。"]'),
('song-ci-297','疏影','吴潜','宋','宋词','song-ci','疏影','[]','寒梢砌玉。',134,'宋词/ci.song.15000.json','["寒梢砌玉。", "把胆瓶顿了，相伴孤宿。", "寂寞幽窗，筛影横斜，宜松更自宜竹。", "残更蝶梦知何处，□只在、昭亭山北。", "问平生、雪压霜欺，得似老枝擎独。", "何事胭脂点染，认桃与辨杏，枝叶青绿。", "莫是冰姿，改换红妆，要近金门朱屋。", "繁华艳丽如飞电，但宛转、断歌零曲。", "且不如、藏白收香，旋学世间边幅。"]'),
('song-ci-298','暗香','吴潜','宋','宋词','song-ci','暗香','[]','澹然绝色。',120,'宋词/ci.song.15000.json','["澹然绝色。", "记故园月下，吹残龙笛。", "怅望楚云，日日归心大刀折。", "犹怕冰条冷蕊，轻点污、丹青凡笔。", "可怪底，屈子离骚，兰蕙独前席。", "院宇，深更寂。", "正目断古邗，暮霭凝积。", "何郎旧梦，四十馀年尚能忆。", "须索梅兄一笑，但矫首、层霄空碧。", "春在手、人在远，倩谁寄得。"]'),
('song-ci-299','疏影','吴潜','宋','宋词','song-ci','疏影','[]','嗤琼笑玉。',134,'宋词/ci.song.15000.json','["嗤琼笑玉。", "向画堂可肯，风露边宿。", "耐冻禁寒，便瘦宜枯，前生莫是孤竹。", "从来不上春工谱，梦不到、沈香亭北。", "算只消、澹影疏香，伴个幽栖人独。", "莫待痴蜂呆蝶，倩青女捺住，多少红绿。", "落雁寒芦，翠鸟冰枝，近傍三间茅屋。", "□□□□□□□，□□□、□□□□。", "想这般，夷旷襟怀，渺视乾员坤幅。"]'),
('song-ci-300','暗香','吴潜','宋','宋词','song-ci','暗香','[]','九垓共色。',120,'宋词/ci.song.15000.json','["九垓共色。", "想洛滨剑客，吹呼长笛。", "貏豸老松，别树平欺烂柯折。", "应是千官鹤舞，腾贺表、谁家椽笔。", "赐宴也，内劝宣来，真个是瑶席。", "休怪，巷陌寂。", "有一种可人，扫了还积。", "悲饥闭户，僵卧袁安我偏忆。", "凝望天童列嶂，谁大胆、偷藏遥碧。", "待问讯、清友看，怕难认得。"]'),
('song-ci-301','疏影','吴潜','宋','宋词','song-ci','疏影','[]','千门委玉。',134,'宋词/ci.song.15000.json','["千门委玉。", "是个人富贵，才隔今宿。", "冒栋摧檐，都未商量，呼童且伴庭竹。", "千蹊万径行踪灭，渺不认、溪南溪北。", "问白鸥，此际谁来，短艇钓鱼翁独。", "偏爱山茶雪里，放红艳数朵，衣素裳绿。", "兽炭金炉，羔酒金锺，正好笙歌华屋。", "敲冰煮茗风流衬，念不到、有人洄曲。", "但老农、欢笑相呼，麦被喜添全幅。"]'),
('song-ci-302','水龙吟','吴潜','宋','宋词','song-ci','水龙吟','[]','十洲三岛蓬壶，是花锦、一团装就。',127,'宋词/ci.song.15000.json','["十洲三岛蓬壶，是花锦、一团装就。", "轻车细辇，绮罗香里，夜光如昼。", "朱户笙箫，画楼帘幕，有人回首。", "想金莲灿烂，星球缥缈，那风景、年时旧。", "应念白头太守。", "怎红旗、六街穿透。", "铺排玳席，追陪珠履，且酾春酎。", "楚舞秦讴，半慵莺舌，叠翻鸳袖。", "把千门喜色，万家和气，祝君王寿。"]'),
('song-ci-303','永遇乐','吴潜','宋','宋词','song-ci','永遇乐','[]','和气熏来，这般光景，管无风雨。',128,'宋词/ci.song.15000.json','["和气熏来，这般光景，管无风雨。", "画栋朱甍，锦坊绣巷，娘子将嫫母。", "星球高挂，灯楼趱出，良夜正消增五。", "遨头事，牙旗铁马，且还那时鄞府。", "甘泉见说，捷书频奏，渐次不烦颦鼓。", "双凤云间，六鳌海上，祝赞齐手舞。", "三呼声里，君王万寿，岁岁传柑笑语。", "便都把，升平旧曲，腔儿旋补。"]'),
('song-ci-304','永遇乐','吴潜','宋','宋词','song-ci','永遇乐','[]','天上人间，这般光景，管无风雨。',129,'宋词/ci.song.15000.json','["天上人间，这般光景，管无风雨。", "绣户珠帘，锦坊花巷，戏队将嫫母。", "月扇团圆，星球灿烂，路偏市三街五。", "升平事，牙旗铁马，且还旧家藩府。", "三垂见说，凯歌频奏，渐次不烦颦鼓。", "双凤云间，六鳌尘外，想间都人欢舞。", "火城春近，金莲地市，消夜果边曾语。", "如今但，梅花纸帐，睡魔欠补。"]'),
('song-ci-305','永遇乐','吴潜','宋','宋词','song-ci','永遇乐','[]','祝告天公，放灯时节，且收今雨。',129,'宋词/ci.song.15000.json','["祝告天公，放灯时节，且收今雨。", "万户今门，六街三市，绽水晶云母。", "香车宝马，珠帘翠幕，不怕禁更敲五。", "霓裳曲，惊回好梦，误游紫宫朱府。", "沈思旧日京华，风景逗晓，犹听戏鼓。", "分镜圆时，断钗合处，倩笑歌与舞。", "如今闲院，蜂残蛾褪，消夜果边自语。", "亏人日煞，梅花纸帐，权将睡补。"]'),
('song-ci-306','隔浦莲・隔浦莲近拍','吴潜','宋','宋词','song-ci','隔浦莲・隔浦莲近拍','[]','兰桡环城数叠。',88,'宋词/ci.song.15000.json','["兰桡环城数叠。", "雾雨侵帘箔。", "翠竹交苍树，幽鸟声声如答。", "苇岸游绿鸭。", "暮山合。", "天际浓云罨，水周币。", "提携一醉，浊贤清圣欢洽。", "瀛洲美景，尽道东南都压。", "今日愁颜回笑颊。", "飞屧。", "且将萱草归插。"]'),
('song-ci-307','隔浦莲・隔浦莲近拍','吴潜','宋','宋词','song-ci','隔浦莲・隔浦莲近拍','[]','扇荷偷换羽葆。',89,'宋词/ci.song.15000.json','["扇荷偷换羽葆。", "院宇人声窈。", "独步亭皋下，阑干并、栖幽鸟。", "新雨抽嫩草。", "檐花闹。", "一片萍铺沼。", "燕雏小。", "书空底事，那堪手版持倒。", "今来古往，几见北邙人晓。", "乡号无何但日到。", "休觉。", "陶然身世尘表。"]'),
('song-ci-308','水调歌头','吴潜','宋','宋词','song-ci','水调歌头','[]','小队旌旗出，画鹢倚嵩竹。',114,'宋词/ci.song.15000.json','["小队旌旗出，画鹢倚嵩竹。", "青秧白水无际，中有一犁耕。", "听得田翁相语，今岁时年恰好，眨眼是秋成。", "老守何能解，持此报皇明。", "望家山，千里外，楚云平。", "良田二顷，非村非郭枕柴局。", "况有檐林香透，更有杨堤阴合，魂梦每宵征。", "巴得西风起，吾亦文前程。"]'),
('song-ci-309','水调歌头','吴潜','宋','宋词','song-ci','水调歌头','[]','老圃无关锁，放客意中行。',114,'宋词/ci.song.15000.json','["老圃无关锁，放客意中行。", "颇欣天地开阔，烟钓与云耕。", "荷长亭亭翠盖，竹长森森翠葆，景致闹装成。", "几树榴花发，映水色偏明。", "绮楼空，金屋静，恨难平。", "鼓笙潇笛，谁怜冷落暗尘局。", "回首百年人事，转眼几番今古，日迈月俱征。", "且尽一杯酒，退步是前程。"]'),
('song-ci-310','水调歌头','吴潜','宋','宋词','song-ci','水调歌头','[]','过了中秋后，今夜月方佳。',114,'宋词/ci.song.15000.json','["过了中秋后，今夜月方佳。", "看来前夜圆满，才自阙些些。", "扫尽乌云黑雾，放出青霄碧落，恰似我情怀。", "把酒自斟酌，脱落到形骸。", "问渠侬，分玉镜，断金钗。", "少年心事，不知容易鬓边华。", "千古天同此月，千古人同此兴，不是旋安排。", "安得高飞去，长以月为家。"]'),
('song-ci-311','水调歌头','吴潜','宋','宋词','song-ci','水调歌头','[]','重九先三日，领客上危楼。',114,'宋词/ci.song.15000.json','["重九先三日，领客上危楼。", "满城风雨都住，天亦相邀头。", "右手持杯满泛，左手持螯大嚼，萸菊互相酬。", "徒倚阑干角，一笑与云浮。", "望平畴，千万顷，稻粱收。", "江澄海晏无事，赢得小迟留。", "但恨流光抹电，假似年华七十，只有六番秋。", "戏马台休问，破帽已飕飕。"]'),
('song-ci-312','水调歌头','吴潜','宋','宋词','song-ci','水调歌头','[]','天宇正高爽，更蹑最高楼。',114,'宋词/ci.song.15000.json','["天宇正高爽，更蹑最高楼。", "长风为我驱驾，极目海山头。", "不用牛山孟浩，不用齐山杜牧，人景自堪酬。", "举酒酹空阔，汗漫与为游。", "拈黄花，怜白首，恨难收。", "颓龄使汝能制，何待更封留。", "眼底朱甍画栋，往往人非物是，蟋蟀自鸣秋。", "万里一搔首，无处著萧飕。"]'),
('song-ci-313','水调歌头','吴潜','宋','宋词','song-ci','水调歌头','[]','屯结海云阵，奋击藉雷公。',114,'宋词/ci.song.15000.json','["屯结海云阵，奋击藉雷公。", "忽然天宇轩豁，杲日正当空。", "照出榴花丹艳，映出栀花玉色，生意与人同。", "闭纵一翻手，造化不言功。", "想平畴，禾穟穟，黍芄芄。", "老农拍手相问，相劳笑声中。", "办取黄鸡白酒，演了山歌村舞，等得庆年丰。", "此际莼鲈客，倚楫待西风。"]'),
('song-ci-314','二郎神','吴潜','宋','宋词','song-ci','二郎神','[]','古稀近也，是六十五翁生日。',128,'宋词/ci.song.15000.json','["古稀近也，是六十五翁生日。", "恰就得端阳，艾人当户，朱笔书符大吉。", "卦气周来从新起，怕白发、苍颜难必。", "随见定性缘，餐饥眠困，喜无秋唧。", "盈溢。", "书生做到，能高官秩。", "况碌碌儿曹，望郎明郡，叨冒差除不一。", "积世主恩，满家天禄，婚嫁近来将毕。", "还自祝，愿早悬车里社，始为收拾。"]'),
('song-ci-315','二郎神','吴潜','宋','宋词','song-ci','二郎神','[]','近时厌雨，喜午日、放开天日。',129,'宋词/ci.song.15000.json','["近时厌雨，喜午日、放开天日。", "不用辟兵符，从今去也，管定千祥万吉。", "已报甘泉新捷到，况更是、年丰堪必。", "任景物换来，蛙鸣蝉噪，耳边𠿏唧。", "洋溢。", "尽教愿乞，兵厨闲秩。", "看恰好圆池，随宜亭榭，人道瀛洲压一。", "且恁浮沈，奈何衰悴，惟怕牧之名毕。", "安得去，占却三神绝顶，瑞芝同拾。"]'),
('song-ci-316','传言玉女','吴潜','宋','宋词','song-ci','传言玉女','[]','众绿亭前，都是郁葱佳气。',90,'宋词/ci.song.15000.json','["众绿亭前，都是郁葱佳气。", "越姬吴媛，粲珠钿翠珥。", "红消粉褪，几许粗桃凡李。", "连珠宝炬，两行缇骑。", "自笑衰翁，又行春锦绣里。", "禁肴宫酝，记当年宣赐。", "休嫌拖逗，且向画堂频醉。", "从今开庆，万欢千喜。"]'),
('song-ci-317','满江红','吴潜','宋','宋词','song-ci','满江红','[]','芳景无多，又还是、乱红飞坠。',115,'宋词/ci.song.15000.json','["芳景无多，又还是、乱红飞坠。", "空怅望、昭亭深处，家山桃李。", "柳眼花心都脱换，蜂须蝶翅难沾缀。", "谩相携、一笑竞良辰，春醪美。", "金兽艺，香风细。", "金凤拍，歌云腻。", "尽秦箫燕管，但逢场尔。", "只恐思乡情味恶，怎禁寒食清明里。", "问此翁、不止四宜休，翁归未。"]'),
('song-ci-318','满江红','吴潜','宋','宋词','song-ci','满江红','[]','聊把芳尊，殷勤勤、斜阳休坠。',115,'宋词/ci.song.15000.json','["聊把芳尊，殷勤勤、斜阳休坠。", "吾老矣，难从仙客，采丹丘李。", "且趁风光一百五，园林尚有残红缀。", "更忉忉、百舌对般春，生能美。", "鸾钗绊，游丝细。", "鸳袖惹，香尘腻。", "想吴姬越女，踏青才尔。", "争似江南樗枥社，俚歌声拂行云里。", "又枝头、梅子正酸时，莺知未。"]'),
('song-ci-319','满江红','吴潜','宋','宋词','song-ci','满江红','[]','楼观峥嵘，浑疑是、天风吹坠。',115,'宋词/ci.song.15000.json','["楼观峥嵘，浑疑是、天风吹坠。", "金屋窈，几时曾贮，粗桃凡李。", "镜断钗分人去后，画阑文砌苍苔缀。", "想当年、日日醉芳丛，侯鲭美。", "春水涨，鳞鳞细。", "春草暗，茸茸腻。", "算留连光景，古犹今尔。", "椿菌鸠鹏休较计，倚空一笑东风里。", "喜知时、好雨夜来稠，秧青未。"]'),
('song-ci-320','满江红','吴潜','宋','宋词','song-ci','满江红','[]','一笑相携，且休管、兔升乌坠。',115,'宋词/ci.song.15000.json','["一笑相携，且休管、兔升乌坠。", "那更是，可人宾客，未饶崔李。", "金叵罗中醽醁莹，玉玲珑畔歌珠缀。", "望湖光、一片浸韶光，真双美。", "云絮襞，能纤细。", "云彩聚，能黏腻。", "料出山归岫，等闲间尔。", "碧沚风流人去后，石窗景物春深里。", "算邯郸、客梦几惊残，炊犹未。"]'),
('song-ci-321','满江红','吴潜','宋','宋词','song-ci','满江红','[]','问海棠花，谁留恋、未教飘坠。',115,'宋词/ci.song.15000.json','["问海棠花，谁留恋、未教飘坠。", "真个好，一般标格，聘梅奴李。", "怯冷拟将苏幕护，怕惊莫把金铃缀。", "望铜梁、玉垒正春深，花空美。", "非粉饰，肌肤细。", "非涂泽，胭脂腻。", "恐人间天上，少其伦尔。", "西子颦收初雨后，太真浴罢微暄里。", "又明朝、杨柳插清明，鹃归未。"]'),
('song-ci-322','满江红','吴潜','宋','宋词','song-ci','满江红','[]','把手西园，有山色、波光相对。',115,'宋词/ci.song.15000.json','["把手西园，有山色、波光相对。", "金马客，明朝飞棹，水肥帆驶。", "问我年华旬并七，异乡时景春巴二。", "最堪怜、游子送行人，垂杨外。", "聊小小，旌旗队。", "聊且且，笙歌载。", "正冥濛烟雨，许多情态。", "南北枝头犹点缀，东西玉畔休辞避。", "待莼鲈、归思动西风，相携未。"]'),
('song-ci-323','满江红','吴潜','宋','宋词','song-ci','满江红','[]','斫却凡柯，放岩桂、出些头地。',115,'宋词/ci.song.15000.json','["斫却凡柯，放岩桂、出些头地。", "从此去，引风披露，畅条昌蕊。", "待得清香千万斛，且饶老子为知己。", "趁今宵、新月驾空来，浮觞里。", "刘安笑，淹留耳。", "吴猛约，何时是。", "想故山深处，翠垂金缀。", "须信人生归去好，他乡未必江山美。", "问钗头、十二意如何，非吾事。"]'),
('song-ci-324','满江红','吴潜','宋','宋词','song-ci','满江红','[]','试问平生，几番见、中秋明月。',115,'宋词/ci.song.15000.json','["试问平生，几番见、中秋明月。", "今老矣，一年紧似，一年时节。", "底事层阴生障碍，不教玉界冰壶彻。", "莫垣娥、嫌此白头翁，心肠别。", "风动处，浮云揭。", "云绽处，清光泄。", "倩何人扫荡，大家澄澈。", "且掉悲欢离合事，相逢只怕尊中竭。", "放儿童、今夜上清霄，探蟾穴。"]'),
('song-ci-325','满江红','吴潜','宋','宋词','song-ci','满江红','[]','丹桂重开，向此际、十分香足。',115,'宋词/ci.song.15000.json','["丹桂重开，向此际、十分香足。", "最好处，云为幕护，雨为膏沐。", "树杪层层如宝盖，枝头点点犹金粟。", "算人间、天上更无花，风流独。", "玉坛畔，仙娥簇。", "玉梁上，仙翁掬。", "叹吾今老矣，两难追逐。", "休把淹留成感慨，时间赏玩时闲福。", "怕今宵、芳景便凋零，高烧烛。"]'),
('song-ci-326','满江红','吴潜','宋','宋词','song-ci','满江红','[]','岁岁重阳，何曾是、两般时景。',115,'宋词/ci.song.15000.json','["岁岁重阳，何曾是、两般时景。", "人自有、悲欢离合，晦明朝暝。", "日月湖边来往艇，楼台水底参差影。", "又何妨、时暂狎沧波，轻鸥并。", "闲顿放，朱门静。", "新结裹，朱帘整。", "尽百年人事，移场换境。", "欲插黄花身已老，强倾绿醑心先醒。", "羡游鱼、有钓不能收，钩空饼。"]'),
('song-ci-327','满江红','吴潜','宋','宋词','song-ci','满江红','[]','安晚堂前，梅开尽、都无留萼。',115,'宋词/ci.song.15000.json','["安晚堂前，梅开尽、都无留萼。", "依旧是、铁心老子，故情堪托。", "长恐寿阳脂粉污，肯教摩诘丹青摸。", "纵沈香、为榭彩为园，难安著。", "高节耸，清名邈。", "翻李俗，粗桃恶。", "但山矾行辈，可来参错。", "六出不妨添羽翼，百花岂愿当头角。", "尽暗香、疏影了平生，何其乐。"]'),
('song-ci-328','满江红','吴潜','宋','宋词','song-ci','满江红','[]','犹记长安，共攀折、琼林仙萼。',115,'宋词/ci.song.15000.json','["犹记长安，共攀折、琼林仙萼。", "人已去，年年梅放，怨怀谁托。", "和靖吟魂应未醒，补之画手何能摸。", "更堪怜、老子此时来，愁难著。", "云昼晚，烟宵邈。", "春欲近，风偏恶。", "早阑干片片，飘零相错。", "邂逅聊拼花底醉，迟留莫管城头角。", "且起居、魏卫国夫人，闻安乐。"]'),
('song-ci-329','满江红','吴潜','宋','宋词','song-ci','满江红','[]','问信江梅，渐推出、红苞绿萼。',115,'宋词/ci.song.15000.json','["问信江梅，渐推出、红苞绿萼。", "堪爱处，平生怀抱，岁寒为托。", "瘦骨皱皮犹老硬，孤标独韵难描摸。", "怕东君、压住等春来，鞭先著。", "止渴事，风烟邈。", "和羹事，风波恶。", "想翠禽啁哳，笑他都错。", "争似花开颓醉玉，月天更引霜天角。", "便一年、强作十年人，山中乐。"]'),
('song-ci-330','满江红','吴潜','宋','宋词','song-ci','满江红','[]','寒食清明，叹人在、天涯海角。',116,'宋词/ci.song.15000.json','["寒食清明，叹人在、天涯海角。", "饶锦绣，十洲装就，只成离索。", "岁去已空莺燕侣，年来尽负鸥凫约。", "想南溪、溪水一篙深，孤舟泊。", "天向晚，东风恶。", "春向晚，花容薄。", "又荼縻架底，绿阴成幄。", "舴艋也闻钲鼓闹，秋千半当笙歌乐。", "问山公、倒载接�奈蓿�都休却。"]'),
('song-ci-331','满江红','吴潜','宋','宋词','song-ci','满江红','[]','钉饾残花，也随分、红红白白。',115,'宋词/ci.song.15000.json','["钉饾残花，也随分、红红白白。", "缘底事，春才好处，又成轻别。", "芳草凄迷归路远，子规更叫黄昏月。", "倚阑干、触处是浓愁，凭谁说。", "我不厌，尊罍挈。", "君莫放，笙歌彻。", "自河南丞相，有兹宾客。", "一笑何曾千古换，半醺便觉乾坤窄。", "怕转头、天际望归舟，江山隔。"]'),
('song-ci-332','满江红','吴潜','宋','宋词','song-ci','满江红','[]','午枕神游，晓鸡唱、城关偷度。',115,'宋词/ci.song.15000.json','["午枕神游，晓鸡唱、城关偷度。", "俄顷里、笋舆伊轧，征夫前路。", "路入江南天地阔，黄云翠浪千千亩。", "有皤翁、三五喜相迎，邻田父。", "旋策杖，寻幽圃。", "旋挈榼，陈高俎。", "疑此身归去，朱陵丹府。", "布谷数声惊梦断，纱窗小阵梅黄雨。", "把人间、万事一般看，投芳醑。"]'),
('song-ci-333','满江红','吴潜','宋','宋词','song-ci','满江红','[]','回首家园，竹多屋、水还多竹。',115,'宋词/ci.song.15000.json','["回首家园，竹多屋、水还多竹。", "那更是，千峰凝翠，一溪凝绿。", "多谢故人相问讯，奚奴步步收珠玉。", "叹暮林、飞鸟也知还，寻归宿。", "遍历了，岳与牧。", "享过了，官与禄。", "算平生万事，尽无不足。", "争奈乞身犹未可，只缘欠种清闲福。", "想瞿硎、仙子亦相思，山之隩。"]'),
('song-ci-334','念奴娇','吴潜','宋','宋词','song-ci','念奴娇','[]','一般妙质，笑乐天、夸诧小蛮樊素。',120,'宋词/ci.song.15000.json','["一般妙质，笑乐天、夸诧小蛮樊素。", "万炳参差罗翠扇，全队西方靓女。", "不假施朱，也非涂碧，所乐惟幽浦。", "神仙姑射，算来合共游处。", "一任冶妓秾姬，采莲歌里，尽是相思苦。", "花气荷馨清入骨，长傍银河东注。", "月澹风轻，雾晞烟细，忽洒霏微雨。", "此时心事，美人泽畔停伫。"]'),
('song-ci-335','念奴娇','吴潜','宋','宋词','song-ci','念奴娇','[]','为嫌涂抹，向万红丛里，澹然疑素。',120,'宋词/ci.song.15000.json','["为嫌涂抹，向万红丛里，澹然疑素。", "非粉非酥能样别，只是凌波仙女。", "隋沼浓妆，汉池冶态，争似沧浪浦。", "净鸥洁鹭，有时飞到佳处。", "梦绕太华峰巅，与天一笑，不觉跻攀苦。", "十丈藕船游汗漫，何惜浮生孤注。", "午鼓惊回，依然尘世，扑簌疏窗雨。", "起来寂寞，倚阑一饷愁伫。"]'),
('song-ci-336','念奴娇','吴潜','宋','宋词','song-ci','念奴娇','[]','白苹影里，向何人可话，平生心素。',120,'宋词/ci.song.15000.json','["白苹影里，向何人可话，平生心素。", "月魄冰魂凝结就，犹薄湘妃洛女。", "吴沼芙蓉，陈陂菡萏，散入玄珠浦。", "采花蜂蝶，雾深都忘归去。", "堪笑并蒂霞冠，双头酡脸，只为多情苦。", "空遣隔江游冶子，撩乱心飞目注。", "同出泥涂，独标玉质，不是曼陀雨。", "风清露冷，有人长自迟伫。"]'),
('song-ci-337','念奴娇','吴潜','宋','宋词','song-ci','念奴娇','["\u5e90\u5c71"]','天然皓质，想当年此种，来从太素。',120,'宋词/ci.song.15000.json','["天然皓质，想当年此种，来从太素。", "一点红尘都不染，罗列蟾宫玉女。", "色压薝林，香欺兰畹，肯向闻筝浦。", "灵龟千岁，有时游漾其处。", "应念社结庐山，翻嗤靖节，底事攒眉苦。", "纽叶为盘花当盏，有酒何妨频注。", "太液波边，昆明池上，岂必沾金雨。", "从教同辈，为他皦皦凝伫。"]'),
('song-ci-338','念奴娇','吴潜','宋','宋词','song-ci','念奴娇','[]','午飙褪暑，向绿阴深处，引杯孤酌。',120,'宋词/ci.song.15000.json','["午飙褪暑，向绿阴深处，引杯孤酌。", "啼鸟一声庭院悄，日影偷移朱箔。", "杏落金丸，荷抽碧筒，景物挨排却。", "虚檐长啸，世缘菌簟篔箨。", "休问雪藕丝蒲，佩兰钿艾，旧梦都高阁。", "惟有流莺当此际，舌弄笙簧如约。", "短棹双溪，么锄三径，归计犹谁托。", "料应猿鹤，近来都怨离索。"]'),
('song-ci-339','八声甘州','吴潜','宋','宋词','song-ci','八声甘州','[]','向鄞江、面熟是薰风，吹燕麦凫葵。',119,'宋词/ci.song.15000.json','["向鄞江、面熟是薰风，吹燕麦凫葵。", "赖君王洪福，河清可晏，物阜人熙。", "想见搴帷使者，随处采声诗。", "羡高禽矰弋，离贴天飞。", "飞到苍云深处，便敛收毛羽，望暮林归。", "可以人不若，剗地挂征衣。", "且招呼、麴生为友，对槐阴、时唱两三卮。", "今宵好，如钩佳月，放出光辉。"]'),
('song-ci-340','感皇恩','吴潜','宋','宋词','song-ci','感皇恩','[]','老去最难禁，流光如水。',81,'宋词/ci.song.15000.json','["老去最难禁，流光如水。", "甲子徒头试□指。", "年年生日，怕被旁人拈起。", "若攀儿额，颓龄犹未。", "方丈瀛洲，蓝溪碧沚。", "转眼鲈莼便秋意。", "君主定许，整顿江头行李。", "角巾归去也，休里第。"]'),
('song-ci-341','谒金门','吴潜','宋','宋词','song-ci','谒金门','[]','纱窗晓。',53,'宋词/ci.song.15000.json','["纱窗晓。", "杜宇数声声悄。", "真个不如归去好。", "天涯人已老。", "欹枕欲眠还觉。", "犹有青灯残照。", "谩道惜花春起早。", "家山千里杳。"]'),
('song-ci-342','谒金门','吴潜','宋','宋词','song-ci','谒金门','[]','停画鹢。',53,'宋词/ci.song.15000.json','["停画鹢。", "天外水澄烟碧。", "莫看遨头人似织。", "今年都老色。", "最苦今朝离夕。", "未卜今年归日。", "生怕晚风消酒力。", "愁城难借一。"]'),
('song-ci-343','谒金门','吴潜','宋','宋词','song-ci','谒金门','[]','山客野。',53,'宋词/ci.song.15000.json','["山客野。", "新把朝衔书写。", "应想江南樗枥下。", "踏歌鸡黍社。", "休问坤牛乾马。", "大率人生且且。", "聊唤玉人斟玉斝。", "莫辞沈醉也。"]'),
('song-ci-344','谒金门','吴潜','宋','宋词','song-ci','谒金门','[]','风韵彻。',53,'宋词/ci.song.15000.json','["风韵彻。", "满架平平铺雪。", "贾女何郎盟共结。", "睡浓香更冽。", "春去悄怀怎说。", "却喜不闻蹄鴂。", "月夜时来闲蹀屧。", "故园三载别。"]'),
('song-ci-345','浣溪沙','吴潜','宋','宋词','song-ci','浣溪沙','[]','庆赏元宵只愿情。',48,'宋词/ci.song.15000.json','["庆赏元宵只愿情。", "天公每事秤能平。", "管教檐溜便收声。", "三市海巡那惜夜，九街社火亦争名。", "权将歌酒作工程。"]'),
('song-ci-346','浣溪沙','吴潜','宋','宋词','song-ci','浣溪沙','[]','春岸春风荻已芽。',48,'宋词/ci.song.15000.json','["春岸春风荻已芽。", "推排春事到芦花。", "只应推上鬓边华。", "投老未归真左计，久阴得霁且舒怀。", "红红白白有残葩。"]'),
('song-ci-347','浣溪沙','吴潜','宋','宋词','song-ci','浣溪沙','[]','海棠已绽牡丹芽。',48,'宋词/ci.song.15000.json','["海棠已绽牡丹芽。", "犹有东君向上花。", "不须惆怅怨春华。", "装缀园林新景物，推敲风月旧情怀。", "也饶浪蕊与浮葩。"]'),
('song-ci-348','浣溪沙','吴潜','宋','宋词','song-ci','浣溪沙','[]','正好江乡笋蕨芽。',48,'宋词/ci.song.15000.json','["正好江乡笋蕨芽。", "他乡却看担头花。", "只将蝶梦付南华。", "万事纷纭都入幻，一杯邂逅且忘怀。", "年年秋卉与春葩。"]'),
('song-ci-349','浣溪沙','吴潜','宋','宋词','song-ci','浣溪沙','[]','雨过池堂水长芽。',48,'宋词/ci.song.15000.json','["雨过池堂水长芽。", "放开晴日正宣花。", "十洲三岛撰繁华。", "水畔丽人唐客恨，山阴佳客晋人怀。", "可怜云蕊与风葩。"]'),
('song-ci-350','浣溪沙','吴潜','宋','宋词','song-ci','浣溪沙','[]','最好荼縻白间黄。',48,'宋词/ci.song.15000.json','["最好荼縻白间黄。", "消他蜂蝶采花忙。", "春残红粉厌梳妆。", "毕卓正思身夜瓮，刘章底用令秋霜。", "今宵帏枕十分香。"]'),
('song-ci-351','浣溪沙','吴潜','宋','宋词','song-ci','浣溪沙','[]','宫额新涂一半黄。',48,'宋词/ci.song.15000.json','["宫额新涂一半黄。", "蔷薇空自效颦忙。", "澹然风韵道家妆。", "可惜今宵无皓月，尚怜向晓有繁霜。", "何妨手拈一枝香。"]'),
('song-ci-352','海棠春','吴潜','宋','宋词','song-ci','海棠春','[]','海棠亭午沾疏雨。',58,'宋词/ci.song.15000.json','["海棠亭午沾疏雨。", "便一饷、胭脂尽吐。", "老去惜花心，相对花无语。", "羽书万里飞来处。", "报扫荡、狐嗥兔舞。", "濯锦古江头，飞景还如许。"]'),
('song-ci-353','海棠春','吴潜','宋','宋词','song-ci','海棠春','[]','嫩晴还更宜轻雨。',58,'宋词/ci.song.15000.json','["嫩晴还更宜轻雨。", "最好处、欲开未吐。", "一点聘梅心，千古凭谁语。", "脸霞晕锦娇人处。", "肯浪逐、红围翠舞。", "银烛莫高烧，春梦无多许。"]'),
('song-ci-354','海棠春','吴潜','宋','宋词','song-ci','海棠春','[]','苍龙夭矫停今雨。',58,'宋词/ci.song.15000.json','["苍龙夭矫停今雨。", "正不待、云吞雾吐。", "绝笑大夫松，今古闲言语。", "清光冷艳侵入处。", "漏月影、婆娑自舞。", "拟作岁寒人，此愿天应许。"]'),
('song-ci-355','霜天晓角','吴潜','宋','宋词','song-ci','霜天晓角','[]','倚花傍月。',53,'宋词/ci.song.15000.json','["倚花傍月。", "花底歌声彻。", "最好月筛花影，花月浸、香奇绝。", "双溪秋月洁。", "桂棹何时发。", "客里明朝送客，多少事、且休说。"]'),
('song-ci-356','霜天晓角','吴潜','宋','宋词','song-ci','霜天晓角','[]','此花此月。',53,'宋词/ci.song.15000.json','["此花此月。", "一般风流彻。", "更好参横斗转，更漏断、人声绝。", "有谁秋共洁。", "篱菊相将发。", "留取岁寒心事，待此际、向君说。"]'),
('song-ci-357','霜天晓角','吴潜','宋','宋词','song-ci','霜天晓角','[]','杯中吸月。',53,'宋词/ci.song.15000.json','["杯中吸月。", "桂树飞琼屑。", "莫道胡床老子，怕风露、向凄冽。", "回首云娥折。", "老大成痴绝。", "且醉今宵光景，莫容易、向人说。"]'),
('song-ci-358','霜天晓角','吴潜','宋','宋词','song-ci','霜天晓角','[]','为花问月。',53,'宋词/ci.song.15000.json','["为花问月。", "谁把金魂屑。", "犹有残英剩蕊，秋向老、香逾冽。", "且莫都攀折。", "有个人愁绝。", "纵使垣娥念旧，星星鬓、如何说。"]'),
('song-ci-359','霜天晓角','吴潜','宋','宋词','song-ci','霜天晓角','[]','新词唱彻。',53,'宋词/ci.song.15000.json','["新词唱彻。", "字字珠玑屑。", "更有张颠草圣，何止是、成双绝。", "金粟如霏雪。", "扫地为芳席。", "且令诸公一笑，怕明夜、无此月。"]'),
('song-ci-360','霜天晓角','吴潜','宋','宋词','song-ci','霜天晓角','[]','小山幽彻。',53,'宋词/ci.song.15000.json','["小山幽彻。", "遍地堆香雪。", "只恐今宵入梦，梦到处、魂孤绝。", "八公头已雪。", "淮南分半席。", "莫道淹留何事，且长啸、对佳月。"]'),
('song-ci-361','霜天晓角','吴潜','宋','宋词','song-ci','霜天晓角','[]','梅花一簇。',53,'宋词/ci.song.15000.json','["梅花一簇。", "花上千枝烛。", "照出靓妆姿态，看不足、咏不足。", "便欲和花宿。", "却被官身局。", "借问江南归未，今夜梦、难拘束。"]'),
('song-ci-362','霜天晓角','吴潜','宋','宋词','song-ci','霜天晓角','[]','秋凉佳月。',53,'宋词/ci.song.15000.json','["秋凉佳月。", "扫尽轻衫热。", "便欲乘风归去，冰玉界、琼林阙。", "不须持寸铁。", "孤吟风措别。", "且唱东坡水调，清露下、满襟雪。"]'),
('song-ci-363','霜天晓角','吴潜','宋','宋词','song-ci','霜天晓角','[]','举杯吸月。',53,'宋词/ci.song.15000.json','["举杯吸月。", "一洗烦襟热。", "想见摩诃池上，星斗转、挂银阙。", "金吾传漏铁。", "此时滋味别。", "阶砌寒蛩声细，携手处、人如雪。"]'),
('song-ci-364','蝶恋花','吴潜','宋','宋词','song-ci','蝶恋花','[]','澹白轻黄纯雅素。',70,'宋词/ci.song.15000.json','["澹白轻黄纯雅素。", "一段风流，欹枕疏窗户。", "夜半香魂飞欲去。", "伴他月里霓裳舞。", "消得留春春且住。", "不比杨花，轻作沾泥絮。", "况是成阴环幄处。", "不愁更被红窗妒。"]'),
('song-ci-365','朝中措','吴潜','宋','宋词','song-ci','朝中措','[]','春空一鸟落云干。',57,'宋词/ci.song.15000.json','["春空一鸟落云干。", "只遣客心酸。", "勺药牡丹时候，午窗轻暖轻寒。", "流光冉冉，清尊易倒，青镜难看。", "谩道华堂深院，谁怜凤只鹓单。"]'),
('song-ci-366','朝中措','吴潜','宋','宋词','song-ci','朝中措','[]','可人想见倚庭干。',57,'宋词/ci.song.15000.json','["可人想见倚庭干。", "嚼句有甘酸。", "休问沈腰潘鬓，何妨岛瘦郊寒。", "时光转眼，兔葵燕麦，又是看看。", "谁念衰翁衰处，春衫晚际尤单。"]'),
('song-ci-367','朝中措','吴潜','宋','宋词','song-ci','朝中措','[]','杨花撩乱与云干。',57,'宋词/ci.song.15000.json','["杨花撩乱与云干。", "春事可悲酸。", "况是雨荒院落，江南但有春寒。", "莺残燕赖，蜂慵蝶褪，谩等闲看。", "不是无情描貌，奚奴且放安单。"]'),
('song-ci-368','朝中措','吴潜','宋','宋词','song-ci','朝中措','[]','夜来梦绕宛溪干。',57,'宋词/ci.song.15000.json','["夜来梦绕宛溪干。", "啼鴂梦中酸。", "过了他乡寒食，白鸥划地盟寒。", "云溪雨壑，月台风榭，借与人看。", "得似野僧无系，孤藤杖底挑单。"]'),
('song-ci-369','朝中措','吴潜','宋','宋词','song-ci','朝中措','[]','兰皋彻夜树旄干。',57,'宋词/ci.song.15000.json','["兰皋彻夜树旄干。", "战渴望梅酸。", "想有歌姬半臂，更深自可鏖寒。", "敲门寄曲，惊回蝶梦，旋篝灯看。", "坛下已收降将，火牛不用田单。"]'),
('song-ci-370','朝中措','吴潜','宋','宋词','song-ci','朝中措','[]','衰翁老大脚犹轻。',57,'宋词/ci.song.15000.json','["衰翁老大脚犹轻。", "行到净凉亭。", "近日方忧多雨，连朝且喜长晴。", "谩寻欢笑，翠涛杯满，金缕歌清。", "况有兰朋竹友，柳词贺句争鸣。"]'),
('song-ci-371','虞美人','吴潜','宋','宋词','song-ci','虞美人','[]','东风催客呼前渡。',66,'宋词/ci.song.15000.json','["东风催客呼前渡。", "宿鸟投林暮。", "欲送人送得归人。", "万叠青山罗列、是愁城。", "谁家台榭当年筑。", "芳草垂杨绿。", "云深雾暗不须悲。", "只缘盈虚消息、少人知。"]');
